              <Grid VerticalAlignment="Center" MaxWidth="140">
                <TextBlock x:Name="LoginBrandNameShadow" Text="MiniBot" Foreground="#000000"
                           FontSize="13" FontWeight="SemiBold"
                           TextTrimming="CharacterEllipsis" MaxWidth="140"
