                  <TextBlock.Effect>
                    <DropShadowEffect Color="#000000" BlurRadius="3.5" ShadowDepth="0"
                                      Opacity="0.85" Direction="0"/>
                  </TextBlock.Effect>
                </TextBlock>
                <TextBlock x:Name="LoginBrandName" Text="MiniBot" Foreground="#B80F0A"
