				if ($loginBrandNameShadow) { $loginBrandNameShadow.Text = $an }
			} catch {}
			$setLoginTitleLabel = {
				param([string]$Text)
				try {
					if ($loginTitleLabel) { $loginTitleLabel.Text = $Text }
					if ($loginTitleLabelShadow) { $loginTitleLabelShadow.Text = $Text }
				} catch {}
			}.GetNewClosure()
			$loginRobotPath = $win.FindName('LoginRobotPath')
			$loginRobotHost = $win.FindName('LoginRobotHost')
			$loginRobotStop0 = $win.FindName('LoginRobotStop0')
			$loginRobotStop1 = $win.FindName('LoginRobotStop1')
			$loginRobotStop2 = $win.FindName('LoginRobotStop2')
			if ((-not $loginRobotStop0 -or -not $loginRobotStop1 -or -not $loginRobotStop2) -and $loginRobotPath) {
				try {
					$lrb = $loginRobotPath.Fill
					if ($lrb -is [System.Windows.Media.LinearGradientBrush] -and $lrb.GradientStops.Count -ge 3) {
						$loginRobotStop0 = $lrb.GradientStops[0]
						$loginRobotStop1 = $lrb.GradientStops[1]
						$loginRobotStop2 = $lrb.GradientStops[2]
					}
				} catch {}
			}
			$loginRobotDataDefault = 'M12,2A2,2 0 0,1 14,4C14,4.74 13.6,5.39 13,5.73V7H14A7,7 0 0,1 21,14H22A1,1 0 0,1 23,15V18A1,1 0 0,1 22,19H21V20A2,2 0 0,1 19,22H5A2,2 0 0,1 3,20V19H2A1,1 0 0,1 1,18V15A1,1 0 0,1 2,14H3A7,7 0 0,1 10,7H11V5.73C10.4,5.39 10,4.74 10,4A2,2 0 0,1 12,2M7.5,13A2.5,2.5 0 0,0 5,15.5A2.5,2.5 0 0,0 7.5,18A2.5,2.5 0 0,0 10,15.5A2.5,2.5 0 0,0 7.5,13M16.5,13A2.5,2.5 0 0,0 14,15.5A2.5,2.5 0 0,0 16.5,18A2.5,2.5 0 0,0 19,15.5A2.5,2.5 0 0,0 16.5,13Z'
			$loginRobotDataHappy = 'M22 14H21C21 10.13 17.87 7 14 7H13V5.73C13.6 5.39 14 4.74 14 4C14 2.9 13.11 2 12 2S10 2.9 10 4C10 4.74 10.4 5.39 11 5.73V7H10C6.13 7 3 10.13 3 14H2C1.45 14 1 14.45 1 15V18C1 18.55 1.45 19 2 19H3V20C3 21.11 3.9 22 5 22H19C20.11 22 21 21.11 21 20V19H22C22.55 19 23 18.55 23 18V15C23 14.45 22.55 14 22 14M9.79 16.5C9.4 15.62 8.53 15 7.5 15S5.6 15.62 5.21 16.5C5.08 16.19 5 15.86 5 15.5C5 14.12 6.12 13 7.5 13S10 14.12 10 15.5C10 15.86 9.92 16.19 9.79 16.5M18.79 16.5C18.4 15.62 17.5 15 16.5 15S14.6 15.62 14.21 16.5C14.08 16.19 14 15.86 14 15.5C14 14.12 15.12 13 16.5 13S19 14.12 19 15.5C19 15.86 18.92 16.19 18.79 16.5Z'
			$loginRobotDataDead = 'M22 14H21C21 10.13 17.87 7 14 7H13V5.73C13.6 5.39 14 4.74 14 4C14 2.9 13.11 2 12 2S10 2.9 10 4C10 4.74 10.4 5.39 11 5.73V7H10C6.13 7 3 10.13 3 14H2C1.45 14 1 14.45 1 15V18C1 18.55 1.45 19 2 19H3V20C3 21.11 3.9 22 5 22H19C20.11 22 21 21.11 21 20V19H22C22.55 19 23 18.55 23 18V15C23 14.45 22.55 14 22 14M9.86 16.68L8.68 17.86L7.5 16.68L6.32 17.86L5.14 16.68L6.32 15.5L5.14 14.32L6.32 13.14L7.5 14.32L8.68 13.14L9.86 14.32L8.68 15.5L9.86 16.68M18.86 16.68L17.68 17.86L16.5 16.68L15.32 17.86L14.14 16.68L15.32 15.5L14.14 14.32L15.32 13.14L16.5 14.32L17.68 13.14L18.86 14.32L17.68 15.5L18.86 16.68Z'
			$setLoginRobotFace = {
				param([string]$Face = 'default')
				try {
					if (-not $loginRobotPath) { return }
					$face = ([string]$Face).ToLowerInvariant()
					if ($face -eq 'happy') { $data = $loginRobotDataHappy }
					elseif ($face -eq 'dead') { $data = $loginRobotDataDead }
					else { $data = $loginRobotDataDefault }
					$loginRobotPath.Data = [System.Windows.Media.Geometry]::Parse($data)
					$cols = @('#C8C8D0', '#6A6A74', '#3A3A42')
					$st = @($loginRobotStop0, $loginRobotStop1, $loginRobotStop2)
					for ($i = 0; $i -lt 3; $i++) {
						if (-not $st[$i]) { continue }
						try { $st[$i].Color = [System.Windows.Media.ColorConverter]::ConvertFromString([string]$cols[$i]) } catch {}
					}
					$dot = [string][char]0x00B7
					if ($face -eq 'happy') { $tip = "MiniBot $dot signed in" }
					elseif ($face -eq 'dead') { $tip = "MiniBot $dot offline" }
					else { $tip = "MiniBot $dot connect" }
					if ($loginRobotHost) {
						try {
							$bcR = New-Object System.Windows.Media.BrushConverter
							$tt = New-Object System.Windows.Controls.ToolTip
							$tt.Background = $bcR.ConvertFromString('#1A1A1E')
							$tt.Foreground = $bcR.ConvertFromString('#C8C8D0')
							$tt.BorderBrush = $bcR.ConvertFromString('#3A3A42')
							$tt.BorderThickness = New-Object System.Windows.Thickness(1)
							$tt.Padding = New-Object System.Windows.Thickness(10, 7, 10, 7)
							$tt.HasDropShadow = $true
							$tbR = New-Object System.Windows.Controls.TextBlock
							$tbR.Text = $tip
							$tbR.Foreground = $bcR.ConvertFromString('#C8C8D0')
							$tbR.FontSize = 12
							$tt.Content = $tbR
							$loginRobotHost.ToolTip = $tt
						} catch { $loginRobotHost.ToolTip = $tip }
					}
				} catch {}
			}.GetNewClosure()
			# Login window icon
			$toShellIcon = {
				param($Source)
				if (-not $Source) { return $null }
				try {
					$enc = New-Object System.Windows.Media.Imaging.PngBitmapEncoder
					[void]$enc.Frames.Add([System.Windows.Media.Imaging.BitmapFrame]::Create($Source))
					$ms = New-Object System.IO.MemoryStream
					try {
						$enc.Save($ms)
						$ms.Position = 0
						$frame = [System.Windows.Media.Imaging.BitmapFrame]::Create(
							$ms,
							[System.Windows.Media.Imaging.BitmapCreateOptions]::None,
							[System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad
						)
						if ($frame.CanFreeze) { $frame.Freeze() }
						return $frame
					} finally { try { $ms.Dispose() } catch {} }
				} catch { return $Source }
			}.GetNewClosure()
			$setNativeIcon = {
				param($Window, $BitmapSource)
				if (-not $Window -or -not $BitmapSource) { return }
				try {
					if (-not ('MiniBot.UI.NativeIcon' -as [type])) {
						Add-Type -Namespace MiniBot.UI -Name NativeIcon -MemberDefinition @"
[System.Runtime.InteropServices.DllImport("user32.dll", CharSet=System.Runtime.InteropServices.CharSet.Auto)]
public static extern System.IntPtr SendMessage(System.IntPtr hWnd, int Msg, System.IntPtr wParam, System.IntPtr lParam);
[System.Runtime.InteropServices.DllImport("user32.dll", SetLastError=true)]
public static extern bool DestroyIcon(System.IntPtr hIcon);
[System.Runtime.InteropServices.DllImport("user32.dll", SetLastError=true)]
public static extern System.IntPtr CopyIcon(System.IntPtr hIcon);
public const int WM_SETICON = 0x0080;
public const int ICON_SMALL = 0;
public const int ICON_BIG = 1;
"@ -ErrorAction Stop
					}
					Add-Type -AssemblyName System.Drawing -ErrorAction SilentlyContinue
					$enc = New-Object System.Windows.Media.Imaging.PngBitmapEncoder
					[void]$enc.Frames.Add([System.Windows.Media.Imaging.BitmapFrame]::Create($BitmapSource))
					$ms = New-Object System.IO.MemoryStream
					try {
						$enc.Save($ms)
						$ms.Position = 0
						$gdi = [System.Drawing.Bitmap]::FromStream($ms)
						try {
							$hIcon = $gdi.GetHicon()
							try {
								$helper = New-Object System.Windows.Interop.WindowInteropHelper($Window)
								$hwnd = $helper.EnsureHandle()
								if ($hwnd -ne [IntPtr]::Zero) {
									$hSmall = [MiniBot.UI.NativeIcon]::CopyIcon($hIcon)
									$hBig = [MiniBot.UI.NativeIcon]::CopyIcon($hIcon)
									$prevSmall = [MiniBot.UI.NativeIcon]::SendMessage($hwnd, [MiniBot.UI.NativeIcon]::WM_SETICON, [IntPtr][MiniBot.UI.NativeIcon]::ICON_SMALL, $hSmall)
									$prevBig = [MiniBot.UI.NativeIcon]::SendMessage($hwnd, [MiniBot.UI.NativeIcon]::WM_SETICON, [IntPtr][MiniBot.UI.NativeIcon]::ICON_BIG, $hBig)
									if ($prevSmall -ne [IntPtr]::Zero) { try { [void][MiniBot.UI.NativeIcon]::DestroyIcon($prevSmall) } catch {} }
									if ($prevBig -ne [IntPtr]::Zero) { try { [void][MiniBot.UI.NativeIcon]::DestroyIcon($prevBig) } catch {} }
								}
							} finally { try { [void][MiniBot.UI.NativeIcon]::DestroyIcon($hIcon) } catch {} }
						} finally { try { $gdi.Dispose() } catch {} }
					} finally { try { $ms.Dispose() } catch {} }
				} catch {}
			}.GetNewClosure()
			$renderLoginRobotIcon = {
				param([string]$Face = 'default', [int]$Size = 64)
				try {
					if ($Size -lt 16) { $Size = 16 }
					if ($Face -eq 'happy') { $data = $loginRobotDataHappy }
					elseif ($Face -eq 'dead') { $data = $loginRobotDataDead }
					else { $data = $loginRobotDataDefault }
					$cols = @('#C8C8D0', '#6A6A74', '#3A3A42')
					$geom = [System.Windows.Media.Geometry]::Parse($data)
					$brush = New-Object System.Windows.Media.LinearGradientBrush
					$brush.StartPoint = New-Object System.Windows.Point(0.15, 0.0)
					$brush.EndPoint = New-Object System.Windows.Point(0.9, 1.0)
					for ($ci = 0; $ci -lt 3; $ci++) {
						$off = @(0.0, 0.48, 1.0)[$ci]
						$col = [System.Windows.Media.ColorConverter]::ConvertFromString([string]$cols[$ci])
						[void]$brush.GradientStops.Add((New-Object System.Windows.Media.GradientStop($col, $off)))
					}
					$brush.Freeze()
					$bgBrush = New-Object System.Windows.Media.SolidColorBrush(([System.Windows.Media.ColorConverter]::ConvertFromString('#252530')))
					$bgBrush.Freeze()
					$visual = New-Object System.Windows.Media.DrawingVisual
					$dc = $visual.RenderOpen()
					try {
						$cx = [double]$Size / 2.0
						$dc.DrawEllipse($bgBrush, $null, (New-Object System.Windows.Point($cx, $cx)), ($cx - 0.5), ($cx - 0.5))
						$pad = [math]::Max(2.0, [double]$Size * 0.14)
						$inner = [double]$Size - (2.0 * $pad)
						$scale = $inner / 24.0
						$dc.PushTransform((New-Object System.Windows.Media.TranslateTransform($pad, $pad)))
						$dc.PushTransform((New-Object System.Windows.Media.ScaleTransform($scale, $scale)))
						$dc.DrawGeometry($brush, $null, $geom)
						$dc.Pop(); $dc.Pop()
					} finally { $dc.Close() }
					$rtb = New-Object System.Windows.Media.Imaging.RenderTargetBitmap(
						[int]$Size, [int]$Size, 96, 96,
						[System.Windows.Media.PixelFormats]::Pbgra32
					)
					$rtb.Render($visual)
					return (& $toShellIcon $rtb)
				} catch { return $null }
			}.GetNewClosure()
			$applyLoginWindowIcon = {
				param([string]$Face = 'default')
				try {
					$bmp = & $renderLoginRobotIcon $Face 64
					if (-not $bmp) { return }
					$win.Icon = $bmp
					if (-not $win.TaskbarItemInfo) {
						$win.TaskbarItemInfo = New-Object System.Windows.Shell.TaskbarItemInfo
					}
					$win.TaskbarItemInfo.Overlay = $bmp
					$win.TaskbarItemInfo.Description = $(if ($Ver) { "MiniBot v$Ver" } else { 'MiniBot' })
					try { & $setNativeIcon $win $bmp } catch {}
				} catch {}
			}.GetNewClosure()
			$makeThemedToolTip = {
				param([string]$Text, [double]$MaxWidth = 340)
				if ([string]::IsNullOrWhiteSpace($Text)) { return $null }
				try {
					$bcT = New-Object System.Windows.Media.BrushConverter
					$tip = New-Object System.Windows.Controls.ToolTip
					$tip.Background = $bcT.ConvertFromString('#1A1A1E')
					$tip.Foreground = $bcT.ConvertFromString('#C8C8D0')
					$tip.BorderBrush = $bcT.ConvertFromString('#3A3A42')
					$tip.BorderThickness = New-Object System.Windows.Thickness(1)
					$tip.Padding = New-Object System.Windows.Thickness(10, 7, 10, 7)
					$tip.HasDropShadow = $true
					try { $tip.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Mouse } catch {}
					$ttb = New-Object System.Windows.Controls.TextBlock
					$ttb.Text = [string]$Text
					$ttb.TextWrapping = [System.Windows.TextWrapping]::Wrap
					$ttb.MaxWidth = [double]$MaxWidth
					$ttb.Foreground = $bcT.ConvertFromString('#C8C8D0')
					$ttb.FontSize = 12
					$ttb.LineHeight = 16
					try { $ttb.FontFamily = New-Object System.Windows.Media.FontFamily('Consolas, Cascadia Mono, Courier New') } catch {}
					$tip.Content = $ttb
					return $tip
				} catch { return [string]$Text }
			}.GetNewClosure()
			$setThemedToolTip = {
				param($Target, [string]$Text, [double]$MaxWidth = 340)
				if ($null -eq $Target) { return }
				try {
					$obj = & $makeThemedToolTip $Text $MaxWidth
					if ($null -ne $obj) {
						$Target.ToolTip = $obj
						try {
							[System.Windows.Controls.ToolTipService]::SetInitialShowDelay($Target, 350)
							[System.Windows.Controls.ToolTipService]::SetShowDuration($Target, 20000)
						} catch {}
					} else {
						$Target.ToolTip = [string]$Text
					}
				} catch {
					try { $Target.ToolTip = [string]$Text } catch {}
				}
			}.GetNewClosure()
			try { & $setLoginRobotFace 'default' } catch {}
			try { & $applyLoginWindowIcon 'default' } catch {}
			if ($sub) { $sub.Text = ("Sign in to access:`n{0}" -f $Hint) }
			$setBackVisible = {
				param([bool]$Show)
				try {
					if (-not $loginTitleBack) { return }
					$loginTitleBack.Visibility = $(if ($Show) {
						[System.Windows.Visibility]::Visible
					} else {
						[System.Windows.Visibility]::Collapsed
					})
				} catch {}
			}.GetNewClosure()

			# Themed tooltips (auth / connect chrome)
			try {
				if ($loginTitleClose) { & $setThemedToolTip $loginTitleClose 'Close' 120 }
				if ($loginTitleBack) { & $setThemedToolTip $loginTitleBack 'Back to endpoint' 200 }
				if ($loginRobotHost) { & $setThemedToolTip $loginRobotHost 'MiniBot' 140 }
				if ($epAuthNone) { & $setThemedToolTip $epAuthNone 'No Authorization header (open LAN servers)' 280 }
				if ($epAuthKey) { & $setThemedToolTip $epAuthKey 'Bearer token (Unsloth, vLLM --api-key, OpenAI-compat keys)' 300 }
				if ($epAuthNpm) { & $setThemedToolTip $epAuthNpm 'HTTP Basic - use for NPM reverse-proxy / session login credentials' 300 }
				if ($epConnect) { & $setThemedToolTip $epConnect 'Test endpoint and continue' 220 }
				if ($epCancel) { & $setThemedToolTip $epCancel 'Quit MiniBot' 160 }
				if ($ok) { & $setThemedToolTip $ok 'Sign in with username and password' 260 }
				if ($cancel) { & $setThemedToolTip $cancel 'Quit MiniBot' 160 }
				if ($saveCb) { & $setThemedToolTip $saveCb 'Remember credentials for next launch' 260 }
				if ($cYes) { & $setThemedToolTip $cYes 'Yes' 100 }
				if ($cNo) { & $setThemedToolTip $cNo 'No' 100 }
				if ($epUrl) { & $setThemedToolTip $epUrl 'OpenAI-compatible API base (prefer .../v1)' 300 }
				if ($epKey) { & $setThemedToolTip $epKey 'Bearer token used when Auth = API' 260 }
			} catch {}
			# Titlebar drag and close hover
			try {
				if ($loginTitleBar) {
					$loginTitleBar.add_MouseLeftButtonDown({
						param($s, $e)
						try {
							if ($loginTitleBack -and $loginTitleBack.IsMouseOver) { return }
							if ($loginTitleClose -and $loginTitleClose.IsMouseOver) { return }
							if ($e.ChangedButton -eq [System.Windows.Input.MouseButton]::Left) { $win.DragMove() }
						} catch {}
					}.GetNewClosure())
				}
				if ($loginTitleClose) {
					$bcL = New-Object System.Windows.Media.BrushConverter
					$loginTitleClose.add_MouseEnter({
						try { $loginTitleClose.Background = $bcL.ConvertFromString('#E81123') } catch {}
					}.GetNewClosure())
					$loginTitleClose.add_MouseLeave({
						try { $loginTitleClose.Background = [System.Windows.Media.Brushes]::Transparent } catch {}
					}.GetNewClosure())
				}
				# Back: same grey hover as main-window Maximize
				if ($loginTitleBack) {
					$bcB = New-Object System.Windows.Media.BrushConverter
					$loginTitleBack.add_MouseEnter({
						try { $loginTitleBack.Background = $bcB.ConvertFromString('#3A3A42') } catch {}
					}.GetNewClosure())
					$loginTitleBack.add_MouseLeave({
						try { $loginTitleBack.Background = [System.Windows.Media.Brushes]::Transparent } catch {}
					}.GetNewClosure())
				}
			} catch {}
			try {
				if ($loginTitleLabel -and $confirmLayer) {
					# keep label in sync when layers swap
				}
			} catch {}

			$stopConfirmPulse = {
				try {
					if ($cBar) {
						$cBar.BeginAnimation([System.Windows.UIElement]::OpacityProperty, $null)
						$cBar.Opacity = 0.55
					}
				} catch {}
			}.GetNewClosure()

			$startConfirmPulse = {
				try {
					if (-not $cBar) { return }
					$anim = New-Object System.Windows.Media.Animation.DoubleAnimation
					$anim.From = 0.35
					$anim.To = 1.0
					$anim.Duration = New-Object System.Windows.Duration ([TimeSpan]::FromMilliseconds(900))
					$anim.AutoReverse = $true
					$anim.RepeatBehavior = [System.Windows.Media.Animation.RepeatBehavior]::Forever
					try {
						$ease = New-Object System.Windows.Media.Animation.SineEase
						$ease.EasingMode = [System.Windows.Media.Animation.EasingMode]::EaseInOut
						$anim.EasingFunction = $ease
					} catch {}
					$cBar.BeginAnimation([System.Windows.UIElement]::OpacityProperty, $anim)
				} catch {}
			}.GetNewClosure()

			$showLogin = {
				try {
					& $stopConfirmPulse
					if ($connectLayer) { $connectLayer.Visibility = [System.Windows.Visibility]::Collapsed }
					if ($confirmLayer) { $confirmLayer.Visibility = [System.Windows.Visibility]::Collapsed }
					if ($loginLayer) { $loginLayer.Visibility = [System.Windows.Visibility]::Visible }
					& $setLoginTitleLabel 'Login'
					# Back only when user reached Login via Connect (manual empty BaseUrl or recovery)
					$allowBack = $false
					try { $allowBack = [bool]$B.CanGoBackToConnect } catch {}
					& $setBackVisible $allowBack
					try { & $setLoginRobotFace 'default' } catch {}
					try { & $applyLoginWindowIcon 'default' } catch {}
					# Refresh host line — ConnectUrl may have changed after a failed first attempt
					try {
						$hintUrl = ''
						try { $hintUrl = [string]$B.ConnectUrl } catch {}
						if ([string]::IsNullOrWhiteSpace($hintUrl) -and $epUrl) {
							try { $hintUrl = ([string]$epUrl.Text).Trim() } catch {}
						}
						if ([string]::IsNullOrWhiteSpace($hintUrl)) { $hintUrl = [string]$Hint }
						if ($sub -and -not [string]::IsNullOrWhiteSpace($hintUrl)) {
							$sub.Text = ("Sign in to access:`n{0}" -f $hintUrl)
						}
					} catch {}
					if ($ok) { $ok.IsDefault = $true }
					if ($cYes) { $cYes.IsDefault = $false }
					if ($epConnect) { try { $epConnect.IsDefault = $false } catch {} }
					if ($err) { $err.Text = '' }
					try { if ($pass) { $pass.Password = '' } } catch {}
					try { if ($user) { [void]$user.Focus() } } catch {}
				} catch {}
			}.GetNewClosure()

			$showConfirm = {
				param([string]$promptText, [string]$titleText)
				try {
					if ($connectLayer) { $connectLayer.Visibility = [System.Windows.Visibility]::Collapsed }
					if ($loginLayer) { $loginLayer.Visibility = [System.Windows.Visibility]::Collapsed }
					if ($confirmLayer) { $confirmLayer.Visibility = [System.Windows.Visibility]::Visible }
					& $setLoginTitleLabel 'Confirm'
					& $setBackVisible $false
					if ($cTitle) {
						try { $cTitle.Inlines.Clear() } catch {}
						$cTitle.Text = 'Invalid Entry'
						$cTitle.FontSize = 16
						$cTitle.FontWeight = [System.Windows.FontWeights]::Bold
						try {
							$bc = New-Object System.Windows.Media.BrushConverter
							$cTitle.Foreground = $bc.ConvertFromString('#E0E0E8')
						} catch {}
					}
					if ($cPrompt) { $cPrompt.Text = $promptText }
					if ($ok) { $ok.IsDefault = $false }
					if ($cYes) {
						$cYes.IsDefault = $true
						try { [void]$cYes.Focus() } catch {}
					}
					& $startConfirmPulse
				} catch {}
			}.GetNewClosure()

			$syncEpKey = {
				try {
					$use = $false
					try { $use = [bool]$epAuthKey.IsChecked } catch {}
					if ($epKey) {
						$epKey.IsEnabled = $use
						$epKey.Opacity = $(if ($use) { 1.0 } else { 0.45 })
					}
					if ($epKeyLbl) { $epKeyLbl.Opacity = $(if ($use) { 1.0 } else { 0.55 }) }
				} catch {}
			}.GetNewClosure()
			try {
				if ($epAuthNone) { $null = $epAuthNone.Add_Checked({ & $syncEpKey }.GetNewClosure()) }
				if ($epAuthKey) { $null = $epAuthKey.Add_Checked({ & $syncEpKey }.GetNewClosure()) }
				if ($epAuthNpm) { $null = $epAuthNpm.Add_Checked({ & $syncEpKey }.GetNewClosure()) }
			} catch {}

			$probeEndpoint = {
				param([string]$BaseUrlIn, [string]$Mode, [string]$Key, [int]$TimeoutSec = 8)
				$raw = ([string]$BaseUrlIn).Trim()
				while ($raw.EndsWith('/')) { $raw = $raw.Substring(0, $raw.Length - 1) }
				$raw = $raw -replace '/chat/completions\s*$', '' -replace '/models\s*$', ''
				$raw = $raw -replace '/v1/chat/completions\s*$', '' -replace '/v1/models\s*$', ''
				while ($raw.EndsWith('/')) { $raw = $raw.Substring(0, $raw.Length - 1) }
				$bases = New-Object System.Collections.Generic.List[string]
				if ($raw -match '/v1$') {
					[void]$bases.Add($raw)
					$root = $raw -replace '/v1$', ''
					if ($root -and -not $bases.Contains($root)) { [void]$bases.Add($root) }
				} else {
					[void]$bases.Add($raw + '/v1')
					[void]$bases.Add($raw)
				}
				$headers = @{}
				if ($Mode -eq 'apikey' -and $Key) { $headers['Authorization'] = "Bearer $Key" }
				try { [System.Net.ServicePointManager]::SecurityProtocol = [System.Net.SecurityProtocolType]::Tls12 } catch {}
				try { [System.Net.ServicePointManager]::Expect100Continue = $false } catch {}
				$lastMsg = 'No response'
				$lastCode = 0
				$pp = $Global:ProgressPreference
				$Global:ProgressPreference = 'SilentlyContinue'
				try {
					foreach ($base in $bases) {
						$testUrl = "$base/models"
						try {
							$response = Invoke-WebRequest -Uri $testUrl -Method GET -Headers $headers -TimeoutSec $TimeoutSec -UseBasicParsing -ErrorAction Stop
							$code = [int]$response.StatusCode
							if ($code -eq 200) {
								$body = ''
								try { $body = [string]$response.Content } catch { $body = '' }
								if ($body -match '"object"\s*:\s*"list"' -or $body -match '"data"\s*:\s*\[' -or $body.Trim().StartsWith('{') -or $body.Trim().StartsWith('[')) {
									return @{ Ok = $true; StatusCode = 200; Message = "OK → $base"; BaseUrl = $base }
								}
								$lastMsg = "HTTP 200 from $testUrl but body is not a models API"
								$lastCode = 200
								continue
							}
							$lastMsg = "HTTP $code from $testUrl"
							$lastCode = $code
						} catch [System.Net.WebException] {
							$code = 0
							try { $code = [int]$_.Exception.Response.StatusCode } catch {}
							if ($code -in 401, 403) {
								if ($Mode -eq 'apikey') {
									return @{ Ok = $false; StatusCode = $code; Message = "Authentication failed ($code) — check API key"; BaseUrl = $base }
								}
								return @{ Ok = $true; StatusCode = $code; Message = 'Reachable (auth required)'; BaseUrl = $base; NeedsAuth = $true }
							}
							if ($code) { $lastMsg = "Server returned HTTP $code from $testUrl"; $lastCode = $code }
							else { $lastMsg = "$($_.Exception.Message)"; $lastCode = 0 }
						} catch {
							$lastMsg = $_.Exception.Message
							$lastCode = 0
						}
					}
				} finally { $Global:ProgressPreference = $pp }
				return @{ Ok = $false; StatusCode = $lastCode; Message = $lastMsg; BaseUrl = $raw }
			}.GetNewClosure()

			$epBusy = [ref]$false
			$epWantCancel = [ref]$false
			$setEpBusy = {
				param([bool]$On)
				$epBusy.Value = $On
				try {
					if ($epConnect) {
						$epConnect.IsEnabled = -not $On
						$epConnect.Content = $(if ($On) { '…' } else { 'Connect' })
					}
					if ($epUrl) { $epUrl.IsEnabled = -not $On }
					if ($epAuthNone) { $epAuthNone.IsEnabled = -not $On }
					if ($epAuthKey) { $epAuthKey.IsEnabled = -not $On }
					if ($epAuthNpm) { $epAuthNpm.IsEnabled = -not $On }
					if (-not $On) { & $syncEpKey } else { if ($epKey) { $epKey.IsEnabled = $false } }
				} catch {}
			}.GetNewClosure()

			$showConnect = {
				try {
					& $stopConfirmPulse
					if ($loginLayer) { $loginLayer.Visibility = [System.Windows.Visibility]::Collapsed }
					if ($confirmLayer) { $confirmLayer.Visibility = [System.Windows.Visibility]::Collapsed }
					if ($connectLayer) { $connectLayer.Visibility = [System.Windows.Visibility]::Visible }
					# Using Connect layer => Login may offer Back later
					try { $B.CanGoBackToConnect = $true } catch {}
					& $setBackVisible $false
					$isConn = $false
					try { $isConn = [bool]$B.ConnectMode } catch {}
					& $setLoginTitleLabel $(if ($isConn) { 'Connect' } else { 'Connection' })
					try {
						if ($isConn) {
							& $setLoginRobotFace 'default'
							& $applyLoginWindowIcon 'default'
						} else {
							& $setLoginRobotFace 'dead'
							& $applyLoginWindowIcon 'dead'
						}
					} catch {}
					if ($epHeading) {
						$epHeading.Text = $(if ($isConn) { 'Enter your model endpoint' } else { 'Cannot reach model endpoint' })
					}
					if ($epSub) {
						if ($isConn) {
							$epSub.Text = 'Connect MiniBot to an OpenAI-compatible API base. Example: http://127.0.0.1:8080/v1  (vLLM, Unsloth, llama.cpp, etc.)'
						} else {
							$em = ''
							try { $em = [string]$B.ConnectError } catch {}
							if ($em) { $epSub.Text = $em }
							else { $epSub.Text = 'The configured BaseUrl is not responding. Check the URL and auth, then try again (prefer .../v1 for vLLM/Unsloth).' }
						}
					}
					try {
						$u0 = ''
						try { $u0 = [string]$B.ConnectUrl } catch {}
						if ([string]::IsNullOrWhiteSpace($u0)) { $u0 = [string]$Hint }
						if ([string]::IsNullOrWhiteSpace($u0)) { $u0 = 'http://127.0.0.1:8080/v1' }
						if ($epUrl) { $epUrl.Text = $u0 }
					} catch {}
					if ($epError) { $epError.Text = '' }
					if ($ok) { try { $ok.IsDefault = $false } catch {} }
					if ($cYes) { try { $cYes.IsDefault = $false } catch {} }
					if ($epConnect) { try { $epConnect.IsDefault = $true } catch {} }
					& $setEpBusy $false
					& $syncEpKey
					$epWantCancel.Value = $false
					try { if ($epUrl) { [void]$epUrl.Focus(); $epUrl.SelectAll() } } catch {}
				} catch {}
			}.GetNewClosure()

			$doConnectCancel = {
				try {
					if ($epBusy.Value) {
						$epWantCancel.Value = $true
						try {
							if ($epError) {
								$bcX = New-Object System.Windows.Media.BrushConverter
								$epError.Foreground = $bcX.ConvertFromString('#8A8A96')
								$epError.Text = 'Cancelling...'
							}
						} catch {}
						return
					}
					$B.EndpointResult = @{
						Cancelled = $true
						Url = ''
						AuthMode = 'none'
						ApiKey = ''
					}
					try { [void]$B.EndpointWait.Set() } catch {}
					try { [void]$B.CredWait.Set() } catch {}
					try { [void]$B.ConfirmWait.Set() } catch {}
					try { $win.Close() } catch {}
				} catch {}
			}.GetNewClosure()

			$tryEpConnect = {
				if ($epBusy.Value) { return }
				try {
					$bcX = New-Object System.Windows.Media.BrushConverter
					$u = ''
					try { $u = ([string]$epUrl.Text).Trim() } catch {}
					if ([string]::IsNullOrWhiteSpace($u)) {
						if ($epError) {
							$epError.Foreground = $bcX.ConvertFromString('#F05C5C')
							$epError.Text = 'Enter a base URL (e.g. http://127.0.0.1:8080 or .../v1).'
						}
						return
					}
					if ($u -notmatch '^(?i)https?://') {
						if ($epError) {
							$epError.Foreground = $bcX.ConvertFromString('#F05C5C')
							$epError.Text = 'URL must start with http:// or https://'
						}
						return
					}
					$mode = 'none'
					try { if ([bool]$epAuthKey.IsChecked) { $mode = 'apikey' } elseif ([bool]$epAuthNpm.IsChecked) { $mode = 'npm' } } catch {}
					$k = ''
					if ($mode -eq 'apikey') {
						try { $k = [string]$epKey.Password } catch { $k = '' }
						if ([string]::IsNullOrWhiteSpace($k) -or $k -eq 'none') {
							if ($epError) {
								$epError.Foreground = $bcX.ConvertFromString('#F05C5C')
								$epError.Text = 'API mode requires a Bearer token.'
							}
							return
						}
					}
					$epWantCancel.Value = $false
					& $setEpBusy $true
					if ($epError) {
						$epError.Foreground = $bcX.ConvertFromString('#8A8A96')
						$epError.Text = 'Connecting...'
					}
					[void]$win.Dispatcher.BeginInvoke([Action]{
						try {
							$probe = & $probeEndpoint $u $mode $k 8
							if ($epWantCancel.Value -or [bool]$B.Closed) {
								if (-not $B.EndpointResult) {
									$B.EndpointResult = @{ Cancelled = $true; Url = ''; AuthMode = 'none'; ApiKey = '' }
								}
								try { [void]$B.EndpointWait.Set() } catch {}
								try { if ($win.IsVisible) { $win.Close() } } catch {}
								return
							}
							if ($probe -and $probe.Ok) {
								# Keep window open for possible auth step — only signal result
								try { $B.ConnectUrl = $u } catch {}
								$B.EndpointResult = @{
									Cancelled = $false
									Url       = $u
									AuthMode  = $mode
									ApiKey    = $(if ($mode -eq 'apikey') { $k } else { '' })
									StatusCode = [int]$probe.StatusCode
									NeedsAuth = [bool]$probe.NeedsAuth
								}
								try { [void]$B.EndpointWait.Set() } catch {}
								# Soft status while host retests / may switch to Login
								try {
									if ($epError) {
										$bc2 = New-Object System.Windows.Media.BrushConverter
										$epError.Foreground = $bc2.ConvertFromString('#8A8A96')
										$epError.Text = $(if ($probe.NeedsAuth) { 'Endpoint reachable - signing in...' } else { 'Connected - continuing...' })
									}
								} catch {}
								& $setEpBusy $false
								return
							}
							$detail = if ($probe -and $probe.Message) { [string]$probe.Message } else { 'No response from server.' }
							$detail = ($detail -replace '[\r\n]+', ' ').Trim()
							if ($detail.Length -gt 120) { $detail = $detail.Substring(0, 117) + '...' }
							if ($epError) {
								$bc2 = New-Object System.Windows.Media.BrushConverter
								$epError.Foreground = $bc2.ConvertFromString('#F05C5C')
								$epError.Text = "Connection was not successful. $detail"
							}
							& $setEpBusy $false
							try { if ($epUrl) { [void]$epUrl.Focus() } } catch {}
						} catch {
							try {
								if ($epError) {
									$bc2 = New-Object System.Windows.Media.BrushConverter
									$epError.Foreground = $bc2.ConvertFromString('#F05C5C')
									$epError.Text = "Connection was not successful. $($_.Exception.Message)"
								}
							} catch {}
							& $setEpBusy $false
						}
					}.GetNewClosure(), [System.Windows.Threading.DispatcherPriority]::Background)
				} catch {
					& $setEpBusy $false
				}
			}.GetNewClosure()

			try {
				if ($epConnect) { $null = $epConnect.Add_Click({ & $tryEpConnect }.GetNewClosure()) }
				if ($epCancel) { $null = $epCancel.Add_Click({ & $doConnectCancel }.GetNewClosure()) }
			} catch {}

			$submit = {
				$u = ''
				$p = ''
				try { $u = [string]$user.Text } catch {}
				try { $p = [string]$pass.Password } catch {}
				if ([string]::IsNullOrWhiteSpace($u) -or [string]::IsNullOrWhiteSpace($p)) {
					if ($err) { $err.Text = 'Username and password are required.' }
					return
				}
				if ($err) { $err.Text = '' }
				$wantSave = $false
				try { if ($saveCb -and $saveCb.IsChecked) { $wantSave = $true } } catch {}
				$B.CredResult = @{
					User           = $u.Trim()
					Pass           = $p
					Cancelled      = $false
					SoftExit       = $false
					HardClose      = $false
					Store          = $wantSave
					StoreSpecified = $true
					ClearStored    = $false
				}
				try { [void]$B.CredWait.Set() } catch {}
			}.GetNewClosure()

			$ok.add_Click({ param($s,$e) try { & $submit } catch {} }.GetNewClosure())
			$doLoginCancel = {
				try {
					$B.CredResult = @{
						User = $null; Pass = $null; Cancelled = $true
						SoftExit = $true; HardClose = $false
					}
					try { [void]$B.CredWait.Set() } catch {}
					try { [void]$B.ConfirmWait.Set() } catch {}
					try { $win.Close() } catch {}
				} catch {}
			}.GetNewClosure()
			$cancel.add_Click({
				param($s,$e)
				try { & $doLoginCancel } catch {}
			}.GetNewClosure())
			if ($loginTitleClose) {
				$loginTitleClose.add_Click({
					param($s,$e)
					try {
						$onConnect = $false
						try { $onConnect = ($connectLayer -and $connectLayer.Visibility -eq [System.Windows.Visibility]::Visible) } catch {}
						if ($onConnect) { & $doConnectCancel } else { & $doLoginCancel }
					} catch {}
				}.GetNewClosure())
			}
			# Back: leave Login (waiting for creds) and re-open Connect for another endpoint
			$doGoBackToConnect = {
				try {
					if (-not [bool]$B.CanGoBackToConnect) { return }
					$B.CredResult = @{
						User = $null; Pass = $null
						Cancelled = $false
						Back = $true
						SoftExit = $false
						HardClose = $false
					}
					try { [void]$B.CredWait.Set() } catch {}
					try { [void]$B.EndpointWait.Reset() } catch {}
					$B.EndpointResult = $null
					& $showConnect
				} catch {}
			}.GetNewClosure()
			if ($loginTitleBack) {
				$loginTitleBack.add_Click({
					param($s, $e)
					try { & $doGoBackToConnect } catch {}
				}.GetNewClosure())
			}
			$pass.add_KeyDown({
				param($s,$e)
				try { if ($e.Key -eq 'Return') { $e.Handled = $true; & $submit } } catch {}
			}.GetNewClosure())
			$user.add_KeyDown({
				param($s,$e)
				try {
					if ($e.Key -eq 'Return') {
						$e.Handled = $true
						try { [void]$pass.Focus() } catch {}
					}
				} catch {}
			}.GetNewClosure())

			$timer = New-Object System.Windows.Threading.DispatcherTimer
			$timer.Interval = [TimeSpan]::FromMilliseconds(40)
			$timer.Add_Tick({
				param($s, $e)
				try {
					$cmd = [string]$B.Cmd
					if ([string]::IsNullOrWhiteSpace($cmd)) { return }
					$B.Cmd = ''
					switch ($cmd) {
						'show_login' {
							try { & $setLoginRobotFace 'default' } catch {}
							& $showLogin
						}
						'show_connect' {
							& $showConnect
						}
						'show_confirm' {
							& $showConfirm ([string]$B.ConfirmPrompt) ([string]$B.ConfirmTitle)
						}
						'success' {
							try {
								$B.AuthOk = $true
								& $setLoginRobotFace 'happy'
								try { & $applyLoginWindowIcon 'happy' } catch {}
								if ($err) { $err.Text = '' }
								& $setLoginTitleLabel 'Signed in'
							} catch {}
							try { $B.RobotSuccessPainted = $true } catch {}
						}
						'close' {
							try { $timer.Stop() } catch {}
							try { $win.Close() } catch {}
							try {
								$disp = [System.Windows.Threading.Dispatcher]::CurrentDispatcher
								if ($disp -and -not $disp.HasShutdownStarted) {
									$disp.BeginInvokeShutdown([System.Windows.Threading.DispatcherPriority]::Normal)
								}
							} catch {}
						}
					}
				} catch {}
			}.GetNewClosure())
			$timer.Start()

			$shutdownUi = {
				try { $timer.Stop() } catch {}
				try { $win.Close() } catch {}
				try {
					$disp = [System.Windows.Threading.Dispatcher]::CurrentDispatcher
					if ($disp -and -not $disp.HasShutdownStarted) {
						$disp.BeginInvokeShutdown([System.Windows.Threading.DispatcherPriority]::Normal)
					}
				} catch {}
			}.GetNewClosure()

			if ($cYes) {
				$cYes.add_Click({
					param($s,$e)
					try {
						$B.ConfirmResult = $true
						& $showLogin
						try { [void]$B.ConfirmWait.Set() } catch {}
					} catch {}
				}.GetNewClosure())
			}
			if ($cNo) {
				$cNo.add_Click({
					param($s,$e)
					try {
						$B.ConfirmResult = $false
						$B.Closed = $true
						$B.CredResult = @{
							User = $null; Pass = $null; Cancelled = $true
							SoftExit = $true; HardClose = $false
						}
						try { [void]$B.ConfirmWait.Set() } catch {}
						try { [void]$B.CredWait.Set() } catch {}
						# Close so single-instance lock can release
						& $shutdownUi
					} catch {}
				}.GetNewClosure())
			}

			$win.add_Closing({
				param($s, $ev)
				try {
					$B.Closed = $true
					try { $epWantCancel.Value = $true } catch {}
					if ($null -eq $B.ConfirmResult) { $B.ConfirmResult = $false }
					if (-not [bool]$B.AuthOk) {
						$B.CredResult = @{
							User = $null; Pass = $null; Cancelled = $true
							SoftExit = $true; HardClose = $false
						}
					}
					if ($null -eq $B.EndpointResult) {
						$B.EndpointResult = @{ Cancelled = $true; Url = ''; AuthMode = 'none'; ApiKey = '' }
					}
					try { [void]$B.CredWait.Set() } catch {}
					try { [void]$B.ConfirmWait.Set() } catch {}
					try { [void]$B.EndpointWait.Set() } catch {}
				} catch {}
			}.GetNewClosure())
			$win.add_Closed({
				param($s, $e)
				try {
					$B.Closed = $true
					try { [void]$B.CredWait.Set() } catch {}
					try { [void]$B.ConfirmWait.Set() } catch {}
					try { [void]$B.EndpointWait.Set() } catch {}
					try {
						$disp = [System.Windows.Threading.Dispatcher]::CurrentDispatcher
						if ($disp -and -not $disp.HasShutdownStarted) {
							$disp.BeginInvokeShutdown([System.Windows.Threading.DispatcherPriority]::Normal)
						}
					} catch {}
				} catch {}
			}.GetNewClosure())

			try {
				if (-not ("MB.Native.Dwm" -as [type])) {
					Add-Type -Namespace MB.Native -Name Dwm -MemberDefinition @"
[System.Runtime.InteropServices.DllImport("dwmapi.dll")]
public static extern int DwmSetWindowAttribute(System.IntPtr hwnd, int attr, ref int attrValue, int attrSize);
"@ -ErrorAction Stop
				}
				$applyDarkTitle = {
					param($w)
					try {
						$helper = New-Object System.Windows.Interop.WindowInteropHelper($w)
						$hwnd = $helper.Handle
						if ($hwnd -eq [IntPtr]::Zero) {
							try { $hwnd = $helper.EnsureHandle() } catch {}
						}
						if ($hwnd -eq [IntPtr]::Zero) { return }
						$useDark = 1
						[void][MB.Native.Dwm]::DwmSetWindowAttribute($hwnd, 20, [ref]$useDark, 4)
						[void][MB.Native.Dwm]::DwmSetWindowAttribute($hwnd, 19, [ref]$useDark, 4)
						try {
							$caption = 0x00302A2A
							[void][MB.Native.Dwm]::DwmSetWindowAttribute($hwnd, 35, [ref]$caption, 4)
						} catch {}
					} catch {}
				}.GetNewClosure()
				$win.add_SourceInitialized({
					param($s, $e)
					try { & $applyDarkTitle $s } catch {}
				}.GetNewClosure())
				try {
					$helper0 = New-Object System.Windows.Interop.WindowInteropHelper($win)
					[void]$helper0.EnsureHandle()
					& $applyDarkTitle $win
				} catch {}
			} catch {}

			# Initial layer: connect-first avoids login flash for empty BaseUrl
			try {
				$il = 'login'
				try { $il = [string]$B.InitialLayer } catch {}
				if ($il -eq 'connect') {
					if ($loginLayer) { $loginLayer.Visibility = [System.Windows.Visibility]::Collapsed }
					& $showConnect
				} else {
					if ($connectLayer) { $connectLayer.Visibility = [System.Windows.Visibility]::Collapsed }
				}
			} catch {}

			$B.Ready = $true
			try { [void]$B.ReadyWait.Set() } catch {}
			# Keep login window topmost
			try { $win.Topmost = $true } catch {}
			[void]$win.Show()
			try {
				[void]$win.Activate()
				try { [void]$win.Focus() } catch {}
			} catch {}
			[System.Windows.Threading.Dispatcher]::Run()
		} catch {
			$B.Failed = $true
			$B.FailMsg = $_.Exception.Message
			$B.Closed = $true
			try { [void]$B.ReadyWait.Set() } catch {}
			try { [void]$B.CredWait.Set() } catch {}
			try { [void]$B.ConfirmWait.Set() } catch {}
			try { [void]$B.EndpointWait.Set() } catch {}
		} finally {
			$B.Closed = $true
			try { [void]$B.CredWait.Set() } catch {}
			try { [void]$B.ConfirmWait.Set() } catch {}
			try { [void]$B.EndpointWait.Set() } catch {}
			try { [void]$B.Done.Set() } catch {}
		}
	}).AddArgument($bag).AddArgument($hint).AddArgument($ver)

	[void]$ps.BeginInvoke()
	[void]$bag.ReadyWait.WaitOne(15000)
	if ($bag.Failed -or -not $bag.Ready) {
		try { $ps.Stop(); $ps.Dispose() } catch {}
		try { $rs.Close(); $rs.Dispose() } catch {}
		$msg = if ($bag.FailMsg) { [string]$bag.FailMsg } else { 'login UI failed to start' }
		throw ("MiniBot login UI failed: {0}" -f $msg)
	}
	$bag.Ps = $ps
	$bag.Runspace = $rs
	$script:MB.LoginSession = $bag
	return $bag
}

function Close-MBLoginSession {
	param(
		$Session = $null,
		[switch]$Success
	)
	if ($null -eq $Session) {
		try { $Session = $script:MB.LoginSession } catch { $Session = $null }
	}
	if ($null -eq $Session) { return }
	try {
		try { [void]$Session.CredWait.Set() } catch {}
		try { [void]$Session.ConfirmWait.Set() } catch {}
		try { [void]$Session.EndpointWait.Set() } catch {}
		if (-not [bool]$Session.Closed) {
			# Show happy robot briefly before close
			if ($Success) {
				try {
					$Session.AuthOk = $true
					$Session.RobotSuccessPainted = $false
					$Session.Cmd = 'success'
					$t0 = [Environment]::TickCount
					while (-not [bool]$Session.RobotSuccessPainted -and (([Environment]::TickCount - $t0) -lt 1000)) {
						Start-Sleep -Milliseconds 30
					}
					Start-Sleep -Milliseconds 450
				} catch {}
			}
			$Session.Cmd = 'close'
			# Short wait for STA to shut down; always force-stop after
			[void]$Session.Done.WaitOne(2000)
		}
	} catch {}
	try { if ($Session.Ps) { $Session.Ps.Stop() } } catch {}
	try { if ($Session.Ps) { $Session.Ps.Dispose() } } catch {}
	try {
		if ($Session.Runspace) {
			try { $Session.Runspace.Close() } catch {}
			try { $Session.Runspace.Dispose() } catch {}
		}
	} catch {}
	try { $Session.Closed = $true } catch {}
	try { [void]$Session.Done.Set() } catch {}
	try { $script:MB.LoginSession = $null } catch {}
}

function Wait-MBLoginSessionCred {
	param(
		$Session,
		[string]$ServerHint = ''
	)
	if ($null -eq $Session -or [bool]$Session.Closed) {
		return @{ User = $null; Pass = $null; Cancelled = $true; SoftExit = $true }
	}
	try { [void]$Session.CredWait.Reset() } catch {}
	$Session.CredResult = $null
	# Always refresh the host line for the Login layer (fixed endpoint after connect retry)
	try {
		$h = ([string]$ServerHint).Trim()
		if ([string]::IsNullOrWhiteSpace($h)) {
			try { $h = [string](Get-Variable -Name BaseUrl -ValueOnly -ErrorAction SilentlyContinue) } catch { $h = '' }
		}
		if ([string]::IsNullOrWhiteSpace($h)) {
			try { $h = [string]$script:MB.PrimaryApiBase } catch { $h = '' }
		}
		if (-not [string]::IsNullOrWhiteSpace($h)) { $Session.ConnectUrl = $h }
	} catch {}
	$Session.Cmd = 'show_login'
	while ($true) {
		if ([bool]$Session.Closed) {
			$r = $Session.CredResult
			if ($null -eq $r) {
				return @{ User = $null; Pass = $null; Cancelled = $true; SoftExit = $true }
			}
			return $r
		}
		if ($Session.CredWait.WaitOne(50)) { break }
	}
	$r = $Session.CredResult
	if ($null -eq $r) {
		return @{ User = $null; Pass = $null; Cancelled = $true; SoftExit = $true }
	}
	return $r
}

function Show-MBLoginSessionConfirm {
	param(
		$Session,
		[string]$Prompt = 'Continue?',
		[string]$Title = ''
	)
	if ($null -eq $Session -or [bool]$Session.Closed) { return $false }
	try { [void]$Session.ConfirmWait.Reset() } catch {}
	$Session.ConfirmResult = $null
	$promptText = ([string]$Prompt).Trim()
	if ([string]::IsNullOrWhiteSpace($promptText)) { $promptText = 'Continue?' }
	$Session.ConfirmTitle = 'Invalid Entry'
	$Session.ConfirmPrompt = $promptText
	$Session.Cmd = 'show_confirm'
	while ($true) {
		if ([bool]$Session.Closed) { return $false }
		if ($Session.ConfirmWait.WaitOne(50)) { break }
	}
	try { return [bool]$Session.ConfirmResult } catch { return $false }
}

function Read-MBCredentialPrompt {
	if (Test-MBWpfActive) {
		$overlay = Show-MBWpfAuthOverlay -ServerHint ([string]$BaseUrl)
		if (-not $overlay -or $overlay.Cancelled -or -not $overlay.User -or -not $overlay.Pass) {
			if ($script:MB.Wpf -and $script:MB.Wpf.ExitRequested -and -not $script:MB.Wpf.SoftClose) {
				return @{ User = $null; Pass = $null; SecurePassword = $null; Cancelled = $true; HardClose = $true }
			}
			return @{
				User           = $null
				Pass           = $null
				SecurePassword = $null
				Cancelled      = $true
				SoftExit       = $true
			}
		}
		$passSecure = $null
		try {
			$passSecure = ConvertTo-SecureString -String $overlay.Pass -AsPlainText -Force
		} catch {}
		$store = $false
		$storeSpec = $false
		try { if ($null -ne $overlay.Store) { $store = [bool]$overlay.Store; $storeSpec = $true } } catch {}
		try { if ($null -ne $overlay.StoreSpecified) { $storeSpec = [bool]$overlay.StoreSpecified } } catch {}
		return @{
			User           = $overlay.User
			Pass           = $overlay.Pass
			SecurePassword = $passSecure
			Cancelled      = $false
			Store          = $store
			StoreSpecified = $storeSpec
		}
	}

	if (-not (Test-MBWpfAvailable)) {
		throw 'MiniBot requires WPF for login UI (PresentationFramework not available).'
	}
	$sess = Start-MBLoginSession -ServerHint ([string]$BaseUrl)
	$dlg = Wait-MBLoginSessionCred -Session $sess -ServerHint ([string]$BaseUrl)
	if ($null -eq $dlg) {
		throw 'MiniBot login UI returned no result.'
	}
	# User pressed titlebar Back -> return to Connect (keep session open)
	try {
		if ([bool]$dlg.Back) {
			return @{
				User           = $null
				Pass           = $null
				SecurePassword = $null
				Cancelled      = $false
				Back           = $true
			}
		}
	} catch {}
	if ($dlg.Cancelled -or -not $dlg.User -or -not $dlg.Pass) {
		Close-MBLoginSession -Session $sess
		return @{
			User           = $null
			Pass           = $null
			SecurePassword = $null
			Cancelled      = $true
			SoftExit       = $true
			HardClose      = [bool]$(if ($dlg) { $dlg.HardClose } else { $false })
		}
	}
	$passSecure = $null
	try {
		$passSecure = ConvertTo-SecureString -String $dlg.Pass -AsPlainText -Force
	} catch {}
	$store = $false
	$storeSpec = $false
	try { if ($null -ne $dlg.Store) { $store = [bool]$dlg.Store; $storeSpec = $true } } catch {}
	try { if ($null -ne $dlg.StoreSpecified) { $storeSpec = [bool]$dlg.StoreSpecified } } catch {}
	return @{
		User           = $dlg.User
		Pass           = $dlg.Pass
		SecurePassword = $passSecure
		Cancelled      = $false
		Store          = $store
		StoreSpecified = $storeSpec
	}
}

function Show-MBWpfConfirmOverlay {
	param(
		[string]$Prompt = 'Continue?',
		[string]$Title = 'MiniBot',
		[string]$YesText = 'Yes',
		[string]$NoText = 'No'
	)
	if (-not (Test-MBWpfActive)) { return $null }

	$W = $script:MB.Wpf
	$W.ConfirmResult = $null
	try { [void]$W.ConfirmWait.Reset() } catch {}

	$promptText = ([string]$Prompt).Trim()
	if ([string]::IsNullOrWhiteSpace($promptText)) { $promptText = 'Continue?' }
	$titleText = 'Invalid Entry'
	$yesLabel = if ([string]::IsNullOrWhiteSpace($YesText)) { 'Yes' } else { [string]$YesText }
	$noLabel = if ([string]::IsNullOrWhiteSpace($NoText)) { 'No' } else { [string]$NoText }

	$d = $W.Dispatcher
	$show = {
		if ($W.ConfirmTitle) {
			try { $W.ConfirmTitle.Inlines.Clear() } catch {}
			$W.ConfirmTitle.Text = $titleText
			$W.ConfirmTitle.FontSize = 16
			$W.ConfirmTitle.FontWeight = [System.Windows.FontWeights]::Bold
			try {
				$bc = New-Object System.Windows.Media.BrushConverter
				$W.ConfirmTitle.Foreground = $bc.ConvertFromString('#E0E0E8')
			} catch {}
		}
		if ($W.ConfirmPrompt) { $W.ConfirmPrompt.Text = $promptText }
		if ($W.ConfirmYes) {
			$W.ConfirmYes.Content = $yesLabel
			$W.ConfirmYes.IsDefault = $true
		}
		if ($W.ConfirmNo) {
			$W.ConfirmNo.Content = $noLabel
			try { $W.ConfirmNo.IsCancel = $true } catch {}
		}
		if ($W.ConfirmOverlay) {
			$W.ConfirmOverlay.Visibility = [System.Windows.Visibility]::Visible
		}
		try {
			if ($W.ConfirmAccentBar) {
				$anim = New-Object System.Windows.Media.Animation.DoubleAnimation
				$anim.From = 0.35
				$anim.To = 1.0
				$anim.Duration = New-Object System.Windows.Duration ([TimeSpan]::FromMilliseconds(900))
				$anim.AutoReverse = $true
				$anim.RepeatBehavior = [System.Windows.Media.Animation.RepeatBehavior]::Forever
				try {
					$ease = New-Object System.Windows.Media.Animation.SineEase
					$ease.EasingMode = [System.Windows.Media.Animation.EasingMode]::EaseInOut
					$anim.EasingFunction = $ease
				} catch {}
				$W.ConfirmAccentBar.BeginAnimation([System.Windows.UIElement]::OpacityProperty, $anim)
			}
		} catch {}
		try {
			if ($W.ConfirmYes) { [void]$W.ConfirmYes.Focus() }
		} catch {}
	}.GetNewClosure()
	try {
		if ($d.CheckAccess()) {
			& $show
		} else {
			[void]$d.Invoke([Action]$show, [System.Windows.Threading.DispatcherPriority]::Normal)
		}
	} catch {
		Write-Warning "Could not show confirm overlay: $($_.Exception.Message)"
		return $false
	}

	while ($true) {
		if ($W.ExitRequested) {
			Hide-MBWpfConfirmOverlay
			return $false
		}
		if ($W.ConfirmWait.WaitOne(50)) { break }
	}

	$result = $false
	try { $result = [bool]$W.ConfirmResult } catch { $result = $false }
	Hide-MBWpfConfirmOverlay
	return $result
}

function Hide-MBWpfConfirmOverlay {
	if (-not $script:MB.Wpf) { return }
	$W = $script:MB.Wpf
	$d = $W.Dispatcher
	if (-not $d) { return }
	$hide = {
		try {
			if ($W.ConfirmAccentBar) {
				$W.ConfirmAccentBar.BeginAnimation([System.Windows.UIElement]::OpacityProperty, $null)
				$W.ConfirmAccentBar.Opacity = 0.55
			}
		} catch {}
		if ($W.ConfirmOverlay) {
			$W.ConfirmOverlay.Visibility = [System.Windows.Visibility]::Collapsed
		}
		if ($W.ConfirmYes) { $W.ConfirmYes.IsDefault = $false }
	}.GetNewClosure()
	try {
		if ($d.CheckAccess()) {
			& $hide
		} else {
			[void]$d.Invoke([Action]$hide, [System.Windows.Threading.DispatcherPriority]::Normal)
		}
	} catch {}
}

function Test-MBUserYesNo {
	param(
		[string]$Prompt = 'Clear stored credentials and retry?'
	)
	$promptText = ($Prompt -replace '^\s+', '' -replace '\s*\[Y/N\]\s*$', '').Trim()
	if ([string]::IsNullOrWhiteSpace($promptText)) { $promptText = 'Continue?' }

	if (Test-MBWpfActive) {
		$r = Show-MBWpfConfirmOverlay -Prompt $promptText -Title 'MiniBot' -YesText 'Yes' -NoText 'No'
		if ($null -eq $r) { return $false }
		return [bool]$r
	}

	$sess = $null
	try { $sess = $script:MB.LoginSession } catch { $sess = $null }
	if ($null -ne $sess -and -not [bool]$sess.Closed) {
		return [bool](Show-MBLoginSessionConfirm -Session $sess -Prompt $promptText -Title 'MiniBot')
	}

	try {
		$sess = Start-MBLoginSession -ServerHint ([string]$BaseUrl)
		return [bool](Show-MBLoginSessionConfirm -Session $sess -Prompt $promptText -Title 'MiniBot')
	} catch {
		throw ("MiniBot requires WPF for confirmation UI: {0}" -f $_.Exception.Message)
	}
}

function Set-MBRuntimePrimaryBase {
	# Update runtime primary endpoint (param + script bag) after user picks a working URL.
	param(
		[Parameter(Mandatory = $true)]
		[string]$Url,
		[ValidateSet('apikey', 'npm', 'none')]
		[string]$AuthMode = 'none',
		[string]$ApiKeyValue = ''
	)
	$n = Normalize-MBApiBase -Url $Url
	if ([string]::IsNullOrWhiteSpace($n)) { throw 'Invalid base URL.' }
	try { Set-Variable -Name BaseUrl -Scope Script -Value $n -Force } catch {}
	try { $script:BaseUrl = $n } catch {}
	try {
		# Keep param-bound value in sync when present in this scope
		if (Get-Variable -Name BaseUrl -ErrorAction SilentlyContinue) {
			Set-Variable -Name BaseUrl -Value $n -Force -ErrorAction SilentlyContinue
		}
	} catch {}
	$script:MB.PrimaryApiBase = $n
	try { $script:MB.ResolvedApiBase = $n } catch {}
	try { Set-MBApiAuthModeForBase -BaseUrl $n -Mode $AuthMode } catch {}
	if ($AuthMode -eq 'apikey' -and (Test-MBApiKeyUsable -Key $ApiKeyValue)) {
		try { Set-MBApiKeyForBase -BaseUrl $n -ApiKeyValue $ApiKeyValue } catch {}
		try { Set-Variable -Name ApiKey -Scope Script -Value $ApiKeyValue -Force } catch {}
		try { Set-Variable -Name ApiKey -Value $ApiKeyValue -Force -ErrorAction SilentlyContinue } catch {}
	} elseif ($AuthMode -eq 'none') {
		try { Set-Variable -Name ApiKey -Scope Script -Value 'none' -Force } catch {}
		try { Set-Variable -Name ApiKey -Value 'none' -Force -ErrorAction SilentlyContinue } catch {}
	}
	return $n
}

function Show-MBEndpointConnectDialog {
	# Endpoint picker on the shared Auth/Connect window (layer swap — not a second window).
	# Stays open on success so 401 can flip to Login without another popup.
	param(
		[string]$CurrentUrl = '',
		[string]$ErrorMessage = '',
		[string]$Title = '',
		[switch]$ConnectMode
	)
	if (-not (Test-MBWpfAvailable)) {
		throw 'MiniBot requires WPF for the connection UI (PresentationFramework not available).'
	}

	$cur = ([string]$CurrentUrl).Trim()
	if ([string]::IsNullOrWhiteSpace($cur)) {
		try { $cur = [string](Get-Variable -Name BaseUrl -ValueOnly -ErrorAction SilentlyContinue) } catch { $cur = '' }
	}
	if ([string]::IsNullOrWhiteSpace($cur)) { $cur = 'http://127.0.0.1:8080/v1' }
	$errMsg = ([string]$ErrorMessage).Trim()
	$isConnect = [bool]$ConnectMode

	$hadSession = $false
	try {
		if ($script:MB.LoginSession -and -not [bool]$script:MB.LoginSession.Closed) { $hadSession = $true }
	} catch {}

	$sess = $null
	try {
		# Always open on Connect layer when this is a new boot window (avoids Login flash)
		if (-not $hadSession) {
			$sess = Start-MBLoginSession -ServerHint $cur -InitialLayer 'connect'
		} else {
			$sess = Start-MBLoginSession -ServerHint $cur
		}
	} catch {
		return @{
			Cancelled = $true
			Url       = $cur
			AuthMode  = 'none'
			ApiKey    = ''
			Error     = $_.Exception.Message
		}
	}

	try {
		$sess.ConnectUrl = $cur
		$sess.ConnectError = $errMsg
		$sess.ConnectMode = $isConnect
		$sess.EndpointResult = $null
		try { [void]$sess.EndpointWait.Reset() } catch {}
		# If we already started on connect layer, still push show_connect to refresh fields
		$sess.Cmd = 'show_connect'
	} catch {}

	while ($true) {
		if ([bool]$sess.Closed) {
			$r = $sess.EndpointResult
			if ($null -eq $r) {
				return @{ Cancelled = $true; Url = $cur; AuthMode = 'none'; ApiKey = '' }
			}
			break
		}
		if ($sess.EndpointWait.WaitOne(50)) { break }
	}

	$r = $sess.EndpointResult
	if ($null -eq $r) {
		return @{ Cancelled = $true; Url = $cur; AuthMode = 'none'; ApiKey = '' }
	}
	if ($r.Cancelled) {
		return @{
			Cancelled = $true
			Url       = $cur
			AuthMode  = 'none'
			ApiKey    = ''
		}
	}
	return @{
		Cancelled = $false
		Url       = [string]$r.Url
		AuthMode  = $(if ($r.AuthMode) { [string]$r.AuthMode } else { 'none' })
		ApiKey    = [string]$r.ApiKey
		NeedsAuth = [bool]$r.NeedsAuth
		StatusCode = $(if ($null -ne $r.StatusCode) { [int]$r.StatusCode } else { 0 })
	}
}

function Connect-MBModelEndpoint {
	param(
		[int]$TimeoutSeconds = 8
	)

	$resolveBase = {
		$b = ''
		try { $b = [string](Get-Variable -Name BaseUrl -ValueOnly -ErrorAction SilentlyContinue) } catch { $b = '' }
		if ([string]::IsNullOrWhiteSpace($b)) {
			try { $b = [string]$script:MB.PrimaryApiBase } catch { $b = '' }
		}
		return $b
	}

	$testParams = @{
		BaseUrl        = (& $resolveBase)
		TimeoutSeconds = $TimeoutSeconds
	}

	# Empty / blank primary → ask for endpoint before any network call
	if ([string]::IsNullOrWhiteSpace([string]$testParams.BaseUrl)) {
		$picked = $null
		try {
			$picked = Show-MBEndpointConnectDialog -CurrentUrl 'http://127.0.0.1:8080/v1' -ConnectMode
		} catch {
			return @{
				Success  = $false
				ConnTest = $null
				Exit     = $true
				HardClose = $true
				Message  = $_.Exception.Message
			}
		}
		if (-not $picked -or $picked.Cancelled -or [string]::IsNullOrWhiteSpace([string]$picked.Url)) {
			return @{
				Success  = $false
				ConnTest = $null
				Exit     = $true
				SoftExit = $true
				Message  = 'Endpoint setup cancelled.'
			}
		}
		try {
			$null = Set-MBRuntimePrimaryBase -Url $picked.Url -AuthMode $picked.AuthMode -ApiKeyValue $picked.ApiKey
		} catch {
			return @{ Success = $false; ConnTest = $null; Exit = $true; Message = $_.Exception.Message }
		}
		$testParams.BaseUrl = (& $resolveBase)
		if ($picked.AuthMode -eq 'apikey' -and $picked.ApiKey) {
			$testParams['BearerToken'] = $picked.ApiKey
		}
	}

	$connTest = Test-ModelConnection @testParams
	if ($connTest.Success) {
		try { Close-MBLoginSession -Success } catch {}
		return @{
			Success  = $true
			ConnTest = $connTest
			Exit     = $false
		}
	}

	# Unreachable / invalid / wrong URL (not HTTP auth) → endpoint recovery dialog (do not just quit)
	if ($connTest.StatusCode -notin 401, 403) {
		$maxEndpointRounds = 6
		$epRound = 0
		while ($epRound -lt $maxEndpointRounds) {
			$epRound++
			$failMsg = if ($connTest -and $connTest.Message) { [string]$connTest.Message } else { 'Unable to reach the model server.' }
			$cur = [string]$testParams.BaseUrl
			$picked = $null
			try {
				$picked = Show-MBEndpointConnectDialog -CurrentUrl $cur -ErrorMessage $failMsg
			} catch {
				return @{
					Success   = $false
					ConnTest  = $connTest
					Exit      = $true
					HardClose = $true
					Message   = $_.Exception.Message
				}
			}
			if (-not $picked -or $picked.Cancelled -or [string]::IsNullOrWhiteSpace([string]$picked.Url)) {
				return @{
					Success  = $false
					ConnTest = $connTest
					Exit     = $true
					SoftExit = $true
					Message  = 'Endpoint setup cancelled.'
				}
			}
			try {
				$n = Set-MBRuntimePrimaryBase -Url $picked.Url -AuthMode $picked.AuthMode -ApiKeyValue $picked.ApiKey
			} catch {
				$connTest = [pscustomobject]@{
					Success = $false; StatusCode = 0
					Message = $_.Exception.Message
					AuthType = 'Basic'; ElapsedMs = 0; BaseUrl = $picked.Url
				}
				continue
			}
			$testParams = @{
				BaseUrl        = $n
				TimeoutSeconds = $TimeoutSeconds
			}
			if ($picked.AuthMode -eq 'apikey' -and (Test-MBApiKeyUsable -Key $picked.ApiKey)) {
				$testParams['BearerToken'] = $picked.ApiKey
			}
			# Clear NPM session unless user chose NPM (they'll login next if 401)
			if ($picked.AuthMode -ne 'npm') {
				try {
					if ($testParams.ContainsKey('Username')) { $testParams.Remove('Username') }
					if ($testParams.ContainsKey('Password')) { $testParams.Remove('Password') }
				} catch {}
			}
			$connTest = Test-ModelConnection @testParams
			if ($connTest.Success) {
				try { Close-MBLoginSession -Success } catch {}
				return @{ Success = $true; ConnTest = $connTest; Exit = $false }
			}
			if ($connTest.StatusCode -in 401, 403) {
				# Reachable but needs credentials — same window flips to Login layer
				break
			}
		}
		if ($connTest.StatusCode -notin 401, 403) {
			return @{
				Success  = $false
				ConnTest = $connTest
				Exit     = $true
				SoftExit = $true
				Message  = $(if ($connTest.Message) { [string]$connTest.Message } else { 'Unable to connect to endpoint.' })
			}
		}
	}

	$wantStore = $false
	try { $wantStore = [bool]$StoreCredentials } catch { $wantStore = $false }
	$maxAuthRounds = 6
	$round = 0

	while ($round -lt $maxAuthRounds) {
		$round++

		$stored = Read-MBStoredCredential
		if ($stored -and $stored.User -and $stored.Pass) {
			$script:MB.NpmUser = $stored.User
			$script:MB.NpmPass = $stored.Pass
			$testParams['Username'] = $stored.User
			$testParams['Password'] = $stored.Pass
			$connTest = Test-ModelConnection @testParams
			if ($connTest.Success) {
				if ($wantStore) {
					Set-MBEnvFlag -Name 'store'
					$script:MB_StoreCredsFromEnv = $false
					$wantStore = $false
				}
				try { Close-MBLoginSession -Success } catch {}
				return @{ Success = $true; ConnTest = $connTest; Exit = $false }
			}

			Write-Host ""
			Write-MBRule -Color DarkRed -Label "auth failed"
			Write-Host "  Stored MiniBot credentials were rejected by the server." -ForegroundColor Yellow
			Write-Host ""
			try {
				$clearStored = Test-MBUserYesNo -Prompt 'Clear stored credentials and retry?'
			} catch {
				try { Close-MBLoginSession } catch {}
				return @{
					Success   = $false
					ConnTest  = $connTest
					Exit      = $true
					HardClose = $true
					Message   = $_.Exception.Message
				}
			}
			if ($clearStored) {
				Clear-MBStoredCredential
				$script:MB.NpmUser = $null
				$script:MB.NpmPass = $null
				if ($testParams.ContainsKey('Username')) { $testParams.Remove('Username') }
				if ($testParams.ContainsKey('Password')) { $testParams.Remove('Password') }
			} else {
				try { Close-MBLoginSession } catch {}
				return @{
					Success  = $false
					ConnTest = $connTest
					Exit     = $true
					SoftExit = $true
					Message  = 'User declined to clear stored credentials.'
				}
			}
		}

		try {
			$entered = Read-MBCredentialPrompt
		} catch {
			try { Close-MBLoginSession } catch {}
			return @{
				Success  = $false
				ConnTest = $connTest
				Exit     = $true
				HardClose = $true
				Message  = $_.Exception.Message
			}
		}
		# Back to Connect: re-pick endpoint (only when CanGoBackToConnect path was used)
		try {
			if ([bool]$entered.Back) {
				$picked = $null
				try {
					$curEp = ''
					try { $curEp = [string]$testParams.BaseUrl } catch {}
					if ([string]::IsNullOrWhiteSpace($curEp)) { $curEp = 'http://127.0.0.1:8080/v1' }
					$useConnectMode = $true
					try {
						if ($script:MB.LoginSession -and $null -ne $script:MB.LoginSession.ConnectMode) {
							$useConnectMode = [bool]$script:MB.LoginSession.ConnectMode
						}
					} catch { $useConnectMode = $true }
					if ($useConnectMode) {
						$picked = Show-MBEndpointConnectDialog -CurrentUrl $curEp -ConnectMode
					} else {
						$failHint = if ($connTest -and $connTest.Message) { [string]$connTest.Message } else { '' }
						$picked = Show-MBEndpointConnectDialog -CurrentUrl $curEp -ErrorMessage $failHint
					}
				} catch {
					try { Close-MBLoginSession } catch {}
					return @{
						Success = $false; ConnTest = $connTest; Exit = $true
						HardClose = $true; Message = $_.Exception.Message
					}
				}
				if (-not $picked -or $picked.Cancelled -or [string]::IsNullOrWhiteSpace([string]$picked.Url)) {
					try { Close-MBLoginSession } catch {}
					return @{
						Success = $false; ConnTest = $connTest; Exit = $true
						SoftExit = $true; Message = 'Endpoint setup cancelled.'
					}
				}
				try {
					$n = Set-MBRuntimePrimaryBase -Url $picked.Url -AuthMode $picked.AuthMode -ApiKeyValue $picked.ApiKey
				} catch {
					$connTest = [pscustomobject]@{
						Success = $false; StatusCode = 0
						Message = $_.Exception.Message
						AuthType = 'None'; ElapsedMs = 0; BaseUrl = $picked.Url
					}
					continue
				}
				$testParams = @{
					BaseUrl        = $n
					TimeoutSeconds = $TimeoutSeconds
				}
				if ($picked.AuthMode -eq 'apikey' -and (Test-MBApiKeyUsable -Key $picked.ApiKey)) {
					$testParams['BearerToken'] = $picked.ApiKey
				}
				if ($picked.AuthMode -ne 'npm') {
					try {
						if ($testParams.ContainsKey('Username')) { $testParams.Remove('Username') }
						if ($testParams.ContainsKey('Password')) { $testParams.Remove('Password') }
					} catch {}
					$script:MB.NpmUser = $null
					$script:MB.NpmPass = $null
				}
				$connTest = Test-ModelConnection @testParams
				if ($connTest.Success) {
					try { Close-MBLoginSession -Success } catch {}
					return @{ Success = $true; ConnTest = $connTest; Exit = $false }
				}
				if ($connTest.StatusCode -in 401, 403) {
					# Still needs auth for the new endpoint - loop to login again
					continue
				}
				# Unreachable after re-pick: keep dialog open via connect layer already; retry loop
				continue
			}
		} catch {}
		if ($entered.Cancelled -or -not $entered.User -or -not $entered.Pass) {
			try { Close-MBLoginSession } catch {}
			return @{
				Success  = $false
				ConnTest = $connTest
				Exit     = $true
				SoftExit = -not [bool]$entered.HardClose
				HardClose = [bool]$entered.HardClose
				Message  = 'Login cancelled.'
			}
		}
		$script:MB.NpmUser = $entered.User
		$script:MB.NpmPass = $entered.Pass
		$testParams['Username'] = $entered.User
		$testParams['Password'] = $entered.Pass
		$connTest = Test-ModelConnection @testParams

		if ($connTest.Success) {
			# Persist credentials when requested
			$doStore = $wantStore
			try {
				if ($entered.StoreSpecified) { $doStore = [bool]$entered.Store }
			} catch {}
			if ($doStore) {
				if (-not (Save-MBStoredCredential -User $entered.User -Password $entered.Pass -SecurePassword $entered.SecurePassword)) {
					Write-Warning "Could not persist credentials; continuing in-memory only."
				}
				Set-MBEnvFlag -Name 'store'
				$script:MB_StoreCredsFromEnv = $false
				$wantStore = $false
			}
			try { Close-MBLoginSession -Success } catch {}
			return @{ Success = $true; ConnTest = $connTest; Exit = $false }
		}

		if ($connTest.StatusCode -in 401, 403) {
			$maybeStored = Read-MBStoredCredential
			Write-Host ""
			Write-MBRule -Color DarkRed -Label "auth failed"
			Write-Host "  Credentials were rejected by the server." -ForegroundColor Yellow
			Write-Host ""
			if ($maybeStored) {
				try {
					$clear = Test-MBUserYesNo -Prompt 'Clear stored credentials and retry?'
				} catch {
					try { Close-MBLoginSession } catch {}
					return @{
						Success   = $false
						ConnTest  = $connTest
						Exit      = $true
						HardClose = $true
						Message   = $_.Exception.Message
					}
				}
				if ($clear) {
					Clear-MBStoredCredential
					$script:MB.NpmUser = $null
					$script:MB.NpmPass = $null
					continue
				} else {
					try { Close-MBLoginSession } catch {}
					return @{
						Success  = $false
						ConnTest = $connTest
						Exit     = $true
						SoftExit = $true
						Message  = 'User declined to clear stored credentials.'
					}
				}
			} else {
				try {
					$retry = Test-MBUserYesNo -Prompt 'Retry with different credentials?'
				} catch {
					try { Close-MBLoginSession } catch {}
					return @{
						Success   = $false
						ConnTest  = $connTest
						Exit      = $true
						HardClose = $true
						Message   = $_.Exception.Message
					}
				}
				if ($retry) {
					continue
				} else {
					try { Close-MBLoginSession } catch {}
					return @{
						Success  = $false
						ConnTest = $connTest
						Exit     = $true
						SoftExit = $true
						Message  = 'User declined to retry authentication.'
					}
				}
			}
		}

		try { Close-MBLoginSession } catch {}
		return @{
			Success  = $false
			ConnTest = $connTest
			Exit     = $false
		}
	}

	try { Close-MBLoginSession } catch {}
	return @{
		Success  = $false
		ConnTest = $connTest
		Exit     = $true
		Message  = 'Too many authentication attempts.'
	}
}

$SafePrefixes = @(
	'Get-','Test-','Resolve-','ConvertTo-','ConvertFrom-','Select-','Where-','Sort-',
	'Group-','Measure-','Format-List','Format-Table','Format-Wide','Format-Custom',
	'Out-String','Out-Null','Compare-Object','Measure-Object','Select-String',
	'Find-','Search-','Show-','Describe-','Trace-'
)
$SafeExactCommands = @(
	'dir','type','ls','cat','whoami','hostname','systeminfo','ipconfig','ping',
	'tracert','pathping','nslookup','netstat','route','arp','getmac',
	'Get-NetIPConfiguration','Test-NetConnection','Test-Connection',
	'Get-Process','Get-Service','Get-ChildItem','Get-Item','Get-Content',
	'Get-Command','Get-Help','Get-Module','Get-Location','pwd',
	'echo','write-output','write-host','cls','clear',
	'ver','where','which'
)
$NeverSafeExact = @(
	'cmd','cmd.exe','powershell','powershell.exe','pwsh','pwsh.exe',
	'sfc','sfc.exe','dism','dism.exe','chkdsk','chkdsk.exe',
	'wmic','wmic.exe','reg','reg.exe','net','net.exe','sc','sc.exe',
	'format','format.exe','diskpart','diskpart.exe','bcdedit','bcdedit.exe',
	'cipher','cipher.exe','shutdown','shutdown.exe','taskkill','taskkill.exe',
	'msiexec','msiexec.exe','certutil','certutil.exe','bitsadmin','bitsadmin.exe',
	'cscript','cscript.exe','wscript','wscript.exe','mshta','mshta.exe',
	'rundll32','rundll32.exe','regsvr32','regsvr32.exe'
)

function Test-MBSafeCommandSegment {
	param([string]$Segment)
	if ([string]::IsNullOrWhiteSpace($Segment)) { return $false }
	$seg = $Segment.Trim()
	# Redirection, assignment, or call-operator requires approval
	if ($seg -match '(?i)(>|>>|<|\|)') { return $false }
	if ($seg -match '(?i)^\&') { return $false }
	$first = ($seg -split '\s+')[0].Trim().TrimStart('&').Trim('"''')
	if ([string]::IsNullOrWhiteSpace($first)) { return $false }
	$leaf = $null
	try { $leaf = Split-Path -Leaf $first -ErrorAction SilentlyContinue } catch {}
	if ($leaf) { $first = $leaf }
	$firstLower = $first.ToLowerInvariant()
	if ($firstLower.EndsWith('.exe') -or $firstLower.EndsWith('.bat') -or $firstLower.EndsWith('.cmd') -or $firstLower.EndsWith('.ps1') -or $firstLower.EndsWith('.vbs') -or $firstLower.EndsWith('.js')) {
		$base = [System.IO.Path]::GetFileNameWithoutExtension($firstLower)
	} else {
		$base = $firstLower
	}
	if ($NeverSafeExact -contains $firstLower -or $NeverSafeExact -contains ($base + '.exe') -or $NeverSafeExact -contains $base) {
		return $false
	}
	if ($SafeExactCommands -contains $firstLower -or $SafeExactCommands -contains $base) { return $true }
	foreach ($p in $SafePrefixes) {
		if ($firstLower.StartsWith($p.ToLowerInvariant()) -or $base.StartsWith($p.ToLowerInvariant())) {
			return $true
		}
	}
	return $false
}

function Test-IsSafeCommand {
	param([string]$Command)
	if ([string]::IsNullOrWhiteSpace($Command)) { return $false }
	$trimmed = $Command.Trim()

	if ($trimmed -match '(?i)(Remove-Item|\brm\s|del\s+/|del\s+\*|Erase-|\bformat\s|Stop-Computer|Restart-Computer|Invoke-Expression|\biex\b|Invoke-Command|Invoke-Item|Start-Process|Start-Job|Start-Service|Stop-Service|Set-Service|New-Service|Remove-Service|Set-Content|Add-Content|Out-File|Clear-Content|Set-ItemProperty|New-Item|Remove-Variable|Invoke-WebRequest|\biwr\b|Invoke-RestMethod|\birm\b|DownloadString|DownloadFile|FromBase64String|bitstransfer|Start-Bitstransfer|Add-Type|Reflection\.Assembly|System\.Reflection|Set-ExecutionPolicy|Unblock-File|Disable-RealtimeMonitoring|Set-MpPreference|reg\s+add|reg\s+delete|net\s+user|net\s+localgroup|schtasks|\bat\.exe|wmic\s|diskpart|bcdedit|cipher\s+/w|EncodedCommand|-enc\s|FromBase64|\[Convert\]::)') {
		return $false
	}

	# Multi-statement / injection constructs require approval
	if ($trimmed -match '[\r\n]') { return $false }
	if ($trimmed -match '`') { return $false }
	if ($trimmed -match '\$\(') { return $false }
	# Here-strings (@' / @") and hashtables (@{) - single-quoted pattern avoids ` escapes breaking []
	if ($trimmed -match '@[''"]|@\{') { return $false }
	if ($trimmed -match ';') { return $false }
	if ($trimmed -match '&&|\|\|') { return $false }
	if ($trimmed -match '(?<![|&])&(?![&=])') { return $false }
	# Redirection requires approval
	if ($trimmed -match '(>|>>|<)') { return $false }

	$segments = @($trimmed -split '\|')
	if ($segments.Count -eq 0) { return $false }
	foreach ($seg in $segments) {
		if (-not (Test-MBSafeCommandSegment -Segment $seg)) { return $false }
	}
	return $true
}

function Test-MBPrivateOrLocalUrl {
	param([string]$Url)
	if ([string]::IsNullOrWhiteSpace($Url)) { return $true }
	try {
		$u = [Uri]$Url
		if ($u.Scheme -match '^(?i)file$') { return $true }
		$h = $u.Host
		if ([string]::IsNullOrWhiteSpace($h)) { return $true }
		$hl = $h.ToLowerInvariant()
		if ($hl -eq 'localhost' -or $hl -eq '127.0.0.1' -or $hl -eq '0.0.0.0' -or $hl -eq '::1' -or $hl -eq '[::1]') {
			return $true
		}
		if ($hl.EndsWith('.local') -or $hl.EndsWith('.internal') -or $hl.EndsWith('.lan') -or $hl.EndsWith('.home')) {
			return $true
		}
		$ip = $null
		if ([System.Net.IPAddress]::TryParse($h, [ref]$ip)) {
			$bytes = $ip.GetAddressBytes()
			if ($ip.AddressFamily -eq [System.Net.Sockets.AddressFamily]::InterNetwork -and $bytes.Length -ge 4) {
				if ($bytes[0] -eq 10) { return $true }
				if ($bytes[0] -eq 127) { return $true }
				if ($bytes[0] -eq 172 -and $bytes[1] -ge 16 -and $bytes[1] -le 31) { return $true }
				if ($bytes[0] -eq 192 -and $bytes[1] -eq 168) { return $true }
				if ($bytes[0] -eq 169 -and $bytes[1] -eq 254) { return $true }
				if ($bytes[0] -eq 0) { return $true }
			}
			if ($ip.AddressFamily -eq [System.Net.Sockets.AddressFamily]::InterNetworkV6) {
				if ([System.Net.IPAddress]::IsLoopback($ip)) { return $true }
				if ($bytes[0] -eq 0xfe -and ($bytes[1] -band 0xc0) -eq 0x80) { return $true }
				if (($bytes[0] -band 0xfe) -eq 0xfc) { return $true }
			}
		}
		return $false
	} catch {
		return $true
	}
}

function Request-MBNetworkApproval {
	param(
		[string]$Method = 'GET',
		[Parameter(Mandatory = $true)][string]$Url,
		[bool]$HasCredentials = $false,
		[string]$ToolName = 'HTTP'
	)
	$reasons = New-Object System.Collections.ArrayList
	$m = if ([string]::IsNullOrWhiteSpace($Method)) { 'GET' } else { $Method.ToUpperInvariant() }
	if ($m -notin @('GET', 'HEAD')) {
		[void]$reasons.Add("method $m (not GET/HEAD)")
	}
	if (Test-MBPrivateOrLocalUrl -Url $Url) {
		[void]$reasons.Add('private/local/file URL')
	}
	if ($HasCredentials) {
		[void]$reasons.Add('credentials attached')
	}
	if ($Url -match '(?i)^file:') {
		[void]$reasons.Add('file: scheme')
	}
	if ($reasons.Count -eq 0) { return $true }

	$details = "Tool: $ToolName`nURL: $Url`nMethod: $m`n`nApproval required because:`n  - " + ($reasons -join "`n  - ")
	return (Request-Confirmation -Title "$ToolName requires approval" -Details $details)
}

function Request-Confirmation {
	[CmdletBinding()]
	param(
		[Parameter(Mandatory = $true)][string]$Title,
		[string]$Details = "",
		[string]$Code = "",
		[string]$CodeLang = "ps"
	)
	try { Sync-MBAutoApproveFromWpf } catch {}
	if ($script:MB.AutoApprove) {
		$script:MB.ApprovalsGranted++
		return $true
	}
	return (Request-MBWpfConfirmation -Title $Title -Details $Details -Code $Code -CodeLang $CodeLang)
}

function Resolve-MBPath {
	param(
		[string]$Path,
		[switch]$MustExist
	)
	if ([string]::IsNullOrWhiteSpace($Path)) { return $script:MB.WorkingDir }

	# Existing files: search smart candidates (media / ReadImage / ReadFile)
	if ($MustExist) {
		$cands = @(Get-MBPathCandidates -Path $Path)
		foreach ($c in $cands) {
			try {
				if (Test-Path -LiteralPath $c) { return $c }
			} catch {}
		}
		if ($cands.Count -gt 0) { return $cands[0] }
		return $Path.Trim().Trim('"').Trim("'")
	}

	# Create/write targets: do not relocate to profile just because a name exists there
	$p = $Path.Trim().Trim('"').Trim("'")
	$p = $p -replace '/', '\'
	$p = $p.TrimStart('<').TrimEnd('>')
	if ($p.StartsWith('file:', [StringComparison]::OrdinalIgnoreCase)) {
		try { $p = ([Uri]$p).LocalPath } catch {}
	}
	if ($p -match '%[^%]+%') {
		try { $p = [Environment]::ExpandEnvironmentVariables($p) } catch {}
	}
	if ($p.StartsWith('~\') -or $p -eq '~') {
		$home = $env:USERPROFILE
		if (-not $home) { try { $home = [Environment]::GetFolderPath('UserProfile') } catch {} }
		if ($home) {
			$rest = if ($p.Length -gt 1) { $p.Substring(2) } else { '' }
			return [System.IO.Path]::GetFullPath((Join-Path $home $rest))
		}
	}
	# Users\Owner\... without drive → C:\Users\Owner\... (not under System32 CWD)
	if ($p -match '^(?i)Users\\') {
		return [System.IO.Path]::GetFullPath(('C:\' + $p))
	}
	# Already glued: C:\Windows\System32\Users\... → C:\Users\...
	if ($p -match '(?i)^[A-Za-z]:\\Windows\\System32\\(Users\\.+)$') {
		return [System.IO.Path]::GetFullPath(('C:\' + $Matches[1]))
	}
	if ($p -match '(?i)^Windows\\System32\\(Users\\.+)$') {
		return [System.IO.Path]::GetFullPath(('C:\' + $Matches[1]))
	}
	$rooted = $false
	try { $rooted = [System.IO.Path]::IsPathRooted($p) } catch { $rooted = $false }
	if ($rooted) {
		if ($p.StartsWith('\') -and -not $p.StartsWith('\\')) {
			return [System.IO.Path]::GetFullPath(('C:' + $p))
		}
		return [System.IO.Path]::GetFullPath($p)
	}
	$wd = $script:MB.WorkingDir
	if ([string]::IsNullOrWhiteSpace($wd)) { $wd = (Get-Location).Path }
	return [System.IO.Path]::GetFullPath((Join-Path $wd $p))
}

function Get-MBPathCandidates {
	# Ordered list of absolute paths to try for a user/model-supplied path.
	# Fixes common case: CWD is C:\Windows\System32 (elevated) + relative "Users\Owner\..."
	param([string]$Path)
	$list = New-Object System.Collections.ArrayList
	$seen = @{}
	$add = {
		param([string]$P)
		if ([string]::IsNullOrWhiteSpace($P)) { return }
		try {
			$full = [System.IO.Path]::GetFullPath($P)
		} catch {
			$full = $P
		}
		$key = $full.ToLowerInvariant()
		if ($seen.ContainsKey($key)) { return }
		$seen[$key] = $true
		[void]$list.Add($full)
	}

	if ([string]::IsNullOrWhiteSpace($Path)) { return @() }
	$p = $Path.Trim().Trim('"').Trim("'")
	$p = $p -replace '/', '\'
	# strip wrapping angle brackets / markdown leftovers
	$p = $p.TrimStart('<').TrimEnd('>')
	if ($p.StartsWith('file:', [StringComparison]::OrdinalIgnoreCase)) {
		try {
			$p = ([Uri]$p).LocalPath
			$p = $p -replace '/', '\'
		} catch {}
	}

	# Unglue accidental System32 CWD joins (elevated launch):
	# C:\Windows\System32\Users\Owner\... → C:\Users\Owner\...
	# Also handle relative "Windows\System32\Users\..." leftovers.
	if ($p -match '(?i)(?:^[A-Za-z]:\\)?Windows\\System32\\(Users\\.+)$') {
		& $add ('C:\' + $Matches[1])
		$pUnglue = 'C:\' + $Matches[1]
		# Prefer unglued path for subsequent logic
		$p = $pUnglue
	} elseif ($p -match '(?i)\\Windows\\System32\\(Users\\.+)$') {
		& $add ('C:\' + $Matches[1])
		$p = 'C:\' + $Matches[1]
	}

	# ~ / %USERPROFILE%
	if ($p.StartsWith('~\' ) -or $p -eq '~') {
		$home = $env:USERPROFILE
		if (-not $home) { try { $home = [Environment]::GetFolderPath('UserProfile') } catch {} }
		if ($home) {
			$rest = if ($p.Length -gt 1) { $p.Substring(2) } else { '' }
			& $add (Join-Path $home $rest)
		}
	}
	if ($p -match '%([^%]+)%') {
		try {
			$expanded = [Environment]::ExpandEnvironmentVariables($p)
			if ($expanded -ne $p) { & $add $expanded }
		} catch {}
	}

	# Already rooted (C:\..., \\server\share, \absolute-on-drive)
	$rooted = $false
	try { $rooted = [System.IO.Path]::IsPathRooted($p) } catch { $rooted = $false }
	if ($rooted) {
		& $add $p
		# \Users\... → C:\Users\... (GetFullPath uses current drive; also try C:)
		if ($p.StartsWith('\') -and -not $p.StartsWith('\\')) {
			& $add ('C:' + $p)
			$drive = $null
			try {
				if ($script:MB.WorkingDir -match '^([A-Za-z]:)') { $drive = $Matches[1] }
			} catch {}
			if ($drive -and $drive -ne 'C:') { & $add ($drive + $p) }
		}
		# Rooted but still looks like a bad System32\Users glue (any drive letter)
		if ($p -match '(?i)^[A-Za-z]:\\Windows\\System32\\Users\\') {
			$rest = $p -replace '(?i)^[A-Za-z]:\\Windows\\System32\\', ''
			& $add ('C:\' + $rest)
		}
	} else {
		# Users\Owner\... or Documents\... without drive → treat as under C:\ or profile
		if ($p -match '^(?i)Users\\') {
			& $add ('C:\' + $p)
		}
		if ($p -match '^(?i)(Documents|Desktop|Downloads|Pictures|Videos|Music)\\') {
			$prof = $env:USERPROFILE
			if (-not $prof) { try { $prof = [Environment]::GetFolderPath('UserProfile') } catch {} }
			if ($prof) { & $add (Join-Path $prof $p) }
			& $add ('C:\Users\Public\' + $p)
		}

		# CWD-relative (agent WorkingDir)
		$wd = $null
		try { $wd = [string]$script:MB.WorkingDir } catch { $wd = $null }
		if ([string]::IsNullOrWhiteSpace($wd)) {
			try { $wd = (Get-Location).Path } catch { $wd = $env:SystemRoot }
		}
		if ($wd) { & $add (Join-Path $wd $p) }

		# If CWD looks like System32 / Windows (common elevated launch), also try profile + Desktop
		$wdLow = if ($wd) { $wd.ToLowerInvariant() } else { '' }
		if ($wdLow -match '\\windows(\\system32)?$' -or $wdLow -match '\\system32$') {
			$prof = $env:USERPROFILE
			if (-not $prof) { try { $prof = [Environment]::GetFolderPath('UserProfile') } catch {} }
			if ($prof) {
				& $add (Join-Path $prof $p)
				foreach ($sub in @('Desktop', 'Documents', 'Downloads', 'Pictures', 'Videos')) {
					& $add (Join-Path (Join-Path $prof $sub) $p)
				}
			}
			# bare filename under Desktop
			$leaf = $null
			try { $leaf = [System.IO.Path]::GetFileName($p) } catch {}
			if ($leaf -and $prof) {
				& $add (Join-Path (Join-Path $prof 'Desktop') $leaf)
				& $add (Join-Path (Join-Path $prof 'Downloads') $leaf)
				& $add (Join-Path (Join-Path $prof 'Documents') $leaf)
				& $add (Join-Path (Join-Path $prof 'Pictures') $leaf)
			}
		} else {
			# Also try under profile for relative paths that look home-ish
			$prof = $env:USERPROFILE
			if ($prof -and $p -notmatch '^[A-Za-z]:') {
				& $add (Join-Path $prof $p)
			}
		}
	}

	return @($list)
}

function Sanitize-MBText {
	param([AllowNull()][string]$Text)
	if ($null -eq $Text -or $Text.Length -eq 0) { return "" }
	try {
		$sb = New-Object System.Text.StringBuilder ($Text.Length)
		$chars = $Text.ToCharArray()
		for ($i = 0; $i -lt $chars.Length; $i++) {
			$code = [int]$chars[$i]
			if ($code -eq 0) { continue }
			if ($code -lt 32 -and $code -ne 9 -and $code -ne 10 -and $code -ne 13) {
				[void]$sb.Append([char]0x20)
				continue
			}
			if ($code -eq 0x7F -or ($code -ge 0x80 -and $code -le 0x9F)) {
				[void]$sb.Append([char]0x20)
				continue
			}
			# Keep valid UTF-16 surrogate pairs; drop lone surrogates
			if ($code -ge 0xD800 -and $code -le 0xDBFF) {
				if (($i + 1) -lt $chars.Length) {
					$low = [int]$chars[$i + 1]
					if ($low -ge 0xDC00 -and $low -le 0xDFFF) {
						[void]$sb.Append($chars[$i])
						[void]$sb.Append($chars[$i + 1])
						$i++
						continue
					}
				}
				continue
			}
			# Lone low surrogate
			if ($code -ge 0xDC00 -and $code -le 0xDFFF) { continue }
			if ($code -eq 0xFFFE -or $code -eq 0xFFFF -or ($code -ge 0xFDD0 -and $code -le 0xFDEF)) { continue }
			if ($code -eq 0xFFFD) { continue }  # replacement char from prior bad decode
			if ($code -eq 0x00AD -or $code -eq 0x2060 -or $code -eq 0x200B) { continue }
			if ($code -eq 0x00A0) { [void]$sb.Append([char]0x20); continue }
			[void]$sb.Append($chars[$i])
		}
		return $sb.ToString()
	} catch {
		$s = [regex]::Replace([string]$Text, '[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]', ' ')
		return $s
	}
}

function ConvertTo-MBWireJson {
	param([AllowNull()][string]$Json)
	if ($null -eq $Json -or $Json.Length -eq 0) { return $Json }
	try {
		$sb = New-Object System.Text.StringBuilder ($Json.Length + 64)
		$chars = $Json.ToCharArray()
		for ($i = 0; $i -lt $chars.Length; $i++) {
			$code = [int]$chars[$i]
			if ($code -ge 0xD800 -and $code -le 0xDBFF) {
				# Surrogate pair as two \u escapes
				if (($i + 1) -lt $chars.Length) {
					$low = [int]$chars[$i + 1]
					if ($low -ge 0xDC00 -and $low -le 0xDFFF) {
						[void]$sb.Append('\u')
						[void]$sb.Append($code.ToString('x4'))
						[void]$sb.Append('\u')
						[void]$sb.Append($low.ToString('x4'))
						$i++
						continue
					}
				}
				[void]$sb.Append('\u003f')
				continue
			}
			if ($code -ge 0xDC00 -and $code -le 0xDFFF) {
				[void]$sb.Append('\u003f')
				continue
			}
			if ($code -gt 127) {
				[void]$sb.Append('\u')
				[void]$sb.Append($code.ToString('x4'))
			} else {
				[void]$sb.Append($chars[$i])
			}
		}
		return $sb.ToString()
	} catch {
		return $Json
	}
}

function Get-MBUtf8JsonBytes {
	param([AllowNull()][string]$Json)
	if ($null -eq $Json) { $Json = '' }
	$wire = ConvertTo-MBWireJson -Json ([string]$Json)
	$sb = New-Object System.Text.StringBuilder ($wire.Length)
	foreach ($ch in $wire.ToCharArray()) {
		$code = [int]$ch
		if ($code -gt 127) {
			[void]$sb.Append([char]0x3F)
		} elseif ($code -lt 32 -and $code -ne 9 -and $code -ne 10 -and $code -ne 13) {
			[void]$sb.Append([char]0x20)
		} else {
			[void]$sb.Append($ch)
		}
	}
	$ascii = $sb.ToString()
	$utf8 = New-Object System.Text.UTF8Encoding $false, $false
	return , $utf8.GetBytes($ascii)
}

function ConvertTo-MBRequestJson {
	param($Object, [int]$Depth = 20)
	if ($null -eq $Object) { return '{}' }
	$json = if ($Object -is [string]) {
		[string]$Object
	} else {
		try {
			ConvertTo-Json -InputObject $Object -Depth $Depth -Compress
		} catch {
			ConvertTo-Json -InputObject $Object -Depth 6 -Compress
		}
	}
	return (ConvertTo-MBWireJson -Json $json)
}

function Repair-MBMessagesEncoding {
	param([array]$Messages)
	$out = New-Object System.Collections.ArrayList
	foreach ($m in @($Messages)) {
		if ($null -eq $m) { continue }
		$role = [string](Get-MBProp $m 'role')
		if ([string]::IsNullOrWhiteSpace($role)) { $role = 'user' }
		$content = Sanitize-MBText -Text ([string](Get-MBProp $m 'content'))
		$msg = @{
			role    = $role
			content = $content
		}
		if ($role -eq 'tool') {
			$tcid = Get-MBProp $m 'tool_call_id'
			if (-not $tcid) { $tcid = Get-MBProp $m 'id' }
			if (-not $tcid) { $tcid = 'tool_call' }
			$msg['tool_call_id'] = Sanitize-MBText -Text ([string]$tcid)
			$name = Get-MBProp $m 'name'
			if ($name) { $msg['name'] = Sanitize-MBText -Text ([string]$name) }
		}
		if ($role -eq 'assistant') {
			$toolCalls = Get-MBProp $m 'tool_calls'
			if ($toolCalls) {
				$tcOut = New-Object System.Collections.ArrayList
				foreach ($tc in @($toolCalls)) {
					$fn = Get-MBProp $tc 'function'
					$fnName = Sanitize-MBText -Text ([string](Get-MBProp $fn 'name'))
					$fnArgs = Get-MBProp $fn 'arguments'
					if ($null -eq $fnArgs) { $fnArgs = '{}' }
					elseif (-not ($fnArgs -is [string])) {
						try { $fnArgs = ConvertTo-MBJson $fnArgs -Depth 10 } catch { $fnArgs = '{}' }
					}
					$fnArgs = Sanitize-MBText -Text ([string]$fnArgs)
					$tcId = Get-MBProp $tc 'id'
					if (-not $tcId) { $tcId = 'call_' + [guid]::NewGuid().ToString('N').Substring(0, 8) }
					[void]$tcOut.Add(@{
						id       = Sanitize-MBText -Text ([string]$tcId)
						type     = 'function'
						function = @{
							name      = $fnName
							arguments = $fnArgs
						}
					})
				}
				if ($tcOut.Count -gt 0) {
					$msg['tool_calls'] = @($tcOut.ToArray())
				}
			}
		}
		[void]$out.Add($msg)
	}
	return $out.ToArray()
}

function Test-MBReplyIncomplete {
	param(
		[AllowNull()][string]$Text,
		[string]$FinishReason = '',
		[bool]$HasToolCalls = $false,
		[int]$CompletionTokens = 0,
		[bool]$HaveUsage = $false
	)
	if ($HasToolCalls) { return $false }
	if ([string]::IsNullOrWhiteSpace($Text)) { return $false }

	if ($FinishReason -match '^(?i)length|max_tokens|limit|max_completion_tokens$') { return $true }

	$budget = [int](Get-MBEffectiveMaxTokens)
	try {
		if ($script:MB.LastRequestMaxTokens -gt 0) { $budget = [int]$script:MB.LastRequestMaxTokens }
	} catch {}
	if ($HaveUsage -and $CompletionTokens -gt 0 -and $budget -gt 0) {
		if ($CompletionTokens -ge [int]([math]::Floor($budget * 0.95))) { return $true }
	}

	$t = $Text.TrimEnd()
	if ($t.Length -lt 12) { return $false }

	if ($t -match '[\.\!\?...]$') { return $false }
	if ($t -match '[\.\!\?...]["''”»)]$') { return $false }
	if ($t -match '(?i)```\s*$') { return $false }
	if ($t -match '[\)\]\}]\s*$') { return $false }          # ends with ) ] }
	if ($t -match '(?i)\*\*\s*$') { return $false }
	if ($t -match '(?i)(thanks|thank you|you''re welcome|done|complete|all set)\.?["''”]*\s*$') {
		return $false
	}
	if ($t -match '(?i)^(ok|okay|yes|no|sure|yep|nope|got it|understood)\.?$') { return $false }

	if ($t -match '[,;:]\s*$') { return $true }
	if ($t -match '[---]\s*$') { return $true }
	if ($t -match '\b(the|a|an|and|or|to|of|for|with|that|this|lets|let''s|can|will|would|should|may|might|from|into|about)\s*$') {
		return $true
	}
	if ($t -match '\s[A-Za-z]$') { return $true }
	if ($t -match '/[a-zA-Z]{1,5}$') { return $true }

	return $false
}

function Get-MBContinuePrompt {
	return @(
		'[CONTINUE] Your previous reply was cut off (token limit or mid-sentence).'
		'Continue EXACTLY from the next word - do not restart, do not repeat any text already written.'
		'Finish the incomplete sentence and complete the FULL answer. Prefer finishing over stopping early.'
	) -join ' '
}

function Limit-MBResult {
	param([string]$Text, [int]$Max = 0)
	if ($Max -le 0) { $Max = $MaxToolResultChars }
	if ($null -eq $Text) { return "" }
	$s = if ($Text -is [string]) { $Text } else { ($Text | Out-String) }
	$s = Sanitize-MBText -Text $s
	try {
		if ($script:HasNative) {
			return [MiniBot.Core.Native]::TruncateMiddle($s, $Max)
		}
	} catch {}
	if ($s.Length -le $Max) { return $s }
	$head = [math]::Floor($Max * 0.55)
	$tail = $Max - $head - 60
	if ($head -lt 1) { $head = 1 }
	if ($tail -lt 1) { $tail = 1 }
	if (($head + $tail) -ge $s.Length) { return $s }
	try {
		return $s.Substring(0, $head) + "`n`n... [truncated $($s.Length - $head - $tail) chars] ...`n`n" + $s.Substring($s.Length - $tail)
	} catch {
		if ($s.Length -gt $Max) { return $s.Substring(0, $Max) + "`n... [truncated]" }
		return $s
	}
}

function Convert-MBJsonReady {
	param($Object, [int]$Depth = 12)
	if ($Depth -lt 0) { return $null }
	if ($null -eq $Object) { return $null }

	if ($Object -is [string]) { return [string]$Object }
	if ($Object -is [bool]) { return [bool]$Object }
	if ($Object -is [byte] -or $Object -is [int16] -or $Object -is [int] -or $Object -is [long]) {
		return [long]$Object
	}
	if ($Object -is [double] -or $Object -is [float] -or $Object -is [decimal]) {
		return [double]$Object
	}
	if ($Object -is [datetime]) { return $Object.ToString('o') }
	if ($Object -is [guid]) { return $Object.ToString() }

	if ($Object -is [System.Collections.IDictionary]) {
		$h = [ordered]@{}
		foreach ($k in @($Object.Keys)) {
			$key = [string]$k
			if ([string]::IsNullOrEmpty($key)) { continue }
			$val = $Object[$k]
			if ($null -eq $val) {
				$h[$key] = $null
			} else {
				$h[$key] = Convert-MBJsonReady -Object $val -Depth ($Depth - 1)
			}
		}
		# Prefer PSCustomObject for JSON on PS 5.1
		return [pscustomobject]$h
	}

	if ($Object -is [System.Array] -or
		($Object -is [System.Collections.IEnumerable] -and -not ($Object -is [string]))) {
		$list = New-Object System.Collections.ArrayList
		foreach ($item in $Object) {
			[void]$list.Add((Convert-MBJsonReady -Object $item -Depth ($Depth - 1)))
		}
		return @($list.ToArray())
	}

	try {
		$props = @($Object.PSObject.Properties | Where-Object {
			$_.MemberType -eq 'NoteProperty' -or $_.MemberType -eq 'Property'
		})
		if ($props.Count -gt 0 -and -not ($Object -is [System.ValueType])) {
			$h = [ordered]@{}
			foreach ($p in $props) {
				if ($p.Name -match '^(Count|Length|Keys|Values|SyncRoot|IsReadOnly|IsFixedSize|IsSynchronized)$' -and
					$Object -is [System.Collections.IEnumerable]) { continue }
				try {
					$h[[string]$p.Name] = Convert-MBJsonReady -Object $p.Value -Depth ($Depth - 1)
				} catch {
					$h[[string]$p.Name] = [string]$p.Value
				}
			}
			if ($h.Count -gt 0) { return [pscustomobject]$h }
		}
	} catch {}

	try { return [string]$Object } catch { return $null }
}

function ConvertTo-MBJson {
	param($Object, $Depth = 6)
	$d = 6
	try { $d = [int]$Depth } catch { $d = 6 }
	if ($d -lt 1) { $d = 1 }
	$safe = $null
	try {
		$safe = Convert-MBJsonReady -Object $Object -Depth ([math]::Max(4, $d + 2))
	} catch {
		$safe = $Object
	}
	try {
		return (ConvertTo-Json -InputObject $safe -Depth $d -Compress)
	} catch {
		try {
			return (ConvertTo-Json -InputObject $safe -Depth 3 -Compress)
		} catch {
			try {
				return (ConvertTo-Json -InputObject ([pscustomobject]@{ error = 'json_serialize_failed'; message = $_.Exception.Message }) -Compress -Depth 2)
			} catch {
				return '{"error":"json_serialize_failed"}'
			}
		}
	}
}

function New-MBSandboxCheck {
	param(
		$Name = 'check',
		$Pass = $false,
		$Detail = '',
		$Expected = $null,
		$Actual = $null,
		$Expr = $null
	)
	$row = [ordered]@{}
	$row['name'] = [string]$Name
	$row['pass'] = [bool](Convert-MBToBool -Value $Pass -Default $false)
	if ($null -ne $Detail -and "$Detail" -ne '') { $row['detail'] = [string]$Detail }
	if ($null -ne $Expected) { $row['expected'] = $(try { if ($Expected -is [string] -or $Expected -is [ValueType]) { $Expected } else { [string]$Expected } } catch { [string]$Expected }) }
	if ($null -ne $Actual) { $row['actual'] = $(try { if ($Actual -is [string] -or $Actual -is [ValueType]) { $Actual } else { [string]$Actual } } catch { [string]$Actual }) }
	if ($null -ne $Expr -and "$Expr" -ne '') { $row['expr'] = [string]$Expr }
	return [pscustomobject]$row
}

function Get-MBProp {
	param($Obj, $Name = $null, $Default = $null)
	if ($null -eq $Name) { return $Default }
	$Name = [string]$Name
	if ($null -eq $Obj) { return $Default }
	if ($Obj -is [hashtable] -or $Obj -is [System.Collections.IDictionary]) {
		foreach ($k in @($Obj.Keys)) {
			if ([string]::Equals([string]$k, $Name, [System.StringComparison]::OrdinalIgnoreCase)) {
				return $Obj[$k]
			}
		}
		return $Default
	}
	$p = $Obj.PSObject.Properties[$Name]
	if ($p) { return $p.Value }
	foreach ($prop in $Obj.PSObject.Properties) {
		if ([string]::Equals($prop.Name, $Name, [System.StringComparison]::OrdinalIgnoreCase)) {
			return $prop.Value
		}
	}
	return $Default
}

function Test-MBHasProp {
	param($Obj, $Name = $null)
	if ($null -eq $Obj -or $null -eq $Name) { return $false }
	$Name = [string]$Name
	if ($Obj -is [hashtable] -or $Obj -is [System.Collections.IDictionary]) {
		foreach ($k in @($Obj.Keys)) {
			if ([string]::Equals([string]$k, $Name, [System.StringComparison]::OrdinalIgnoreCase)) { return $true }
		}
		return $false
	}
	if ($Obj.PSObject.Properties[$Name]) { return $true }
	foreach ($prop in $Obj.PSObject.Properties) {
		if ([string]::Equals($prop.Name, $Name, [System.StringComparison]::OrdinalIgnoreCase)) { return $true }
	}
	return $false
}

function Convert-MBToBool {
	param($Value, $Default = $false)
	$def = $false
	if ($Default -is [bool]) { $def = $Default }
	elseif ("$Default" -match '^(?i)1|true|yes$') { $def = $true }
	if ($null -eq $Value) { return $def }
	if ($Value -is [bool]) { return $Value }
	if ($Value -is [int] -or $Value -is [long]) { return ($Value -ne 0) }
	$s = ([string]$Value).Trim().ToLowerInvariant()
	if ($s -in @('1', 'true', 'yes', 'on', 'y')) { return $true }
	if ($s -in @('0', 'false', 'no', 'off', 'n', '')) { return $false }
	return $def
}

function Convert-MBToInt {
	param($Value, $Default = 0)
	$def = 0
	try { if ($null -ne $Default) { $def = [int]$Default } } catch { $def = 0 }
	if ($null -eq $Value) { return $def }
	if ($Value -is [int] -or $Value -is [long]) { return [int]$Value }
	$n = 0
	if ([int]::TryParse(([string]$Value).Trim(), [ref]$n)) { return $n }
	return $def
}

function Convert-MBForceArray {
	param($Value)
	if ($null -eq $Value) { return @() }
	if ($Value -is [string]) { return @($Value) }
	if ($Value -is [System.Array]) { return @($Value) }
	if ($Value -is [System.Collections.IEnumerable] -and -not ($Value -is [string])) {
		return @($Value)
	}
	return @($Value)
}

function Convert-MBToCodeString {
	param($Value)
	if ($null -eq $Value) { return '' }
	if ($Value -is [string]) { return [string]$Value }
	if ($Value -is [System.Array] -or ($Value -is [System.Collections.IEnumerable] -and -not ($Value -is [string]))) {
		$parts = New-Object System.Collections.Generic.List[string]
		foreach ($x in @($Value)) {
			if ($null -eq $x) { continue }
			if ($x -is [string]) { [void]$parts.Add($x) }
			else {
				$t = Get-MBProp $x 'code'
				if ($null -eq $t) { $t = Get-MBProp $x 'text' }
				if ($null -eq $t) { $t = Get-MBProp $x 'content' }
				if ($null -ne $t) { [void]$parts.Add([string]$t) }
				else {
					try { [void]$parts.Add((ConvertTo-MBJson $x -Depth 6)) } catch { [void]$parts.Add([string]$x) }
				}
			}
		}
		return ($parts -join "`n")
	}
	try {
		$asCode = Get-MBProp $Value 'code'
		if ($null -ne $asCode) { return (Convert-MBToCodeString $asCode) }
	} catch {}
	return [string]$Value
}

function Convert-MBToolArguments {
	param($ArgString)

	if ($null -eq $ArgString) { return [pscustomobject]@{} }
	if (-not ($ArgString -is [string])) {
		return $ArgString
	}

	$s = [string]$ArgString
	$s = $s.Trim()
	if ($s.Length -eq 0 -or $s -eq 'null') { return [pscustomobject]@{} }

	if ($s -match '(?s)^```(?:json)?\s*(.*?)\s*```$') {
		$s = $Matches[1].Trim()
	}

	try {
		$obj = $s | ConvertFrom-Json -ErrorAction Stop
		if ($null -eq $obj) { return [pscustomobject]@{} }
		if ($obj -is [string]) {
			$inner = ([string]$obj).Trim()
			if ($inner.StartsWith('{') -or $inner.StartsWith('[')) {
				try { return ($inner | ConvertFrom-Json -ErrorAction Stop) } catch {}
			}
		}
		return $obj
	} catch {
	}

	$ht = [ordered]@{}
	try {
		if ($s -match '"code"\s*:\s*"((?:\\.|[^"\\])*)"') {
			$codeVal = $Matches[1]
			$codeVal = $codeVal -replace '\\n', "`n" -replace '\\r', "`r" -replace '\\t', "`t" -replace '\\"', '"' -replace '\\\\', '\'
			$ht['code'] = $codeVal
		}
		if ($s -match '"name"\s*:\s*"((?:\\.|[^"\\])*)"') {
			$ht['name'] = ($Matches[1] -replace '\\"', '"')
		}
		if ($s -match '"piece"\s*:\s*"((?:\\.|[^"\\])*)"') {
			$ht['piece'] = ($Matches[1] -replace '\\"', '"')
		}
		if ($s -match '"path"\s*:\s*"((?:\\.|[^"\\])*)"') {
			$ht['path'] = ($Matches[1] -replace '\\"', '"')
		}
		if ($s -match '"save_as"\s*:\s*"((?:\\.|[^"\\])*)"') {
			$ht['save_as'] = ($Matches[1] -replace '\\"', '"')
		}
		if ($s -match '"test_script"\s*:\s*"((?:\\.|[^"\\])*)"') {
			$ts = $Matches[1]
			$ts = $ts -replace '\\n', "`n" -replace '\\r', "`r" -replace '\\t', "`t" -replace '\\"', '"' -replace '\\\\', '\'
			$ht['test_script'] = $ts
		}
		if ($s -match '"expect_stdout"\s*:\s*"((?:\\.|[^"\\])*)"') {
			$ht['expect_stdout'] = ($Matches[1] -replace '\\n', "`n" -replace '\\"', '"')
		}
		if ($s -match '"expect_exit"\s*:\s*(-?\d+)') {
			$ht['expect_exit'] = [int]$Matches[1]
		}
		if ($s -match '"compose"\s*:\s*(true|false)') {
			$ht['compose'] = ($Matches[1] -eq 'true')
		}
		if ($s -match '"pieces"\s*:\s*\[(.*?)\]') {
			$inner = $Matches[1]
			$plist = New-Object System.Collections.Generic.List[string]
			[regex]::Matches($inner, '"([^"]+)"') | ForEach-Object { [void]$plist.Add($_.Groups[1].Value) }
			if ($plist.Count -gt 0) { $ht['pieces'] = @($plist) }
		}
		if ($s -match '"assert"\s*:\s*\[(.*?)\]') {
			$inner = $Matches[1]
			$alist = New-Object System.Collections.Generic.List[string]
			[regex]::Matches($inner, '"((?:\\.|[^"\\])*)"') | ForEach-Object {
				$a = $_.Groups[1].Value -replace '\\"', '"' -replace '\\n', "`n"
				[void]$alist.Add($a)
			}
			if ($alist.Count -gt 0) { $ht['assert'] = @($alist) }
		} elseif ($s -match '"assert"\s*:\s*"((?:\\.|[^"\\])*)"') {
			$ht['assert'] = @(($Matches[1] -replace '\\"', '"' -replace '\\n', "`n"))
		}
	} catch {}

	if ($ht.Count -gt 0) {
		return [pscustomobject]$ht
	}

	return [pscustomobject]@{
		_parse_error = $true
		_raw_preview = $(if ($s.Length -gt 300) { $s.Substring(0, 297) + '...' } else { $s })
	}
}

function Test-MBMultimodalContent {
	param($Content)
	if ($null -eq $Content) { return $false }
	if ($Content -is [string]) { return $false }
	if ($Content -is [System.Array]) { return $true }
	if ($Content -is [System.Collections.IList] -and -not ($Content -is [string])) {
		try {
			if (@($Content).Count -gt 0) {
				$first = @($Content)[0]
				$t = Get-MBProp $first 'type'
				if ($t -in @('text','image_url','image')) { return $true }
			}
		} catch {}
	}
	return $false
}

function Normalize-MBContentPart {
	param($Part)
	if ($null -eq $Part) { return $null }
	$type = [string](Get-MBProp $Part 'type')
	if ($type -eq 'image_url') {
		$img = Get-MBProp $Part 'image_url'
		$url = $null
		if ($img -is [string]) { $url = $img }
		else { $url = [string](Get-MBProp $img 'url') }
		if ([string]::IsNullOrWhiteSpace($url)) { return $null }
		return @{
			type      = 'image_url'
			image_url = @{ url = $url }
		}
	}
	if ($type -eq 'image') {
		$data = Get-MBProp $Part 'data'
		$url = Get-MBProp $Part 'url'
		if ($data) {
			return @{
				type      = 'image_url'
				image_url = @{ url = ("data:image/png;base64," + ([string]$data).Trim()) }
			}
		}
		if ($url) {
			return @{
				type      = 'image_url'
				image_url = @{ url = [string]$url }
			}
		}
		return $null
	}
	$text = Get-MBProp $Part 'text'
	if ($null -eq $text) { $text = Get-MBProp $Part 'content' }
	return @{
		type = 'text'
		text = (Sanitize-MBText -Text ([string]$text))
	}
}

function Normalize-MBMessagesForApi {
	param([array]$Messages)

	$out = New-Object System.Collections.ArrayList
	foreach ($m in @($Messages)) {
		if ($null -eq $m) { continue }
		$role = [string](Get-MBProp $m 'role')
		if ([string]::IsNullOrWhiteSpace($role)) { $role = 'user' }

		$rawContent = Get-MBProp $m 'content'
		$content = $null
		if (Test-MBMultimodalContent -Content $rawContent) {
			$parts = New-Object System.Collections.ArrayList
			foreach ($p in @($rawContent)) {
				$np = Normalize-MBContentPart -Part $p
				if ($null -ne $np) { [void]$parts.Add($np) }
			}
			if ($parts.Count -eq 0) {
				$content = ""
			} elseif ($parts.Count -eq 1 -and $parts[0].type -eq 'text') {
				$content = [string]$parts[0].text
			} else {
				$content = @($parts.ToArray())
			}
		} elseif ($null -eq $rawContent) {
			$content = ""
		} elseif ($rawContent -is [string]) {
			$content = Sanitize-MBText -Text $rawContent
		} else {
			$content = Sanitize-MBText -Text ([string]$rawContent)
		}

		$msg = @{
			role    = $role
			content = $content
		}

		if ($role -eq 'tool') {
			$tcid = Get-MBProp $m 'tool_call_id'
			if (-not $tcid) { $tcid = Get-MBProp $m 'id' }
			if (-not $tcid) { $tcid = 'tool_call' }
			$msg['tool_call_id'] = Sanitize-MBText -Text ([string]$tcid)
			$name = Get-MBProp $m 'name'
			if ($name) { $msg['name'] = Sanitize-MBText -Text ([string]$name) }
		}

		if ($role -eq 'assistant') {
			$toolCalls = Get-MBProp $m 'tool_calls'
			if ($toolCalls) {
				$tcOut = New-Object System.Collections.ArrayList
				foreach ($tc in @($toolCalls)) {
					$fn = Get-MBProp $tc 'function'
					$fnName = Sanitize-MBText -Text ([string](Get-MBProp $fn 'name'))
					$fnArgs = Get-MBProp $fn 'arguments'
					if ($null -eq $fnArgs) { $fnArgs = '{}' }
					elseif (-not ($fnArgs -is [string])) {
						try { $fnArgs = ConvertTo-MBJson $fnArgs -Depth 10 } catch { $fnArgs = '{}' }
					}
					$fnArgs = Sanitize-MBText -Text ([string]$fnArgs)
					$tcId = Get-MBProp $tc 'id'
					if (-not $tcId) { $tcId = 'call_' + [guid]::NewGuid().ToString('N').Substring(0, 8) }

					[void]$tcOut.Add(@{
						id       = Sanitize-MBText -Text ([string]$tcId)
						type     = 'function'
						function = @{
							name      = $fnName
							arguments = $fnArgs
						}
					})
				}
				if ($tcOut.Count -gt 0) {
					$msg['tool_calls'] = @($tcOut.ToArray())
				}
			}
		}

		[void]$out.Add($msg)
	}
	return $out.ToArray()
}

function Get-MBMessagesWithPendingVision {
	param([array]$Messages)
	$pv = $script:MB.PendingVision
	if (-not $pv -or [string]::IsNullOrWhiteSpace([string]$pv.Base64)) {
		return @($Messages)
	}
	$kb = [math]::Round([double]$pv.SizeBytes / 1KB, 1)
	$label = if ($pv.Label) { [string]$pv.Label } else { 'screen' }
	$saved = $pv.SavedPath
	$kind = if ($pv.Kind) { [string]$pv.Kind } else { 'screen' }
	$src = if ($pv.SourcePath) { [string]$pv.SourcePath } else { '' }
	if ($saved) {
		$text = "You can see this image ($label). A full-resolution file was also saved to disk. In your reply: (1) describe what you see if relevant; (2) ALWAYS include the exact save path: $saved"
	} elseif ($kind -eq 'pdf') {
		$srcBit = if ($src) { " from PDF: $src" } else { '' }
		$text = "You can see a rendered PDF page$srcBit ($label, $($pv.Width)x$($pv.Height), ${kb} KB). The text layer was missing or garbled - extract fields VISUALLY (names, policy numbers, dates, limits, insurer). Do not invent values not visible. Do not invent other paths."
	} elseif ($src) {
		$text = "You can see this image from disk: $src ($label, $($pv.Width)x$($pv.Height), ${kb} KB). Describe what you see that answers the user. Do not invent other paths."
	} else {
		$text = "You can see this $kind image ($label, $($pv.Width)x$($pv.Height), ${kb} KB). Reply by describing what you see that answers their question. Do not invent a file path. Do not mention tools unless asked."
	}
	$mime = if ($pv.Mime) { [string]$pv.Mime } else { 'image/png' }
	if ($mime -notmatch '^image/') { $mime = 'image/png' }
	$dataUrl = "data:${mime};base64,$($pv.Base64)"
	$visionMsg = @{
		role    = 'user'
		content = @(
			@{ type = 'text'; text = $text }
			@{ type = 'image_url'; image_url = @{ url = $dataUrl } }
		)
	}
	return @(@($Messages) + $visionMsg)
}

function Clear-MBPendingVision {
	param([switch]$KeepMeta)
	$pv = $script:MB.PendingVision
	if ($pv -and -not $KeepMeta) {
		$script:MB.LastVisionMeta = @{
			Width     = $pv.Width
			Height    = $pv.Height
			SizeBytes = $pv.SizeBytes
			Label     = $pv.Label
			Attached  = (Get-Date).ToString('o')
		}
	}
	$script:MB.PendingVision = $null
}

function New-MBChatRequestBody {
	param(
		[array]$Messages,
		[array]$Tools,
		[string]$ModelName,
		[double]$Temp,
		[int]$MaxTok,
		[bool]$Stream = $true
	)

	$Messages = @(Get-MBMessagesWithPendingVision -Messages $Messages)

	$normMessages = @(Normalize-MBMessagesForApi -Messages $Messages)

	for ($i = 0; $i -lt $normMessages.Count; $i++) {
		if ($normMessages[$i] -is [hashtable] -and $normMessages[$i].ContainsKey('content')) {
			$c = $normMessages[$i]['content']
			if ($c -is [string]) {
				$normMessages[$i]['content'] = Sanitize-MBText -Text $c
			}
		}
	}

	$req = @{
		model        = $ModelName
		messages     = $normMessages
		tools        = $Tools
		tool_choice  = 'auto'
		temperature  = $Temp
		max_tokens   = $MaxTok
		stream       = $Stream
		cache_prompt = $true
	}
	if ($Stream) {
		$req['stream_options'] = @{ include_usage = $true }
	}
	try {
		return (ConvertTo-MBRequestJson -Object $req -Depth 20)
	} catch {
		Write-MBWarn "JSON build failed ($($_.Exception.Message)) - truncating tool results and retrying..."
		for ($i = 0; $i -lt $normMessages.Count; $i++) {
			if ($normMessages[$i] -is [hashtable] -and $normMessages[$i]['role'] -eq 'tool') {
				$c = [string]$normMessages[$i]['content']
				if ($c.Length -gt 4000) {
					$normMessages[$i]['content'] = (Limit-MBResult $c 4000)
				}
			}
		}
		$req['messages'] = $normMessages
		return (ConvertTo-MBRequestJson -Object $req -Depth 20)
	}
}

# Capability map kept short for cold-start token cost.
# Cold-start group map. Model enables groups by these names.
# Short labels for errors / ListToolGroups only (not expanded into every system prompt OFF line)
$script:MBGroupQuickMap = [ordered]@{
	senses = 'vision/TTS'; system = 'inventory'; network = 'LAN/shares-find'
	diag = 'BSOD/disk/events'; repair = 'sfc/dism/chkdsk'; setup = 'tune/setup'
	identity = 'users/domain'; shares = 'map/share/print'; installers = 'apps'
	sandbox = 'PS lab'; files = 'dl/zip/cab/iso'; packages = 'PSGallery'
	registry = 'reg'; clipboard = 'clip'; web = 'HTTP/GitHub'
}

$script:MBSystemPromptBase = @"
You are $AgentName v$Version - local Windows tool-first agent (PS 5.1). Evidence only; concise; CWD-relative paths unless absolute; never dump multi-MB/binary/.dmp.
No delete/destroy unless operator asked for that specific target. Mutate after read when possible; deny = stop. Prefer tools over RunCommand.
Never ReadFile images/video/PDF/binary (crashes servers) — vision: senses ReadImage/ReadPdf; operator display: markdown below.
INLINE MEDIA (chat UI) — REQUIRED for play/show/hear: always embed on its own line as ![label](absolute-path). Prefer absolute Windows paths. Images png/jpg/gif/webp/bmp/tif; video mp4/m4v/mov/wmv; audio mp3/wav/flac/m4a/aac/ogg/wma. After DownloadFile / ViewScreen save / FindFiles pick / any "play or show" ask: emit ![…](…) so it plays in-chat. NEVER Start-Process/Invoke-Item/explorer/VLC/default-app first. External player ONLY if format not inline-compatible or operator explicitly asked external. Do not reply with a bare path alone when they should see/hear it.
Tool groups: only active schemas are visible. core always on. EnableToolGroup group=a,b or groups=[a,b] silently before work (same turn; multi ok; no ListToolGroups/narration).
MAP: senses=vision/TTS | system=inventory | network=LAN+ProbeShares+lists | diag=BSOD/disk/events/kill | repair=sfc/dism/chkdsk | setup=tune/reboot/NewMachine | identity=users/domain | shares=map/share/print mutate | installers=apps | sandbox=PS lab | files=dl/zip/cab/iso | packages=PSGallery | registry | clipboard | web=HTTP/GitHub
FindFiles: multi-ext one call; truncated=normal (use rows); specific ask→narrow; vague play/show→pick one then INLINE ![label](path); no GCI -Recurse dumps. Bad tool output twice→tell operator. User text = results only.
"@

$script:MBGroupPrompt = [ordered]@{
	core = @"
CORE: text files Read/Write/Edit/ApplyPatch; List/Search/FindFiles; HexView/HexEdit (path2=diff, next_diff, annotate magic/PE/controls/ASCII+UTF16 strings); RunCommand; CWD/env; EnableToolGroup. Prefer specialized tools. MEDIA: always ![label](absolute-path) inline in chat for play/show — shell-open/default app last resort only.
"@
	senses = @"
SENSES: ReadImage (vision, auto-downscale); ReadPdf page=1 first; ViewScreen look-only default (if save=true → show with ![label](path) inline, not external open); SpeakText. No ReadFile on images/PDF.
"@
	system = @"
SYSTEM: GetSystemInfo/Process*/Memory/Power/Service/Software/Updates/Uptime. Prefer over Get-ComputerInfo.
"@
	network = @"
NETWORK: GetNetworkInfo/NetConnections/ScanNetwork; ProbeShares (REQUIRED to find shares - never net view loops); GetLocalShares/MappedDrives/Printers. Known host→ProbeShares computer=; search→omit hosts. Then shares group to map/create.
"@
	diag = @"
DIAG: BSOD/events/disk/startup/tasks/drivers/StopProcess/RunQuickDiagnostics. Never dump .dmp bytes. Kill only if asked.
"@
	repair = @"
REPAIR: RunRepairTool sfc|dism|chkdsk (prompt). Prefer diag first.
"@
	setup = @"
SETUP: volume/brightness/options/restore/uninstall/reboot/NewMachineSetup (prompt on mutate).
"@
	identity = @"
IDENTITY: Add/RemoveLocalUser; Join/LeaveDomain. Leave needs local admin creds in chat (NEED_INPUT if missing).
"@
	shares = @"
SHARES mutate: Map/Unmap; CreateShare (path,name,user,pass,everyone_full required); RemoveShare; printers. Lists=network. Find remote=ProbeShares then Map.
"@
	installers = @"
INSTALLERS: ListInstallers / InstallPackage (prompt; silent).
"@
	sandbox = @"
SANDBOX: SandBoxWrite→SandBox piece/pieces+assert; compose to ship. Claim pass only if ok=true.
"@
	files = @"
FILES: DownloadFile; zip Expand/Compress; MakeCab/ExpandCab; MakeIso/MountIso/UnmountIso (prompt on mutate). After download/save of media, show with ![label](path) inline.
"@
	packages = @"
PACKAGES: Find/Get/Install/Update PS modules (mutate prompts).
"@
	registry = @"
REGISTRY: ReadRegistry; SetRegistry (prompt).
"@
	clipboard = @"
CLIPBOARD: read|write (prompt).
"@
	web = @"
WEB: MakeHttpRequest/BrowsePage/GitHub raw+list. File downloads→files DownloadFile.
"@
}

function Get-MBSystemPrompt {
	$parts = New-Object System.Collections.ArrayList
	[void]$parts.Add([string]$script:MBSystemPromptBase)

	$active = @()
	try { $active = @($script:MB.ActiveToolGroups) } catch { $active = @('core') }
	if ($active.Count -eq 0) { $active = @('core') }
	$activeSet = @{}
	foreach ($g in $active) {
		if ($g) { $activeSet[[string]$g.ToLowerInvariant()] = $true }
	}
	if ($activeSet.ContainsKey('full') -or $activeSet.ContainsKey('all')) {
		foreach ($k in @($script:MBGroupPrompt.Keys)) { $activeSet[$k] = $true }
	}
	if (-not $activeSet.ContainsKey('core')) { $activeSet['core'] = $true }

	$order = @('core','senses','system','network','diag','repair','setup','identity','shares','installers','sandbox','files','packages','registry','clipboard','web')
	$onList = New-Object System.Collections.ArrayList
	$offBits = New-Object System.Collections.ArrayList
	foreach ($g in $order) {
		if ($activeSet.ContainsKey($g)) {
			[void]$onList.Add($g)
			if ($script:MBGroupPrompt.Contains($g)) {
				$snip = ([string]$script:MBGroupPrompt[$g]).Trim()
				if ($snip) { [void]$parts.Add($snip) }
			}
		} else {
			[void]$offBits.Add($g)
		}
	}

	[void]$parts.Add(("ON: {0}." -f (($onList | ForEach-Object { $_ }) -join ',')))
	if ($offBits.Count -gt 0) {
		[void]$parts.Add(("OFF (EnableToolGroup group=a,b): {0}." -f ($offBits -join ',')))
	}
	return (($parts | Where-Object { $_ -and "$_".Trim() }) -join "`n")
}

