				if (Test-MBHasProp $ArgsObj 'port') { $p['port'] = [int](Get-MBProp $ArgsObj 'port') }
				if (Test-MBHasProp $ArgsObj 'max') { $p['max'] = [int](Get-MBProp $ArgsObj 'max') }
