function Resolve-MBRobotMoodFromStatus {
	param([string]$Mode = 'ready')
	$m = ([string]$Mode).Trim().ToLowerInvariant()
	switch -Regex ($m) {
		'think'                  { return 'confused' }
		'work'                   { return 'excited' }
		'compact|autocompact'    { return 'default' }
		'error|fail|dead'        { return 'dead' }
		'off|offline|disconnect' { return 'off' }
		'angry|warn'             { return 'angry' }
		default                  { return 'happy' }
	}
}

function Get-MBRobotGradientForMood {
	param([string]$Mood = 'happy')
	switch ([string]$Mood) {
		'dead'  { return @('#D0C4C6', '#B08084', '#9A585C') }
		'error' { return @('#D0C4C6', '#B08084', '#9A585C') }
		default { return @('#C8C8D0', '#6A6A74', '#3A3A42') }
	}
}

function ConvertTo-MBShellIconBitmap {
	param($Source)
	if (-not $Source) { return $null }
	try {
		$enc = New-Object System.Windows.Media.Imaging.PngBitmapEncoder
		[void]$enc.Frames.Add([System.Windows.Media.Imaging.BitmapFrame]::Create($Source))
		$ms = New-Object System.IO.MemoryStream
		try {
			$enc.Save($ms)
			$ms.Position = 0
			$frame = [System.Windows.Media.Imaging.BitmapFrame]::Create(
				$ms,
				[System.Windows.Media.Imaging.BitmapCreateOptions]::None,
				[System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad
			)
			if ($frame.CanFreeze) { $frame.Freeze() }
			return $frame
		} finally {
			try { $ms.Dispose() } catch {}
		}
	} catch {
		try {
			if ($Source.CanFreeze -and -not $Source.IsFrozen) { $Source.Freeze() }
		} catch {}
		return $Source
	}
}

function Set-MBNativeWindowIcon {
	param($Window, $BitmapSource)
	if (-not $Window -or -not $BitmapSource) { return }
	try {
		if (-not ('MiniBot.UI.NativeIcon' -as [type])) {
			Add-Type -Namespace MiniBot.UI -Name NativeIcon -MemberDefinition @"
[System.Runtime.InteropServices.DllImport("user32.dll", CharSet=System.Runtime.InteropServices.CharSet.Auto)]
public static extern System.IntPtr SendMessage(System.IntPtr hWnd, int Msg, System.IntPtr wParam, System.IntPtr lParam);
[System.Runtime.InteropServices.DllImport("user32.dll", SetLastError=true)]
public static extern bool DestroyIcon(System.IntPtr hIcon);
[System.Runtime.InteropServices.DllImport("user32.dll", SetLastError=true)]
public static extern System.IntPtr CopyIcon(System.IntPtr hIcon);
public const int WM_SETICON = 0x0080;
public const int ICON_SMALL = 0;
public const int ICON_BIG = 1;
"@ -ErrorAction Stop
		}
		Add-Type -AssemblyName System.Drawing -ErrorAction SilentlyContinue
		$enc = New-Object System.Windows.Media.Imaging.PngBitmapEncoder
		[void]$enc.Frames.Add([System.Windows.Media.Imaging.BitmapFrame]::Create($BitmapSource))
		$ms = New-Object System.IO.MemoryStream
		try {
			$enc.Save($ms)
			$ms.Position = 0
			$gdi = [System.Drawing.Bitmap]::FromStream($ms)
			try {
				$hIcon = $gdi.GetHicon()
				try {
					$helper = New-Object System.Windows.Interop.WindowInteropHelper($Window)
					$hwnd = $helper.EnsureHandle()
					if ($hwnd -ne [IntPtr]::Zero) {
						$hSmall = [MiniBot.UI.NativeIcon]::CopyIcon($hIcon)
						$hBig = [MiniBot.UI.NativeIcon]::CopyIcon($hIcon)
						$prevSmall = [MiniBot.UI.NativeIcon]::SendMessage($hwnd, [MiniBot.UI.NativeIcon]::WM_SETICON, [IntPtr][MiniBot.UI.NativeIcon]::ICON_SMALL, $hSmall)
						$prevBig = [MiniBot.UI.NativeIcon]::SendMessage($hwnd, [MiniBot.UI.NativeIcon]::WM_SETICON, [IntPtr][MiniBot.UI.NativeIcon]::ICON_BIG, $hBig)
						if ($prevSmall -ne [IntPtr]::Zero) { try { [void][MiniBot.UI.NativeIcon]::DestroyIcon($prevSmall) } catch {} }
						if ($prevBig -ne [IntPtr]::Zero) { try { [void][MiniBot.UI.NativeIcon]::DestroyIcon($prevBig) } catch {} }
					}
				} finally {
					try { [void][MiniBot.UI.NativeIcon]::DestroyIcon($hIcon) } catch {}
				}
			} finally {
				try { $gdi.Dispose() } catch {}
			}
		} finally {
			try { $ms.Dispose() } catch {}
		}
	} catch {}
}

function New-MBRobotIconBitmap {
	param(
		[string]$Face = 'happy',
		[int]$Size = 64,
		[string]$PathData = '',
		[string[]]$Colors = @()
	)
	try {
		if ($Size -lt 16) { $Size = 16 }
		if ($Size -gt 256) { $Size = 256 }
		$faceKey = if ([string]::IsNullOrWhiteSpace($Face)) { 'happy' } else { [string]$Face }
		if ([string]::IsNullOrWhiteSpace($PathData)) {
			$cat = Get-MBRobotPathCatalog
			if (@($cat.Keys) -notcontains $faceKey) { $faceKey = 'happy' }
			if (@($cat.Keys) -notcontains $faceKey) { $faceKey = 'default' }
			$PathData = [string]$cat[$faceKey]
		}
		if ([string]::IsNullOrWhiteSpace($PathData)) { return $null }
		if (-not $Colors -or @($Colors).Count -lt 3) {
			$Colors = @(Get-MBRobotGradientForMood -Mood $faceKey)
		}
		$geom = [System.Windows.Media.Geometry]::Parse($PathData)
		$c0 = [System.Windows.Media.ColorConverter]::ConvertFromString([string]$Colors[0])
		$c1 = [System.Windows.Media.ColorConverter]::ConvertFromString([string]$Colors[1])
		$c2 = [System.Windows.Media.ColorConverter]::ConvertFromString([string]$Colors[2])
		$brush = New-Object System.Windows.Media.LinearGradientBrush
		$brush.StartPoint = New-Object System.Windows.Point(0.15, 0.0)
		$brush.EndPoint = New-Object System.Windows.Point(0.9, 1.0)
		[void]$brush.GradientStops.Add((New-Object System.Windows.Media.GradientStop($c0, 0.0)))
		[void]$brush.GradientStops.Add((New-Object System.Windows.Media.GradientStop($c1, 0.48)))
		[void]$brush.GradientStops.Add((New-Object System.Windows.Media.GradientStop($c2, 1.0)))
		$brush.Freeze()
		$bgCol = [System.Windows.Media.ColorConverter]::ConvertFromString('#252530')
		$bgBrush = New-Object System.Windows.Media.SolidColorBrush($bgCol)
		$bgBrush.Freeze()

		$visual = New-Object System.Windows.Media.DrawingVisual
		$dc = $visual.RenderOpen()
		try {
			$cx = [double]$Size / 2.0
			$r = $cx - 0.5
			$dc.DrawEllipse($bgBrush, $null, (New-Object System.Windows.Point($cx, $cx)), $r, $r)
			$pad = [math]::Max(2.0, [double]$Size * 0.14)
			$inner = [double]$Size - (2.0 * $pad)
			$scale = $inner / 24.0
			$dc.PushTransform((New-Object System.Windows.Media.TranslateTransform($pad, $pad)))
			$dc.PushTransform((New-Object System.Windows.Media.ScaleTransform($scale, $scale)))
			$dc.DrawGeometry($brush, $null, $geom)
			$dc.Pop()
			$dc.Pop()
		} finally {
			$dc.Close()
		}
		$rtb = New-Object System.Windows.Media.Imaging.RenderTargetBitmap(
			[int]$Size, [int]$Size, 96, 96,
			[System.Windows.Media.PixelFormats]::Pbgra32
		)
		$rtb.Render($visual)
		return (ConvertTo-MBShellIconBitmap -Source $rtb)
	} catch {
		return $null
	}
}

function Set-MBWindowRobotIcon {
	param(
		$Window,
		[string]$Face = 'happy',
		[string]$Description = 'MiniBot',
		$Bitmap = $null
	)
	if (-not $Window) { return $null }
	try {
		$bmp = $Bitmap
		if (-not $bmp) {
			$bmp = New-MBRobotIconBitmap -Face $Face -Size 64
		}
		if (-not $bmp) { return $null }
		$Window.Icon = $bmp
		try {
			if (-not $Window.TaskbarItemInfo) {
				$Window.TaskbarItemInfo = New-Object System.Windows.Shell.TaskbarItemInfo
			}
			$Window.TaskbarItemInfo.Overlay = $bmp
			$Window.TaskbarItemInfo.Description = $Description
		} catch {}
		try { Set-MBNativeWindowIcon -Window $Window -BitmapSource $bmp } catch {}
		return $bmp
	} catch {
		return $null
	}
}

function Set-MBWpfRobotMood {
	param(
		[string]$Mode = 'ready',
		[switch]$Force
	)
	try {
		$W = $script:MB.Wpf
		if (-not $W) { return }
		$sb = $null
		try { $sb = $W.SetRobotMood } catch { $sb = $null }
		if ($sb) {
			$run = {
				try { & $sb $Mode ([bool]$Force) } catch {}
			}.GetNewClosure()
			$d = $null
			try { $d = $W.Dispatcher } catch {}
			if ($d -and -not $d.CheckAccess()) {
				try { [void]$d.BeginInvoke([Action]$run) } catch { try { & $run } catch {} }
			} else {
				& $run
			}
			return
		}
		if (-not $W.TitleRobotPath) { return }
		$mood = Resolve-MBRobotMoodFromStatus -Mode $Mode
		if (-not $Force -and [string]$W.RobotMood -eq $mood) { return }
		$cat = Get-MBRobotPathCatalog
		$faceKey = if (@($cat.Keys) -contains $mood) { $mood } else { 'default' }
		$data = [string]$cat[$faceKey]
		if (-not $W.RobotGeomCache) { $W.RobotGeomCache = @{} }
		if (-not $W.RobotGeomCache.ContainsKey($faceKey)) {
			$W.RobotGeomCache[$faceKey] = [System.Windows.Media.Geometry]::Parse($data)
		}
		$W.TitleRobotPath.Data = $W.RobotGeomCache[$faceKey]
		$W.RobotMood = $faceKey
	} catch {}
}

function Update-MBWpfSticky {
	param(
		[string]$Line1,
		[string]$Line2,
		[string]$BrandName,
		[string]$Line1Rest,
		[string]$Left,
		[string]$Center,
		[string]$Right,
		[string]$Hint,
		[string]$Status,
		[string]$PoweredBy,
		[string]$AutoCompactLine,
		[double]$CtxPct,
		[string]$CtxColor,
		[string]$CtxPctText,
		[string]$CtxTokText
	)
	if (-not (Test-MBWpfActive)) { return }
	$cur = $script:MB.Wpf.PendingSticky
	if (-not $cur) { $cur = @{} }
	if ($PSBoundParameters.ContainsKey('Line1')) { $cur.Line1 = ConvertTo-MBWpfSafeText -Text $Line1 }
	if ($PSBoundParameters.ContainsKey('BrandName')) { $cur.BrandName = ConvertTo-MBWpfSafeText -Text $BrandName }
	if ($PSBoundParameters.ContainsKey('Line1Rest')) { $cur.Line1Rest = ConvertTo-MBWpfSafeText -Text $Line1Rest }
	if ($PSBoundParameters.ContainsKey('Line2')) { $cur.Line2 = ConvertTo-MBWpfSafeText -Text $Line2 }
	if ($PSBoundParameters.ContainsKey('Left')) { $cur.Left = ConvertTo-MBWpfSafeText -Text $Left }
	if ($PSBoundParameters.ContainsKey('Center')) { $cur.Center = ConvertTo-MBWpfSafeText -Text $Center }
	if ($PSBoundParameters.ContainsKey('Right')) { $cur.Right = ConvertTo-MBWpfSafeText -Text $Right }
	if ($PSBoundParameters.ContainsKey('Hint')) { $cur.Hint = ConvertTo-MBWpfSafeText -Text $Hint }
	if ($PSBoundParameters.ContainsKey('PoweredBy')) { $cur.PoweredBy = ConvertTo-MBWpfSafeText -Text $PoweredBy }
	if ($PSBoundParameters.ContainsKey('AutoCompactLine')) { $cur.AutoCompactLine = ConvertTo-MBWpfSafeText -Text $AutoCompactLine }
	if ($PSBoundParameters.ContainsKey('Status')) {
		# Status mode for UI spinner
		# Strip leading non-letter status glyphs
		$raw = [string]$Status
		$label = $raw.Trim()
		while ($label.Length -gt 0) {
			$c = [int][char]$label[0]
			$isLetter = (($c -ge 65 -and $c -le 90) -or ($c -ge 97 -and $c -le 122))
			if ($isLetter) { break }
			$label = $label.Substring(1).TrimStart()
		}
		if ([string]::IsNullOrWhiteSpace($label)) { $label = $raw.Trim() }
		$mode = 'ready'
		if ($label -match '(?i)auto-?compact|compact') {
			$mode = 'compacting'
			$label = 'auto-compacting...'
		} elseif ($label -match '(?i)error|fail') {
			$mode = 'error'
			$label = 'error'
		} elseif ($label -match '(?i)think') {
			$mode = 'thinking'
			$label = 'thinking...'
		} elseif ($label -match '(?i)work') {
			$mode = 'working'
			$label = 'working...'
		} else {
			$mode = 'ready'
			$label = 'ready'
		}
		$cur.StatusMode = $mode
		$cur.StatusLabel = $label
		# Apply sticky status immediately
		try {
			$prev = [string]$script:MB.Wpf.StatusMode
			$script:MB.Wpf.StatusMode = $mode
			$script:MB.Wpf.StatusLabel = $label
			$busy = ($mode -eq 'thinking' -or $mode -eq 'working' -or $mode -eq 'compacting')
			$wasBusy = ($prev -eq 'thinking' -or $prev -eq 'working' -or $prev -eq 'compacting')
			if ($busy -and (-not $wasBusy -or $prev -ne $mode)) {
				$script:MB.Wpf.StatusBusySince = [Environment]::TickCount
			} elseif (-not $busy) {
				$script:MB.Wpf.StatusBusySince = 0
			}
		} catch {}
	}
	if ($PSBoundParameters.ContainsKey('CtxPct')) { $cur.CtxPct = [double]$CtxPct }
	if ($PSBoundParameters.ContainsKey('CtxColor')) { $cur.CtxColor = [string]$CtxColor }
	if ($PSBoundParameters.ContainsKey('CtxPctText')) { $cur.CtxPctText = ConvertTo-MBWpfSafeText -Text $CtxPctText }
	if ($PSBoundParameters.ContainsKey('CtxTokText')) { $cur.CtxTokText = ConvertTo-MBWpfSafeText -Text $CtxTokText }
	$script:MB.Wpf.PendingSticky = $cur
}

function Sync-MBAutoApproveFromWpf {
	# Sync auto-approve from UI toggle
	if (-not $script:MB.Wpf) { return }
	try {
		if ([bool]$script:MB.Wpf.AutoApproveDirty) {
			$script:MB.AutoApprove = [bool]$script:MB.Wpf.AutoApproveOn
			$script:MB.Wpf.AutoApproveDirty = $false
		} else {
			$script:MB.Wpf.AutoApproveOn = [bool]$script:MB.AutoApprove
		}
	} catch {
		try { $script:MB.Wpf.AutoApproveOn = [bool]$script:MB.AutoApprove } catch {}
	}
	try { Sync-MBCwdFromWpf } catch {}
}

function Sync-MBAutoCompactFromWpf {
	# Sync AutoCompact from UI toggle
	if (-not $script:MB.Wpf) { return }
	try {
		if ([bool]$script:MB.Wpf.AutoCompactDirty) {
			$script:MB.AutoCompact = [bool]$script:MB.Wpf.AutoCompactOn
			$script:MB.Wpf.AutoCompactDirty = $false
		} else {
			$script:MB.Wpf.AutoCompactOn = [bool]$script:MB.AutoCompact
		}
	} catch {
		try { $script:MB.Wpf.AutoCompactOn = [bool]$script:MB.AutoCompact } catch {}
	}
}

function Get-MBWpfLowerRightText {
	try { Sync-MBAutoApproveFromWpf } catch {}
	try { Sync-MBAutoCompactFromWpf } catch {}
	try { Sync-MBActiveModelFromWpf } catch {}
	try {
		if ($script:MB.Wpf -and [bool]$script:MB.Wpf.RemoteModelsRefreshWanted) {
			$script:MB.Wpf.RemoteModelsRefreshWanted = $false
			$null = Refresh-MBRemoteModels -Force
			try { Update-MBWpfWindowTitle } catch {}
		}
	} catch {}
	$dot = [string][char]0x00B7
	$parts = New-Object System.Collections.ArrayList
	$n = 0
	try { $n = [int]$script:MB.CompactionCount } catch { $n = 0 }
	# Compaction count chip
	if ($n -gt 0) {
		[void]$parts.Add(("x{0}" -f $n))
	}
	$acOn = [bool]$script:MB.AutoCompact
	[void]$parts.Add($(if ($acOn) { 'auto-compact: ON' } else { 'auto-compact: OFF' }))
	$autoOn = [bool]$script:MB.AutoApprove
	[void]$parts.Add($(if ($autoOn) { 'auto-approve: ON' } else { 'auto-approve: OFF' }))
	[void]$parts.Add(("tools used {0}" -f [int]$script:MB.ToolCalls))
	return ($parts -join ("  {0}  " -f $dot))
}

function Get-MBWpfAutoCompactLine {
	# AutoCompact status text
	if ($script:MB.AutoCompact) { return 'AutoCompact: ON' }
	return 'AutoCompact: OFF'
}

function Update-MBWpfWindowTitle {
	# Update custom titlebar brand, path, and model picker label
	if (-not (Test-MBWpfActive)) { return }
	$W = $script:MB.Wpf
	if (-not $W) { return }
	try {
		$agent = if ($AgentName) { [string]$AgentName } else { 'MiniBot' }
		$brand = "[{0}-Agent]" -f $agent
		$path = ''
		try { $path = Get-MBShortPath -Path $script:MB.WorkingDir -MaxLen 56 } catch { $path = [string]$script:MB.WorkingDir }
		$active = ''
		try { $active = Get-MBActiveModel } catch { $active = '' }
		$powered = ''
		if (-not [string]::IsNullOrWhiteSpace($active)) {
			$powered = ("PoweredBy: {0}" -f $active.Trim())
		} else {
			$powered = 'PoweredBy: Select Model'
		}
		$dot = [string][char]0x00B7
		$parts = New-Object System.Collections.ArrayList
		[void]$parts.Add($brand)
		if (-not [string]::IsNullOrWhiteSpace($path)) { [void]$parts.Add($path) }
		if ($powered) { [void]$parts.Add($powered) }
		$W.PendingWindowTitle = ($parts -join ("  {0}  " -f $dot))
		$W.PendingTitleBrand = $brand
		$W.PendingTitleBrandName = $agent
		$W.PendingTitlePath = $(if ($path) { [string]$path } else { '' })
		$W.PendingTitlePoweredBy = $powered
		try { $W.ActiveModel = [string]$script:MB.ActiveModel } catch {}
		try { $W.RemoteModels = @($script:MB.RemoteModels) } catch {}
		try { $W.CurrentCwd = [string]$script:MB.WorkingDir } catch {}
	} catch {}
}

function Sync-MBCwdFromWpf {
	# Apply cwd from titlebar popup
	if (-not $script:MB.Wpf) { return }
	try {
		if (-not [bool]$script:MB.Wpf.CwdDirty) { return }
		$p = [string]$script:MB.Wpf.PendingCwd
		$script:MB.Wpf.CwdDirty = $false
		if ([string]::IsNullOrWhiteSpace($p)) { return }
		$p = $p.Trim().Trim('"')
		if (-not [System.IO.Directory]::Exists($p)) {
			try {
				if ($script:MB.Wpf.WriteQueue) {
					$script:MB.Wpf.WriteQueue.Enqueue([pscustomobject]@{
						Kind = 'text'; Text = ("`n  Folder not found: {0}`n" -f $p); Color = 'Yellow'; NoNewline = $false
						Brand = $(try { [string]$AgentName } catch { 'MiniBot' })
					})
				}
			} catch {}
			return
		}
		$full = [System.IO.Path]::GetFullPath($p)
		$script:MB.WorkingDir = $full
		try { Set-Location -LiteralPath $full } catch {}
		try { $script:MB.Wpf.CurrentCwd = $full } catch {}
		try {
			if ($script:MB.Wpf.WriteQueue) {
				$script:MB.Wpf.WriteQueue.Enqueue([pscustomobject]@{
					Kind = 'text'; Text = ("`n  WORKING_DIR: {0}`n" -f $full); Color = 'Green'; NoNewline = $false
					Brand = $(try { [string]$AgentName } catch { 'MiniBot' })
				})
			}
		} catch {}
		try { Update-MBWpfWindowTitle } catch {}
		try { Refresh-MBWpfStickyFromSession } catch {}
	} catch {
		try { $script:MB.Wpf.CwdDirty = $false } catch {}
	}
}

function Update-MBWpfLiveChrome {
	param(
		[switch]$Force
	)
	if (-not (Test-MBWpfActive)) { return }
	try {
		try { Sync-MBCwdFromWpf } catch {}
		if ($script:MB.Wpf.NeedPathBudgetRefresh) {
			$script:MB.Wpf.NeedPathBudgetRefresh = $false
			try { Refresh-MBWpfStickyFromSession } catch {}
		}
		try { Update-MBWpfWindowTitle } catch {}
		$now = [Environment]::TickCount
		$last = 0
		try { $last = [int]$script:MB.WpfLiveChromeTick } catch { $last = 0 }
		$doCtx = $Force -or ($last -eq 0) -or ((($now - $last) -band 0x7fffffff) -ge 120)
		$right = Get-MBWpfLowerRightText
		if (-not $doCtx) {
			Update-MBWpfSticky -Right $right
			return
		}
		$script:MB.WpfLiveChromeTick = $now
		$est = Get-MBContextEstimate -Messages @($script:Messages)
		$pctStr = ('{0,3:P0}' -f $est.Pct).Trim()
		$tokStr = '{0:N0}/{1:N0}' -f $est.PromptTokens, $est.UsableTokens
		$ctxHex = Get-MBWpfCtxBarColor -Level $est.Level
		Update-MBWpfSticky -Right $right `
			-CtxPct ([double]$est.Pct) -CtxColor $ctxHex -CtxPctText $pctStr -CtxTokText $tokStr
	} catch {}
}

function Refresh-MBWpfStickyFromSession {
	param([string]$Hint = '')
	if (-not (Test-MBWpfActive)) { return }
	try {
		$est = Get-MBContextEstimate -Messages @($script:Messages)
		$dot = [string][char]0x00B7  # middot separator
		$pctStr = ('{0,3:P0}' -f $est.Pct).Trim()
		$tokStr = '{0:N0}/{1:N0}' -f $est.PromptTokens, $est.UsableTokens
		try { Update-MBWpfWindowTitle } catch {}
		$right = Get-MBWpfLowerRightText
		if (-not $Hint) {
			$Hint = "Enter send  {0}  Ctrl+Enter newline  {0}  Esc interrupt  {0}  /help" -f $dot
		}
		$st = if ($script:MB.IsCompacting) { 'auto-compacting' } `
			elseif ($script:MB.IsThinking) { 'thinking...' } `
			elseif ($script:MB.IsWorking) { 'working' } `
			else { 'ready' }
		$ctxHex = Get-MBWpfCtxBarColor -Level $est.Level
		Update-MBWpfSticky -Right $right -Hint $Hint -Status $st `
			-CtxPct ([double]$est.Pct) -CtxColor $ctxHex -CtxPctText $pctStr -CtxTokText $tokStr
		try { Update-MBWpfToolGroupBar } catch {}
		try { $script:MB.WpfLiveChromeTick = [Environment]::TickCount } catch {}
	} catch {}
}

function Set-MBWpfPromptEnabled {
	param(
		[bool]$Enabled,
		[switch]$Focus
	)
	if (-not (Test-MBWpfActive)) { return }
	$script:MB.Wpf.PromptArmed = [bool]$Enabled
	$script:MB.Wpf.PendingPromptEnabled = [bool]$Enabled
	if ($Enabled -and $Focus) {
		try { $script:MB.Wpf.PendingPromptFocus = $true } catch {}
	}
}

function Focus-MBWpfPrompt {
	if (-not (Test-MBWpfActive)) { return }
	try { if ([bool]$script:MB.Wpf.ModalUi) { return } } catch {}
	$promptRef = $null
	$winRef = $null
	$d = $null
	try { $promptRef = $script:MB.Wpf.Prompt } catch {}
	try { $winRef = $script:MB.Wpf.Window } catch {}
	try { $d = $script:MB.Wpf.Dispatcher } catch {}
	if (-not $promptRef -or -not $d) { return }

	try {
		$script:MB.Wpf.PromptArmed = $true
		$script:MB.Wpf.PendingPromptEnabled = $true
		$script:MB.Wpf.PendingPromptFocus = $false
	} catch {}

	$sb = {
		$p = $promptRef
		$w = $winRef
		if (-not $p) { return }
		try {
			try {
				if ([bool]$script:MB.Wpf.ModalUi) { return }
				if ([bool]$script:MB.Wpf.AuthActive) { return }
				if ($script:MB.Wpf.AuthOverlay -and $script:MB.Wpf.AuthOverlay.Visibility -eq [System.Windows.Visibility]::Visible) { return }
				if ($script:MB.Wpf.ConfirmOverlay -and $script:MB.Wpf.ConfirmOverlay.Visibility -eq [System.Windows.Visibility]::Visible) { return }
			} catch {}
			$p.IsEnabled = $true
			$p.Focusable = $true
			$p.IsReadOnly = $false
			try {
				if ($script:MB.Wpf.SyncSendBtn) { & $script:MB.Wpf.SyncSendBtn $true }
			} catch {}
			try {
				if ($w -and $w.WindowState -eq [System.Windows.WindowState]::Minimized) {
					$w.WindowState = [System.Windows.WindowState]::Normal
				}
				if ($w) { [void]$w.Activate() }
			} catch {}
			try { [void]$p.Focus() } catch {}
			try { [void][System.Windows.Input.Keyboard]::Focus($p) } catch {}
			try {
				if ($null -ne $p.Text) { $p.CaretIndex = $p.Text.Length }
				else { $p.CaretIndex = 0 }
			} catch {}
		} catch {}
	}.GetNewClosure()

	try {
		if ($d.CheckAccess()) { & $sb }
		else { [void]$d.Invoke([Action]$sb, [System.Windows.Threading.DispatcherPriority]::Send) }
	} catch {
		try { Invoke-MBWpf -Action $sb } catch {}
	}
}

function Read-MBWpfUserInput {
	try {
		Write-MBDebugLog -Step 'READ_WPF_INPUT_BEGIN'
		if (-not (Test-MBWpfActive)) {
			Write-MBDebugLog -Step 'READ_WPF_INPUT_NOT_ACTIVE'
			return ""
		}
		try { Refresh-MBWpfStickyFromSession -Hint ("enter send  {0}  Ctrl+Enter newline  {0}  Esc interrupt  {0}  /help" -f ([char]0x00B7)) } catch {}
		Set-MBWpfPromptEnabled -Enabled $true -Focus
		try { Focus-MBWpfPrompt } catch {}
		Write-MBDebugLog -Step 'READ_WPF_INPUT_ARMED'
		$script:MB.Wpf.InputResult = $null
		$script:MB.Wpf.InterruptFlag = $false
		try { [void]$script:MB.Wpf.InputWait.Reset() } catch {}
		$script:MB.Wpf.InputResult = $null
		try {
			while ($true) {
				if ($script:MB.Wpf.ExitRequested) {
					Write-MBDebugLog -Step 'READ_WPF_INPUT_EXIT_REQUESTED'
					return [string][char]0x1B + 'WPF_CLOSE'
				}
				if ($script:MB.Wpf.InterruptFlag) {
					$script:MB.Wpf.InterruptFlag = $false
					$script:MB.Interrupt = $true
					Write-MBDebugLog -Step 'READ_WPF_INPUT_INTERRUPT_FLAG'
				}
				$signaled = $false
				try { $signaled = $script:MB.Wpf.InputWait.WaitOne(20) } catch { $signaled = $false }
				try { Sync-MBCwdFromWpf } catch {}
				# Apply PoweredBy model switch / Add-endpoint while idle (do not wait for next typed line)
				try { Sync-MBActiveModelFromWpf } catch {}
				try {
					if ($script:MB.Wpf -and [bool]$script:MB.Wpf.RemoteModelsRefreshWanted) {
						$script:MB.Wpf.RemoteModelsRefreshWanted = $false
						$null = Refresh-MBRemoteModels -Force
						try { Update-MBWpfWindowTitle } catch {}
					}
				} catch {}
				if ($signaled) {
					if ($script:MB.Wpf.ExitRequested) {
						Write-MBDebugLog -Step 'READ_WPF_INPUT_EXIT_AFTER_SIGNAL'
						return [string][char]0x1B + 'WPF_CLOSE'
					}
					$r = [string]$script:MB.Wpf.InputResult
					$script:MB.Wpf.InputResult = $null
					Write-MBDebugLog -Step 'READ_WPF_INPUT_RECEIVED' -Detail ("len={0}" -f $(if ($null -eq $r) { -1 } else { $r.Length }))
					Set-MBWpfPromptEnabled -Enabled $false
					try {
						Refresh-MBWpfStickyFromSession -Hint ("esc interrupt  {0}  model working..." -f ([char]0x00B7))
					} catch {}
					Write-MBDebugLog -Step 'READ_WPF_INPUT_RETURN'
					return $r
				}
			}
		} finally {
			try { Set-MBWpfPromptEnabled -Enabled $false } catch {}
			Write-MBDebugLog -Step 'READ_WPF_INPUT_FINALLY'
		}
	} catch {
		Write-MBDebugLog -Step 'READ_WPF_INPUT_ERROR' -Detail $_.Exception.Message
		Show-MBWpfError -Title 'Prompt error' -Message 'Failed while waiting for input.' -Exception $_.Exception
		return ""
	}
}

function Restore-MBWpfStickyAfterApproval {
	if (-not (Test-MBWpfActive)) { return }
	$dot = [string][char]0x00B7
	try {
		if ($script:MB.IsCompacting) {
			Refresh-MBWpfStickyFromSession -Hint ("esc interrupt  {0}  auto-compacting..." -f $dot)
			Update-MBWpfSticky -Status 'compacting'
		} elseif ($script:MB.IsThinking) {
			Refresh-MBWpfStickyFromSession -Hint ("esc interrupt  {0}  model thinking..." -f $dot)
			Update-MBWpfSticky -Status 'thinking'
		} elseif ($script:MB.IsWorking) {
			Refresh-MBWpfStickyFromSession -Hint ("esc interrupt  {0}  model working..." -f $dot)
			Update-MBWpfSticky -Status 'working'
		} else {
			Refresh-MBWpfStickyFromSession
			Update-MBWpfSticky -Status 'ready'
		}
	} catch {
		try { Refresh-MBWpfStickyFromSession } catch {}
	}
}

function Request-MBWpfConfirmation {
	param(
		[string]$Title,
		[string]$Details = "",
		[string]$Code = "",
		[string]$CodeLang = "ps"
	)
	if (-not (Test-MBWpfActive)) { return $null }
	Write-MBWpfRaw -Text "" -Color DarkGray
	Write-MBWpfApprovalBanner -Label 'approval'
	Write-MBWpfRaw -Text "" -Color DarkGray
	if (-not [string]::IsNullOrWhiteSpace($Title)) {
		Write-MBWpfRaw -Text ("  {0}" -f $Title) -Color White
	}
	if ($Details) {
		foreach ($line in ($Details -split "`r?`n")) {
			if ([string]::IsNullOrWhiteSpace($line)) {
				Write-MBWpfRaw -Text "" -Color DarkGray
			} else {
				Write-MBWpfRaw -Text ("  {0}" -f $line) -Color DarkGray
			}
		}
	}
	if (-not [string]::IsNullOrWhiteSpace($Code)) {
		$lang = ([string]$CodeLang).Trim()
		if ([string]::IsNullOrWhiteSpace($lang)) { $lang = 'ps' }
		$codeText = [string]$Code
		$codeText = $codeText -replace "`r`n", "`n" -replace "`r", "`n"
		Write-MBWpfSynText -Text $codeText -Lang $lang
	}
	Write-MBWpfRaw -Text "" -Color DarkGray
	Write-MBWpfApprovalButtons
	Write-MBWpfRaw -Text "" -Color DarkGray
	Update-MBWpfSticky -Hint "approval: Y / N / A  (buttons or keyboard)"
	Set-MBWpfPromptEnabled -Enabled $true -Focus
	try { Focus-MBWpfPrompt } catch {}
	$script:MB.Wpf.InputResult = $null
	try {
		while ($true) {
			if ($script:MB.Wpf.ExitRequested) { return $false }
			try { Sync-MBActiveModelFromWpf } catch {}
			if ($script:MB.Wpf.InputWait.WaitOne(20)) {
				$c = ([string]$script:MB.Wpf.InputResult).Trim().ToLowerInvariant()
				$script:MB.Wpf.InputResult = $null
				Set-MBWpfPromptEnabled -Enabled $false
				try { Disable-MBWpfActiveApprovalButtons } catch {}
				switch -Regex ($c) {
					'^(y|yes)$' { $script:MB.ApprovalsGranted++; return $true }
					'^(n|no)$'  { $script:MB.ApprovalsDenied++; return $false }
					'^(a|all|yes to all|yestoall)$' {
						$script:MB.AutoApprove = $true
						try {
							if ($script:MB.Wpf) {
								$script:MB.Wpf.AutoApproveOn = $true
								$script:MB.Wpf.AutoApproveDirty = $false
								$script:MB.Wpf.LowerRightSig = ''
							}
						} catch {}
						$script:MB.ApprovalsGranted++
						$script:MB.ModeSwitch = $true
						Write-MBWpfRaw -Text "  Auto-Approve ENABLED for this session." -Color Green
						try { Update-MBWpfLiveChrome -Force } catch {}
						return $true
					}
					default {
						Write-MBWpfRaw -Text "  Enter Y, N, or A - or use the buttons." -Color Yellow
						Write-MBWpfApprovalButtons
						Set-MBWpfPromptEnabled -Enabled $true -Focus
						try { Focus-MBWpfPrompt } catch {}
					}
				}
			}
		}
	} finally {
		try { Disable-MBWpfActiveApprovalButtons } catch {}
		try { Set-MBWpfPromptEnabled -Enabled $false } catch {}
		try { Restore-MBWpfStickyAfterApproval } catch {}
	}
}

function Ensure-MBConNative {
	try {
		if (-not ('MiniBot.WpfNative.MBCon' -as [type])) {
			Add-Type -MemberDefinition @"
[DllImport("kernel32.dll")] public static extern IntPtr GetConsoleWindow();
[DllImport("kernel32.dll")] public static extern uint GetCurrentThreadId();
[DllImport("user32.dll")] public static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);
[DllImport("user32.dll")] public static extern bool SetForegroundWindow(IntPtr hWnd);
[DllImport("user32.dll")] public static extern bool BringWindowToTop(IntPtr hWnd);
[DllImport("user32.dll")] public static extern bool IsWindow(IntPtr hWnd);
[DllImport("user32.dll")] public static extern IntPtr GetForegroundWindow();
[DllImport("user32.dll")] public static extern uint GetWindowThreadProcessId(IntPtr hWnd, out uint lpdwProcessId);
[DllImport("user32.dll")] public static extern bool AttachThreadInput(uint idAttach, uint idAttachTo, bool fAttach);
[DllImport("user32.dll")] public static extern bool AllowSetForegroundWindow(int dwProcessId);
[DllImport("user32.dll")] public static extern bool SetWindowPos(IntPtr hWnd, IntPtr hWndInsertAfter, int X, int Y, int cx, int cy, uint uFlags);
"@ -Name 'MBCon' -Namespace 'MiniBot.WpfNative' -ErrorAction Stop
		}
	} catch {}
}

function Hide-MBNativeConsole {
	# No-op when -HideConsole:$false (or default flipped at top of script)
	try {
		if ($null -ne $script:MB_HideConsole -and -not [bool]$script:MB_HideConsole) { return }
	} catch {}
	try {
		Ensure-MBConNative
		$hwnd = [MiniBot.WpfNative.MBCon]::GetConsoleWindow()
		if ($hwnd -eq [IntPtr]::Zero) {
			try { $hwnd = [IntPtr]$script:MB_HiddenConsoleHwnd } catch { $hwnd = [IntPtr]::Zero }
		}
		if ($hwnd -ne [IntPtr]::Zero) {
			$script:MB_HiddenConsoleHwnd = $hwnd
			[void][MiniBot.WpfNative.MBCon]::ShowWindow($hwnd, 0)  # SW_HIDE
		}
	} catch {}
}

function Invoke-MBWpfBringToFront {
	param([switch]$StayTopmost)
	if (-not (Test-MBWpfActive)) { return }
	try { if ([bool]$script:MB.Wpf.ModalUi) { return } } catch {}
	try { Ensure-MBConNative } catch {}
	$keep = [bool]$StayTopmost
	try {
		if ($script:MB.Wpf) { $script:MB.Wpf.BootstrapTopmost = $keep }
	} catch {}
	$winRef = $null
	try { $winRef = $script:MB.Wpf.Window } catch { $winRef = $null }
	$d = $null
	try { $d = $script:MB.Wpf.Dispatcher } catch { $d = $null }
	if (-not $winRef -or -not $d) { return }

	# Build closure before [Action] so captured locals stick
	$sb = {
		$w = $winRef
		$keepTop = $keep
		if (-not $w) { return }
		try {
			try { if ([bool]$script:MB.Wpf.ModalUi) { return } } catch {}
			if ($w.WindowState -eq [System.Windows.WindowState]::Minimized) {
				$w.WindowState = [System.Windows.WindowState]::Normal
			}
			try { [void]$w.Show() } catch {}
			try {
				$w.Topmost = $false
				$w.Topmost = $true
			} catch { try { $w.Topmost = $true } catch {} }
			try { [void]$w.Activate() } catch {}
			try { [void]$w.Focus() } catch {}
			try {
				if ('MiniBot.WpfNative.MBCon' -as [type]) {
					$helper = New-Object System.Windows.Interop.WindowInteropHelper($w)
					$hwnd = $helper.Handle
					if ($hwnd -eq [IntPtr]::Zero) {
						try { $hwnd = $helper.EnsureHandle() } catch {}
					}
					if ($hwnd -ne [IntPtr]::Zero) {
						[void][MiniBot.WpfNative.MBCon]::ShowWindow($hwnd, 9)
						[void][MiniBot.WpfNative.MBCon]::BringWindowToTop($hwnd)
						try {
							$fg = [MiniBot.WpfNative.MBCon]::GetForegroundWindow()
							$dummy = [uint32]0
							$fgTid = [MiniBot.WpfNative.MBCon]::GetWindowThreadProcessId($fg, [ref]$dummy)
							$curTid = [MiniBot.WpfNative.MBCon]::GetCurrentThreadId()
							if ($fgTid -ne 0 -and $fgTid -ne $curTid) {
								[void][MiniBot.WpfNative.MBCon]::AttachThreadInput($curTid, $fgTid, $true)
								[void][MiniBot.WpfNative.MBCon]::SetForegroundWindow($hwnd)
								[void][MiniBot.WpfNative.MBCon]::AttachThreadInput($curTid, $fgTid, $false)
							} else {
								[void][MiniBot.WpfNative.MBCon]::SetForegroundWindow($hwnd)
							}
						} catch {
							try { [void][MiniBot.WpfNative.MBCon]::SetForegroundWindow($hwnd) } catch {}
						}
						try {
							[void][MiniBot.WpfNative.MBCon]::SetWindowPos($hwnd, [IntPtr](-1), 0, 0, 0, 0, ([uint32](0x0001 -bor 0x0002 -bor 0x0040)))
							if (-not $keepTop) {
								[void][MiniBot.WpfNative.MBCon]::SetWindowPos($hwnd, [IntPtr](-2), 0, 0, 0, 0, ([uint32](0x0001 -bor 0x0002 -bor 0x0040)))
							}
						} catch {}
					}
				}
			} catch {}
			if (-not $keepTop) {
				try {
					$w.Topmost = $true
					$w.Topmost = $false
				} catch { try { $w.Topmost = $false } catch {} }
				try { [void]$w.Activate() } catch {}
			}
		} catch {}
	}.GetNewClosure()
	$act = [Action]$sb

	try {
		if ($d.CheckAccess()) { & $sb }
		else { [void]$d.Invoke($act, [System.Windows.Threading.DispatcherPriority]::Send) }
	} catch {
		try { Invoke-MBWpf -Action $sb } catch {}
	}
}

function Clear-MBWpfBootstrapTopmost {
	if (-not (Test-MBWpfActive)) { return }
	try {
		if ($script:MB.Wpf) { $script:MB.Wpf.BootstrapTopmost = $false }
	} catch {}
	try { Ensure-MBConNative } catch {}
	$winRef = $null
	try { $winRef = $script:MB.Wpf.Window } catch { $winRef = $null }
	$d = $null
	try { $d = $script:MB.Wpf.Dispatcher } catch { $d = $null }
	if (-not $winRef -or -not $d) { return }

	$sb = {
		$w = $winRef
		if (-not $w) { return }
		try {
			$w.Topmost = $true
			$w.Topmost = $false
			$w.Topmost = $false
		} catch {
			try { $w.Topmost = $false } catch {}
		}
		try {
			if ('MiniBot.WpfNative.MBCon' -as [type]) {
				$helper = New-Object System.Windows.Interop.WindowInteropHelper($w)
				$hwnd = $helper.Handle
				if ($hwnd -ne [IntPtr]::Zero) {
					[void][MiniBot.WpfNative.MBCon]::SetWindowPos(
						$hwnd, [IntPtr](-2), 0, 0, 0, 0,
						([uint32](0x0001 -bor 0x0002 -bor 0x0040))
					)
				}
			}
		} catch {}
	}.GetNewClosure()
	$act = [Action]$sb

	try {
		if ($d.CheckAccess()) { & $sb }
		else { [void]$d.Invoke($act, [System.Windows.Threading.DispatcherPriority]::Send) }
	} catch {
		try { Invoke-MBWpf -Action $sb } catch {}
	}

	try {
		$sb2 = {
			try {
				$w2 = $winRef
				if (-not $w2) { return }
				if ($w2.Topmost) {
					$w2.Topmost = $true
					$w2.Topmost = $false
				}
				try {
					if ('MiniBot.WpfNative.MBCon' -as [type]) {
						$helper = New-Object System.Windows.Interop.WindowInteropHelper($w2)
						$hwnd = $helper.Handle
						if ($hwnd -ne [IntPtr]::Zero) {
							[void][MiniBot.WpfNative.MBCon]::SetWindowPos(
								$hwnd, [IntPtr](-2), 0, 0, 0, 0,
								([uint32](0x0001 -bor 0x0002 -bor 0x0040))
							)
						}
					}
				} catch {}
			} catch {}
		}.GetNewClosure()
		[void]$d.BeginInvoke([System.Windows.Threading.DispatcherPriority]::ApplicationIdle, [Action]$sb2)
	} catch {}
}


function Start-MBWpfHost {
	if ($script:MB.Wpf -and $script:MB.Wpf.Ready) { return $true }

	if (-not (Test-MBWpfDotNetReady)) {
		try {
			$dotnetchecker = New-Object -ComObject Wscript.Shell
			$dotnetchecker.Popup(
				"dotNET 3.0 or higher is required for the MiniBot WPF host.",
				0,
				'MiniBot WPF',
				0x0
			) | Out-Null
		} catch {}
		Write-Warning "WPF requires .NET Framework 3.0+; not starting WPF host."
		return $false
	}

	if (-not (Test-MBWpfAvailable)) { return $false }

	# Shared state for UI and agent runspaces
	$wpf = [hashtable]::Synchronized(@{
		Ready         = $false
		Failed        = $false
		FailMsg       = ''
		Dispatcher    = $null
		Window        = $null
		Log           = $null
		Prompt        = $null
		HdrLine1      = $null
		HdrLine1Shadow = $null
		HdrLine2      = $null
		HdrLine2Shadow = $null
		HdrToolGroups = $null
		ToolGroupsFp  = ''
		ToolGroupsBuilt = $false
		ToolGroupsDirty = $true
		ToolGroupsData  = $null
		HdrPoweredBy  = $null
		HdrPoweredByShadow = $null
		HdrPoweredByHost = $null
		HdrAutoCompact = $null
		HdrAutoCompactShadow = $null
		HdrLeft       = $null
		HdrCenter     = $null
		HdrRight      = $null
		HintBar       = $null
		HintBarBorder = $null
		StatusDot     = $null
		LowerCenter   = $null
		LowerRight    = $null
		CtxBarFill    = $null
		CtxPctText    = $null
		CtxTokText    = $null
		CtxBarMaxW    = 120
		MonoFont      = $null
		EmojiFont     = $null
		LogMaxLineChars = 0
		LogLineCharRun  = 0   # chars on the current (open) paragraph
		LogWordWrap     = $true
		WordWrapToggle  = $null
		ReplyStartBlock = -1
		ActiveCodeBox   = $null
		ActiveCodeBorder = $null
		StatusMode    = 'ready'     # ready | thinking | working | compacting
		StatusLabel   = 'ready'
		SpinIdx       = 0
		SpinLastTick  = 0
		StatusBusySince = 0         # Environment.TickCount when busy mode started
		StatusTimer   = $null       # TextBlock for elapsed seconds
		InputWait     = New-Object System.Threading.AutoResetEvent $false
		InputResult   = $null
		PromptArmed   = $false
		ExitRequested = $false
		# all exits hard-kill the process (single-instance lock)
		SoftClose     = $false
		CloseKind     = ''          # always treated as user_x on close
		ForceProcessExit = $false
		AuthActive    = $false      # true while login overlay is visible (blocks prompt focus)
		AuthFocusTicks = 0          # re-apply username focus for a few timer frames
		AuthNeedActivate = $false   # keep forcing OS foreground until window is active
		BootstrapTopmost = $true    # Topmost until main screen loads; then cleared
		ModalUi       = $false      # true while file picker / modal blocks Activate steals
		History       = [System.Collections.ArrayList]::Synchronized((New-Object System.Collections.ArrayList))
		HistIndex     = -1
		ReadyWait     = New-Object System.Threading.ManualResetEvent $false
		InterruptFlag = $false
		SendBtn       = $null
		SendMode      = 'send'      # send | stop
		AgentName     = [string]$AgentName
		Version       = [string]$Version
		ModelAlias    = $(try { [string]$ModelAlias } catch { '' })
		ActiveModel   = $(try { [string]$script:MB.ActiveModel } catch { try { [string]$Model } catch { '' } })
		ActiveModelBase = $(try { [string]$script:MB.ActiveModelBase } catch { '' })
		ActiveModelKey = $(try { [string]$script:MB.ActiveModelKey } catch { '' })
		RemoteModels  = $(try { @($script:MB.RemoteModels) } catch { @() })
		RemoteModelEntries = $(try { @($script:MB.RemoteModelEntries) } catch { @() })
		ExtraApiBases = $(try { @($script:MB.ExtraApiBases) } catch { @() })
		ExtraApiKeys = $(try { if ($script:MB.ExtraApiKeys -is [hashtable]) { $script:MB.ExtraApiKeys } else { @{} } } catch { @{} })
		ExtraApiAuth = $(try { if ($script:MB.ExtraApiAuth -is [hashtable]) { $script:MB.ExtraApiAuth } else { @{} } } catch { @{} })
		NpmUser = $(try { [string]$script:MB.NpmUser } catch { '' })
		NpmPass = $(try { [string]$script:MB.NpmPass } catch { '' })
		RemoteModelsSeq = 0
		RemoteModelsSeqApplied = 0
		RemoteModelsRefreshWanted = $false
		PendingAddBaseUrl = ''
		PendingAddBaseApiKey = ''
		PendingAddBaseAuthMode = 'apikey'
		PendingAddBaseDirty = $false
		PendingAddBaseResult = $null
		ModelDirty    = $false
		ModelPickerUpdating = $false
		AutoCompactOn = $(try { [bool]$script:MB.AutoCompact } catch { $true })
		AutoApproveOn = $(try { [bool]$script:MB.AutoApprove } catch { $false })
		AutoApproveDirty = $false
		AutoCompactDirty = $false
		PendingUiCommand = $null
		PendingWindowTitle = $null
		CurrentCwd    = $(try { [string]$script:MB.WorkingDir } catch { '' })
		PendingCwd    = ''
		CwdDirty      = $false
		CwdPopup      = $null
		LowerRightSig = ''
		Ps            = $null
		Runspace      = $null
		WriteQueue    = New-Object 'System.Collections.Concurrent.ConcurrentQueue[object]'
		PendingSticky = $null
		PendingPromptEnabled = $null
		PendingPromptFocus = $false   # true => focus PromptBox when arming
		ActiveApprovalHost = $null    # inline Yes/No/All button strip in log
		NeedPathBudgetRefresh = $false
		LastPathBudgetTick = 0
		BrushCache    = @{}
		MdStretchElements = New-Object System.Collections.ArrayList
		CredWait      = New-Object System.Threading.ManualResetEvent $false
		CredResult    = $null
		AuthOverlay   = $null
		AuthUser      = $null
		AuthPass      = $null
		AuthError     = $null
		AuthTitle     = $null
		AuthSubtitle  = $null
		AuthOk        = $null
		AuthCancel    = $null
		AuthSaveCreds = $null
		ConfirmWait   = New-Object System.Threading.ManualResetEvent $false
		ConfirmResult = $null
		ConfirmOverlay = $null
		ConfirmTitle  = $null
		ConfirmPrompt = $null
		ConfirmYes    = $null
		ConfirmNo     = $null
		ConfirmAccentBar = $null
		SessionPickerWait = New-Object System.Threading.ManualResetEvent $false
		SessionPickerResult = $null
		SessionPickerMode = 'Open'
		SessionPickerRows = $null
		SessionPickerReload = $null
		SessionPickerOverlay = $null
		InitStoreCreds = $false
		DebugLogPath  = (Get-MBDebugLogPath)
		DebugLogEnabled = [bool]$(try { [bool]$script:MB.DebugLogEnabled } catch { $false })
	})
	$script:MB.Wpf = $wpf
	# Default OSD volume (0–1); STA AddScript / StartInline read this from the bag
	try { $wpf['VideoDefaultVolume'] = 1.0 } catch {}
	# Fresh-bind video helpers as UNBOUND scriptblocks + source text for STA rebuild
	try {
		Set-MBVideoScriptGlobals | Out-Null
		Register-MBVideoApi | Out-Null
		$apiV = $null
		try { $apiV = $global:MB_VideoApi } catch {}
		if ($null -ne $apiV) {
			if ($null -ne $apiV['StartInline']) { $wpf['VideoStartInline'] = $apiV['StartInline'] }
			if ($null -ne $apiV['StopInline']) { $wpf['VideoStopInline'] = $apiV['StopInline'] }
			if ($null -ne $apiV['Toggle']) { $wpf['VideoToggle'] = $apiV['Toggle'] }
			if ($null -ne $apiV['PopOut']) { $wpf['VideoPopOut'] = $apiV['PopOut'] }
			if ($null -ne $apiV['Resolve']) { $wpf['VideoResolve'] = $apiV['Resolve'] }
			$wpf['VideoApi'] = $apiV
		}
		# Source text — STA AddScript re-[scriptblock]::Create these so New-Object works there
		if ($global:MB_Video_StartInlineText) { $wpf['VideoStartInlineText'] = $global:MB_Video_StartInlineText }
		if ($global:MB_Video_StopInlineText) { $wpf['VideoStopInlineText'] = $global:MB_Video_StopInlineText }
		if ($global:MB_Video_ToggleText) { $wpf['VideoToggleText'] = $global:MB_Video_ToggleText }
		if ($global:MB_Video_PopOutText) { $wpf['VideoPopOutText'] = $global:MB_Video_PopOutText }
		if ($global:MB_Video_ResolveText) { $wpf['VideoResolveText'] = $global:MB_Video_ResolveText }
	} catch {}
	# Shared robot path catalog for UI runspace
	try {
		$wpf.RobotCatalog = Get-MBRobotPathCatalog
		$wpf.RobotGeomCache = @{}
		$wpf.RobotMood = ''
		$wpf.SetRobotMood = $null
	} catch {}
	try { Write-MBDebugLog -Step 'WPF_HOST_STARTING' -Detail $wpf.DebugLogPath } catch {}

	$rs = [System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspace()
	$rs.ApartmentState = [System.Threading.ApartmentState]::STA
	$rs.ThreadOptions = [System.Management.Automation.Runspaces.PSThreadOptions]::ReuseThread
	$rs.Open()
	$ps = [PowerShell]::Create()
	$ps.Runspace = $rs
	$wpf.Runspace = $rs
	$wpf.Ps = $ps

	[void]$ps.AddScript({
		param($W)
		try {
			Add-Type -AssemblyName PresentationFramework
			Add-Type -AssemblyName PresentationCore
			Add-Type -AssemblyName WindowsBase
			Add-Type -AssemblyName System.Xaml

			# Rebuild video Start/Stop/etc in THIS STA runspace (unbound). Bag scriptblocks from
			# the main runspace lose New-Object/Test-Path; Create() here fixes that.
			try {
				if ($W -is [hashtable]) {
					if (-not $W.ContainsKey('VideoDefaultVolume') -or $null -eq $W['VideoDefaultVolume']) {
						$W['VideoDefaultVolume'] = 1.0
					}
					foreach ($pair in @(
						@{ T = 'VideoStartInlineText'; K = 'VideoStartInline' },
						@{ T = 'VideoStopInlineText';  K = 'VideoStopInline' },
						@{ T = 'VideoToggleText';      K = 'VideoToggle' },
						@{ T = 'VideoPopOutText';      K = 'VideoPopOut' },
						@{ T = 'VideoResolveText';     K = 'VideoResolve' }
					)) {
						$txt = $W[$pair.T]
						if ([string]::IsNullOrWhiteSpace([string]$txt)) { continue }
						try {
							$W[$pair.K] = [scriptblock]::Create([string]$txt)
						} catch {}
					}
					try {
						if ($W['VideoApi'] -is [hashtable]) {
							if ($W['VideoStartInline']) { $W['VideoApi']['StartInline'] = $W['VideoStartInline'] }
							if ($W['VideoStopInline'])  { $W['VideoApi']['StopInline']  = $W['VideoStopInline'] }
							if ($W['VideoToggle'])      { $W['VideoApi']['Toggle']      = $W['VideoToggle'] }
							if ($W['VideoPopOut'])      { $W['VideoApi']['PopOut']      = $W['VideoPopOut'] }
							if ($W['VideoResolve'])     { $W['VideoApi']['Resolve']     = $W['VideoResolve'] }
						}
					} catch {}
				}
			} catch {}

			$xaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        xmlns:shell="clr-namespace:System.Windows.Shell;assembly=PresentationFramework"
        Title="MiniBot"
        Width="980" Height="640"
        MinWidth="640" MinHeight="400"
        WindowStartupLocation="CenterScreen"
        ShowActivated="True"
        Topmost="True"
        WindowStyle="None"
        ResizeMode="CanResize"
        AllowsTransparency="True"
        Background="Transparent"
        Foreground="#C8C8D0"
        FontFamily="Consolas, Cascadia Mono, Courier New"
        FontSize="13">
  <!-- Outer chrome radius -->
  <shell:WindowChrome.WindowChrome>
    <shell:WindowChrome CaptionHeight="36"
                        ResizeBorderThickness="6"
                        GlassFrameThickness="0"
                        CornerRadius="8,8,8,8"
                        UseAeroCaptionButtons="False"/>
  </shell:WindowChrome.WindowChrome>
  <Window.Resources>
    <!-- NoMouseOver button template -->
    <ControlTemplate x:Key="NoMouseOverButtonTemplate" TargetType="Button">
      <Border Background="{TemplateBinding Background}"
              BorderBrush="{TemplateBinding BorderBrush}"
              BorderThickness="{TemplateBinding BorderThickness}"
              Padding="{TemplateBinding Padding}"
              CornerRadius="4"
              SnapsToDevicePixels="True">
        <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/>
      </Border>
      <ControlTemplate.Triggers>
        <Trigger Property="IsEnabled" Value="False">
          <Setter Property="Opacity" Value="0.45"/>
        </Trigger>
      </ControlTemplate.Triggers>
    </ControlTemplate>
 <!-- Dark scrollbar -->
    <SolidColorBrush x:Key="MbScrollTrack" Color="#1A1A1E"/>
    <SolidColorBrush x:Key="MbScrollThumb" Color="#3A3A42"/>
    <SolidColorBrush x:Key="MbScrollThumbHover" Color="#52525C"/>
    <SolidColorBrush x:Key="MbScrollThumbDrag" Color="#6A6A76"/>
    <SolidColorBrush x:Key="MbScrollBtn" Color="#2A2A30"/>
    <Style x:Key="MbScrollBarThumb" TargetType="Thumb">
      <Setter Property="OverridesDefaultStyle" Value="True"/>
      <Setter Property="IsTabStop" Value="False"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="Thumb">
            <Border x:Name="Bd" Background="{StaticResource MbScrollThumb}" CornerRadius="3" Margin="1"/>
            <ControlTemplate.Triggers>
              <Trigger Property="IsMouseOver" Value="True">
                <Setter TargetName="Bd" Property="Background" Value="{StaticResource MbScrollThumbHover}"/>
              </Trigger>
              <Trigger Property="IsDragging" Value="True">
                <Setter TargetName="Bd" Property="Background" Value="{StaticResource MbScrollThumbDrag}"/>
              </Trigger>
            </ControlTemplate.Triggers>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
    <Style x:Key="MbScrollRepeat" TargetType="RepeatButton">
      <Setter Property="OverridesDefaultStyle" Value="True"/>
      <Setter Property="Focusable" Value="False"/>
      <Setter Property="IsTabStop" Value="False"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="RepeatButton">
            <Border Background="{StaticResource MbScrollTrack}"/>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
    <Style x:Key="MbDarkCheckBox" TargetType="CheckBox">
      <Setter Property="Foreground" Value="#C8C8D0"/>
      <Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Focusable" Value="False"/>
      <Setter Property="SnapsToDevicePixels" Value="True"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="CheckBox">
            <StackPanel Orientation="Horizontal" Background="Transparent">
              <Border x:Name="Box" Width="13" Height="13" Background="#121216"
                      BorderBrush="#52525C" BorderThickness="1" CornerRadius="2"
                      VerticalAlignment="Center" Margin="0,0,6,0">
                <Path x:Name="CheckMark" Data="M1.5,6.5 L4.8,10 L11.5,2.5"
                      Stroke="#9ECE6A" StrokeThickness="1.7" Visibility="Collapsed"
                      Stretch="None" HorizontalAlignment="Center" VerticalAlignment="Center"/>
              </Border>
              <ContentPresenter VerticalAlignment="Center" RecognizesAccessKey="True"/>
            </StackPanel>
            <ControlTemplate.Triggers>
              <Trigger Property="IsChecked" Value="True">
                <Setter TargetName="CheckMark" Property="Visibility" Value="Visible"/>
                <Setter TargetName="Box" Property="BorderBrush" Value="#6A6A76"/>
                <Setter TargetName="Box" Property="Background" Value="#1A1A1E"/>
              </Trigger>
              <Trigger Property="IsMouseOver" Value="True">
                <Setter TargetName="Box" Property="BorderBrush" Value="#8A8A96"/>
              </Trigger>
            </ControlTemplate.Triggers>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
    <!-- Login primary button -->
    <Style x:Key="MbAuthPrimaryBtn" TargetType="Button">
      <Setter Property="Background" Value="#4A4A56"/>
      <Setter Property="Foreground" Value="#E0E0E8"/>
      <Setter Property="BorderThickness" Value="0"/>
      <Setter Property="FontWeight" Value="Bold"/>
      <Setter Property="Cursor" Value="Hand"/>
      <Setter Property="SnapsToDevicePixels" Value="True"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="Button">
            <Border x:Name="Bd" Background="{TemplateBinding Background}"
                    CornerRadius="3" SnapsToDevicePixels="True">
              <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/>
            </Border>
            <ControlTemplate.Triggers>
              <Trigger Property="IsMouseOver" Value="True">
                <Setter TargetName="Bd" Property="Background" Value="#5C5C6A"/>
              </Trigger>
              <Trigger Property="IsPressed" Value="True">
                <Setter TargetName="Bd" Property="Background" Value="#3A3A48"/>
              </Trigger>
              <Trigger Property="IsEnabled" Value="False">
                <Setter TargetName="Bd" Property="Opacity" Value="0.5"/>
              </Trigger>
            </ControlTemplate.Triggers>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
    <!-- Login secondary button -->
    <Style x:Key="MbAuthSecondaryBtn" TargetType="Button">
      <Setter Property="Background" Value="#2A2A30"/>
      <Setter Property="Foreground" Value="#C8C8D0"/>
      <Setter Property="BorderBrush" Value="#3A3A42"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Cursor" Value="Hand"/>
      <Setter Property="SnapsToDevicePixels" Value="True"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="Button">
            <Border x:Name="Bd" Background="{TemplateBinding Background}"
                    BorderBrush="{TemplateBinding BorderBrush}"
                    BorderThickness="{TemplateBinding BorderThickness}"
                    CornerRadius="3" SnapsToDevicePixels="True">
              <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/>
            </Border>
            <ControlTemplate.Triggers>
              <Trigger Property="IsMouseOver" Value="True">
                <Setter TargetName="Bd" Property="Background" Value="#363640"/>
                <Setter TargetName="Bd" Property="BorderBrush" Value="#5A5A66"/>
              </Trigger>
              <Trigger Property="IsPressed" Value="True">
                <Setter TargetName="Bd" Property="Background" Value="#222228"/>
                <Setter TargetName="Bd" Property="BorderBrush" Value="#4A4A56"/>
              </Trigger>
            </ControlTemplate.Triggers>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
    <Style TargetType="ScrollBar">
      <Setter Property="Background" Value="{StaticResource MbScrollTrack}"/>
      <Setter Property="Foreground" Value="{StaticResource MbScrollThumb}"/>
      <Setter Property="Width" Value="12"/>
      <Setter Property="MinWidth" Value="12"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="ScrollBar">
            <Grid Background="{StaticResource MbScrollTrack}">
              <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="*"/>
                <RowDefinition Height="Auto"/>
              </Grid.RowDefinitions>
              <Border Grid.Row="0" Height="12" Background="{StaticResource MbScrollBtn}"/>
              <Track x:Name="PART_Track" Grid.Row="1" IsDirectionReversed="True">
                <Track.DecreaseRepeatButton>
                  <RepeatButton Command="ScrollBar.PageUpCommand" Style="{StaticResource MbScrollRepeat}"/>
                </Track.DecreaseRepeatButton>
                <Track.Thumb>
                  <Thumb Style="{StaticResource MbScrollBarThumb}"/>
                </Track.Thumb>
                <Track.IncreaseRepeatButton>
                  <RepeatButton Command="ScrollBar.PageDownCommand" Style="{StaticResource MbScrollRepeat}"/>
                </Track.IncreaseRepeatButton>
              </Track>
              <Border Grid.Row="2" Height="12" Background="{StaticResource MbScrollBtn}"/>
            </Grid>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
      <Style.Triggers>
        <Trigger Property="Orientation" Value="Horizontal">
          <Setter Property="Width" Value="Auto"/>
          <Setter Property="Height" Value="12"/>
          <Setter Property="MinHeight" Value="12"/>
          <Setter Property="Template">
            <Setter.Value>
              <ControlTemplate TargetType="ScrollBar">
                <Grid Background="{StaticResource MbScrollTrack}">
                  <Grid.ColumnDefinitions>
                    <ColumnDefinition Width="Auto"/>
                    <ColumnDefinition Width="*"/>
                    <ColumnDefinition Width="Auto"/>
                  </Grid.ColumnDefinitions>
                  <Border Grid.Column="0" Width="12" Background="{StaticResource MbScrollBtn}"/>
                  <Track x:Name="PART_Track" Grid.Column="1" IsDirectionReversed="False">
                    <Track.DecreaseRepeatButton>
                      <RepeatButton Command="ScrollBar.PageLeftCommand" Style="{StaticResource MbScrollRepeat}"/>
                    </Track.DecreaseRepeatButton>
                    <Track.Thumb>
                      <Thumb Style="{StaticResource MbScrollBarThumb}"/>
                    </Track.Thumb>
                    <Track.IncreaseRepeatButton>
                      <RepeatButton Command="ScrollBar.PageRightCommand" Style="{StaticResource MbScrollRepeat}"/>
                    </Track.IncreaseRepeatButton>
                  </Track>
                  <Border Grid.Column="2" Width="12" Background="{StaticResource MbScrollBtn}"/>
                </Grid>
              </ControlTemplate>
            </Setter.Value>
          </Setter>
        </Trigger>
      </Style.Triggers>
    </Style>
 <!-- Dark ScrollViewer -->
    <Style TargetType="ScrollViewer">
      <Setter Property="Background" Value="Transparent"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="ScrollViewer">
            <Grid Background="{TemplateBinding Background}">
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="*"/>
                <ColumnDefinition Width="Auto"/>
              </Grid.ColumnDefinitions>
              <Grid.RowDefinitions>
                <RowDefinition Height="*"/>
                <RowDefinition Height="Auto"/>
              </Grid.RowDefinitions>
              <ScrollContentPresenter Grid.Column="0" Grid.Row="0"
                                      Margin="{TemplateBinding Padding}"
                                      Content="{TemplateBinding Content}"
                                      ContentTemplate="{TemplateBinding ContentTemplate}"
                                      CanContentScroll="{TemplateBinding CanContentScroll}"/>
              <ScrollBar x:Name="PART_VerticalScrollBar" Grid.Column="1" Grid.Row="0"
                         Orientation="Vertical"
                         ViewportSize="{TemplateBinding ViewportHeight}"
                         Maximum="{TemplateBinding ScrollableHeight}"
                         Value="{TemplateBinding VerticalOffset}"
                         Visibility="{TemplateBinding ComputedVerticalScrollBarVisibility}"/>
              <ScrollBar x:Name="PART_HorizontalScrollBar" Grid.Column="0" Grid.Row="1"
                         Orientation="Horizontal"
                         ViewportSize="{TemplateBinding ViewportWidth}"
                         Maximum="{TemplateBinding ScrollableWidth}"
                         Value="{TemplateBinding HorizontalOffset}"
                         Visibility="{TemplateBinding ComputedHorizontalScrollBarVisibility}"/>
 <!-- Scrollbar corner -->
              <Rectangle Grid.Column="1" Grid.Row="1" Fill="{StaticResource MbScrollTrack}"/>
            </Grid>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
  </Window.Resources>
  <!-- WindowRoot: chrome + full-window overlays as SIBLINGS (not inside 2-row title/body grid). -->
  <Grid x:Name="WindowRoot">
  <!-- Outer rounded chrome: transparent window + CornerRadius border.
       ClipToBounds keeps content out of square corners; radius cleared when maximized. -->
  <Border x:Name="MainChromeBorder" BorderBrush="#2A2A30" BorderThickness="1" Background="#121216"
          CornerRadius="8" ClipToBounds="True" SnapsToDevicePixels="True">
    <Grid x:Name="RootOuter">
      <Grid.RowDefinitions>
        <RowDefinition Height="36"/>
        <RowDefinition Height="*"/>
      </Grid.RowDefinitions>
 <!-- Custom titlebar -->
      <Border x:Name="CustomTitleBar" Grid.Row="0" Background="#2A2A30" BorderBrush="#3A3A42"
              BorderThickness="0,0,0,1" Padding="10,0,0,0" CornerRadius="8,8,0,0"
              SnapsToDevicePixels="True">
        <Grid>
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
          </Grid.ColumnDefinitions>
          <StackPanel Grid.Column="0" Orientation="Horizontal" VerticalAlignment="Center" Margin="0,0,8,0">
            <!-- Titlebar robot -->
            <Grid x:Name="TitleRobotHost" Width="26" Height="26" Margin="4,0,0,0"
                  VerticalAlignment="Center" ToolTip="MiniBot"
                  shell:WindowChrome.IsHitTestVisibleInChrome="True">
              <Path x:Name="TitleRobotPath" Width="22" Height="22" Stretch="Uniform"
                    HorizontalAlignment="Center" VerticalAlignment="Center"
                    Data="M12,2A2,2 0 0,1 14,4C14,4.74 13.6,5.39 13,5.73V7H14A7,7 0 0,1 21,14H22A1,1 0 0,1 23,15V18A1,1 0 0,1 22,19H21V20A2,2 0 0,1 19,22H5A2,2 0 0,1 3,20V19H2A1,1 0 0,1 1,18V15A1,1 0 0,1 2,14H3A7,7 0 0,1 10,7H11V5.73C10.4,5.39 10,4.74 10,4A2,2 0 0,1 12,2M7.5,13A2.5,2.5 0 0,0 5,15.5A2.5,2.5 0 0,0 7.5,18A2.5,2.5 0 0,0 10,15.5A2.5,2.5 0 0,0 7.5,13M16.5,13A2.5,2.5 0 0,0 14,15.5A2.5,2.5 0 0,0 16.5,18A2.5,2.5 0 0,0 19,15.5A2.5,2.5 0 0,0 16.5,13Z">
                <Path.Fill>
                  <LinearGradientBrush StartPoint="0.15,0" EndPoint="0.9,1">
                    <GradientStop x:Name="TitleRobotStop0" Color="#C8C8D0" Offset="0"/>
                    <GradientStop x:Name="TitleRobotStop1" Color="#6A6A74" Offset="0.48"/>
                    <GradientStop x:Name="TitleRobotStop2" Color="#3A3A42" Offset="1"/>
                  </LinearGradientBrush>
                </Path.Fill>
                <Path.Effect>
                  <DropShadowEffect x:Name="TitleRobotShadow" Color="#000000" BlurRadius="3.5" ShadowDepth="1.25"
                                    Opacity="0.72" Direction="315"/>
                </Path.Effect>
                <Path.RenderTransform>
                  <TranslateTransform x:Name="TitleRobotTranslate" X="0" Y="0"/>
                </Path.RenderTransform>
              </Path>
            </Grid>
            <Ellipse x:Name="TitleDotBrand" Width="3.5" Height="3.5" Fill="#8A8A96"
                     Margin="9,1,9,0" VerticalAlignment="Center" Opacity="0.9"
                     SnapsToDevicePixels="False">
              <Ellipse.Effect>
                <DropShadowEffect Color="#000000" BlurRadius="1.5" ShadowDepth="0.5" Opacity="0.45" Direction="270"/>
              </Ellipse.Effect>
            </Ellipse>
            <!-- Brand name -->
            <StackPanel x:Name="TitleBrand" Orientation="Horizontal" VerticalAlignment="Center" MaxWidth="240">
              <TextBlock Text="[" Foreground="#A0A0AA" FontSize="13" FontWeight="SemiBold"
                         VerticalAlignment="Center"/>
              <Grid VerticalAlignment="Center" MaxWidth="140">
                <TextBlock x:Name="TitleBrandNameShadow" Text="MiniBot" Foreground="#000000"
                           FontSize="13" FontWeight="SemiBold"
                           TextTrimming="CharacterEllipsis" MaxWidth="140"
                           Margin="1.2,1.2,0,0" Opacity="0.9" IsHitTestVisible="False">
                  <TextBlock.Effect>
                    <DropShadowEffect Color="#000000" BlurRadius="3.5" ShadowDepth="0"
                                      Opacity="0.85" Direction="0"/>
                  </TextBlock.Effect>
                </TextBlock>
                <TextBlock x:Name="TitleBrandName" Text="MiniBot" Foreground="#B80F0A"
                           FontSize="13" FontWeight="SemiBold"
                           TextTrimming="CharacterEllipsis" MaxWidth="140">
                  <TextBlock.Effect>
                    <DropShadowEffect Color="#FF3A1A" BlurRadius="10" ShadowDepth="0"
                                      Opacity="0.72" Direction="0"/>
                  </TextBlock.Effect>
                </TextBlock>
              </Grid>
              <TextBlock Text="-" Foreground="#A0A0AA" FontSize="13" FontWeight="SemiBold"
                         VerticalAlignment="Center"/>
              <Grid VerticalAlignment="Center">
                <TextBlock Text="Agent" Foreground="#000000" FontSize="13" FontWeight="SemiBold"
                           Margin="1.2,1.2,0,0" Opacity="0.9" IsHitTestVisible="False">
                  <TextBlock.Effect>
                    <DropShadowEffect Color="#000000" BlurRadius="3.5" ShadowDepth="0"
                                      Opacity="0.85" Direction="0"/>
                  </TextBlock.Effect>
                </TextBlock>
                <TextBlock Text="Agent" Foreground="#B80F0A" FontSize="13" FontWeight="SemiBold">
                  <TextBlock.Effect>
                    <DropShadowEffect Color="#FF3A1A" BlurRadius="10" ShadowDepth="0"
                                      Opacity="0.55" Direction="0"/>
                  </TextBlock.Effect>
                </TextBlock>
              </Grid>
              <TextBlock Text="]" Foreground="#A0A0AA" FontSize="13" FontWeight="SemiBold"
                         VerticalAlignment="Center"/>
            </StackPanel>
            <Ellipse x:Name="TitleDotPath" Width="3.5" Height="3.5" Fill="#8A8A96"
                     Margin="9,1,9,0" VerticalAlignment="Center" Opacity="0.9"
                     SnapsToDevicePixels="False">
              <Ellipse.Effect>
                <DropShadowEffect Color="#000000" BlurRadius="1.5" ShadowDepth="0.5" Opacity="0.45" Direction="270"/>
              </Ellipse.Effect>
            </Ellipse>
            <Grid VerticalAlignment="Center" MaxWidth="520">
              <TextBlock x:Name="TitlePathShadow" Text="" Foreground="#000000" FontSize="12"
                         VerticalAlignment="Center" Margin="1.2,1.2,0,0" Opacity="0.9"
                         TextTrimming="CharacterEllipsis" MaxWidth="520" IsHitTestVisible="False">
                <TextBlock.Effect>
                  <DropShadowEffect Color="#000000" BlurRadius="3.5" ShadowDepth="0"
                                    Opacity="0.85" Direction="0"/>
                </TextBlock.Effect>
              </TextBlock>
              <TextBlock x:Name="TitlePath" Text="" Foreground="#C8C8D0" FontSize="12"
                         VerticalAlignment="Center" Cursor="Hand"
                         TextTrimming="CharacterEllipsis" MaxWidth="520"
                         shell:WindowChrome.IsHitTestVisibleInChrome="True"/>
            </Grid>
          </StackPanel>
          <StackPanel Grid.Column="1" Orientation="Horizontal" VerticalAlignment="Center"
                      HorizontalAlignment="Right" Margin="12,0,10,0" MaxWidth="320">
            <TextBlock x:Name="TitlePoweredByLabel" Text="PoweredBy: " Foreground="#8A8A96" FontSize="12"
                       VerticalAlignment="Center" Margin="0,0,4,0"/>
            <!-- Themed model chip (tool-group style): click toggles dark ContextMenu -->
            <Border x:Name="TitleModelPicker" Background="#3A3A42" BorderBrush="#4A4A56"
                    BorderThickness="1" CornerRadius="3" Padding="7,2,6,2"
                    VerticalAlignment="Center" Cursor="Hand" MaxWidth="230"
                    SnapsToDevicePixels="True"
                    shell:WindowChrome.IsHitTestVisibleInChrome="True">
              <StackPanel Orientation="Horizontal">
                <TextBlock x:Name="TitleModelPickerText" Text="Select Model"
                           Foreground="#BB9AF7" FontSize="11" FontWeight="SemiBold"
                           VerticalAlignment="Center" TextTrimming="CharacterEllipsis"
                           MaxWidth="195"/>
                <TextBlock Text=" &#x25BE;" Foreground="#8A8A96" FontSize="10"
                           VerticalAlignment="Center" Margin="1,0,0,0"/>
              </StackPanel>
            </Border>
            <TextBlock x:Name="TitlePoweredBy" Visibility="Collapsed"/>
            <TextBlock x:Name="TitlePoweredByShadow" Visibility="Collapsed"/>
          </StackPanel>
          <StackPanel Grid.Column="2" Orientation="Horizontal" VerticalAlignment="Stretch">
            <!-- Window buttons -->
            <Button x:Name="TitleBtnMin" Width="46" Height="36"
                    Background="Transparent" BorderThickness="0" Cursor="Hand"
                    Focusable="False" shell:WindowChrome.IsHitTestVisibleInChrome="True"
                    ToolTip="Minimize" Template="{StaticResource NoMouseOverButtonTemplate}">
              <Path x:Name="TitleBtnMinPath" Width="10" Height="1" Stretch="Fill"
                    Stroke="#C8C8D0" StrokeThickness="1" Data="M0,0 L10,0"
                    HorizontalAlignment="Center" VerticalAlignment="Center"/>
            </Button>
            <Button x:Name="TitleBtnMax" Width="46" Height="36"
                    Background="Transparent" BorderThickness="0" Cursor="Hand"
                    Focusable="False" shell:WindowChrome.IsHitTestVisibleInChrome="True"
                    ToolTip="Maximize" Template="{StaticResource NoMouseOverButtonTemplate}">
              <Path x:Name="TitleBtnMaxPath" Width="10" Height="10" Stretch="Uniform"
                    Stroke="#C8C8D0" StrokeThickness="1" Fill="Transparent"
                    Data="M0.5,0.5 H9.5 V9.5 H0.5 Z"
                    HorizontalAlignment="Center" VerticalAlignment="Center"/>
            </Button>
            <Button x:Name="TitleBtnClose" Width="46" Height="36"
                    Background="Transparent" BorderThickness="0" Cursor="Hand"
                    Focusable="False" shell:WindowChrome.IsHitTestVisibleInChrome="True"
                    ToolTip="Close" Template="{StaticResource NoMouseOverButtonTemplate}">
              <Path x:Name="TitleBtnClosePath" Width="10" Height="10" Stretch="Uniform"
                    Stroke="#C8C8D0" StrokeThickness="1.15"
                    Data="M0,0 L10,10 M10,0 L0,10"
                    HorizontalAlignment="Center" VerticalAlignment="Center"/>
            </Button>
          </StackPanel>
        </Grid>
      </Border>
 <!-- Main console chrome -->
      <Grid x:Name="RootGrid" Grid.Row="1">
        <Grid.RowDefinitions>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="*"/>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

 <!-- Tool groups header -->
        <Border Grid.Row="0" Panel.ZIndex="3" Background="#2A2A30" BorderBrush="#3A3A42"
                BorderThickness="0,0,0,0" Padding="12,8,12,6">
          <Grid>
            <Grid.RowDefinitions>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="2"/>
            </Grid.RowDefinitions>
            <Grid Grid.Row="0">
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="*" MinWidth="80"/>
                <ColumnDefinition Width="Auto"/>
              </Grid.ColumnDefinitions>
              <!-- Two-line wrap for tool group chips; brand/path/PoweredBy live in window Title -->
              <WrapPanel x:Name="HdrToolGroups" Grid.Column="0" Orientation="Horizontal"
                         VerticalAlignment="Center" Margin="0,0,12,0"
                         MaxHeight="44"/>
              <!-- Legacy header nodes (collapsed) -->
              <TextBlock x:Name="HdrLine1" Visibility="Collapsed"/>
              <TextBlock x:Name="HdrLine1Shadow" Visibility="Collapsed"/>
              <TextBlock x:Name="HdrPoweredBy" Visibility="Collapsed"/>
              <TextBlock x:Name="HdrPoweredByShadow" Visibility="Collapsed"/>
              <Grid x:Name="HdrPoweredByHost" Visibility="Collapsed"/>
              <TextBlock x:Name="HdrAutoCompact" Visibility="Collapsed"/>
              <TextBlock x:Name="HdrAutoCompactShadow" Visibility="Collapsed"/>
              <CheckBox x:Name="WordWrapToggle" Grid.Column="1" Style="{StaticResource MbDarkCheckBox}"
                        VerticalAlignment="Bottom" HorizontalAlignment="Right" Margin="4,0,0,0"
                        IsChecked="True" ToolTip="Wrap long log lines">
                <CheckBox.Content>
                  <TextBlock x:Name="WordWrapLabel" Text="wrap" Foreground="#C8C8D0" FontSize="12"
                             FontFamily="Consolas, Cascadia Mono, Courier New"
                             VerticalAlignment="Center" Margin="0,-2,0,0"/>
                </CheckBox.Content>
              </CheckBox>
            </Grid>
 <!-- Brand accent -->
            <Rectangle Grid.Row="1" Height="2" Margin="0,6,0,0" RadiusX="1" RadiusY="1">
              <Rectangle.Fill>
                <LinearGradientBrush StartPoint="0,0" EndPoint="1,0">
                  <GradientStop Color="#B80F0A" Offset="0"/>
                  <GradientStop Color="#7AA2F7" Offset="0.55"/>
                  <GradientStop Color="#3A3A42" Offset="1"/>
                </LinearGradientBrush>
              </Rectangle.Fill>
            </Rectangle>
          </Grid>
        </Border>
        <Rectangle Grid.Row="1" Height="1" Fill="#3A3A42" Panel.ZIndex="2"/>

 <!-- Log -->
        <RichTextBox x:Name="LogBox" Grid.Row="2" IsReadOnly="True" IsDocumentEnabled="True"
                     IsUndoEnabled="False"
                     VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled"
                     BorderThickness="0" Background="#121216" Foreground="#C8C8D0"
                     Padding="12,6" AcceptsReturn="True" CaretBrush="#8A8A96"
                     FontFamily="Consolas, Cascadia Mono, Segoe UI Emoji, Segoe UI Symbol, Courier New">
          <RichTextBox.Resources>
            <Style TargetType="Paragraph">
              <Setter Property="Margin" Value="0"/>
              <Setter Property="Padding" Value="0"/>
              <Setter Property="LineHeight" Value="16"/>
            </Style>
          </RichTextBox.Resources>
 <!-- PageWidth: viewport when wrap on; content width when wrap off -->
          <FlowDocument PagePadding="0" LineHeight="16"
                        FontFamily="Consolas, Cascadia Mono, Segoe UI Emoji, Segoe UI Symbol, Courier New"/>
        </RichTextBox>

 <!-- Speech visualizer (real TTS PCM from SAPI WaveStream - no WASAPI) -->
        <Border x:Name="SpeechWaveBox" Grid.Row="3" Visibility="Collapsed"
                Background="#1A1A1E" BorderBrush="#3A3A42" BorderThickness="1"
                CornerRadius="6" Margin="12,8,12,6" HorizontalAlignment="Stretch"
                SnapsToDevicePixels="True" ClipToBounds="True">
          <Grid>
            <Grid.RowDefinitions>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="84"/>
            </Grid.RowDefinitions>
            <Border Grid.Row="0" Background="#252530" Padding="10,5,10,5"
                    CornerRadius="5,5,0,0" SnapsToDevicePixels="True">
              <Grid>
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <TextBlock x:Name="SpeechWaveLang" Grid.Column="0" Text="speech"
                           Foreground="#8A8A96" FontSize="11"
                           FontFamily="Consolas, Cascadia Mono, Courier New"
                           VerticalAlignment="Center"/>
                <TextBlock x:Name="SpeechWaveStatus" Grid.Column="1" Text="idle"
                           Foreground="#6A6A76" FontSize="11"
                           FontFamily="Consolas, Cascadia Mono, Courier New"
                           VerticalAlignment="Center" Margin="12,0,0,0"/>
              </Grid>
            </Border>
            <Border Grid.Row="1" Background="#121216" CornerRadius="0,0,5,5" ClipToBounds="True">
              <Canvas x:Name="SpeechWaveCanvas" Background="Transparent" ClipToBounds="True">
                <Polyline x:Name="SpeechWaveLine" Stroke="#00BFFF" StrokeThickness="1.35"
                          StrokeLineJoin="Round" StrokeStartLineCap="Round" StrokeEndLineCap="Round"
                          SnapsToDevicePixels="False"/>
              </Canvas>
            </Border>
          </Grid>
        </Border>

 <!-- Lower status: status+timer (dynamic width by mode) | ctx | meta
             ready → compact (ctx far left); thinking/working → same reserved band + timer;
             auto-compacting → label may grow and shift ctx once. -->
        <Border Grid.Row="4" Background="#1E1E24" BorderBrush="#2A2A30" BorderThickness="0,1,0,0" Padding="12,4">
          <Grid>
            <Grid.ColumnDefinitions>
              <ColumnDefinition Width="Auto"/>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="Auto"/>
            </Grid.ColumnDefinitions>
            <StackPanel x:Name="StatusBand" Grid.Column="0" Orientation="Horizontal" VerticalAlignment="Center" Margin="0,0,14,0">
              <TextBlock x:Name="StatusDot" Text="* ready" Foreground="#9ECE6A"
                         VerticalAlignment="Center" Margin="0,0,0,0" FontWeight="SemiBold"
                         FontFamily="Consolas, Cascadia Mono, Segoe UI Symbol, Courier New"/>
              <TextBlock x:Name="StatusTimer" Text="" Foreground="#6A6A76"
                         VerticalAlignment="Center" HorizontalAlignment="Left"
                         FontWeight="SemiBold"
                         FontFamily="Consolas, Cascadia Mono, Courier New"/>
            </StackPanel>
            <StackPanel Grid.Column="1" Orientation="Horizontal" VerticalAlignment="Center">
              <TextBlock Text="ctx " Foreground="#6A6A76" VerticalAlignment="Center"/>
              <Border Width="120" Height="12" Background="#2A2A30" CornerRadius="2"
                      VerticalAlignment="Center" Margin="0,0,8,0" ClipToBounds="True">
                <Rectangle x:Name="CtxBarFill" Width="0" Height="12" HorizontalAlignment="Left" Fill="#9ECE6A"/>
              </Border>
              <TextBlock x:Name="CtxPctText" Text="0%" Foreground="#9ECE6A"
                         VerticalAlignment="Center" Margin="0,0,10,0" FontWeight="SemiBold"/>
              <TextBlock x:Name="CtxTokText" Text="" Foreground="#6A6A76" VerticalAlignment="Center"/>
            </StackPanel>
            <StackPanel x:Name="LowerRight" Grid.Column="2" Orientation="Horizontal"
                        VerticalAlignment="Center" HorizontalAlignment="Right" Margin="12,0,0,0"/>
          </Grid>
        </Border>

 <!-- Prompt -->
        <Border Grid.Row="5" Background="#1A1A1E" BorderBrush="#2A2A30" BorderThickness="0,1,0,0" Padding="10,8">
          <Grid>
            <Grid.ColumnDefinitions>
              <ColumnDefinition Width="Auto"/>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="Auto"/>
            </Grid.ColumnDefinitions>
            <TextBlock Grid.Column="0" Text="> " Foreground="#8A8A96" FontSize="14" VerticalAlignment="Top" Margin="0,6,4,0"/>
            <Border x:Name="PromptHost" Grid.Column="1" BorderBrush="#3A3A42" BorderThickness="1"
                    CornerRadius="4" Background="#121216" Padding="8,6" Margin="0,0,8,0"
                    VerticalAlignment="Stretch" MinHeight="42">
              <TextBox x:Name="PromptBox" AcceptsReturn="True" TextWrapping="Wrap"
                       MinHeight="28" MaxHeight="140" VerticalScrollBarVisibility="Auto"
                       BorderThickness="0" Background="Transparent" Foreground="#E0E0E8"
                       CaretBrush="#C8C8D0" FontFamily="Consolas, Cascadia Mono, Courier New"
                       FontSize="13" IsEnabled="True" IsReadOnly="True" Focusable="True"/>
            </Border>
            <Button x:Name="SendBtn" Grid.Column="2" Width="88" MinHeight="41"
                    VerticalAlignment="Stretch" Cursor="Hand" ToolTip="Send"
                    HorizontalContentAlignment="Center" VerticalContentAlignment="Center"
                    Background="#2A2A30" Foreground="#8A8A96" BorderBrush="#3A3A42" BorderThickness="1"
                    Padding="6,0" Margin="0,0,3,1" IsEnabled="False"
                    Template="{StaticResource NoMouseOverButtonTemplate}">
              <!-- Send icon -->
              <Path x:Name="SendBtnPath" Width="20" Height="20" Stretch="Uniform"
                    HorizontalAlignment="Center" VerticalAlignment="Center"
                    Data="M12,2A10,10 0 0,1 22,12A10,10 0 0,1 12,22A10,10 0 0,1 2,12A10,10 0 0,1 12,2M8,7.71V11.05L15.14,12L8,12.95V16.29L18,12L8,7.71Z">
                <Path.Fill>
                  <LinearGradientBrush StartPoint="0.2,0" EndPoint="0.85,1">
                    <GradientStop x:Name="SendBtnGrad0" Color="#C0C0C8" Offset="0"/>
                    <GradientStop x:Name="SendBtnGrad1" Color="#8A8A96" Offset="0.5"/>
                    <GradientStop x:Name="SendBtnGrad2" Color="#5A5A66" Offset="1"/>
                  </LinearGradientBrush>
                </Path.Fill>
                <Path.Effect>
                  <DropShadowEffect x:Name="SendBtnShadow" BlurRadius="4" ShadowDepth="1.5"
                                    Opacity="0.75" Direction="315" Color="Black"/>
                </Path.Effect>
              </Path>
            </Button>
          </Grid>
        </Border>

 <!-- Hints (bottom corners match chrome when restored) -->
        <Border x:Name="HintBarBorder" Grid.Row="6" Background="#16161A" BorderBrush="#2A2A30"
                BorderThickness="0,1,0,0" Padding="12,4"
                CornerRadius="0,0,8,8" SnapsToDevicePixels="True">
          <TextBlock x:Name="HintBar" Text="enter send  |  Ctrl+Enter newline  |  Esc / Stop interrupt  |  /help"
                     Foreground="#5A5A66" FontSize="11"/>
        </Border>
      </Grid>
    </Grid>
  </Border>

 <!-- Overlays -->
      <Grid x:Name="AuthOverlay" Visibility="Collapsed" Panel.ZIndex="200">
        <Border Background="#E6121216"/>
        <Border Width="420" HorizontalAlignment="Center" VerticalAlignment="Center"
                Background="#121216" BorderBrush="#2A2A30" BorderThickness="1" CornerRadius="8"
                ClipToBounds="True" SnapsToDevicePixels="True">
          <Grid>
            <Grid.RowDefinitions>
              <RowDefinition Height="36"/>
              <RowDefinition Height="*"/>
            </Grid.RowDefinitions>
            <Border Grid.Row="0" Background="#2A2A30" BorderBrush="#3A3A42" BorderThickness="0,0,0,1"
                    CornerRadius="8,8,0,0" Padding="10,0,0,0">
              <Grid>
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <StackPanel Orientation="Horizontal" VerticalAlignment="Center">
                  <TextBlock VerticalAlignment="Center" FontSize="13" FontWeight="SemiBold">
                    <Run Text="[" Foreground="#A0A0AA"/><Run x:Name="AuthBarBrandName" Text="MiniBot" Foreground="#B80F0A"/><Run Text="-" Foreground="#A0A0AA"/><Run Text="Agent" Foreground="#B80F0A"/><Run Text="]" Foreground="#A0A0AA"/>
                  </TextBlock>
                  <Ellipse Width="3.5" Height="3.5" Fill="#8A8A96"
                           Margin="9,1,9,0" VerticalAlignment="Center" Opacity="0.9"
                           SnapsToDevicePixels="False">
                    <Ellipse.Effect>
                      <DropShadowEffect Color="#000000" BlurRadius="1.5" ShadowDepth="0.5" Opacity="0.45" Direction="270"/>
                    </Ellipse.Effect>
                  </Ellipse>
                  <TextBlock Text="Login" Foreground="#C8C8D0" FontSize="12" VerticalAlignment="Center"/>
                </StackPanel>
                <Button x:Name="AuthTitleClose" Grid.Column="1" Width="46" Height="36"
                        Background="Transparent" BorderThickness="0" Cursor="Hand" Focusable="False"
                        Template="{StaticResource NoMouseOverButtonTemplate}" ToolTip="Close">
                  <Path Width="10" Height="10" Stretch="Uniform" Stroke="#C8C8D0" StrokeThickness="1.15"
                        Data="M0,0 L10,10 M10,0 L0,10" HorizontalAlignment="Center" VerticalAlignment="Center"/>
                </Button>
              </Grid>
            </Border>
            <Border Grid.Row="1" Background="#121216" Padding="22,18,22,14"
                    CornerRadius="0,0,8,8" SnapsToDevicePixels="True">
              <Grid>
                <Grid.RowDefinitions>
                  <RowDefinition Height="Auto"/>
                  <RowDefinition Height="18"/>
                  <RowDefinition Height="Auto"/>
                </Grid.RowDefinitions>
                <StackPanel Grid.Row="0">
                  <TextBlock x:Name="AuthTitle" Text="Authentication required" Foreground="#E0E0E8"
                             FontSize="16" FontWeight="Bold" Margin="0,0,0,6"/>
                  <TextBlock x:Name="AuthSubtitle" Text="" Foreground="#8A8A96" TextWrapping="Wrap"
                             FontSize="12" Margin="0,0,0,10" MaxHeight="40" TextTrimming="CharacterEllipsis"/>
                  <TextBlock Text="Username" Foreground="#A0A0AA" FontSize="11" Margin="0,0,0,4"/>
                  <TextBox x:Name="AuthUser" Height="32" Padding="8,6" Margin="0,0,0,8"
                           Background="#121216" Foreground="#E0E0E8" CaretBrush="#C8C8D0"
                           BorderBrush="#3A3A42" BorderThickness="1"
                           FontFamily="Consolas, Cascadia Mono, Courier New" FontSize="13"
                           Focusable="True" IsTabStop="True" TabIndex="0"/>
                  <TextBlock Text="Password" Foreground="#A0A0AA" FontSize="11" Margin="0,0,0,4"/>
                  <PasswordBox x:Name="AuthPass" Height="32" Padding="8,6" Margin="0,0,0,6"
                               Background="#121216" Foreground="#E0E0E8" CaretBrush="#C8C8D0"
                               BorderBrush="#3A3A42" BorderThickness="1"
                               FontFamily="Consolas, Cascadia Mono, Courier New" FontSize="13"
                               Focusable="True" IsTabStop="True" TabIndex="1"/>
                  <CheckBox x:Name="AuthSaveCreds" Style="{StaticResource MbDarkCheckBox}"
                            Margin="0,0,0,0" Cursor="Hand" Focusable="True" IsTabStop="True"
                            TabIndex="2" IsChecked="False">
                    <CheckBox.Content>
                      <TextBlock Text="Save credentials" Foreground="#A0A0AA" FontSize="12"
                                 Margin="0,-1,0,0"/>
                    </CheckBox.Content>
                  </CheckBox>
                </StackPanel>
                <TextBlock x:Name="AuthError" Grid.Row="1" Text="" Foreground="#F05C5C" FontSize="11"
                           TextWrapping="NoWrap" TextTrimming="CharacterEllipsis" VerticalAlignment="Center"/>
                <StackPanel Grid.Row="2" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,2,0,0">
                  <Button x:Name="AuthOk" Style="{StaticResource MbAuthPrimaryBtn}"
                          Content="Sign in" Width="96" Height="30" Margin="0,0,8,0"
                          IsDefault="False" TabIndex="3"/>
                  <Button x:Name="AuthCancel" Style="{StaticResource MbAuthSecondaryBtn}"
                          Content="Quit" Width="88" Height="30" TabIndex="4"/>
                </StackPanel>
              </Grid>
            </Border>
          </Grid>
        </Border>
      </Grid>
      <Grid x:Name="ConfirmOverlay" Visibility="Collapsed" Panel.ZIndex="300">
        <Border Background="#E6121216"/>
        <Border Width="420" HorizontalAlignment="Center" VerticalAlignment="Center"
                Background="#121216" BorderBrush="#2A2A30" BorderThickness="1" CornerRadius="8"
                ClipToBounds="True" SnapsToDevicePixels="True">
          <Grid>
            <Grid.RowDefinitions>
              <RowDefinition Height="36"/>
              <RowDefinition Height="*"/>
            </Grid.RowDefinitions>
            <Border Grid.Row="0" Background="#2A2A30" BorderBrush="#3A3A42" BorderThickness="0,0,0,1"
                    CornerRadius="8,8,0,0" Padding="10,0,0,0">
              <Grid>
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <StackPanel Orientation="Horizontal" VerticalAlignment="Center">
                  <TextBlock VerticalAlignment="Center" FontSize="13" FontWeight="SemiBold">
                    <Run Text="[" Foreground="#A0A0AA"/><Run x:Name="ConfirmBarBrandName" Text="MiniBot" Foreground="#B80F0A"/><Run Text="-" Foreground="#A0A0AA"/><Run Text="Agent" Foreground="#B80F0A"/><Run Text="]" Foreground="#A0A0AA"/>
                  </TextBlock>
                  <Ellipse Width="3.5" Height="3.5" Fill="#8A8A96"
                           Margin="9,1,9,0" VerticalAlignment="Center" Opacity="0.9"
                           SnapsToDevicePixels="False">
                    <Ellipse.Effect>
                      <DropShadowEffect Color="#000000" BlurRadius="1.5" ShadowDepth="0.5" Opacity="0.45" Direction="270"/>
                    </Ellipse.Effect>
                  </Ellipse>
                  <TextBlock Text="Confirm" Foreground="#C8C8D0" FontSize="12" VerticalAlignment="Center"/>
                </StackPanel>
                <Button x:Name="ConfirmTitleClose" Grid.Column="1" Width="46" Height="36"
                        Background="Transparent" BorderThickness="0" Cursor="Hand" Focusable="False"
                        Template="{StaticResource NoMouseOverButtonTemplate}" ToolTip="Close">
                  <Path Width="10" Height="10" Stretch="Uniform" Stroke="#C8C8D0" StrokeThickness="1.15"
                        Data="M0,0 L10,10 M10,0 L0,10" HorizontalAlignment="Center" VerticalAlignment="Center"/>
                </Button>
              </Grid>
            </Border>
            <Border Grid.Row="1" Background="#121216" Padding="22,18,22,16"
                    CornerRadius="0,0,8,8" SnapsToDevicePixels="True">
              <Grid>
                <Grid.RowDefinitions>
                  <RowDefinition Height="Auto"/>
                  <RowDefinition Height="Auto"/>
                  <RowDefinition Height="Auto"/>
                  <RowDefinition Height="Auto"/>
                </Grid.RowDefinitions>
                <TextBlock x:Name="ConfirmTitle" Text="Invalid Entry" Foreground="#E0E0E8"
                           FontSize="16" FontWeight="Bold" Margin="0,0,0,6"/>
                <Rectangle x:Name="ConfirmAccentBar" Grid.Row="1" Height="3" Margin="0,0,0,14"
                           RadiusX="1.5" RadiusY="1.5" Opacity="0.55">
                  <Rectangle.Fill>
                    <LinearGradientBrush StartPoint="0,0" EndPoint="1,0">
                      <GradientStop Color="#7DCFFF" Offset="0"/>
                      <GradientStop Color="#FFFFFF" Offset="0.5"/>
                      <GradientStop Color="#7DCFFF" Offset="1"/>
                    </LinearGradientBrush>
                  </Rectangle.Fill>
                </Rectangle>
                <TextBlock x:Name="ConfirmPrompt" Grid.Row="2" Text="" Foreground="#C8C8D0"
                           FontSize="13" TextWrapping="Wrap" Margin="0,0,0,18" LineHeight="20"/>
                <StackPanel Grid.Row="3" Orientation="Horizontal" HorizontalAlignment="Right">
                  <Button x:Name="ConfirmYes" Style="{StaticResource MbAuthPrimaryBtn}"
                          Content="Yes" MinWidth="96" Height="30" Padding="16,0" Margin="0,0,8,0"
                          IsDefault="True" TabIndex="0"/>
                  <Button x:Name="ConfirmNo" Style="{StaticResource MbAuthSecondaryBtn}"
                          Content="No" MinWidth="88" Height="30" Padding="16,0"
                          IsCancel="True" TabIndex="1"/>
                </StackPanel>
              </Grid>
            </Border>
          </Grid>
        </Border>
      </Grid>

      <Grid x:Name="SessionPickerOverlay" Visibility="Collapsed" Panel.ZIndex="250">
        <Border Background="#E6121216"/>
        <Border Width="720" Height="500" MinWidth="480" MinHeight="340"
                MaxWidth="920" MaxHeight="640"
                HorizontalAlignment="Center" VerticalAlignment="Center"
                Background="#121216" BorderBrush="#2A2A30" BorderThickness="1"
                CornerRadius="8" ClipToBounds="True" SnapsToDevicePixels="True">
          <Grid>
            <Grid.RowDefinitions>
              <RowDefinition Height="36"/>
              <RowDefinition Height="*"/>
            </Grid.RowDefinitions>
            <Border Grid.Row="0" Background="#2A2A30" BorderBrush="#3A3A42" BorderThickness="0,0,0,1"
                    CornerRadius="8,8,0,0" Padding="10,0,0,0">
              <Grid>
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <StackPanel Orientation="Horizontal" VerticalAlignment="Center">
                  <TextBlock VerticalAlignment="Center" FontSize="13" FontWeight="SemiBold">
                    <Run Text="[" Foreground="#A0A0AA"/><Run x:Name="SessionBarBrandName" Text="MiniBot" Foreground="#B80F0A"/><Run Text="-" Foreground="#A0A0AA"/><Run Text="Agent" Foreground="#B80F0A"/><Run Text="]" Foreground="#A0A0AA"/>
                  </TextBlock>
                  <Ellipse Width="3.5" Height="3.5" Fill="#8A8A96"
                           Margin="9,1,9,0" VerticalAlignment="Center" Opacity="0.9"
                           SnapsToDevicePixels="False">
                    <Ellipse.Effect>
                      <DropShadowEffect Color="#000000" BlurRadius="1.5" ShadowDepth="0.5" Opacity="0.45" Direction="270"/>
                    </Ellipse.Effect>
                  </Ellipse>
                  <TextBlock x:Name="SessionPickerTitle" Text="Load session" Foreground="#C8C8D0" FontSize="12"
                             VerticalAlignment="Center" TextTrimming="CharacterEllipsis" MaxWidth="420"/>
                </StackPanel>
                <Button x:Name="SessionPickerTitleClose" Grid.Column="1" Width="46" Height="36"
                        Background="Transparent" BorderThickness="0" Cursor="Hand" Focusable="False"
                        Template="{StaticResource NoMouseOverButtonTemplate}" ToolTip="Close">
                  <Path Width="10" Height="10" Stretch="Uniform" Stroke="#C8C8D0" StrokeThickness="1.15"
                        Data="M0,0 L10,10 M10,0 L0,10" HorizontalAlignment="Center" VerticalAlignment="Center"/>
                </Button>
              </Grid>
            </Border>
            <Border Grid.Row="1" Background="#121216" CornerRadius="0,0,8,8" SnapsToDevicePixels="True">
            <Grid Margin="16,14,16,14">
            <Grid.RowDefinitions>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="*"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
            </Grid.RowDefinitions>
            <DockPanel Grid.Row="0" Margin="0,0,0,8" LastChildFill="True">
              <Button x:Name="SessionPickerBrowse" Style="{StaticResource MbAuthSecondaryBtn}"
                      Content="Browse..." MinWidth="84" Height="30" Margin="6,0,0,0"
                      DockPanel.Dock="Right" Padding="10,0"/>
              <Button x:Name="SessionPickerUp" Style="{StaticResource MbAuthSecondaryBtn}"
                      Content="Up" MinWidth="52" Height="30" Margin="6,0,0,0"
                      DockPanel.Dock="Right" Padding="10,0"/>
              <Button x:Name="SessionPickerGo" Style="{StaticResource MbAuthSecondaryBtn}"
                      Content="Go" MinWidth="52" Height="30" Margin="6,0,0,0"
                      DockPanel.Dock="Right" Padding="10,0"/>
              <TextBox x:Name="SessionPickerPath" Height="30" Padding="8,5"
                       Background="#121216" Foreground="#E0E0E8" CaretBrush="#C8C8D0"
                       BorderBrush="#3A3A42" BorderThickness="1" VerticalContentAlignment="Center"
                       FontFamily="Consolas, Cascadia Mono, Courier New" FontSize="13"/>
            </DockPanel>
            <TextBlock x:Name="SessionPickerStatus" Grid.Row="1" Text="Sessions (newest first)"
                       Foreground="#6A6A76" FontSize="11" Margin="0,0,0,6"/>
            <ListBox x:Name="SessionPickerList" Grid.Row="2"
                     Background="#121216" Foreground="#C8C8D0" BorderBrush="#3A3A42"
                     BorderThickness="1" FontFamily="Consolas, Cascadia Mono, Courier New"
                     FontSize="12" Padding="2"
                     ScrollViewer.HorizontalScrollBarVisibility="Disabled">
              <ListBox.Resources>
                <SolidColorBrush x:Key="{x:Static SystemColors.HighlightBrushKey}" Color="#3A3A42"/>
                <SolidColorBrush x:Key="{x:Static SystemColors.HighlightTextBrushKey}" Color="#7DCFFF"/>
                <SolidColorBrush x:Key="{x:Static SystemColors.ControlBrushKey}" Color="#121216"/>
                <Style TargetType="ListBoxItem">
                  <Setter Property="Padding" Value="8,4"/>
                  <Setter Property="Background" Value="Transparent"/>
                  <Setter Property="Foreground" Value="#C8C8D0"/>
                  <Setter Property="BorderThickness" Value="0"/>
                  <Style.Triggers>
                    <Trigger Property="IsMouseOver" Value="True">
                      <Setter Property="Background" Value="#363640"/>
                      <Setter Property="Foreground" Value="#E0E0E8"/>
                    </Trigger>
                    <Trigger Property="IsSelected" Value="True">
                      <Setter Property="Background" Value="#3A3A42"/>
                      <Setter Property="Foreground" Value="#7DCFFF"/>
                    </Trigger>
                  </Style.Triggers>
                </Style>
              </ListBox.Resources>
            </ListBox>
            <DockPanel Grid.Row="3" Margin="0,10,0,10" LastChildFill="True">
              <TextBlock Text="File name:  " Foreground="#8A8A96" VerticalAlignment="Center"
                         DockPanel.Dock="Left"/>
              <TextBox x:Name="SessionPickerName" Height="30" Padding="8,5"
                       Background="#121216" Foreground="#E0E0E8" CaretBrush="#C8C8D0"
                       BorderBrush="#3A3A42" BorderThickness="1" VerticalContentAlignment="Center"
                       FontFamily="Consolas, Cascadia Mono, Courier New" FontSize="13"/>
            </DockPanel>
            <StackPanel Grid.Row="4" Orientation="Horizontal" HorizontalAlignment="Right">
              <Button x:Name="SessionPickerOk" Style="{StaticResource MbAuthPrimaryBtn}"
                      Content="Open" MinWidth="96" Height="30" Padding="16,0" Margin="0,0,8,0"
                      IsDefault="False"/>
              <Button x:Name="SessionPickerCancel" Style="{StaticResource MbAuthSecondaryBtn}"
                      Content="Cancel" MinWidth="88" Height="30" Padding="16,0"
                      IsCancel="False"/>
            </StackPanel>
            </Grid>
            </Border>
          </Grid>
        </Border>
      </Grid>
  </Grid>
</Window>
'@
			$reader = New-Object System.Xml.XmlNodeReader ([xml]$xaml)
			$window = [Windows.Markup.XamlReader]::Load($reader)
			$W.Window = $window
			$W.Log = $window.FindName('LogBox')
			$W.Prompt = $window.FindName('PromptBox')
			$W.SendBtn = $window.FindName('SendBtn')
			$W.SendBtnPath = $window.FindName('SendBtnPath')
			$W.SendBtnGrad0 = $window.FindName('SendBtnGrad0')
			$W.SendBtnGrad1 = $window.FindName('SendBtnGrad1')
			$W.SendBtnGrad2 = $window.FindName('SendBtnGrad2')
			$W.SendBtnShadow = $window.FindName('SendBtnShadow')
			if ((-not $W.SendBtnGrad0 -or -not $W.SendBtnGrad1 -or -not $W.SendBtnGrad2) -and $W.SendBtnPath) {
				try {
					$sf = $W.SendBtnPath.Fill
					if ($sf -is [System.Windows.Media.LinearGradientBrush] -and $sf.GradientStops.Count -ge 3) {
						$W.SendBtnGrad0 = $sf.GradientStops[0]
						$W.SendBtnGrad1 = $sf.GradientStops[1]
						$W.SendBtnGrad2 = $sf.GradientStops[2]
					}
				} catch {}
			}
			if ($W.SendBtnPath) {
				try { $W.SendBtnPath.RenderTransform = [System.Windows.Media.Transform]::Identity } catch {}
				if (-not $W.SendBtnShadow) {
					try {
						if ($W.SendBtnPath.Effect -is [System.Windows.Media.Effects.DropShadowEffect]) {
							$W.SendBtnShadow = $W.SendBtnPath.Effect
						} else {
							$fx = New-Object System.Windows.Media.Effects.DropShadowEffect
							$fx.BlurRadius = 4
							$fx.ShadowDepth = 1.5
							$fx.Opacity = 0.75
							$fx.Direction = 315
							$fx.Color = [System.Windows.Media.Colors]::Black
							$W.SendBtnPath.Effect = $fx
							$W.SendBtnShadow = $fx
						}
					} catch {}
				}
			}
			# Send and stop path geometry
			$W.SendGeomData = 'M12,2A10,10 0 0,1 22,12A10,10 0 0,1 12,22A10,10 0 0,1 2,12A10,10 0 0,1 12,2M8,7.71V11.05L15.14,12L8,12.95V16.29L18,12L8,7.71Z'
			$W.StopGeomData = 'M12,2A10,10 0 0,1 22,12A10,10 0 0,1 12,22A10,10 0 0,1 2,12A10,10 0 0,1 12,2M9,9H15V15H9V9Z'
			$W.HdrLine1 = $window.FindName('HdrLine1')
			$W.HdrLine1Shadow = $window.FindName('HdrLine1Shadow')
			$W.HdrLine2 = $null
			$W.HdrLine2Shadow = $null
			$W.HdrToolGroups = $window.FindName('HdrToolGroups')
			$W.ToolGroupsFp = ''
			$W.ToolGroupsBuilt = $false
			$W.ToolGroupsDirty = $true
			$W.ToolGroupsData = $null
			$W.HdrPoweredBy = $window.FindName('HdrPoweredBy')
			$W.HdrPoweredByShadow = $window.FindName('HdrPoweredByShadow')
			$W.HdrPoweredByHost = $window.FindName('HdrPoweredByHost')
			$W.CustomTitleBar = $window.FindName('CustomTitleBar')
			$W.TitleRobotHost = $window.FindName('TitleRobotHost')
			$W.TitleRobotPath = $window.FindName('TitleRobotPath')
			$W.TitleRobotStop0 = $window.FindName('TitleRobotStop0')
			$W.TitleRobotStop1 = $window.FindName('TitleRobotStop1')
			$W.TitleRobotStop2 = $window.FindName('TitleRobotStop2')
			$W.TitleRobotShadow = $window.FindName('TitleRobotShadow')
			$W.TitleRobotTranslate = $window.FindName('TitleRobotTranslate')
			# Resolve gradient/effect refs if FindName missed them
			if ((-not $W.TitleRobotStop0 -or -not $W.TitleRobotStop1 -or -not $W.TitleRobotStop2) -and $W.TitleRobotPath) {
				try {
					$rb = $W.TitleRobotPath.Fill
					if ($rb -is [System.Windows.Media.LinearGradientBrush] -and $rb.GradientStops.Count -ge 3) {
						$W.TitleRobotStop0 = $rb.GradientStops[0]
						$W.TitleRobotStop1 = $rb.GradientStops[1]
						$W.TitleRobotStop2 = $rb.GradientStops[2]
					}
				} catch {}
			}
			if (-not $W.TitleRobotShadow -and $W.TitleRobotPath) {
				try { $W.TitleRobotShadow = $W.TitleRobotPath.Effect } catch {}
			}
			if (-not $W.TitleRobotTranslate -and $W.TitleRobotPath) {
				try {
					$rt = $W.TitleRobotPath.RenderTransform
					if ($rt -is [System.Windows.Media.TranslateTransform]) {
						$W.TitleRobotTranslate = $rt
					} else {
						$tt = New-Object System.Windows.Media.TranslateTransform(0, 0)
						$W.TitleRobotPath.RenderTransform = $tt
						$W.TitleRobotTranslate = $tt
					}
				} catch {}
			}
			if (-not $W.RobotGeomCache) { $W.RobotGeomCache = @{} }
			$W.RobotMood = ''
			$W.RobotErrorBounceOn = $false
			$W.RobotErrorStoryboard = $null
			$W.StopRobotErrorBounce = {
				try {
					if ($W.RobotErrorStoryboard) {
						try { $W.RobotErrorStoryboard.Stop() } catch {}
						try { $W.RobotErrorStoryboard.Children.Clear() } catch {}
						$W.RobotErrorStoryboard = $null
					}
					if ($W.TitleRobotTranslate) {
						try { $W.TitleRobotTranslate.BeginAnimation([System.Windows.Media.TranslateTransform]::YProperty, $null) } catch {}
						$W.TitleRobotTranslate.Y = 0
						$W.TitleRobotTranslate.X = 0
					}
					if ($W.TitleRobotShadow) {
						try {
							$W.TitleRobotShadow.BeginAnimation([System.Windows.Media.Effects.DropShadowEffect]::ShadowDepthProperty, $null)
							$W.TitleRobotShadow.BeginAnimation([System.Windows.Media.Effects.DropShadowEffect]::BlurRadiusProperty, $null)
						} catch {}
						try {
							$W.TitleRobotShadow.ShadowDepth = 1.25
							$W.TitleRobotShadow.BlurRadius = 3.5
						} catch {}
					}
					$W.RobotErrorBounceOn = $false
				} catch {}
			}.GetNewClosure()
			$W.StartRobotErrorBounce = {
				try {
					if ([bool]$W.RobotErrorBounceOn -and $W.RobotErrorStoryboard) { return }
					if (-not $W.TitleRobotPath) { return }
					if (-not $W.TitleRobotTranslate) {
						$tt = New-Object System.Windows.Media.TranslateTransform(0, 0)
						$W.TitleRobotPath.RenderTransform = $tt
						$W.TitleRobotTranslate = $tt
					}
					if (-not $W.TitleRobotShadow) {
						try { $W.TitleRobotShadow = $W.TitleRobotPath.Effect } catch {}
					}
					try {
						if ($W.RobotErrorStoryboard) {
							try { $W.RobotErrorStoryboard.Stop() } catch {}
							$W.RobotErrorStoryboard = $null
						}
						if ($W.TitleRobotTranslate) {
							try { $W.TitleRobotTranslate.BeginAnimation([System.Windows.Media.TranslateTransform]::YProperty, $null) } catch {}
							$W.TitleRobotTranslate.Y = 0
						}
					} catch {}

					$addKf = {
						param($anim, $ms, $val)
						$frame = New-Object System.Windows.Media.Animation.LinearDoubleKeyFrame
						$frame.KeyTime = [System.Windows.Media.Animation.KeyTime]::FromTimeSpan([TimeSpan]::FromMilliseconds($ms))
						$frame.Value = [double]$val
						[void]$anim.KeyFrames.Add($frame)
					}
					$cycleMs = 1350
					$yAnim = New-Object System.Windows.Media.Animation.DoubleAnimationUsingKeyFrames
					$yAnim.Duration = New-Object System.Windows.Duration ([TimeSpan]::FromMilliseconds($cycleMs))
					& $addKf $yAnim 0 0
					& $addKf $yAnim 120 -3
					& $addKf $yAnim 240 0
					& $addKf $yAnim 360 -3
					& $addKf $yAnim 480 0
					& $addKf $yAnim $cycleMs 0

					$depthAnim = New-Object System.Windows.Media.Animation.DoubleAnimationUsingKeyFrames
					$depthAnim.Duration = $yAnim.Duration
					& $addKf $depthAnim 0 1.25
					& $addKf $depthAnim 120 3.0
					& $addKf $depthAnim 240 1.25
					& $addKf $depthAnim 360 3.0
					& $addKf $depthAnim 480 1.25
					& $addKf $depthAnim $cycleMs 1.25

					$blurAnim = New-Object System.Windows.Media.Animation.DoubleAnimationUsingKeyFrames
					$blurAnim.Duration = $yAnim.Duration
					& $addKf $blurAnim 0 3.5
					& $addKf $blurAnim 120 5.0
					& $addKf $blurAnim 240 3.5
					& $addKf $blurAnim 360 5.0
					& $addKf $blurAnim 480 3.5
					& $addKf $blurAnim $cycleMs 3.5

					$story = New-Object System.Windows.Media.Animation.Storyboard
					$story.RepeatBehavior = [System.Windows.Media.Animation.RepeatBehavior]::Forever
					[System.Windows.Media.Animation.Storyboard]::SetTarget($yAnim, $W.TitleRobotTranslate)
					[System.Windows.Media.Animation.Storyboard]::SetTargetProperty($yAnim, (New-Object System.Windows.PropertyPath([System.Windows.Media.TranslateTransform]::YProperty)))
					[void]$story.Children.Add($yAnim)
					if ($W.TitleRobotShadow) {
						[System.Windows.Media.Animation.Storyboard]::SetTarget($depthAnim, $W.TitleRobotShadow)
						[System.Windows.Media.Animation.Storyboard]::SetTargetProperty($depthAnim, (New-Object System.Windows.PropertyPath([System.Windows.Media.Effects.DropShadowEffect]::ShadowDepthProperty)))
						[void]$story.Children.Add($depthAnim)
						[System.Windows.Media.Animation.Storyboard]::SetTarget($blurAnim, $W.TitleRobotShadow)
						[System.Windows.Media.Animation.Storyboard]::SetTargetProperty($blurAnim, (New-Object System.Windows.PropertyPath([System.Windows.Media.Effects.DropShadowEffect]::BlurRadiusProperty)))
						[void]$story.Children.Add($blurAnim)
					}
					$W.RobotErrorStoryboard = $story
					$story.Begin()
					$W.RobotErrorBounceOn = $true
				} catch {
					try { $W.RobotErrorBounceOn = $false } catch {}
				}
			}.GetNewClosure()
			# Apply robot face and gradient for status
			$W.SetRobotMood = {
				param([string]$Mode = 'ready', [bool]$Force = $false)
				try {
					if (-not $W.TitleRobotPath) { return }
					$m = ([string]$Mode).Trim().ToLowerInvariant()
					$face = 'happy'
					$isError = $false
					if ($m -match 'error|fail|dead') { $face = 'dead'; $isError = $true }
					elseif ($m -match 'think') { $face = 'confused' }
					elseif ($m -match 'work') { $face = 'excited' }
					elseif ($m -match 'compact|autocompact') { $face = 'default' }
					elseif ($m -match 'off|offline|disconnect') { $face = 'off' }
					elseif ($m -match 'angry|warn') { $face = 'angry' }
					elseif ($m -match 'happy|success') { $face = 'happy' }
					elseif ($m -match 'default|neutral|normal') { $face = 'default' }
					if (-not $Force -and [string]$W.RobotMood -eq $face -and [bool]$W.RobotErrorBounceOn -eq $isError) { return }

					$cat = $W.RobotCatalog
					if (-not $cat) { return }
					$faceKey = if (@($cat.Keys) -contains $face) { $face } else { 'default' }
					$data = [string]$cat[$faceKey]
					if ([string]::IsNullOrWhiteSpace($data)) { return }
					if (-not $W.RobotGeomCache) { $W.RobotGeomCache = @{} }
					if (-not $W.RobotGeomCache.ContainsKey($faceKey)) {
						$W.RobotGeomCache[$faceKey] = [System.Windows.Media.Geometry]::Parse($data)
					}
					$W.TitleRobotPath.Data = $W.RobotGeomCache[$faceKey]
					$W.RobotMood = $faceKey

					$cols = if ($isError) {
						@('#D0C4C6', '#B08084', '#9A585C')
					} else {
						@('#C8C8D0', '#6A6A74', '#3A3A42')
					}
					$stops = @($W.TitleRobotStop0, $W.TitleRobotStop1, $W.TitleRobotStop2)
					for ($si = 0; $si -lt 3; $si++) {
						if (-not $stops[$si]) { continue }
						try {
							$stops[$si].Color = [System.Windows.Media.ColorConverter]::ConvertFromString([string]$cols[$si])
						} catch {}
					}
					$tip = switch ($faceKey) {
						'confused' { 'thinking' }
						'excited'  { 'working' }
						'default'  { 'compacting' }
						'dead'     { 'error' }
						'off'      { 'offline' }
						'angry'    { 'warning' }
						default    { 'ready' }
					}
					$tipFull = 'MiniBot' + [string][char]0x00A0 + [string][char]0x00B7 + [string][char]0x00A0 + $tip
					if ($W.TitleRobotHost) { $W.TitleRobotHost.ToolTip = $tipFull }
					elseif ($W.TitleRobotPath) { $W.TitleRobotPath.ToolTip = $tipFull }
					if ($isError) {
						try { if ($W.StartRobotErrorBounce) { & $W.StartRobotErrorBounce } } catch {}
					} else {
						try { if ($W.StopRobotErrorBounce) { & $W.StopRobotErrorBounce } } catch {}
					}
					# Sync taskbar icon with robot face
					try {
						if ($W.ApplyWindowRobotIcon) { & $W.ApplyWindowRobotIcon $faceKey }
					} catch {}
				} catch {}
			}.GetNewClosure()
			try { & $W.SetRobotMood 'ready' $true } catch {}
			$W.TitleDotBrand = $window.FindName('TitleDotBrand')
			$W.TitleDotPath = $window.FindName('TitleDotPath')
			$W.TitleBrand = $window.FindName('TitleBrand')
			$W.TitleBrandName = $window.FindName('TitleBrandName')
			$W.TitleBrandNameShadow = $window.FindName('TitleBrandNameShadow')
			$W.TitlePath = $window.FindName('TitlePath')
			$W.TitlePathShadow = $window.FindName('TitlePathShadow')
			try {
				if ($W.TitlePath -and $W.SetThemedToolTip) {
					& $W.SetThemedToolTip $W.TitlePath 'Click to change working directory' 280
				} elseif ($W.TitlePath) {
					$W.TitlePath.ToolTip = 'Click to change working directory'
				}
			} catch {}
			$W.TitlePoweredBy = $window.FindName('TitlePoweredBy')
			$W.TitlePoweredByShadow = $window.FindName('TitlePoweredByShadow')
			$W.TitlePoweredByLabel = $window.FindName('TitlePoweredByLabel')
			$W.TitleModelPicker = $window.FindName('TitleModelPicker')
			$W.TitleModelPickerText = $window.FindName('TitleModelPickerText')
			$W.RemoteModelsSeqApplied = 0
			$W.ModelPickerUpdating = $false
			$W.ActiveModel = $(try { [string]$W.ActiveModel } catch { '' })
			$W.ModelDirty = $false
			if (-not $W.RemoteModels) { $W.RemoteModels = @() }
			$W.ShortModelLabel = {
				param([string]$Id, [int]$MaxLen = 36)
				$m = ([string]$Id).Trim()
				if ([string]::IsNullOrWhiteSpace($m)) { return 'Select Model' }
				if ($m.Length -le $MaxLen) { return $m }
				$m2 = $m -replace '\.gguf$', ''
				if ($m2.Length -le $MaxLen) { return $m2 }
				return ($m2.Substring(0, [math]::Max(1, $MaxLen - 3)) + '...')
			}.GetNewClosure()
			# Dark themed ToolTip (matches tool-group chips / menus)
			$W.MakeThemedToolTip = {
				param([string]$Text, [double]$MaxWidth = 340)
				if ([string]::IsNullOrWhiteSpace($Text)) { return $null }
				try {
					$bc = New-Object System.Windows.Media.BrushConverter
					foreach ($hx in @('#1A1A1E', '#C8C8D0', '#3A3A42')) {
						if (-not $W.BrushCache.ContainsKey($hx)) {
							try { $W.BrushCache[$hx] = $bc.ConvertFromString($hx) } catch {}
						}
					}
					$tipBg = $W.BrushCache['#1A1A1E']
					$tipFg = $W.BrushCache['#C8C8D0']
					$tipBd = $W.BrushCache['#3A3A42']
					$tip = New-Object System.Windows.Controls.ToolTip
					$tip.Background = $tipBg
					$tip.Foreground = $tipFg
					$tip.BorderBrush = $tipBd
					$tip.BorderThickness = New-Object System.Windows.Thickness(1)
					$tip.Padding = New-Object System.Windows.Thickness(10, 7, 10, 7)
					$tip.HasDropShadow = $true
					try { $tip.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Mouse } catch {}
					$ttb = New-Object System.Windows.Controls.TextBlock
					$ttb.Text = [string]$Text
					$ttb.TextWrapping = [System.Windows.TextWrapping]::Wrap
					$ttb.MaxWidth = [double]$MaxWidth
					$ttb.Foreground = $tipFg
					$ttb.FontSize = 12
					$ttb.LineHeight = 16
					try {
						if ($W.MonoFont) { $ttb.FontFamily = $W.MonoFont }
					} catch {}
					$tip.Content = $ttb
					return $tip
				} catch {
					return [string]$Text
				}
			}.GetNewClosure()
			$W.SetThemedToolTip = {
				param($Target, [string]$Text, [double]$MaxWidth = 340)
				if ($null -eq $Target) { return }
				try {
					$obj = $null
					if ($W.MakeThemedToolTip) { $obj = & $W.MakeThemedToolTip $Text $MaxWidth }
					if ($null -ne $obj) {
						$Target.ToolTip = $obj
						try {
							[System.Windows.Controls.ToolTipService]::SetInitialShowDelay($Target, 350)
							[System.Windows.Controls.ToolTipService]::SetShowDuration($Target, 20000)
						} catch {}
					} else {
						$Target.ToolTip = [string]$Text
					}
				} catch {
					try { $Target.ToolTip = [string]$Text } catch {}
				}
			}.GetNewClosure()
			$W.BuildModelMenu = {
				param([object[]]$Models = @(), [string]$Selected = '')
				try {
					$chip = $W.TitleModelPicker
					$lbl = $W.TitleModelPickerText
					if (-not $chip) { return }
					$bc = New-Object System.Windows.Media.BrushConverter
					foreach ($hx in @('#1A1A1E', '#C8C8D0', '#3A3A42', '#BB9AF7', '#8A8A96', '#B8F07A')) {
						if (-not $W.BrushCache.ContainsKey($hx)) {
							try { $W.BrushCache[$hx] = $bc.ConvertFromString($hx) } catch {}
						}
					}
					$menuBg = $W.BrushCache['#1A1A1E']
					$menuFg = $W.BrushCache['#C8C8D0']
					$chipBg = $W.BrushCache['#3A3A42']
					$accent = $W.BrushCache['#BB9AF7']
					$muted = $W.BrushCache['#8A8A96']
					$selFg = $W.BrushCache['#B8F07A']
					$entries = @()
					try { $entries = @($W.RemoteModelEntries) } catch { $entries = @() }
					if ($entries.Count -eq 0 -and $Models -and @($Models).Count -gt 0) {
						# Fallback: plain id list (primary only)
						$entries = @($Models | ForEach-Object {
							[pscustomobject]@{ Key = [string]$_; Id = [string]$_; Base = ''; Host = ''; Label = [string]$_ }
						})
					}
					$sel = ([string]$Selected).Trim()
					$selKey = ''
					try { $selKey = [string]$W.ActiveModelKey } catch { $selKey = '' }
					if ($entries.Count -eq 1) {
						$sel = [string]$entries[0].Id
						$selKey = [string]$entries[0].Key
						$curKey = ''
						try { $curKey = [string]$W.ActiveModelKey } catch { $curKey = '' }
						$W.ActiveModel = $sel
						$W.ActiveModelBase = [string]$entries[0].Base
						$W.ActiveModelKey = $selKey
						# Only mark dirty when selection actually changes (avoids switch/save loops)
						if ($curKey -ne $selKey) { $W.ModelDirty = $true }
					} elseif ($entries.Count -gt 1) {
						$hit = $null
						if ($selKey) { $hit = @($entries | Where-Object { $_.Key -eq $selKey } | Select-Object -First 1) }
						if (-not $hit -and $sel) { $hit = @($entries | Where-Object { $_.Id -eq $sel } | Select-Object -First 1) }
						if ($hit) {
							$sel = [string]$hit.Id
							$selKey = [string]$hit.Key
						} else {
							$sel = ''
							$selKey = ''
						}
					}
					$display = if ($sel) { (& $W.ShortModelLabel $sel 36) } else { 'Select Model' }
					if ($lbl) {
						$lbl.Text = $display
						$lbl.Foreground = $(if ($sel) { $accent } else { $muted })
					}
					if ($entries.Count -eq 0) {
						$chip.Opacity = 0.55
						$chip.IsEnabled = $true
						if ($W.SetThemedToolTip) {
							& $W.SetThemedToolTip $chip 'No models yet - click to refresh or add an endpoint'
						} else {
							$chip.ToolTip = 'No models yet - click to refresh or add an endpoint'
						}
					} else {
						$chip.Opacity = 1.0
						$chip.IsEnabled = $true
						$tipBase = ''
						try {
							if ($selKey) {
								$he = @($entries | Where-Object { $_.Key -eq $selKey } | Select-Object -First 1)
								if ($he -and $he.Host) { $tipBase = "`nEndpoint: $($he.Host)" }
							}
						} catch {}
						$tipTxt = if ($sel) {
							"Model: $sel$tipBase`nClick to open/close model list or add endpoint"
						} else {
							'Click to open/close model list or add endpoint'
						}
						if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $chip $tipTxt }
						else { $chip.ToolTip = $tipTxt }
					}
					$cm = New-Object System.Windows.Controls.ContextMenu
					try {
						$cm.Background = $menuBg
						$cm.Foreground = $menuFg
						$cm.BorderBrush = $chipBg
						$cm.BorderThickness = New-Object System.Windows.Thickness(1)
						$cm.Padding = New-Object System.Windows.Thickness(2)
						if ($null -eq $cm.Resources) { $cm.Resources = New-Object System.Windows.ResourceDictionary }
						try { $cm.Resources[[System.Windows.SystemColors]::MenuBrushKey] = $menuBg } catch {}
						try { $cm.Resources[[System.Windows.SystemColors]::MenuBarBrushKey] = $menuBg } catch {}
						try { $cm.Resources[[System.Windows.SystemColors]::ControlBrushKey] = $menuBg } catch {}
						try { $cm.Resources[[System.Windows.SystemColors]::MenuTextBrushKey] = $menuFg } catch {}
						try { $cm.Resources[[System.Windows.SystemColors]::HighlightBrushKey] = $chipBg } catch {}
						try { $cm.Resources[[System.Windows.SystemColors]::HighlightTextBrushKey] = $menuFg } catch {}
						try {
							$cmTplXaml = @'
<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="ContextMenu">
  <Border Background="{TemplateBinding Background}"
          BorderBrush="{TemplateBinding BorderBrush}"
          BorderThickness="{TemplateBinding BorderThickness}"
          CornerRadius="4" Padding="{TemplateBinding Padding}"
          SnapsToDevicePixels="True">
    <StackPanel IsItemsHost="True" KeyboardNavigation.DirectionalNavigation="Cycle"/>
  </Border>
</ControlTemplate>
'@
							$cmTpl = [Windows.Markup.XamlReader]::Parse($cmTplXaml)
							if ($null -ne $cmTpl) { $cm.Template = $cmTpl }
						} catch {}
						try {
							$miStyle = New-Object System.Windows.Style ([System.Windows.Controls.MenuItem])
							$miStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::BackgroundProperty, $menuBg)))
							$miStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::BorderThicknessProperty, (New-Object System.Windows.Thickness(0)))))
							$miStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::PaddingProperty, (New-Object System.Windows.Thickness(10, 5, 14, 5)))))
							$miTplXaml = @'
<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="MenuItem">
  <Border x:Name="Bd" Background="{TemplateBinding Background}"
          BorderThickness="0" Padding="{TemplateBinding Padding}" SnapsToDevicePixels="True"
          TextElement.Foreground="{TemplateBinding Foreground}">
    <ContentPresenter ContentSource="Header" RecognizesAccessKey="True"
                      VerticalAlignment="Center" HorizontalAlignment="Left"
                      TextElement.Foreground="{TemplateBinding Foreground}"/>
  </Border>
  <ControlTemplate.Triggers>
    <Trigger Property="IsHighlighted" Value="True">
      <Setter TargetName="Bd" Property="Background" Value="#3A3A42"/>
    </Trigger>
  </ControlTemplate.Triggers>
</ControlTemplate>
'@
							$miTpl = [Windows.Markup.XamlReader]::Parse($miTplXaml)
							if ($null -ne $miTpl) {
								$miStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::TemplateProperty, $miTpl)))
							}
							$cm.Resources[[System.Windows.Controls.MenuItem]] = $miStyle
						} catch {}
					} catch {}
					if ($entries.Count -eq 0) {
						$mi = New-Object System.Windows.Controls.MenuItem
						$mi.Header = 'No models . click chip to refresh'
						$mi.IsEnabled = $false
						$mi.Foreground = $muted
						[void]$cm.Items.Add($mi)
					} else {
						$menuCount = 0
						foreach ($ent in $entries) {
							$mid = [string]$ent.Id
							$ekey = [string]$ent.Key
							$elabel = if ($ent.Label) { [string]$ent.Label } else { $mid }
							# Active model stays on the chip only - never list it in the switch menu
							$isSel = ($selKey -and $ekey -eq $selKey) -or ((-not $selKey) -and $sel -and $mid -eq $sel)
							if ($isSel) { continue }
							$mi = New-Object System.Windows.Controls.MenuItem
							$mi.IsEnabled = $true
							$mi.Focusable = $false
							try { $mi.StaysOpenOnClick = $false } catch {}
							$hdr = New-Object System.Windows.Controls.TextBlock
							$hdr.Text = "  $elabel"
							$hdr.FontSize = 12
							$hdr.Foreground = $menuFg
							$mi.Header = $hdr
							$mi.Tag = [pscustomobject]@{ Id = $mid; Base = [string]$ent.Base; Key = $ekey }
							$mi.Background = $menuBg
							$mi.Foreground = $menuFg
							$null = $mi.Add_Click({
								param($s2, $e2)
								try {
									$tag = $null
									try { $tag = $s2.Tag } catch { $tag = $null }
									$id = ''; $b = ''; $k = ''
									if ($tag -is [string]) { $id = [string]$tag }
									else {
										try { $id = [string]$tag.Id } catch {}
										try { $b = [string]$tag.Base } catch {}
										try { $k = [string]$tag.Key } catch {}
									}
									if ([string]::IsNullOrWhiteSpace($id)) { return }
									$W.ActiveModel = $id
									$W.ActiveModelBase = $b
									$W.ActiveModelKey = $k
									$W.ModelDirty = $true
									if ($W.TitleModelPickerText) {
										$W.TitleModelPickerText.Text = (& $W.ShortModelLabel $id 36)
										$W.TitleModelPickerText.Foreground = $W.BrushCache['#BB9AF7']
									}
									if ($W.TitleModelPicker) {
										$tipTxt = "Model: $id`nClick to change or add endpoint"
										if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $W.TitleModelPicker $tipTxt }
										else { $W.TitleModelPicker.ToolTip = $tipTxt }
									}
									try {
										if ($W.BuildModelMenu) { & $W.BuildModelMenu @($W.RemoteModels) $id }
									} catch {}
								} catch {}
							}.GetNewClosure())
							[void]$cm.Items.Add($mi)
							$menuCount++
						}
						if ($menuCount -eq 0 -and $entries.Count -gt 0) {
							$mi = New-Object System.Windows.Controls.MenuItem
							$mi.Header = '(active model - add another endpoint to switch)'
							$mi.IsEnabled = $false
							$mi.Foreground = $muted
							[void]$cm.Items.Add($mi)
						}
					}
					# Separator + add endpoint
					try {
						$sep = New-Object System.Windows.Controls.Separator
						try { $sep.Background = $chipBg } catch {}
						try { $sep.Margin = New-Object System.Windows.Thickness(4, 4, 4, 4) } catch {}
						[void]$cm.Items.Add($sep)
					} catch {}
					$addMi = New-Object System.Windows.Controls.MenuItem
					$addMi.IsEnabled = $true
					$addMi.Focusable = $false
					$addHdr = New-Object System.Windows.Controls.TextBlock
					$addHdr.Text = '+  Add endpoint...'
					$addHdr.FontSize = 12
					$addHdr.Foreground = $accent
					$addMi.Header = $addHdr
					$addMi.Background = $menuBg
					$addMi.Foreground = $accent
					$null = $addMi.Add_Click({
						param($s2, $e2)
						try {
							if ($W.ShowAddEndpointDialog) { & $W.ShowAddEndpointDialog }
						} catch {}
					}.GetNewClosure())
					[void]$cm.Items.Add($addMi)
					try {
						$cm.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Bottom
						$cm.PlacementTarget = $chip
						$cm.HorizontalOffset = 0
						$cm.VerticalOffset = 2
					} catch {}
					# Keep open state if rebuild happens while menu is visible
					$wasShowing = $false
					try { $wasShowing = [bool]$W.ModelMenuIsShowing } catch { $wasShowing = $false }
					try {
						$oldCm = $chip.ContextMenu
						if ($oldCm -and [bool]$oldCm.IsOpen) {
							$wasShowing = $true
							try { $oldCm.IsOpen = $false } catch {}
						}
					} catch {}
					$chip.ContextMenu = $cm
					$null = $cm.Add_Closed({
						try { $W.ModelMenuIsShowing = $false } catch {}
						# Same left-click that dismisses the menu is delivered to the chip next —
						# stamp close time so PreviewMouseLeftButtonDown does not reopen it.
						try { $W.ModelMenuClosedTick = [Environment]::TickCount } catch {}
					}.GetNewClosure())
					# One-time click toggle (open on first click, close on second)
					if (-not $W.ModelPickerClickHooked) {
						$W.ModelPickerClickHooked = $true
						try { $W.ModelMenuIsShowing = $false } catch {}
						try { $W.ModelMenuClosedTick = 0 } catch {}
						$null = $chip.Add_PreviewMouseLeftButtonDown({
							param($sender, $e)
							try {
								if (-not $sender) { return }
								$m = $null
								try { $m = $sender.ContextMenu } catch { $m = $null }
								if (-not $m) { return }
								$e.Handled = $true
								$now = [Environment]::TickCount

								# Click that just closed the menu (WPF closes first, then raises this on the chip)
								$closedTick = 0
								try { $closedTick = [int]$W.ModelMenuClosedTick } catch { $closedTick = 0 }
								if ($closedTick -ne 0) {
									$dt = ($now - $closedTick) -band 0x7fffffff
									if ($dt -lt 500) {
										try { $W.ModelMenuClosedTick = 0 } catch {}
										try { $W.ModelMenuIsShowing = $false } catch {}
										try { $m.IsOpen = $false } catch {}
										return
									}
								}

								$isOpen = $false
								try { if ([bool]$m.IsOpen) { $isOpen = $true } } catch {}
								try { if ([bool]$W.ModelMenuIsShowing) { $isOpen = $true } } catch {}
								if ($isOpen) {
									try { $W.ModelMenuIsShowing = $false } catch {}
									try { $W.ModelMenuClosedTick = $now } catch {}
									try { $m.IsOpen = $false } catch {}
									return
								}

								# Open (refresh list only when empty — rebuild while open breaks toggle)
								try {
									$needRefresh = $false
									$ents = $null
									try { $ents = @($W.RemoteModelEntries) } catch { $ents = @() }
									if (-not $ents -or $ents.Count -eq 0) { $needRefresh = $true }
									if ($needRefresh) { $W.RemoteModelsRefreshWanted = $true }
								} catch {}
								try {
									$m.PlacementTarget = $sender
									$m.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Bottom
									$m.HorizontalOffset = 0
									$m.VerticalOffset = 2
								} catch {}
								try { $W.ModelMenuClosedTick = 0 } catch {}
								try { $W.ModelMenuIsShowing = $true } catch {}
								$m.IsOpen = $true
							} catch {}
						}.GetNewClosure())
					}
					if ($wasShowing) {
						try {
							$W.ModelMenuIsShowing = $true
							$cm.IsOpen = $true
						} catch {}
					}
				} catch {}
			}.GetNewClosure()
			$W.ApplyModelPicker = {
				param([object[]]$Models = @(), [string]$Selected = '')
				try {
					if ($W.BuildModelMenu) { & $W.BuildModelMenu $Models $Selected }
				} catch {}
			}.GetNewClosure()
			$W.ShowAddEndpointDialog = {
				try {
					$owner = $W.Window
					if (-not $owner) { return }
					$bc = New-Object System.Windows.Media.BrushConverter
					$dlg = New-Object System.Windows.Window
					$dlg.Title = 'MiniBot - Add endpoint'
					$dlg.Width = 480
					$dlg.Height = 380
					$dlg.WindowStartupLocation = [System.Windows.WindowStartupLocation]::CenterOwner
					$dlg.Owner = $owner
					$dlg.ResizeMode = [System.Windows.ResizeMode]::NoResize
					$dlg.WindowStyle = [System.Windows.WindowStyle]::None
					$dlg.AllowsTransparency = $true
					$dlg.Background = [System.Windows.Media.Brushes]::Transparent
					$dlg.Foreground = $bc.ConvertFromString('#C8C8D0')
					try {
						if ($W.Window -and $W.Window.Icon) { $dlg.Icon = $W.Window.Icon }
					} catch {}
					$outer = New-Object System.Windows.Controls.Border
					$outer.Background = $bc.ConvertFromString('#121216')
					$outer.BorderBrush = $bc.ConvertFromString('#2A2A30')
					$outer.BorderThickness = New-Object System.Windows.Thickness(1)
					$outer.CornerRadius = New-Object System.Windows.CornerRadius(8)
