							$dlg.IsEnabled = $false
							try { $dlg.Dispatcher.Invoke([action]{}, [System.Windows.Threading.DispatcherPriority]::Background) } catch {}
							$ok = $false
							$msg = ''
							try {
								$testUrl = [string]$url
								if ($testUrl -notmatch '^(?i)https?://') {
									if ($testUrl -match '^\d+$') { $testUrl = "http://127.0.0.1:$testUrl" }
									else { $testUrl = "http://$testUrl" }
								}
								while ($testUrl.EndsWith('/')) { $testUrl = $testUrl.Substring(0, $testUrl.Length - 1) }
								$testUrl = $testUrl -replace '/chat/completions\s*$', '' -replace '/models\s*$', ''
								$testUrl = $testUrl -replace '/v1/chat/completions\s*$', '' -replace '/v1/models\s*$', ''
								$candidates = New-Object System.Collections.ArrayList
								# Prefer /v1 first (vLLM / Unsloth / OpenAI-compat)
								if ($testUrl -match '/v1$') {
									[void]$candidates.Add($testUrl)
									$rootCand = $testUrl -replace '/v1$', ''
									if ($rootCand) { [void]$candidates.Add($rootCand) }
								} else {
									[void]$candidates.Add($testUrl + '/v1')
									[void]$candidates.Add($testUrl)
								}
								$headers = @{}
								try {
									if ($authMode -eq 'apikey' -and -not [string]::IsNullOrWhiteSpace($apiKeyIn) -and $apiKeyIn -notin @('none','null','-')) {
										$headers['Authorization'] = 'Bearer ' + $apiKeyIn.Trim()
									} elseif ($authMode -eq 'npm') {
										if ($W.NpmUser -and $W.NpmPass) {
											$b64 = [System.Text.Encoding]::UTF8.GetBytes(("{0}:{1}" -f $W.NpmUser, $W.NpmPass))
											$headers['Authorization'] = 'Basic ' + [Convert]::ToBase64String($b64)
										} else {
											throw 'NPM auth selected but session has no NPM credentials (log in first).'
										}
									}
									# authMode 'none' → no Authorization header
								} catch {
									$lastErr = $_.Exception.Message
									throw
								}
								$foundBase = ''
								$foundIds = New-Object System.Collections.ArrayList
								$lastErr = ''
								foreach ($base in $candidates) {
									try {
										$resp = Invoke-WebRequest -Uri "$base/models" -Method GET -Headers $headers -TimeoutSec 8 -UseBasicParsing -ErrorAction Stop
										if ([int]$resp.StatusCode -ne 200) { continue }
										$bodyTxt = [string]$resp.Content
										if ($bodyTxt.TrimStart().StartsWith('<')) { continue }
										$obj = $bodyTxt | ConvertFrom-Json -ErrorAction Stop
										$ids = New-Object System.Collections.ArrayList
										$rows = @()
										if ($obj.data) { $rows = @($obj.data) }
										elseif ($obj.models) { $rows = @($obj.models) }
										elseif ($obj -is [System.Array]) { $rows = @($obj) }
										elseif ($obj.id) { $rows = @($obj) }
										foreach ($row in $rows) {
											$sid = ''
											if ($row -is [string]) { $sid = $row }
											else {
												try { $sid = [string]$row.id } catch {}
												if (-not $sid) { try { $sid = [string]$row.model } catch {} }
												if (-not $sid) { try { $sid = [string]$row.name } catch {} }
												if (-not $sid) { try { $sid = [string]$row.display_name } catch {} }
											}
											$sid = ([string]$sid).Trim()
											if ($sid -and $ids -notcontains $sid) { [void]$ids.Add($sid) }
										}
										if ($ids.Count -gt 0) {
											$foundBase = $base
											$foundIds = $ids
											break
										}
									} catch {
										$lastErr = $_.Exception.Message
										continue
									}
								}
								if ($foundBase -and $foundIds.Count -gt 0) {
									$ok = $true
									$modeLabel = switch ($authMode) { 'npm' { 'Basic (NPM)' } 'none' { 'None' } default { 'API' } }
									$msg = ("OK - {0} model(s) at {1} ({2})" -f $foundIds.Count, $foundBase, $modeLabel)
									try {
										$lst = New-Object System.Collections.ArrayList
										foreach ($x in @($W.ExtraApiBases)) {
											if ($x) { [void]$lst.Add([string]$x) }
										}
										$haveBase = $false
										foreach ($x in @($lst)) {
											if ([string]::Equals([string]$x, $foundBase, [StringComparison]::OrdinalIgnoreCase)) { $haveBase = $true; break }
										}
										if (-not $haveBase) { [void]$lst.Add($foundBase) }
										$W.ExtraApiBases = @($lst)
										# Per-endpoint auth mode + optional Bearer key
										try {
											if ($null -eq $W.ExtraApiAuth -or -not ($W.ExtraApiAuth -is [hashtable])) {
												$W.ExtraApiAuth = @{}
											}
											$W.ExtraApiAuth[$foundBase] = $authMode
											$rootAuth = $foundBase -replace '/v1$', ''
											if ($rootAuth) { $W.ExtraApiAuth[$rootAuth] = $authMode }
											if ($foundBase -notmatch '/v1$') { $W.ExtraApiAuth[($foundBase + '/v1')] = $authMode }
										} catch {}
										if ($authMode -eq 'apikey' -and -not [string]::IsNullOrWhiteSpace($apiKeyIn) -and $apiKeyIn -notin @('none','null','-')) {
											try {
												if ($null -eq $W.ExtraApiKeys -or -not ($W.ExtraApiKeys -is [hashtable])) {
													$W.ExtraApiKeys = @{}
												}
												$W.ExtraApiKeys[$foundBase] = $apiKeyIn.Trim()
												$rootB = $foundBase -replace '/v1$', ''
												if ($rootB) { $W.ExtraApiKeys[$rootB] = $apiKeyIn.Trim() }
												if ($foundBase -notmatch '/v1$') { $W.ExtraApiKeys[($foundBase + '/v1')] = $apiKeyIn.Trim() }
											} catch {}
											$W.PendingAddBaseApiKey = $apiKeyIn.Trim()
										} else {
											$W.PendingAddBaseApiKey = ''
										}
										$W.PendingAddBaseAuthMode = $authMode
										# Queue for main runspace: merge bases, re-probe, select model, reload banner text
										$W.PendingAddBaseUrl = $foundBase
										$W.PendingAddBaseDirty = $true
										$W.RemoteModelsRefreshWanted = $true
										# Optimistic: put new models into PoweredBy list immediately so they survive
										# switching back to primary llama.cpp before main refresh finishes
										try {
											$hostLab = $foundBase
											try {
												$uTmp = [uri]$foundBase
												if ($uTmp.IsDefaultPort) { $hostLab = $uTmp.Host }
												else { $hostLab = ("{0}:{1}" -f $uTmp.Host, $uTmp.Port) }
											} catch {}
											$entList = New-Object System.Collections.ArrayList
											$seenKeys = @{}
											foreach ($ex in @($W.RemoteModelEntries)) {
												if (-not $ex) { continue }
												$ek = [string]$ex.Key
												if ($ek -and -not $seenKeys.ContainsKey($ek)) {
													$seenKeys[$ek] = $true
													[void]$entList.Add($ex)
												}
											}
											$idList = New-Object System.Collections.ArrayList
											foreach ($xid in @($W.RemoteModels)) {
												if ($xid -and $idList -notcontains [string]$xid) { [void]$idList.Add([string]$xid) }
											}
											$multi = ($entList.Count -gt 0) -or ($foundIds.Count -gt 0)
											foreach ($nid in @($foundIds)) {
												$nid = [string]$nid
												if ([string]::IsNullOrWhiteSpace($nid)) { continue }
												$nkey = ('{0}|{1}' -f $nid, $foundBase)
												if ($seenKeys.ContainsKey($nkey)) { continue }
												$seenKeys[$nkey] = $true
												$lab = if ($multi) { "{0}  @  {1}" -f $nid, $hostLab } else { $nid }
												[void]$entList.Add([pscustomobject]@{
													Key = $nkey; Id = $nid; Base = $foundBase
													Host = $hostLab; Label = $lab
													NCtx = 0; NCtxTrain = 0; NParams = 0; Size = 0; Vision = $false
												})
												if ($idList -notcontains $nid) { [void]$idList.Add($nid) }
											}
											# Multi-endpoint labels for pre-existing entries too
											if ($entList.Count -gt 1) {
												$relabeled = New-Object System.Collections.ArrayList
												foreach ($ex in @($entList)) {
													$hid = if ($ex.Host) { [string]$ex.Host } else { 'endpoint' }
													$lab2 = "{0}  @  {1}" -f [string]$ex.Id, $hid
													[void]$relabeled.Add([pscustomobject]@{
														Key = [string]$ex.Key; Id = [string]$ex.Id; Base = [string]$ex.Base
														Host = $hid; Label = $lab2
														NCtx = $(try { [int]$ex.NCtx } catch { 0 })
														NCtxTrain = $(try { [int]$ex.NCtxTrain } catch { 0 })
														NParams = $(try { [double]$ex.NParams } catch { 0 })
														Size = $(try { [double]$ex.Size } catch { 0 })
														Vision = $(try { [bool]$ex.Vision } catch { $false })
													})
												}
												$entList = $relabeled
											}
											$W.RemoteModelEntries = @($entList)
											$W.RemoteModels = @($idList)
											$W.RemoteModelsSeq = (Get-Date).Ticks
										} catch {}
										# Optimistic PoweredBy label until main finishes refresh
										try {
											$firstId = [string](@($foundIds)[0])
											if ($firstId) {
												$W.ActiveModel = $firstId
												$W.ActiveModelBase = $foundBase
												$W.ActiveModelKey = ('{0}|{1}' -f $firstId, $foundBase)
												$W.ModelDirty = $true
												if ($W.TitleModelPickerText) {
													$short = $firstId
													if ($short.Length -gt 36) { $short = $short.Substring(0, 33) + '...' }
													$W.TitleModelPickerText.Text = $short
													$W.TitleModelPickerText.Foreground = $W.BrushCache['#BB9AF7']
												}
												if ($W.BuildModelMenu) {
													& $W.BuildModelMenu @($W.RemoteModels) $firstId
												}
											}
										} catch {}
									} catch {}
								} else {
									$ok = $false
									if ($lastErr -match '(?i)401|Not authenticated|Invalid token|Unauthorized') {
										$msg = 'Auth failed - pick API and enter a Bearer token, or pick Basic (NPM) if this host uses reverse-proxy login.'
									} elseif ($lastErr) {
										$msg = $lastErr
									} else {
										$msg = 'Connection failed or no models at that endpoint'
									}
								}
							} catch {
								$ok = $false
								$msg = $_.Exception.Message
							}
							$dlg.IsEnabled = $true
							if ($ok) {
								$status.Foreground = $bc.ConvertFromString('#9ECE6A')
								$status.Text = $msg
								# Do not rebuild menu from stale RemoteModels — wait for RemoteModelsSeq after main refresh
								Start-Sleep -Milliseconds 250
								try { $dlg.DialogResult = $true } catch {}
								$dlg.Close()
							} else {
								$status.Foreground = $bc.ConvertFromString('#F05C5C')
								$status.Text = $(if ($msg) { $msg } else { 'Connection failed' })
							}
						} catch {
							try { $dlg.IsEnabled = $true } catch {}
							try {
								$status.Foreground = $bc.ConvertFromString('#F05C5C')
								$status.Text = $_.Exception.Message
							} catch {}
						}
					}.GetNewClosure())
					try { $box.Focus() } catch {}
					try { $box.SelectAll() } catch {}
					[void]$dlg.ShowDialog()
				} catch {}
			}.GetNewClosure()
			try {
				$initModels = @()
				try { $initModels = @($W.RemoteModels) } catch { $initModels = @() }
				$initSel = ''
				try { $initSel = [string]$W.ActiveModel } catch { $initSel = '' }
				if ($W.ApplyModelPicker) { & $W.ApplyModelPicker $initModels $initSel }
			} catch {}
			$W.TitleBtnMin = $window.FindName('TitleBtnMin')
			$W.TitleBtnMax = $window.FindName('TitleBtnMax')
			$W.TitleBtnClose = $window.FindName('TitleBtnClose')
			$W.TitleBtnMinPath = $window.FindName('TitleBtnMinPath')
			$W.TitleBtnMaxPath = $window.FindName('TitleBtnMaxPath')
			$W.TitleBtnClosePath = $window.FindName('TitleBtnClosePath')
			# Maximize to work area (not WindowState.Maximized)
			$W.IsWorkAreaMaximized = $false
			$W.RestoreBounds = $null
			$W.MaxGeom = 'M0.5,0.5 H9.5 V9.5 H0.5 Z'
			$W.RestoreGeom = 'M0,3 H7.5 V10.5 H0 Z M3,0 H10.5 V7.5'
			# Titlebar window buttons
			try {
				$getWorkAreaForWindow = {
					param($win)
					try {
						Add-Type -AssemblyName System.Windows.Forms -ErrorAction SilentlyContinue
						$helper = New-Object System.Windows.Interop.WindowInteropHelper($win)
						$hwnd = $helper.Handle
						$scr = $null
						if ($hwnd -ne [IntPtr]::Zero) {
							$scr = [System.Windows.Forms.Screen]::FromHandle($hwnd)
						} else {
							$cx = [int]($win.Left + ($win.Width / 2.0))
							$cy = [int]($win.Top + ($win.Height / 2.0))
							$scr = [System.Windows.Forms.Screen]::FromPoint((New-Object System.Drawing.Point($cx, $cy)))
						}
						$wa = $scr.WorkingArea
						$src = [System.Windows.PresentationSource]::FromVisual($win)
						if ($src -and $src.CompositionTarget) {
							$t = $src.CompositionTarget.TransformFromDevice
							$p1 = $t.Transform((New-Object System.Windows.Point($wa.Left, $wa.Top)))
							$p2 = $t.Transform((New-Object System.Windows.Point(($wa.Left + $wa.Width), ($wa.Top + $wa.Height))))
							return @{ Left = [double]$p1.X; Top = [double]$p1.Y; Width = [double]($p2.X - $p1.X); Height = [double]($p2.Y - $p1.Y) }
						}
						return @{ Left = [double]$wa.Left; Top = [double]$wa.Top; Width = [double]$wa.Width; Height = [double]$wa.Height }
					} catch {
						$r = [System.Windows.SystemParameters]::WorkArea
						return @{ Left = [double]$r.Left; Top = [double]$r.Top; Width = [double]$r.Width; Height = [double]$r.Height }
					}
				}.GetNewClosure()
				$W.GetWorkAreaForWindow = $getWorkAreaForWindow
				$setMaxIcon = {
					param([bool]$isMax)
					try {
						if ($W.TitleBtnMaxPath) {
							$g = if ($isMax) { $W.RestoreGeom } else { $W.MaxGeom }
							$W.TitleBtnMaxPath.Data = [System.Windows.Media.Geometry]::Parse([string]$g)
						}
						if ($W.TitleBtnMax) {
							$tip = if ($isMax) { 'Restore' } else { 'Maximize' }
							if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $W.TitleBtnMax $tip 180 }
							else { $W.TitleBtnMax.ToolTip = $tip }
						}
					} catch {}
				}.GetNewClosure()
				$W.SetMaxIcon = $setMaxIcon
				$toggleWorkAreaMax = {
					try {
						if ($W.IsWorkAreaMaximized) {
							$rb = $W.RestoreBounds
							if ($rb) {
								$window.Left = [double]$rb.Left
								$window.Top = [double]$rb.Top
								$window.Width = [double]$rb.Width
								$window.Height = [double]$rb.Height
							}
							$W.IsWorkAreaMaximized = $false
							& $setMaxIcon $false
						} else {
							$W.RestoreBounds = @{
								Left = [double]$window.Left
								Top = [double]$window.Top
								Width = [double]$window.Width
								Height = [double]$window.Height
							}
							try { $window.WindowState = [System.Windows.WindowState]::Normal } catch {}
							$wa = & $getWorkAreaForWindow $window
							$window.Left = [double]$wa.Left
							$window.Top = [double]$wa.Top
							$window.Width = [Math]::Max(200.0, [double]$wa.Width)
							$window.Height = [Math]::Max(150.0, [double]$wa.Height)
							$W.IsWorkAreaMaximized = $true
							& $setMaxIcon $true
						}
						try {
							if ($W.ApplyWindowChromeCorners) { & $W.ApplyWindowChromeCorners $window $W }
						} catch {}
					} catch {}
				}.GetNewClosure()
				$W.ToggleWorkAreaMax = $toggleWorkAreaMax
				# Themed tooltips (title chrome)
				try {
					if ($W.SetThemedToolTip) {
						if ($W.TitleBtnMin) { & $W.SetThemedToolTip $W.TitleBtnMin 'Minimize' 160 }
						if ($W.TitleBtnMax) {
							$mx = if ([bool]$W.IsWorkAreaMaximized) { 'Restore' } else { 'Maximize' }
							& $W.SetThemedToolTip $W.TitleBtnMax $mx 160
						}
						if ($W.TitleBtnClose) { & $W.SetThemedToolTip $W.TitleBtnClose 'Close' 140 }
					}
				} catch {}
				# Hover: exit red, min/max lighter grey (NoMouseOver - Background only)
				$bcTitle = New-Object System.Windows.Media.BrushConverter
				$hoverGrey = $bcTitle.ConvertFromString('#3A3A42')
				$hoverRed = $bcTitle.ConvertFromString('#E81123')
				$hoverClear = [System.Windows.Media.Brushes]::Transparent
				if ($W.TitleBtnMin) {
					$W.TitleBtnMin.add_MouseEnter({
						try { $W.TitleBtnMin.Background = $hoverGrey } catch {}
					}.GetNewClosure())
					$W.TitleBtnMin.add_MouseLeave({
						try { $W.TitleBtnMin.Background = $hoverClear } catch {}
					}.GetNewClosure())
					$W.TitleBtnMin.add_Click({
						try { $window.WindowState = [System.Windows.WindowState]::Minimized } catch {}
					}.GetNewClosure())
				}
				if ($W.TitleBtnMax) {
					$W.TitleBtnMax.add_MouseEnter({
						try { $W.TitleBtnMax.Background = $hoverGrey } catch {}
					}.GetNewClosure())
					$W.TitleBtnMax.add_MouseLeave({
						try { $W.TitleBtnMax.Background = $hoverClear } catch {}
					}.GetNewClosure())
					$W.TitleBtnMax.add_Click({
						try { & $toggleWorkAreaMax } catch {}
					}.GetNewClosure())
				}
				if ($W.TitleBtnClose) {
					$W.TitleBtnClose.add_MouseEnter({
						try { $W.TitleBtnClose.Background = $hoverRed } catch {}
					}.GetNewClosure())
					$W.TitleBtnClose.add_MouseLeave({
						try { $W.TitleBtnClose.Background = $hoverClear } catch {}
					}.GetNewClosure())
					$W.TitleBtnClose.add_Click({
						try { $window.Close() } catch {}
					}.GetNewClosure())
				}
				# Double-click titlebar maximizes to work area
				if ($W.CustomTitleBar) {
					$W.CustomTitleBar.add_MouseLeftButtonDown({
						param($s, $e)
						try {
							if ($e.ClickCount -eq 2) { & $toggleWorkAreaMax }
						} catch {}
					}.GetNewClosure())
				}
				# Title path: cwd editor popup
				try {
					if ($W.TitlePath) {
						if (-not $W.BrushCache) { $W.BrushCache = @{} }
						$bcCwd = New-Object System.Windows.Media.BrushConverter
						$cwdHexes = @('#121216', '#1E1E24', '#2A2A30', '#3A3A42', '#E0E0E8', '#C8C8D0', '#6A6A76', '#F05C5C', '#7DCFFF', '#4A4A56', '#5C5C6A', '#3A3A48', '#363640', '#5A5A66', '#222228')
						foreach ($hx in $cwdHexes) {
							if (-not $W.BrushCache.ContainsKey($hx)) {
								try { $W.BrushCache[$hx] = $bcCwd.ConvertFromString($hx) } catch {}
							}
						}
						$cwdPopup = New-Object System.Windows.Controls.Primitives.Popup
						$cwdPopup.StaysOpen = $true
						$cwdPopup.AllowsTransparency = $true
						$cwdPopup.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Bottom
						$cwdPopup.PlacementTarget = $W.TitlePath
						$cwdPopup.HorizontalOffset = 0
						$cwdPopup.VerticalOffset = 4
						$cwdShell = New-Object System.Windows.Controls.Border
						$cwdShell.Background = $W.BrushCache['#121216']
						$cwdShell.BorderBrush = $W.BrushCache['#2A2A30']
						$cwdShell.BorderThickness = New-Object System.Windows.Thickness(1)
						$cwdShell.CornerRadius = New-Object System.Windows.CornerRadius(8)
						$cwdShell.Padding = New-Object System.Windows.Thickness(12, 10, 12, 10)
						$cwdShell.MinWidth = 420
						$cwdShell.MaxWidth = 640
						$cwdShell.SnapsToDevicePixels = $true
						$cwdRoot = New-Object System.Windows.Controls.StackPanel
						$cwdRoot.Orientation = [System.Windows.Controls.Orientation]::Vertical
						$cwdLabel = New-Object System.Windows.Controls.TextBlock
						$cwdLabel.Text = 'Working directory'
						$cwdLabel.Foreground = $W.BrushCache['#C8C8D0']
						$cwdLabel.FontSize = 12
						$cwdLabel.FontWeight = [System.Windows.FontWeights]::SemiBold
						$cwdLabel.Margin = New-Object System.Windows.Thickness(0, 0, 0, 8)
						$cwdRow = New-Object System.Windows.Controls.DockPanel
						$cwdRow.LastChildFill = $true
						$cwdRow.Margin = New-Object System.Windows.Thickness(0, 0, 0, 6)
						$cwdGo = New-Object System.Windows.Controls.Button
						$cwdGo.Content = 'Go'
						$cwdGo.MinWidth = 52
						$cwdGo.Height = 30
						$cwdGo.Margin = New-Object System.Windows.Thickness(6, 0, 0, 0)
						$cwdGo.Padding = New-Object System.Windows.Thickness(10, 0, 10, 0)
						$cwdGo.Cursor = [System.Windows.Input.Cursors]::Hand
						$cwdGo.Focusable = $true
						$cwdGo.Background = $W.BrushCache['#2A2A30']
						$cwdGo.Foreground = $W.BrushCache['#C8C8D0']
						$cwdGo.BorderBrush = $W.BrushCache['#3A3A42']
						$cwdGo.BorderThickness = New-Object System.Windows.Thickness(1)
						try {
							$cwdGo.Template = [System.Windows.Markup.XamlReader]::Parse(@'
<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="Button">
  <Border x:Name="Bd" Background="{TemplateBinding Background}"
          BorderBrush="{TemplateBinding BorderBrush}"
          BorderThickness="{TemplateBinding BorderThickness}"
          CornerRadius="4" Padding="{TemplateBinding Padding}" SnapsToDevicePixels="True">
    <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/>
  </Border>
  <ControlTemplate.Triggers>
    <Trigger Property="IsMouseOver" Value="True">
      <Setter TargetName="Bd" Property="Background" Value="#363640"/>
      <Setter TargetName="Bd" Property="BorderBrush" Value="#5A5A66"/>
    </Trigger>
    <Trigger Property="IsPressed" Value="True">
      <Setter TargetName="Bd" Property="Background" Value="#222228"/>
    </Trigger>
  </ControlTemplate.Triggers>
</ControlTemplate>
'@)
						} catch {}
						[System.Windows.Controls.DockPanel]::SetDock($cwdGo, [System.Windows.Controls.Dock]::Right)
						$cwdBox = New-Object System.Windows.Controls.TextBox
						$cwdBox.Height = 30
						$cwdBox.Padding = New-Object System.Windows.Thickness(8, 5, 8, 5)
						$cwdBox.Background = $W.BrushCache['#121216']
						$cwdBox.Foreground = $W.BrushCache['#E0E0E8']
						$cwdBox.CaretBrush = $W.BrushCache['#C8C8D0']
						$cwdBox.BorderBrush = $W.BrushCache['#3A3A42']
						$cwdBox.BorderThickness = New-Object System.Windows.Thickness(1)
						$cwdBox.VerticalContentAlignment = [System.Windows.VerticalAlignment]::Center
						try {
							$cwdBox.FontFamily = New-Object System.Windows.Media.FontFamily('Consolas, Cascadia Mono, Courier New')
						} catch {}
						$cwdBox.FontSize = 13
						[void]$cwdRow.Children.Add($cwdGo)
						[void]$cwdRow.Children.Add($cwdBox)
						$cwdStatus = New-Object System.Windows.Controls.TextBlock
						$cwdStatus.Text = 'Enter a folder path, then Go'
						$cwdStatus.Foreground = $W.BrushCache['#6A6A76']
						$cwdStatus.FontSize = 11
						$cwdStatus.TextWrapping = [System.Windows.TextWrapping]::Wrap
						[void]$cwdRoot.Children.Add($cwdLabel)
						[void]$cwdRoot.Children.Add($cwdRow)
						[void]$cwdRoot.Children.Add($cwdStatus)
						$cwdShell.Child = $cwdRoot
						$cwdPopup.Child = $cwdShell
						$W.CwdPopup = $cwdPopup
						$W.CwdPopupBox = $cwdBox
						$W.CwdPopupGo = $cwdGo
						$W.CwdPopupStatus = $cwdStatus
						$openCwdPopup = {
							try {
								$cur = ''
								try { $cur = [string]$W.CurrentCwd } catch {}
								if ([string]::IsNullOrWhiteSpace($cur)) {
									try { $cur = [string]$W.TitlePath.Text } catch {}
								}
								if ([string]::IsNullOrWhiteSpace($cur)) {
									try { $cur = [Environment]::CurrentDirectory } catch { $cur = '' }
								}
								$W.CwdPopupBox.Text = $cur
								$W.CwdPopupStatus.Text = 'Enter a folder path, then Go'
								try { $W.CwdPopupStatus.Foreground = $W.BrushCache['#6A6A76'] } catch {}
								$W.CwdPopup.PlacementTarget = $W.TitlePath
								$W.CwdPopup.IsOpen = $true
								try {
									[void]$W.CwdPopupBox.Focus()
									$W.CwdPopupBox.SelectAll()
								} catch {}
							} catch {}
						}.GetNewClosure()
						$closeCwdPopup = {
							try { if ($W.CwdPopup) { $W.CwdPopup.IsOpen = $false } } catch {}
						}.GetNewClosure()
						$applyCwdGo = {
							try {
								$dir = ([string]$W.CwdPopupBox.Text).Trim().Trim('"')
								if ([string]::IsNullOrWhiteSpace($dir)) {
									$W.CwdPopupStatus.Text = 'Enter a folder path first.'
									try { $W.CwdPopupStatus.Foreground = $W.BrushCache['#F05C5C'] } catch {}
									return
								}
								$exists = $false
								try { $exists = [System.IO.Directory]::Exists($dir) } catch { $exists = $false }
								if (-not $exists) {
									$W.CwdPopupStatus.Text = 'Folder not found - check the path and try again.'
									try { $W.CwdPopupStatus.Foreground = $W.BrushCache['#F05C5C'] } catch {}
									return
								}
								$full = $dir
								try { $full = [System.IO.Path]::GetFullPath($dir) } catch { $full = $dir }
								$W.CwdPopupBox.Text = $full
								$W.PendingCwd = $full
								$W.CurrentCwd = $full
								$W.CwdDirty = $true
								# Optimistic title path (short)
								$disp = $full
								if ($disp.Length -gt 56) { $disp = '...' + $disp.Substring($disp.Length - 53) }
								$W.PendingTitlePath = $disp
								try { $W.TitlePath.Text = $disp } catch {}
								try { if ($W.TitlePathShadow) { $W.TitlePathShadow.Text = $disp } } catch {}
								$W.CwdPopupStatus.Text = ('Working directory set: {0}' -f $full)
								try { $W.CwdPopupStatus.Foreground = $W.BrushCache['#7DCFFF'] } catch {}
								try { $W.CwdPopup.IsOpen = $false } catch {}
							} catch {}
						}.GetNewClosure()
						$W.OpenCwdPopup = $openCwdPopup
						$W.CloseCwdPopup = $closeCwdPopup
						$W.ApplyCwdGo = $applyCwdGo
						$cwdGo.add_Click({
							param($s, $e)
							try { & $applyCwdGo } catch {}
						}.GetNewClosure())
						$cwdBox.add_KeyDown({
							param($s, $e)
							try {
								if ($e.Key -eq 'Return') {
									$e.Handled = $true
									& $applyCwdGo
								} elseif ($e.Key -eq 'Escape') {
									$e.Handled = $true
									& $closeCwdPopup
								}
							} catch {}
						}.GetNewClosure())
						$W.TitlePath.add_MouseLeftButtonUp({
							param($s, $e)
							try {
								if ($null -ne $e) { $e.Handled = $true }
								if ($W.CwdPopup -and [bool]$W.CwdPopup.IsOpen) {
									& $closeCwdPopup
								} else {
									& $openCwdPopup
								}
							} catch {}
						}.GetNewClosure())
						$W.TitlePath.add_MouseLeftButtonDown({
							param($s, $e)
							try { if ($null -ne $e) { $e.Handled = $true } } catch {}
						}.GetNewClosure())
						# Click outside closes cwd popup
						if ($W.Window -and -not $W.CwdPopupOutsideHooked) {
							$W.CwdPopupOutsideHooked = $true
							$W.Window.add_PreviewMouseDown({
								param($s, $e)
								try {
									if (-not $W.CwdPopup -or -not [bool]$W.CwdPopup.IsOpen) { return }
									$src = $null
									try { $src = $e.OriginalSource } catch {}
									$keep = $false
									try {
										$vis = $src
										while ($null -ne $vis) {
											if ($vis -eq $W.TitlePath -or $vis -eq $W.CwdPopup.Child) { $keep = $true; break }
											try { $vis = [System.Windows.Media.VisualTreeHelper]::GetParent($vis) } catch { break }
										}
									} catch {}
									if (-not $keep) { $W.CwdPopup.IsOpen = $false }
								} catch {}
							}.GetNewClosure())
						}
					}
				} catch {}
			} catch {}
			$W.HdrAutoCompact = $window.FindName('HdrAutoCompact')
			$W.HdrAutoCompactShadow = $window.FindName('HdrAutoCompactShadow')
			$W.HdrLeft = $W.HdrLine1
			$W.HdrRight = $window.FindName('LowerRight')
			$W.LowerRight = $window.FindName('LowerRight')
			$W.WordWrapToggle = $window.FindName('WordWrapToggle')
			$W.LogWordWrap = $true
			try {
				if ($W.WordWrapToggle) { $W.WordWrapToggle.IsChecked = $true }
			} catch {}
			try {
				if ($W.WordWrapToggle -and $W.SetThemedToolTip) {
					& $W.SetThemedToolTip $W.WordWrapToggle 'Wrap long log lines' 220
					$wwLbl = $window.FindName('WordWrapLabel')
					if ($wwLbl) { & $W.SetThemedToolTip $wwLbl 'Wrap long log lines' 220 }
				}
			} catch {}
			$W.CtxBarFill = $window.FindName('CtxBarFill')
			$W.CtxPctText = $window.FindName('CtxPctText')
			$W.CtxTokText = $window.FindName('CtxTokText')
			$W.CtxBarMaxW = 120
			$W.HintBar = $window.FindName('HintBar')
			$W.HintBarBorder = $window.FindName('HintBarBorder')
			$W.SpeechWaveBox = $window.FindName('SpeechWaveBox')
			$W.SpeechWaveCanvas = $window.FindName('SpeechWaveCanvas')
			$W.SpeechWaveLine = $window.FindName('SpeechWaveLine')
			$W.SpeechWaveStatus = $window.FindName('SpeechWaveStatus')
			$W.SpeechWaveLang = $window.FindName('SpeechWaveLang')
			$W.SpeechWaveTimer = $null
			$W.SpeechWavePhase = 0.0
			$W.SpeechWaveSeed = 1
			$W.StatusDot = $window.FindName('StatusDot')
			$W.StatusTimer = $window.FindName('StatusTimer')
			$W.StatusBand = $window.FindName('StatusBand')
			$W.StatusBusySince = 0
			try {
				$W.MonoFont = New-Object System.Windows.Media.FontFamily(
					'Consolas, Cascadia Mono, Courier New, Segoe UI Emoji, Segoe UI Symbol, Segoe UI')
				$W.EmojiFont = New-Object System.Windows.Media.FontFamily(
					'Segoe UI Emoji, Segoe UI Symbol, Segoe UI')
			} catch {}
			$W.AuthOverlay = $window.FindName('AuthOverlay')
			$W.AuthTitle = $window.FindName('AuthTitle')
			$W.AuthSubtitle = $window.FindName('AuthSubtitle')
			$W.AuthUser = $window.FindName('AuthUser')
			$W.AuthPass = $window.FindName('AuthPass')
			$W.AuthError = $window.FindName('AuthError')
			$W.AuthOk = $window.FindName('AuthOk')
			$W.AuthCancel = $window.FindName('AuthCancel')
			$W.AuthTitleClose = $window.FindName('AuthTitleClose')
			$W.AuthSaveCreds = $window.FindName('AuthSaveCreds')
			$W.ConfirmOverlay = $window.FindName('ConfirmOverlay')
			$W.ConfirmTitle = $window.FindName('ConfirmTitle')
			$W.ConfirmPrompt = $window.FindName('ConfirmPrompt')
			$W.ConfirmYes = $window.FindName('ConfirmYes')
			$W.ConfirmNo = $window.FindName('ConfirmNo')
			$W.ConfirmTitleClose = $window.FindName('ConfirmTitleClose')
			$W.ConfirmAccentBar = $window.FindName('ConfirmAccentBar')
			$W.SessionPickerOverlay = $window.FindName('SessionPickerOverlay')
			$W.SessionPickerTitle = $window.FindName('SessionPickerTitle')
			$W.SessionPickerTitleClose = $window.FindName('SessionPickerTitleClose')
			try {
				$barAgent = ''
				try { $barAgent = [string]$W.AgentName } catch {}
				if ([string]::IsNullOrWhiteSpace($barAgent)) {
					try { $barAgent = [string]$AgentName } catch { $barAgent = 'MiniBot' }
				}
				if ([string]::IsNullOrWhiteSpace($barAgent)) { $barAgent = 'MiniBot' }
				foreach ($barNm in @('AuthBarBrandName', 'ConfirmBarBrandName', 'SessionBarBrandName')) {
					try {
						$barEl = $window.FindName($barNm)
						if ($null -ne $barEl) { $barEl.Text = $barAgent }
					} catch {}
				}
			} catch {}
			$W.SessionPickerPath = $window.FindName('SessionPickerPath')
			$W.SessionPickerGo = $window.FindName('SessionPickerGo')
			$W.SessionPickerUp = $window.FindName('SessionPickerUp')
			$W.SessionPickerBrowse = $window.FindName('SessionPickerBrowse')
			$W.SessionPickerStatus = $window.FindName('SessionPickerStatus')
			$W.SessionPickerList = $window.FindName('SessionPickerList')
			$W.SessionPickerName = $window.FindName('SessionPickerName')
			$W.SessionPickerOk = $window.FindName('SessionPickerOk')
			$W.SessionPickerCancel = $window.FindName('SessionPickerCancel')
			$W.SessionPickerRows = New-Object System.Collections.ArrayList
			# Titlebar close button hover
			try {
				$bcDlg = New-Object System.Windows.Media.BrushConverter
				$hoverRed = $bcDlg.ConvertFromString('#E81123')
				$hoverClear = [System.Windows.Media.Brushes]::Transparent
				$wireDlgCloseHover = {
					param($btn)
					if (-not $btn) { return }
					$btn.add_MouseEnter({
						try { $btn.Background = $hoverRed } catch {}
					}.GetNewClosure())
					$btn.add_MouseLeave({
						try { $btn.Background = $hoverClear } catch {}
					}.GetNewClosure())
				}.GetNewClosure()
				& $wireDlgCloseHover $W.AuthTitleClose
				& $wireDlgCloseHover $W.ConfirmTitleClose
				& $wireDlgCloseHover $W.SessionPickerTitleClose
			} catch {}

			
			# Session picker overlay
			try {
			$sessionPickerReload = {
				# Folder scan off UI thread
				try {
					$list = $W.SessionPickerList
					$pathBox = $W.SessionPickerPath
					$status = $W.SessionPickerStatus
					if (-not $list -or -not $pathBox) { return }
					$dir = ([string]$pathBox.Text).Trim().Trim('"')
					if ([string]::IsNullOrWhiteSpace($dir)) {
						if ($status) {
							$status.Text = 'Enter a folder path first.'
							try {
								$bc = New-Object System.Windows.Media.BrushConverter
								$status.Foreground = $bc.ConvertFromString('#F05C5C')
							} catch {}
						}
						return
					}
					# Require existing folder path
					$exists = $false
					try { $exists = [System.IO.Directory]::Exists($dir) } catch { $exists = $false }
					if (-not $exists) {
						if ($status) {
							$status.Text = 'Folder not found - check the path and try again.'
							try {
								$bc = New-Object System.Windows.Media.BrushConverter
								$status.Foreground = $bc.ConvertFromString('#F05C5C')
							} catch {}
						}
						return
					}
					$pathBox.Text = $dir
					$list.Items.Clear()
					$W.SessionPickerRows = New-Object System.Collections.ArrayList
					[void]$list.Items.Add('(scanning...)')
					if ($status) {
						$status.Text = 'Scanning...'
						try {
							$bc = New-Object System.Windows.Media.BrushConverter
							$status.Foreground = $bc.ConvertFromString('#6A6A76')
						} catch {}
					}
					try { Ensure-MBSessionScanType } catch {}
					$gen = 0
					try { $gen = [int]$W.SessionPickerScanGen + 1 } catch { $gen = 1 }
					$W.SessionPickerScanGen = $gen
					$dirCopy = $dir
					$genCopy = $gen
					$rs = $null
					$ps = $null
					try {
						$rs = [System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspace()
						$rs.Open()
						$ps = [powershell]::Create()
						$ps.Runspace = $rs
						[void]$ps.AddScript({
							param([string]$Dir, [int]$Max, [int]$TimeoutMs)
							if (-not ('MiniBot.SessionScan' -as [type])) { return @() }
							$raw = [MiniBot.SessionScan]::ListSessions($Dir, $Max, $TimeoutMs)
							if (-not $raw) { return @() }
							$out = New-Object System.Collections.ArrayList
							foreach ($r in @($raw)) {
								if ($null -eq $r -or $r.Length -lt 6) { continue }
								[void]$out.Add(@{
									Name = [string]$r[0]; Path = [string]$r[1]; Modified = [string]$r[2]
									Size = [string]$r[3]; Type = [string]$r[4]; Line = [string]$r[5]
								})
							}
							return @($out)
						}).AddArgument($dirCopy).AddArgument(400).AddArgument(1500)
						$async = $ps.BeginInvoke()
						$timer = New-Object System.Windows.Threading.DispatcherTimer
						$timer.Interval = [TimeSpan]::FromMilliseconds(50)
						$timer.Tag = @{
							Async = $async; PS = $ps; RS = $rs; Gen = $genCopy; Dir = $dirCopy
						}
						$timer.add_Tick({
							param($s, $e)
							try {
								$tag = $s.Tag
								if (-not $tag -or -not $tag.Async) { try { $s.Stop() } catch {}; return }
								if (-not $tag.Async.IsCompleted) { return }
								try { $s.Stop() } catch {}
								$rows = @()
								try {
									$out = $tag.PS.EndInvoke($tag.Async)
									if ($out) { $rows = @($out) }
								} catch { $rows = @() }
								try { $tag.PS.Dispose() } catch {}
								try { $tag.RS.Close(); $tag.RS.Dispose() } catch {}
								$curGen = 0
								try { $curGen = [int]$W.SessionPickerScanGen } catch {}
								if ($curGen -ne [int]$tag.Gen) { return }
								$curDir = ''
								try { $curDir = ([string]$W.SessionPickerPath.Text).Trim().Trim('"') } catch {}
								if ($curDir -and $tag.Dir -and ($curDir -ne [string]$tag.Dir)) { return }
								if (-not $W.SessionPickerList) { return }
								$W.SessionPickerRows = New-Object System.Collections.ArrayList
								$W.SessionPickerList.Items.Clear()
								if ($rows.Count -eq 0) {
									[void]$W.SessionPickerList.Items.Add('(none)')
									if ($W.SessionPickerStatus) {
										$W.SessionPickerStatus.Text = 'No .json/.md here - type a name and Save/Open'
										try {
											$bc = New-Object System.Windows.Media.BrushConverter
											$W.SessionPickerStatus.Foreground = $bc.ConvertFromString('#6A6A76')
										} catch {}
									}
								} else {
									foreach ($row in $rows) {
										[void]$W.SessionPickerRows.Add($row)
										[void]$W.SessionPickerList.Items.Add([string]$row.Line)
									}
									if ($W.SessionPickerStatus) {
										$W.SessionPickerStatus.Text = ('{0} session(s)  |  newest first' -f $W.SessionPickerRows.Count)
										try {
											$bc = New-Object System.Windows.Media.BrushConverter
											$W.SessionPickerStatus.Foreground = $bc.ConvertFromString('#6A6A76')
										} catch {}
									}
								}
							} catch {
								try {
									if ($W.SessionPickerList) {
										$W.SessionPickerList.Items.Clear()
										[void]$W.SessionPickerList.Items.Add('(scan failed)')
									}
								} catch {}
							}
						}.GetNewClosure())
						$timer.Start()
					} catch {
						try { if ($ps) { $ps.Dispose() } } catch {}
						try { if ($rs) { $rs.Close(); $rs.Dispose() } } catch {}
						try {
							$list.Items.Clear()
							[void]$list.Items.Add('(scan failed)')
						} catch {}
					}
				} catch {}
			}.GetNewClosure()
			$W.SessionPickerReload = $sessionPickerReload

			# Dismiss picker UI before agent continues
			$sessionPickerDismissUi = {
				try {
					if ($W.SessionPickerOverlay) {
						$W.SessionPickerOverlay.Visibility = [System.Windows.Visibility]::Collapsed
						$W.SessionPickerOverlay.IsHitTestVisible = $false
					}
					if ($W.SessionPickerOk) { try { $W.SessionPickerOk.IsDefault = $false } catch {} }
					if ($W.SessionPickerCancel) { try { $W.SessionPickerCancel.IsCancel = $false } catch {} }
				} catch {}
			}.GetNewClosure()
			$sessionPickerAccept = {
				try {
					$mode = [string]$W.SessionPickerMode
					if ([string]::IsNullOrWhiteSpace($mode)) { $mode = 'Open' }
					$p = $null
					if ($mode -eq 'Save') {
						$nm = ''
						try { $nm = ([string]$W.SessionPickerName.Text).Trim().Trim('"') } catch {}
						$idx = -1
						try { $idx = [int]$W.SessionPickerList.SelectedIndex } catch {}
						if ([string]::IsNullOrWhiteSpace($nm) -and $idx -ge 0 -and $idx -lt $W.SessionPickerRows.Count) {
							$nm = [string]$W.SessionPickerRows[$idx].Name
						}
						if ([string]::IsNullOrWhiteSpace($nm)) { return }
						$low = $nm.ToLowerInvariant()
						if (-not ($low.EndsWith('.json') -or $low.EndsWith('.md') -or $low.EndsWith('.markdown'))) {
							$nm = $nm + '.json'
						}
						$dir = ''
						try { $dir = ([string]$W.SessionPickerPath.Text).Trim() } catch {}
						$p = [System.IO.Path]::Combine($dir, $nm)
						if ([System.IO.File]::Exists($p)) {
							# Avoid owned MessageBox on borderless host
							$r = [System.Windows.MessageBox]::Show(
								('Overwrite existing file?' + [Environment]::NewLine + [Environment]::NewLine + $p),
								'Save session',
								[System.Windows.MessageBoxButton]::YesNo,
								[System.Windows.MessageBoxImage]::Warning
							)
							if ($r -ne [System.Windows.MessageBoxResult]::Yes) { return }
						}
					} else {
						$idx = -1
						try { $idx = [int]$W.SessionPickerList.SelectedIndex } catch {}
						if ($idx -ge 0 -and $idx -lt $W.SessionPickerRows.Count) {
							$p = [string]$W.SessionPickerRows[$idx].Path
						}
						if ([string]::IsNullOrWhiteSpace($p) -or -not [System.IO.File]::Exists($p)) { return }
					}
					$W.SessionPickerResult = $p
					# Dismiss overlay before save continues
					& $sessionPickerDismissUi
					try { [void]$W.SessionPickerWait.Set() } catch {}
				} catch {}
			}.GetNewClosure()

			if ($W.SessionPickerGo) {
				$W.SessionPickerGo.add_Click({ & $sessionPickerReload }.GetNewClosure())
			}
			if ($W.SessionPickerUp) {
				$W.SessionPickerUp.add_Click({
					try {
						$cur = ([string]$W.SessionPickerPath.Text).Trim()
						$parent = [System.IO.Directory]::GetParent($cur)
						if ($parent) {
							$W.SessionPickerPath.Text = $parent.FullName
							& $sessionPickerReload
						}
					} catch {}
				}.GetNewClosure())
			}
			if ($W.SessionPickerBrowse) {
				$W.SessionPickerBrowse.add_Click({
					try {
						Add-Type -AssemblyName System.Windows.Forms -ErrorAction SilentlyContinue
						$fb = New-Object System.Windows.Forms.FolderBrowserDialog
						$fb.Description = 'Choose folder'
						$fb.ShowNewFolderButton = $true
						try {
							$cur = ([string]$W.SessionPickerPath.Text).Trim()
							if ($cur -and [System.IO.Directory]::Exists($cur)) { $fb.SelectedPath = $cur }
						} catch {}
						$dr = $fb.ShowDialog()
						if ($dr -eq [System.Windows.Forms.DialogResult]::OK -and $fb.SelectedPath) {
							$W.SessionPickerPath.Text = [string]$fb.SelectedPath
							& $sessionPickerReload
						}
					} catch {}
				}.GetNewClosure())
			}
			if ($W.SessionPickerPath) {
				$W.SessionPickerPath.add_KeyDown({
					param($s, $e)
					if ($e.Key -eq 'Return') {
						$e.Handled = $true
						& $sessionPickerReload
					}
				}.GetNewClosure())
			}
			if ($W.SessionPickerList) {
				$W.SessionPickerList.add_SelectionChanged({
					try {
						$idx = [int]$W.SessionPickerList.SelectedIndex
						if ($idx -ge 0 -and $idx -lt $W.SessionPickerRows.Count -and $W.SessionPickerName) {
							$W.SessionPickerName.Text = [string]$W.SessionPickerRows[$idx].Name
						}
					} catch {}
				}.GetNewClosure())
				$W.SessionPickerList.add_MouseDoubleClick({
					& $sessionPickerAccept
				}.GetNewClosure())
			}
			if ($W.SessionPickerOk) {
				$W.SessionPickerOk.add_Click({ & $sessionPickerAccept }.GetNewClosure())
			}
			if ($W.SessionPickerCancel) {
				$W.SessionPickerCancel.add_Click({
					$W.SessionPickerResult = $null
					try { & $sessionPickerDismissUi } catch {}
					try { [void]$W.SessionPickerWait.Set() } catch {}
				}.GetNewClosure())
			}
			if ($W.SessionPickerTitleClose) {
				$W.SessionPickerTitleClose.add_Click({
					$W.SessionPickerResult = $null
					try { & $sessionPickerDismissUi } catch {}
					try { [void]$W.SessionPickerWait.Set() } catch {}
				}.GetNewClosure())
			}
			} catch {
				try { $W['SessionPickerWireError'] = [string]$_.Exception.Message } catch {}
			}

			$W.Dispatcher = [System.Windows.Threading.Dispatcher]::CurrentDispatcher
			try {
				$bootTitle = "[{0}-Agent]" -f $(if ($W.AgentName) { [string]$W.AgentName } else { 'MiniBot' })
				$bootModel = ''
				try { $bootModel = [string]$W.ActiveModel } catch { $bootModel = '' }
				if ([string]::IsNullOrWhiteSpace($bootModel)) {
					try { $bootModel = @($W.RemoteModels)[0] } catch { $bootModel = '' }
				}
				$sep = ("  {0}  " -f [string][char]0x00B7)
				if (-not [string]::IsNullOrWhiteSpace($bootModel)) {
					$bootTitle = ("{0}{1}PoweredBy: {2}" -f $bootTitle, $sep, $bootModel.Trim())
				} else {
					$bootTitle = ("{0}{1}PoweredBy: Select Model" -f $bootTitle, $sep)
				}
				$window.Title = $bootTitle
			} catch {
				$window.Title = ("MiniBot v{0}" -f $W.Version)
			}
			# Window and taskbar robot icon
			try {
				$appId = 'MiniBot-Agent'
				try { if ($W.AgentName) { $appId = ("{0}-Agent" -f $W.AgentName) } } catch {}
				$W.AppId = $appId
				if (-not $W.RobotIconCache) { $W.RobotIconCache = @{} }
				$W.ToShellIcon = {
					param($Source)
					if (-not $Source) { return $null }
					try {
						$enc = New-Object System.Windows.Media.Imaging.PngBitmapEncoder
						[void]$enc.Frames.Add([System.Windows.Media.Imaging.BitmapFrame]::Create($Source))
						$ms = New-Object System.IO.MemoryStream
						try {
							$enc.Save($ms)
							$ms.Position = 0
							$frame = [System.Windows.Media.Imaging.BitmapFrame]::Create(
								$ms,
								[System.Windows.Media.Imaging.BitmapCreateOptions]::None,
								[System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad
							)
							if ($frame.CanFreeze) { $frame.Freeze() }
							return $frame
						} finally { try { $ms.Dispose() } catch {} }
					} catch { return $Source }
				}.GetNewClosure()
				$W.SetNativeWindowIcon = {
					param($Window, $BitmapSource)
					if (-not $Window -or -not $BitmapSource) { return }
					try {
						if (-not ('MiniBot.UI.NativeIcon' -as [type])) {
							Add-Type -Namespace MiniBot.UI -Name NativeIcon -MemberDefinition @"
[System.Runtime.InteropServices.DllImport("user32.dll", CharSet=System.Runtime.InteropServices.CharSet.Auto)]
public static extern System.IntPtr SendMessage(System.IntPtr hWnd, int Msg, System.IntPtr wParam, System.IntPtr lParam);
[System.Runtime.InteropServices.DllImport("user32.dll", SetLastError=true)]
public static extern bool DestroyIcon(System.IntPtr hIcon);
[System.Runtime.InteropServices.DllImport("user32.dll", SetLastError=true)]
public static extern System.IntPtr CopyIcon(System.IntPtr hIcon);
public const int WM_SETICON = 0x0080;
public const int ICON_SMALL = 0;
public const int ICON_BIG = 1;
"@ -ErrorAction Stop
						}
						Add-Type -AssemblyName System.Drawing -ErrorAction SilentlyContinue
						$enc = New-Object System.Windows.Media.Imaging.PngBitmapEncoder
						[void]$enc.Frames.Add([System.Windows.Media.Imaging.BitmapFrame]::Create($BitmapSource))
						$ms = New-Object System.IO.MemoryStream
						try {
							$enc.Save($ms)
							$ms.Position = 0
							$gdi = [System.Drawing.Bitmap]::FromStream($ms)
							try {
								$hIcon = $gdi.GetHicon()
								try {
									$helper = New-Object System.Windows.Interop.WindowInteropHelper($Window)
									$hwnd = $helper.EnsureHandle()
									if ($hwnd -ne [IntPtr]::Zero) {
										$hSmall = [MiniBot.UI.NativeIcon]::CopyIcon($hIcon)
										$hBig = [MiniBot.UI.NativeIcon]::CopyIcon($hIcon)
										$prevSmall = [MiniBot.UI.NativeIcon]::SendMessage($hwnd, [MiniBot.UI.NativeIcon]::WM_SETICON, [IntPtr][MiniBot.UI.NativeIcon]::ICON_SMALL, $hSmall)
										$prevBig = [MiniBot.UI.NativeIcon]::SendMessage($hwnd, [MiniBot.UI.NativeIcon]::WM_SETICON, [IntPtr][MiniBot.UI.NativeIcon]::ICON_BIG, $hBig)
										if ($prevSmall -ne [IntPtr]::Zero) { try { [void][MiniBot.UI.NativeIcon]::DestroyIcon($prevSmall) } catch {} }
										if ($prevBig -ne [IntPtr]::Zero) { try { [void][MiniBot.UI.NativeIcon]::DestroyIcon($prevBig) } catch {} }
									}
								} finally { try { [void][MiniBot.UI.NativeIcon]::DestroyIcon($hIcon) } catch {} }
							} finally { try { $gdi.Dispose() } catch {} }
						} finally { try { $ms.Dispose() } catch {} }
					} catch {}
				}.GetNewClosure()
				$W.RenderRobotIcon = {
					param([string]$Face = 'happy', [int]$Size = 64)
					try {
						if ($Size -lt 16) { $Size = 16 }
						$cat = $W.RobotCatalog
						$faceKey = if ($cat -and (@($cat.Keys) -contains $Face)) { $Face } else { 'happy' }
						if ($cat -and (@($cat.Keys) -notcontains $faceKey)) { $faceKey = 'default' }
						$data = if ($cat) { [string]$cat[$faceKey] } else { '' }
						if ([string]::IsNullOrWhiteSpace($data)) { return $null }
						$cols = if ($faceKey -eq 'dead' -or $faceKey -eq 'error') {
							@('#D0C4C6', '#B08084', '#9A585C')
						} else {
							@('#C8C8D0', '#6A6A74', '#3A3A42')
						}
						$geom = [System.Windows.Media.Geometry]::Parse($data)
						$brush = New-Object System.Windows.Media.LinearGradientBrush
						$brush.StartPoint = New-Object System.Windows.Point(0.15, 0.0)
						$brush.EndPoint = New-Object System.Windows.Point(0.9, 1.0)
						for ($ci = 0; $ci -lt 3; $ci++) {
							$off = @(0.0, 0.48, 1.0)[$ci]
							$col = [System.Windows.Media.ColorConverter]::ConvertFromString([string]$cols[$ci])
							[void]$brush.GradientStops.Add((New-Object System.Windows.Media.GradientStop($col, $off)))
						}
						$brush.Freeze()
						$bgBrush = New-Object System.Windows.Media.SolidColorBrush(([System.Windows.Media.ColorConverter]::ConvertFromString('#252530')))
						$bgBrush.Freeze()
						$visual = New-Object System.Windows.Media.DrawingVisual
						$dc = $visual.RenderOpen()
						try {
							$cx = [double]$Size / 2.0
							$dc.DrawEllipse($bgBrush, $null, (New-Object System.Windows.Point($cx, $cx)), ($cx - 0.5), ($cx - 0.5))
							$pad = [math]::Max(2.0, [double]$Size * 0.14)
							$inner = [double]$Size - (2.0 * $pad)
							$scale = $inner / 24.0
							$dc.PushTransform((New-Object System.Windows.Media.TranslateTransform($pad, $pad)))
							$dc.PushTransform((New-Object System.Windows.Media.ScaleTransform($scale, $scale)))
							$dc.DrawGeometry($brush, $null, $geom)
							$dc.Pop(); $dc.Pop()
						} finally { $dc.Close() }
						$rtb = New-Object System.Windows.Media.Imaging.RenderTargetBitmap(
							[int]$Size, [int]$Size, 96, 96,
							[System.Windows.Media.PixelFormats]::Pbgra32
						)
						$rtb.Render($visual)
						if ($W.ToShellIcon) { return (& $W.ToShellIcon $rtb) }
						if ($rtb.CanFreeze) { $rtb.Freeze() }
						return $rtb
					} catch { return $null }
				}.GetNewClosure()
				$W.ApplyWindowRobotIcon = {
					param([string]$Face = 'happy')
					try {
						if (-not $W.Window) { return }
						$faceKey = if ([string]::IsNullOrWhiteSpace($Face)) { 'happy' } else { [string]$Face }
						if (-not $W.RobotIconCache) { $W.RobotIconCache = @{} }
						if (-not $W.RobotIconCache.ContainsKey($faceKey)) {
							$bmpNew = $null
							if ($W.RenderRobotIcon) { $bmpNew = & $W.RenderRobotIcon $faceKey 64 }
							if ($bmpNew) { $W.RobotIconCache[$faceKey] = $bmpNew }
						}
						$bmp = $null
						try { $bmp = $W.RobotIconCache[$faceKey] } catch {}
						if (-not $bmp) { return }
						$W.Window.Icon = $bmp
						if (-not $W.Window.TaskbarItemInfo) {
							$W.Window.TaskbarItemInfo = New-Object System.Windows.Shell.TaskbarItemInfo
						}
						$W.Window.TaskbarItemInfo.Overlay = $bmp
						$W.Window.TaskbarItemInfo.Description = $(if ($W.AppId) { [string]$W.AppId } else { 'MiniBot' })
						if ($W.SetNativeWindowIcon) { & $W.SetNativeWindowIcon $W.Window $bmp }
					} catch {}
				}.GetNewClosure()
				try { & $W.ApplyWindowRobotIcon 'happy' } catch {}
				try {
					$window.add_SourceInitialized({
						try { if ($W.ApplyWindowRobotIcon) { & $W.ApplyWindowRobotIcon $(if ($W.RobotMood) { [string]$W.RobotMood } else { 'happy' }) } } catch {}
					}.GetNewClosure())
				} catch {}
			} catch {}

			# Collapse unused sticky header nodes
			try {
				foreach ($el in @($W.HdrPoweredBy, $W.HdrPoweredByShadow, $W.HdrPoweredByHost, $W.HdrLine1, $W.HdrLine1Shadow, $W.HdrAutoCompact, $W.HdrAutoCompactShadow)) {
					if ($el) {
						try { $el.Visibility = [System.Windows.Visibility]::Collapsed } catch {}
					}
				}
			} catch {}

			$syncLogPageWidth = {
				param($box, $bag)
				try {
					if (-not $box -or -not $box.Document) { return }
					$viewW = [double]$box.ActualWidth
					if ($viewW -lt 40 -or [double]::IsNaN($viewW)) { return }

					$padL = 0.0; $padR = 0.0
					try {
						$padL = [double]$box.Padding.Left
						$padR = [double]$box.Padding.Right
					} catch {
						$padL = 12.0; $padR = 12.0
					}
					$vBar = 0.0
					try {
						if ($box.ComputedVerticalScrollBarVisibility -eq [System.Windows.Visibility]::Visible) {
							$vBar = 14.0
						} else {
							$vBar = 2.0
						}
					} catch { $vBar = 14.0 }

					$columnW = $viewW - $padL - $padR - $vBar - 2.0
					if ($columnW -lt 40) { $columnW = 40 }

					$wrap = $false
					try { $wrap = [bool]$bag.LogWordWrap } catch { $wrap = $false }
					if ($wrap) {
						$box.Document.PageWidth = $columnW
						$box.HorizontalScrollBarVisibility = [System.Windows.Controls.ScrollBarVisibility]::Disabled
						return
					}

					$charW = 7.2
					$maxChars = 0
					try { $maxChars = [int]$bag.LogMaxLineChars } catch { $maxChars = 0 }
					$contentW = if ($maxChars -gt 0) { ($maxChars * $charW) + 8.0 } else { 0.0 }

					$needsH = ($contentW -gt ($columnW + 1.0))
					if ($needsH) {
						$pageW = [math]::Min(60000.0, [math]::Max($columnW, $contentW))
						$box.Document.PageWidth = $pageW
						$box.HorizontalScrollBarVisibility = [System.Windows.Controls.ScrollBarVisibility]::Auto
					} else {
						$box.Document.PageWidth = $columnW
						$box.HorizontalScrollBarVisibility = [System.Windows.Controls.ScrollBarVisibility]::Disabled
					}
				} catch {}
			}.GetNewClosure()
			$W.SyncLogPageWidth = $syncLogPageWidth
			$syncMdStretch = {
				param($box, $bag)
				try {
					if (-not $box -or -not $bag) { return }
					$viewW = [double]$box.ActualWidth
					if ($viewW -lt 40 -or [double]::IsNaN($viewW)) { return }
					$padL = 12.0; $padR = 12.0
					try {
						$padL = [double]$box.Padding.Left
						$padR = [double]$box.Padding.Right
					} catch {}
					$vBar = 16.0
					try {
						if ($box.ComputedVerticalScrollBarVisibility -eq [System.Windows.Visibility]::Visible) {
							$vBar = 16.0
						}
					} catch {}
					$w = $viewW - $padL - $padR - $vBar - 2.0
					if ($w -lt 40) { $w = 40 }
					$list = $null
					try {
						if ($bag -is [hashtable]) {
							if (-not $bag.ContainsKey('MdStretchElements') -or $null -eq $bag['MdStretchElements']) {
								$bag['MdStretchElements'] = New-Object System.Collections.ArrayList
							}
							$list = $bag['MdStretchElements']
						} else {
							try { $list = $bag.MdStretchElements } catch { $list = $null }
							if ($null -eq $list) {
								$list = New-Object System.Collections.ArrayList
								try { $bag | Add-Member -NotePropertyName MdStretchElements -NotePropertyValue $list -Force } catch {
									try { $bag.MdStretchElements = $list } catch {}
								}
							}
						}
					} catch { $list = $null }
					if ($null -eq $list) { return }
					$alive = New-Object System.Collections.ArrayList
					foreach ($el in @($list)) {
						if ($null -eq $el) { continue }
						try {
							if ($null -eq $el.Parent) { continue }
							$el.Width = $w
							try { $el.MaxWidth = $w } catch {}
							try {
								$meta = $el.Tag
								if ($meta -is [hashtable] -and $meta['Kind'] -eq 'md-code' -and $null -ne $meta['Rtb']) {
									$rtb = $meta['Rtb']
									if ($null -ne $rtb.Document) {
										$rtb.Document.PageWidth = [Math]::Max(80, $w - 8)
									}
								}
							} catch {}
							[void]$alive.Add($el)
						} catch {}
					}
					if ($bag -is [hashtable]) { $bag['MdStretchElements'] = $alive }
					else {
						try { $bag.MdStretchElements = $alive } catch {}
					}
				} catch {}
			}.GetNewClosure()
			$W.SyncMdStretch = $syncMdStretch
			if ($W.Log) {
				try { $W.Log.HorizontalScrollBarVisibility = [System.Windows.Controls.ScrollBarVisibility]::Disabled } catch {}
				$W.Log.add_SizeChanged({
					param($s, $e)
					try { & $syncLogPageWidth $W.Log $W } catch {}
					try { & $syncMdStretch $W.Log $W } catch {}
				}.GetNewClosure())
				$W.Log.add_Loaded({
					param($s, $e)
					try { & $syncLogPageWidth $W.Log $W } catch {}
					try { & $syncMdStretch $W.Log $W } catch {}
				}.GetNewClosure())
				try { & $syncLogPageWidth $W.Log $W } catch {}
			}
			if ($W.WordWrapToggle) {
				$onWrapChanged = {
					param($s, $e)
					try {
						$W.LogWordWrap = [bool]$W.WordWrapToggle.IsChecked
						if ($W.SyncLogPageWidth -and $W.Log) { & $W.SyncLogPageWidth $W.Log $W }
						try {
							$tb = $window.FindName('WordWrapLabel')
							if (-not $tb) { $tb = $W.WordWrapToggle.Content }
							if ($tb -is [System.Windows.Controls.TextBlock]) {
								$hex = if ($W.LogWordWrap) { '#C8C8D0' } else { '#6A6A76' }
								$bc = New-Object System.Windows.Media.BrushConverter
								$tb.Foreground = $bc.ConvertFromString($hex)
							}
						} catch {}
					} catch {}
				}.GetNewClosure()
				$W.WordWrapToggle.add_Checked($onWrapChanged)
				$W.WordWrapToggle.add_Unchecked($onWrapChanged)
				try { & $onWrapChanged $null $null } catch {}
			}

			# Dark chrome + corner policy (rounded border; kill Win11 DWM rounding)
			$applyWindowChromeCorners = {
				param($win, $bag)
				try {
					# Use work-area maximize flag (not WindowState.Maximized)
					$maximized = $false
					try { $maximized = [bool]$bag.IsWorkAreaMaximized } catch { $maximized = $false }
					$r = if ($maximized) { 0.0 } else { 8.0 }
					$main = $null
					try { $main = $bag.MainChromeBorder } catch { $main = $null }
					if (-not $main) { try { $main = $win.FindName('MainChromeBorder') } catch {} }
					$title = $null
					try { $title = $bag.CustomTitleBar } catch { $title = $null }
					if (-not $title) { try { $title = $win.FindName('CustomTitleBar') } catch {} }
					if ($main) {
						$main.CornerRadius = New-Object System.Windows.CornerRadius($r)
						# Maximized: flush to work area (no transparent gap around rounded mask)
						if ($maximized) {
							$main.Margin = New-Object System.Windows.Thickness(0)
							$main.BorderThickness = New-Object System.Windows.Thickness(0)
						} else {
							$main.Margin = New-Object System.Windows.Thickness(0)
							$main.BorderThickness = New-Object System.Windows.Thickness(1)
						}
					}
					if ($title) {
						if ($maximized) {
							$title.CornerRadius = New-Object System.Windows.CornerRadius(0)
						} else {
							$title.CornerRadius = New-Object System.Windows.CornerRadius($r, $r, 0, 0)
						}
					}
					# Bottom chrome strip (hint bar) matches top radius when restored
					$hintBar = $null
					try { $hintBar = $bag.HintBarBorder } catch { $hintBar = $null }
					if (-not $hintBar) { try { $hintBar = $win.FindName('HintBarBorder') } catch {} }
					if ($hintBar) {
						if ($maximized) {
							$hintBar.CornerRadius = New-Object System.Windows.CornerRadius(0)
						} else {
							$hintBar.CornerRadius = New-Object System.Windows.CornerRadius(0, 0, $r, $r)
						}
					}
					# Keep WindowChrome radius in sync
					try {
						$chrome = [System.Windows.Shell.WindowChrome]::GetWindowChrome($win)
						if ($chrome) {
							if ($maximized) {
								$chrome.CornerRadius = New-Object System.Windows.CornerRadius(0)
								$chrome.CaptionHeight = 36
							} else {
								$chrome.CornerRadius = New-Object System.Windows.CornerRadius($r)
								$chrome.CaptionHeight = 36
							}
						}
					} catch {}
				} catch {}
			}.GetNewClosure()
			$applyDarkTitle = {
				param($win)
				try {
					if (-not ("MB.Native.Dwm" -as [type])) {
						Add-Type -Namespace MB.Native -Name Dwm -MemberDefinition @"
[System.Runtime.InteropServices.DllImport("dwmapi.dll")]
public static extern int DwmSetWindowAttribute(System.IntPtr hwnd, int attr, ref int attrValue, int attrSize);
"@ -ErrorAction Stop
					}
					$helper = New-Object System.Windows.Interop.WindowInteropHelper($win)
					$hwnd = $helper.Handle
					if ($hwnd -eq [IntPtr]::Zero) { return }
					$useDark = 1
					# DWMWA_USE_IMMERSIVE_DARK_MODE: 20 (20H1+), 19 (older)
					[void][MB.Native.Dwm]::DwmSetWindowAttribute($hwnd, 20, [ref]$useDark, 4)
					[void][MB.Native.Dwm]::DwmSetWindowAttribute($hwnd, 19, [ref]$useDark, 4)
					# DWMWA_WINDOW_CORNER_PREFERENCE (33): 1 = DWMWCP_DONOTROUND
					# We draw our own CornerRadius border; OS rounding leaves ugly square fill.
					try {
						$noRound = 1
						[void][MB.Native.Dwm]::DwmSetWindowAttribute($hwnd, 33, [ref]$noRound, 4)
					} catch {}
					# DWMWA_CAPTION_COLOR (35); COLORREF 0x00BBGGRR = #2A2A30
					try {
						$caption = 0x00302A2A
						[void][MB.Native.Dwm]::DwmSetWindowAttribute($hwnd, 35, [ref]$caption, 4)
					} catch {}
					# DWMWA_BORDER_COLOR (34) match chrome
					try {
						$border = 0x00302A2A
						[void][MB.Native.Dwm]::DwmSetWindowAttribute($hwnd, 34, [ref]$border, 4)
					} catch {}
				} catch {}
			}.GetNewClosure()
			try {
				$W.MainChromeBorder = $window.FindName('MainChromeBorder')
				$W.ApplyWindowChromeCorners = $applyWindowChromeCorners
			} catch {}
			# IPScanner-style vague border pulse: Base ↔ soft cyan, 6s forever on BorderBrush only.
			$W.StartChromeGlow = {
				try {
					if ($W.ChromeGlowStory) { return }
					$border = $W.MainChromeBorder
					if (-not $border) {
						try { $border = $window.FindName('MainChromeBorder') } catch {}
						$W.MainChromeBorder = $border
					}
					if (-not $border) { return }
					# Unfrozen SolidColorBrush so Color can animate (frozen brushes cannot)
					$brush = New-Object System.Windows.Media.SolidColorBrush
					$cBase = [System.Windows.Media.ColorConverter]::ConvertFromString('#2A2A30')
					# Soft deep-sky lift - IPScanner-style #CCCCCC↔#00BFFF, dialed for dark chrome (readable but not loud)
					$cPeak = [System.Windows.Media.ColorConverter]::ConvertFromString('#4A8AB8')
					$brush.Color = $cBase
					$border.BorderBrush = $brush
					try { $border.BorderThickness = New-Object System.Windows.Thickness 1 } catch {}
					$sb = New-Object System.Windows.Media.Animation.Storyboard
					$sb.RepeatBehavior = [System.Windows.Media.Animation.RepeatBehavior]::Forever
					$anim = New-Object System.Windows.Media.Animation.ColorAnimationUsingKeyFrames
					$anim.Duration = New-Object System.Windows.Duration ([TimeSpan]::FromSeconds(6.0))
					$anim.RepeatBehavior = [System.Windows.Media.Animation.RepeatBehavior]::Forever
					$mkKf = {
						param([System.Windows.Media.Color]$C, [double]$Sec)
						$kf = New-Object System.Windows.Media.Animation.LinearColorKeyFrame
						$kf.Value = $C
						$kf.KeyTime = [System.Windows.Media.Animation.KeyTime]::FromTimeSpan([TimeSpan]::FromSeconds($Sec))
						return $kf
					}
					[void]$anim.KeyFrames.Add((& $mkKf $cBase 0.0))
					[void]$anim.KeyFrames.Add((& $mkKf $cPeak 3.0))
					[void]$anim.KeyFrames.Add((& $mkKf $cBase 6.0))
					[System.Windows.Media.Animation.Storyboard]::SetTarget($anim, $brush)
					[System.Windows.Media.Animation.Storyboard]::SetTargetProperty($anim, (New-Object System.Windows.PropertyPath('Color')))
					[void]$sb.Children.Add($anim)
					$W.ChromeGlowBrush = $brush
					$W.ChromeGlowStory = $sb
					$sb.Begin()
				} catch {}
			}.GetNewClosure()
			$W.SyncChromeGlow = {
				# No geometry - pulse is on BorderBrush; re-arm only if storyboard was lost
				try {
					if (-not $W.ChromeGlowStory -and $W.StartChromeGlow) { & $W.StartChromeGlow }
				} catch {}
			}.GetNewClosure()
			$window.add_SourceInitialized({
				param($s, $e)
				try { & $applyDarkTitle $s } catch {}
				try { & $applyWindowChromeCorners $s $W } catch {}
			}.GetNewClosure())
			$window.add_Loaded({
				param($s, $e)
				try { & $applyDarkTitle $s } catch {}
				try { & $applyWindowChromeCorners $s $W } catch {}
				try { if ($W.StartChromeGlow) { & $W.StartChromeGlow } } catch {}
			}.GetNewClosure())
			$window.add_StateChanged({
				param($s, $e)
				try { & $applyWindowChromeCorners $s $W } catch {}
				try {
					if ($W.SetMaxIcon) { & $W.SetMaxIcon ([bool]$W.IsWorkAreaMaximized) }
				} catch {}
			}.GetNewClosure())
			$window.add_SizeChanged({
				param($s, $e)
				try {
					$now = [Environment]::TickCount
					$last = 0
					try { $last = [int]$W.LastPathBudgetTick } catch {}
					if ($last -ne 0 -and ((($now - $last) -band 0x7fffffff) -lt 120)) {
						try { if ($W.SyncMdStretch -and $W.Log) { & $W.SyncMdStretch $W.Log $W } } catch {}
						return
					}
					$W.LastPathBudgetTick = $now
					$W.NeedPathBudgetRefresh = $true
					try { if ($W.SyncMdStretch -and $W.Log) { & $W.SyncMdStretch $W.Log $W } } catch {}
				} catch {}
			}.GetNewClosure())

			$submitAuth = {
				try {
					$u = ''
					$p = ''
					try { $u = [string]$W.AuthUser.Text } catch {}
					try { $p = [string]$W.AuthPass.Password } catch {}
					if ([string]::IsNullOrWhiteSpace($u) -or [string]::IsNullOrWhiteSpace($p)) {
						if ($W.AuthError) { $W.AuthError.Text = 'Username and password are required.' }
						return
					}
					if ($W.AuthError) { $W.AuthError.Text = '' }
					$wantSave = $false
					try { if ($W.AuthSaveCreds -and $W.AuthSaveCreds.IsChecked) { $wantSave = $true } } catch {}
					$W.CredResult = @{
						User           = $u.Trim()
						Pass           = $p
						Cancelled      = $false
						Store          = $wantSave
						StoreSpecified = $true
						ClearStored    = $false
					}
					if ($W.AuthOverlay) { $W.AuthOverlay.Visibility = [System.Windows.Visibility]::Collapsed }
					if ($W.AuthOk) { $W.AuthOk.IsDefault = $false }
					try { $W.AuthPass.Password = '' } catch {}
					[void]$W.CredWait.Set()
				} catch {
					try {
						[System.Windows.MessageBox]::Show(
							$_.Exception.Message,
							'Login error',
							[System.Windows.MessageBoxButton]::OK,
							[System.Windows.MessageBoxImage]::Error
						) | Out-Null
					} catch {}
				}
			}.GetNewClosure()

			$W.AuthOk.add_Click({
				param($s,$e)
				try { & $submitAuth } catch {
					try {
						[System.Windows.MessageBox]::Show($_.Exception.Message, 'Login error') | Out-Null
					} catch {}
				}
			}.GetNewClosure())
			$doAuthCancel = {
				try {
					$W.SoftClose = $false
					$W.CloseKind = 'user_x'
					$W.ForceProcessExit = $true
					$W.ExitRequested = $true
					$W.CredResult = @{
						User = $null; Pass = $null; Cancelled = $true; SoftExit = $false; HardClose = $true
						Store = $false; StoreSpecified = $true; ClearStored = $false
					}
					if ($W.AuthOverlay) { $W.AuthOverlay.Visibility = [System.Windows.Visibility]::Collapsed }
					if ($W.AuthOk) { $W.AuthOk.IsDefault = $false }
					try { $W.AuthPass.Password = '' } catch {}
					[void]$W.CredWait.Set()
				} catch {}
			}.GetNewClosure()
			$W.AuthCancel.add_Click({
				param($s,$e)
				try { & $doAuthCancel } catch {}
			}.GetNewClosure())
			if ($W.AuthTitleClose) {
				$W.AuthTitleClose.add_Click({
					param($s,$e)
					try { & $doAuthCancel } catch {}
				}.GetNewClosure())
			}
			$W.AuthPass.add_KeyDown({
				param($s,$e)
				try {
					if ($e.Key -eq 'Return') { $e.Handled = $true; & $submitAuth }
				} catch {}
			}.GetNewClosure())
			$W.AuthUser.add_KeyDown({
				param($s,$e)
				try {
					if ($e.Key -eq 'Return') {
						$e.Handled = $true
						try { [void]$W.AuthPass.Focus() } catch {}
					}
				} catch {}
			}.GetNewClosure())

			if ($W.ConfirmYes) {
				$W.ConfirmYes.add_Click({
					param($s, $e)
					try {
						$W.ConfirmResult = $true
						if ($W.ConfirmOverlay) {
							$W.ConfirmOverlay.Visibility = [System.Windows.Visibility]::Collapsed
						}
						if ($W.ConfirmYes) { $W.ConfirmYes.IsDefault = $false }
						[void]$W.ConfirmWait.Set()
					} catch {}
				}.GetNewClosure())
			}
			$doConfirmNo = {
				try {
					$W.ConfirmResult = $false
					if ($W.ConfirmOverlay) {
						$W.ConfirmOverlay.Visibility = [System.Windows.Visibility]::Collapsed
					}
					if ($W.ConfirmYes) { $W.ConfirmYes.IsDefault = $false }
					[void]$W.ConfirmWait.Set()
				} catch {}
			}.GetNewClosure()
			if ($W.ConfirmNo) {
				$W.ConfirmNo.add_Click({
					param($s, $e)
					try { & $doConfirmNo } catch {}
				}.GetNewClosure())
			}
			if ($W.ConfirmTitleClose) {
				$W.ConfirmTitleClose.add_Click({
					param($s, $e)
					try { & $doConfirmNo } catch {}
				}.GetNewClosure())
			}

			$conv = New-Object System.Windows.Media.BrushConverter
			$colorMap = @{
				'Black'='#5C5C5C'; 'DarkBlue'='#7AA2F7'; 'DarkGreen'='#9ECE6A'; 'DarkCyan'='#7DCFFF'
				'DarkRed'='#B80F0A'; 'DarkMagenta'='#BB9AF7'; 'DarkYellow'='#E0AF68'; 'Gray'='#A0A0AA'
				'DarkGray'='#565F89'; 'Blue'='#7AA2F7'; 'Green'='#9ECE6A'; 'Cyan'='#7DCFFF'
				'Red'='#B80F0A'; 'Magenta'='#BB9AF7'; 'Yellow'='#E0AF68'; 'White'='#C0CAF5'
			}
			$brailleFrames = @(
				[string][char]0x280B,  # ⠋
				[string][char]0x2819,  # ⠙
				[string][char]0x2839,  # ⠹
				[string][char]0x2838,  # ⠸
				[string][char]0x283C,  # ⠼
				[string][char]0x2834,  # ⠴
				[string][char]0x2826,  # ⠦
				[string][char]0x2827,  # ⠧
				[string][char]0x2807,  # ⠇
				[string][char]0x280F   # ⠏
			)
			$appendRuns = {
				param($para, $chunk, $brush, $monoFont, $emojiFont)
				if ([string]::IsNullOrEmpty($chunk) -or $null -eq $para) { return }
				$sb = New-Object System.Text.StringBuilder
				$mode = $null  # 't' text, 'e' emoji
				$emit = {
					param($targetPara, $m, $s, $br, $mf, $ef)
					if ($null -eq $s -or $s.Length -eq 0) { return }
					$run = New-Object System.Windows.Documents.Run ($s.ToString())
					if ($m -eq 'e') {
						if ($ef) { $run.FontFamily = $ef }
						try { $run.ClearValue([System.Windows.Documents.TextElement]::ForegroundProperty) } catch {}
					} else {
						if ($mf) { $run.FontFamily = $mf }
						$run.Foreground = $br
					}
					$targetPara.Inlines.Add($run)
					[void]$s.Clear()
				}
				$i = 0
				$len = $chunk.Length
				while ($i -lt $len) {
					$code = [int][char]$chunk[$i]
					$cp = $code
					$take = 1
					# Surrogate pair: full codepoint
					if ($code -ge 0xD800 -and $code -le 0xDBFF -and ($i + 1) -lt $len) {
						$low = [int][char]$chunk[$i + 1]
						if ($low -ge 0xDC00 -and $low -le 0xDFFF) {
							$cp = 0x10000 + (($code - 0xD800) -shl 10) + ($low - 0xDC00)
							$take = 2
						}
					}
					$isEmoji = $false
					if ($cp -ge 0x1F000 -and $cp -le 0x1FAFF) { $isEmoji = $true }
					elseif ($cp -ge 0x1F1E6 -and $cp -le 0x1F1FF) { $isEmoji = $true }
					elseif ($cp -ge 0x2600 -and $cp -le 0x27BF) { $isEmoji = $true }
					elseif ($cp -ge 0x2300 -and $cp -le 0x23FF) { $isEmoji = $true }
					elseif ($cp -ge 0x2B00 -and $cp -le 0x2BFF) { $isEmoji = $true }
					elseif ($cp -ge 0xFE00 -and $cp -le 0xFE0F) { $isEmoji = $true }
					elseif ($cp -eq 0x200D -or $cp -eq 0x20E3) { $isEmoji = $true }
					elseif ($cp -ge 0x1F300 -and $cp -le 0x1F9FF) { $isEmoji = $true }
					elseif ($cp -ge 0xE0020 -and $cp -le 0xE007F) { $isEmoji = $true }
					$want = if ($isEmoji) { 'e' } else { 't' }
					if ($null -eq $mode) { $mode = $want }
					if ($want -ne $mode) {
						& $emit $para $mode $sb $brush $monoFont $emojiFont
						$mode = $want
					}
					[void]$sb.Append($chunk.Substring($i, $take))
					$i += $take
				}
				& $emit $para $mode $sb $brush $monoFont $emojiFont
			}.GetNewClosure()

			# Code-block syntax highlighting (regex lexer → WPF Runs)
			$synNormLang = {
				param([string]$L)
				$x = ([string]$L).Trim().ToLowerInvariant() -replace '^\.+', ''
				switch -Regex ($x) {
					'^(ps1|psm1|psd1|powershell|pwsh|ps)$' { return 'ps' }
					'^(py|python|pyw)$' { return 'py' }
					'^(js|javascript|jsx|mjs|cjs)$' { return 'js' }
					'^(ts|typescript|tsx)$' { return 'ts' }
					'^(json|jsonc)$' { return 'json' }
					'^(sh|bash|zsh|shell|ksh)$' { return 'sh' }
					'^(cs|csharp|c#)$' { return 'cs' }
					'^(c|h)$' { return 'c' }
					'^(cpp|cxx|cc|hpp|hh|hxx)$' { return 'cpp' }
					'^(java)$' { return 'java' }
					'^(kt|kotlin)$' { return 'java' }
					'^(go|golang)$' { return 'go' }
					'^(rs|rust)$' { return 'rust' }
					'^(rb|ruby)$' { return 'rb' }
					'^(php)$' { return 'php' }
					'^(sql|mysql|pgsql|postgres|tsql|plsql)$' { return 'sql' }
					'^(html|htm|xml|svg|xaml|xsl|xsd)$' { return 'xml' }
					'^(css|scss|less|sass)$' { return 'css' }
					'^(yml|yaml)$' { return 'yaml' }
					'^(md|markdown)$' { return 'md' }
					'^(diff|patch)$' { return 'diff' }
					'^(ini|toml|conf|cfg|env)$' { return 'ini' }
					'^(dockerfile|docker)$' { return 'docker' }
					'^(bat|cmd)$' { return 'bat' }
					'^(r)$' { return 'r' }
					'^(lua)$' { return 'lua' }
					'^(swift)$' { return 'swift' }
					'^(vb|vbs|vba)$' { return 'vb' }
					default { return 'generic' }
				}
			}.GetNewClosure()

			$synBuildRules = {
				param([string]$Norm)
				$o = New-Object System.Collections.ArrayList
				$add = {
					param($list, $name, $pat)
					try {
						$rx = New-Object System.Text.RegularExpressions.Regex (
