						& $add $o 'number'   $num
						& $add $o 'function' '\b(?:function\s+)?([A-Za-z_$][\w$]*)\s*(?=\()|\b([A-Za-z_$][\w$]*)\s*(?==>\s*)'
						& $add $o 'operator' '===|!==|=>|\?\?|\?\.|&&|\|\||\*\*|[-+*/%&|^~<>!=]=?|\?\?='
					}
