						& $add $o 'type'     '\b(?:string|int|long|bool|byte|char|decimal|double|float|object|void|var|dynamic|Task|List|Dictionary|IEnumerable|Action|Func|DateTime|Guid|Exception)\b'
						& $add $o 'number'   $num
						& $add $o 'function' '\b([A-Za-z_]\w*)\s*(?=\()'
						& $add $o 'operator' '=>|\?\?|\?\.|&&|\|\||[-+*/%&|^~<>!=]=?'
