					'php' {
						& $add $o 'comment' ("$cBlock|$cLine|#[^\r\n]*")
						& $add $o 'string'  ("$strDQ|$strSQ")
						& $add $o 'variable' '\$[A-Za-z_]\w*'
						& $add $o 'keyword'  '\b(?:abstract|and|array|as|break|callable|case|catch|class|clone|const|continue|declare|default|do|echo|else|elseif|empty|enddeclare|endfor|endforeach|endif|endswitch|endwhile|eval|exit|extends|final|finally|fn|for|foreach|function|global|goto|if|implements|include|include_once|instanceof|insteadof|interface|isset|list|match|namespace|new|or|print|private|protected|public|readonly|require|require_once|return|static|switch|throw|trait|try|unset|use|var|while|xor|yield|true|false|null)\b'
						& $add $o 'number'   $num
						& $add $o 'function' '\bfunction\s+([A-Za-z_]\w*)|\b([A-Za-z_]\w*)\s*(?=\()'
					}
					'sql' {
						& $add $o 'comment' ("$cBlock|--[^\r\n]*")
						& $add $o 'string'  ("$strDQ|$strSQ")
						& $add $o 'keyword'  '(?i)\b(?:select|from|where|and|or|not|in|is|null|as|join|inner|left|right|full|outer|on|group|by|order|having|limit|offset|insert|into|values|update|set|delete|create|alter|drop|table|index|view|database|schema|primary|key|foreign|references|unique|check|default|constraint|cascade|restrict|union|all|distinct|case|when|then|else|end|exists|between|like|ilike|with|recursive|over|partition|window|rank|count|sum|avg|min|max|cast|coalesce|nullif|true|false|asc|desc|inner|cross|natural|using|returning|conflict|do|nothing|begin|commit|rollback|transaction|grant|revoke|truncate|replace|merge|upsert|explain|analyze|vacuum)\b'
						& $add $o 'number'   $num
						& $add $o 'type'     '(?i)\b(?:int|integer|bigint|smallint|tinyint|decimal|numeric|float|real|double|money|char|varchar|nvarchar|text|ntext|date|datetime|timestamp|time|bool|boolean|blob|clob|json|uuid|serial|bigserial)\b'
					}
					'xml' {
						& $add $o 'comment' '<!--[\s\S]*?-->'
						& $add $o 'string'  ("$strDQ|$strSQ")
						& $add $o 'tag'     '</?[A-Za-z_][\w:.-]*|/?>'
						& $add $o 'attribute' '\b[A-Za-z_][\w:.-]*(?=\s*=)'
						& $add $o 'meta'    '<\?[\s\S]*?\?>|<!\[CDATA\[[\s\S]*?\]\]>'
					}
					'css' {
						& $add $o 'comment' $cBlock
						& $add $o 'string'  ("$strDQ|$strSQ")
						& $add $o 'keyword'  '@[A-Za-z-]+|\b(?:important|from|to)\b'
						& $add $o 'property' '(?m)^\s*([A-Za-z-]+)\s*(?=:)|(?<=[;{]\s*)([A-Za-z-]+)\s*(?=:)'
						& $add $o 'number'   ($num + '(?:px|em|rem|%|vh|vw|s|ms|deg|fr)?')
						& $add $o 'function' '\b([A-Za-z-]+)\s*(?=\()'
						& $add $o 'selector' '[.#][A-Za-z_][\w-]*'
					}
					'yaml' {
						& $add $o 'comment' $hashLine
						& $add $o 'string'  ("$strDQ|$strSQ")
						& $add $o 'keyword'  '\b(?:true|false|null|yes|no|on|off)\b'
						& $add $o 'number'   $num
						& $add $o 'property' '(?m)^(?:\s*-\s*)?([A-Za-z_][\w.-]*)\s*(?=:)'
						& $add $o 'meta'    '(?m)^---$|^\.\.\.$|&\w+|\*\w+|<<\s*:'
					}
					'md' {
						& $add $o 'header'  '(?m)^#{1,6}\s+[^\r\n]+'
						& $add $o 'string'  ($strDQ + '|' + $strBT + '|\*\*[^*]+\*\*|__[^_]+__|\*[^*]+\*|_[^_]+_')
						& $add $o 'meta'    '(?m)^(?:\s*[-*+]|\s*\d+\.)\s+|^\s*>\s+|\[([^\]]+)\]\([^)]+\)'
						& $add $o 'comment' ('(?m)^' + '```' + '[\w]*$|^~~~[\w]*$')
					}
					'diff' {
						& $add $o 'meta'    '(?m)^(?:diff |index |--- |\+\+\+ |@@ ).*$'
						& $add $o 'keyword' '(?m)^\+.*$'
						& $add $o 'tag'     '(?m)^-.*$'
						& $add $o 'comment' '(?m)^(?:\s|\\).*\$'
					}
					'ini' {
						& $add $o 'comment' ('[;#][^\r\n]*')
						& $add $o 'header'  '(?m)^\[[^\]]+\]'
						& $add $o 'property' '(?m)^([A-Za-z_][\w.-]*)\s*(?==)'
						& $add $o 'string'  ("$strDQ|$strSQ")
						& $add $o 'number'  $num
						& $add $o 'keyword' '\b(?:true|false|on|off|yes|no)\b'
					}
					'docker' {
						& $add $o 'comment' $hashLine
						& $add $o 'keyword'  '(?i)\b(?:FROM|RUN|CMD|LABEL|MAINTAINER|EXPOSE|ENV|ADD|COPY|ENTRYPOINT|VOLUME|USER|WORKDIR|ARG|ONBUILD|STOPSIGNAL|HEALTHCHECK|SHELL|AS)\b'
						& $add $o 'string'  ("$strDQ|$strSQ")
						& $add $o 'number'  $num
						& $add $o 'variable' '\$\{[^}]+\}|\$\w+'
					}
					'bat' {
						& $add $o 'comment' '(?i)(?:^|\s)(?:REM\b|::)[^\r\n]*'
						& $add $o 'keyword'  '(?i)\b(?:if|else|for|in|do|goto|call|exit|set|setlocal|endlocal|enabledelayedexpansion|echo|pause|shift|start|pushd|popd|cd|dir|copy|move|del|type|exist|defined|errorlevel|equ|neq|lss|leq|gtr|geq|not)\b'
						& $add $o 'variable' '%[^%]+%|!\w+!'
						& $add $o 'string'  $strDQ
						& $add $o 'number'  $num
					}
					'r' {
						& $add $o 'comment' $hashLine
						& $add $o 'string'  ("$strDQ|$strSQ")
						& $add $o 'keyword'  '\b(?:if|else|repeat|while|function|for|in|next|break|TRUE|FALSE|NULL|Inf|NaN|NA|NA_integer_|NA_real_|NA_complex_|NA_character_|library|require|source|return)\b'
						& $add $o 'number'   $num
						& $add $o 'function' '\b([A-Za-z.][\w.]*)\s*(?=\()'
						& $add $o 'operator' '<-|<<-|->|->>|%[^%]+%|==|!=|<=|>=|&&|\|\|'
					}
					'lua' {
						& $add $o 'comment' ('--\[\[[\s\S]*?\]\]|--[^\r\n]*')
						& $add $o 'string'  ("$strDQ|$strSQ|\[\[[\s\S]*?\]\]")
						& $add $o 'keyword'  '\b(?:and|break|do|else|elseif|end|false|for|function|goto|if|in|local|nil|not|or|repeat|return|then|true|until|while)\b'
						& $add $o 'number'   $num
						& $add $o 'function' '\bfunction\s+([A-Za-z_]\w*(?:\.[A-Za-z_]\w*)*)|\b([A-Za-z_]\w*)\s*(?=\()'
					}
					'swift' {
						& $add $o 'comment' ("$cBlock|$cLine")
						& $add $o 'string'  ('"""[\s\S]*?"""|"(?:\\.|[^"\\])*"')
						& $add $o 'keyword'  '\b(?:associatedtype|class|deinit|enum|extension|fileprivate|func|import|init|inout|internal|let|open|operator|private|protocol|public|rethrows|static|struct|subscript|typealias|var|break|case|continue|default|defer|do|else|fallthrough|for|guard|if|in|repeat|return|switch|where|while|as|Any|catch|false|is|nil|super|self|Self|throw|throws|true|try|async|await|actor|some|opaque)\b'
						& $add $o 'type'     '\b(?:Int|String|Bool|Double|Float|Array|Dictionary|Set|Optional|Result|Error|Void)\b'
						& $add $o 'number'   $num
						& $add $o 'function' '\bfunc\s+([A-Za-z_]\w*)|\b([A-Za-z_]\w*)\s*(?=\()'
					}
					'vb' {
						& $add $o 'comment' ("'[^\r\n]*|(?i)\bREM\b[^\r\n]*")
						& $add $o 'string'  $strDQ
						& $add $o 'keyword'  '(?i)\b(?:AddHandler|AddressOf|Alias|And|AndAlso|As|Boolean|ByRef|Byte|ByVal|Call|Case|Catch|CBool|CByte|CChar|CDate|CDbl|CDec|Char|CInt|Class|CLng|CObj|Const|Continue|CSByte|CShort|CSng|CStr|CType|CUInt|CULng|CUShort|Date|Decimal|Declare|Default|Delegate|Dim|DirectCast|Do|Double|Each|Else|ElseIf|End|Enum|Erase|Error|Event|Exit|False|Finally|For|Friend|Function|Get|GetType|GetXMLNamespace|Global|GoTo|Handles|If|Implements|Imports|In|Inherits|Integer|Interface|Is|IsNot|Let|Lib|Like|Long|Loop|Me|Mod|Module|MustInherit|MustOverride|MyBase|MyClass|Namespace|Narrowing|New|Next|Not|Nothing|NotInheritable|NotOverridable|Object|Of|On|Operator|Option|Optional|Or|OrElse|Overloads|Overridable|Overrides|ParamArray|Partial|Private|Property|Protected|Public|RaiseEvent|ReadOnly|ReDim|REM|RemoveHandler|Resume|Return|SByte|Select|Set|Shadows|Shared|Short|Single|Static|Step|Stop|String|Structure|Sub|SyncLock|Then|Throw|To|True|Try|TryCast|TypeOf|UInteger|ULong|UShort|Using|When|While|Widening|With|WithEvents|WriteOnly|Xor|Async|Await|Iterator|Yield)\b'
						& $add $o 'number'   $num
					}
					default {
						& $add $o 'comment' ("$cBlock|$cLine|$hashLine")
						& $add $o 'string'  ("$strDQ|$strSQ|$strBT")
						& $add $o 'keyword'  '\b(?:if|else|elif|elseif|for|while|do|switch|case|break|continue|return|function|func|def|class|struct|enum|import|from|export|const|let|var|new|try|catch|finally|throw|true|false|null|nil|None|True|False|and|or|not|in|of|as|is|public|private|protected|static|void|int|string|bool|float|double)\b'
						& $add $o 'number'   $num
						& $add $o 'function' '\b([A-Za-z_]\w*)\s*(?=\()'
						& $add $o 'operator' '==|!=|<=|>=|&&|\|\||=>|[-+*/%&|^~<>!=]=?'
					}
				}
				return $o
			}.GetNewClosure()

			$synTokenize = {
				param([string]$Text, [string]$Norm)
				$spans = New-Object System.Collections.ArrayList
				if ([string]::IsNullOrEmpty($Text)) { return $spans }
				$cache = $null
				try {
					if ($W -is [hashtable]) {
						if (-not $W.ContainsKey('SynRuleCache') -or $null -eq $W['SynRuleCache']) {
							$W['SynRuleCache'] = @{}
						}
						$cache = $W['SynRuleCache']
					}
				} catch { $cache = $null }
				$rules = $null
				if ($null -ne $cache -and $cache.ContainsKey($Norm)) {
					$rules = $cache[$Norm]
				} else {
					$rules = & $synBuildRules $Norm
					if ($null -ne $cache) { $cache[$Norm] = $rules }
				}
				if ($null -eq $rules -or $rules.Count -eq 0) {
					[void]$spans.Add(@{ T = $Text; K = 'plain' })
					return $spans
				}
				$pos = 0
				$len = $Text.Length
				$maxScan = [Math]::Min($len, 120000)
				while ($pos -lt $maxScan) {
					$bestIdx = [int]::MaxValue
					$bestLen = 0
					$bestName = 'plain'
					$bestVal = $null
					foreach ($r in $rules) {
						try {
							$m = $r.Rx.Match($Text, $pos)
							if ($m.Success -and $m.Index -ge $pos -and $m.Length -gt 0) {
								if ($m.Index -lt $bestIdx -or ($m.Index -eq $bestIdx -and $m.Length -gt $bestLen)) {
									$bestIdx = $m.Index
									$bestLen = $m.Length
									$bestName = [string]$r.N
									$bestVal = $m.Value
								}
							}
						} catch {}
					}
					if ($null -eq $bestVal) {
						[void]$spans.Add(@{ T = $Text.Substring($pos, $maxScan - $pos); K = 'plain' })
						$pos = $maxScan
						break
					}
					if ($bestIdx -gt $pos) {
						[void]$spans.Add(@{ T = $Text.Substring($pos, $bestIdx - $pos); K = 'plain' })
					}
					$k = $bestName
					if ($k -eq 'decorator') { $k = 'meta' }
					[void]$spans.Add(@{ T = $bestVal; K = $k })
					$pos = $bestIdx + $bestLen
				}
				if ($pos -lt $len) {
					[void]$spans.Add(@{ T = $Text.Substring($pos); K = 'plain' })
				}
				$merged = New-Object System.Collections.ArrayList
				foreach ($s in $spans) {
					if ($merged.Count -gt 0) {
						$prev = $merged[$merged.Count - 1]
						if ([string]$prev.K -eq [string]$s.K) {
							$prev.T = [string]$prev.T + [string]$s.T
							continue
						}
					}
					[void]$merged.Add(@{ T = [string]$s.T; K = [string]$s.K })
				}
				return $merged
			}.GetNewClosure()

			$synColorMap = @{
				plain       = '#C8C8D0'
				comment     = '#6A6A76'
				string      = '#9ECE6A'
				keyword     = '#BB9AF7'
				number      = '#FF9E64'
				function    = '#7AA2F7'
				type        = '#7DCFFF'
				variable    = '#E0AF68'
				operator    = '#89DDFF'
				punctuation = '#8A8A96'
				tag         = '#F05C5C'
				attribute   = '#E0AF68'
				builtin     = '#7AA2F7'
				property    = '#7DCFFF'
				meta        = '#BB9AF7'
				header      = '#7AA2F7'
			}

			$paintCodeHighlight = {
				param($rtb, [string]$plain, [string]$lang, $conv, $brushCache, $monoFont)
				if ($null -eq $rtb) { return }
				try {
					# Trim trailing newlines for code display
					if ($null -eq $plain) { $plain = '' }
					while ($plain.Length -gt 0 -and ($plain.EndsWith("`r`n") -or $plain.EndsWith("`n") -or $plain.EndsWith("`r"))) {
						if ($plain.EndsWith("`r`n")) { $plain = $plain.Substring(0, $plain.Length - 2) }
						else { $plain = $plain.Substring(0, $plain.Length - 1) }
					}
					$norm = & $synNormLang $lang
					$tokens = & $synTokenize $plain $norm
					$doc = New-Object System.Windows.Documents.FlowDocument
					$doc.PagePadding = New-Object System.Windows.Thickness(0)
					try { $doc.TextAlignment = [System.Windows.TextAlignment]::Left } catch {}
					$para = New-Object System.Windows.Documents.Paragraph
					$para.Margin = New-Object System.Windows.Thickness(0)
					$para.Padding = New-Object System.Windows.Thickness(0)
					try { $para.LineHeight = 18 } catch {}
					if ($null -eq $tokens -or $tokens.Count -eq 0) {
						$run = New-Object System.Windows.Documents.Run ($(if ($null -eq $plain) { '' } else { $plain }))
						$hx0 = '#C8C8D0'
						if (-not $brushCache.ContainsKey($hx0)) { $brushCache[$hx0] = $conv.ConvertFromString($hx0) }
						$run.Foreground = $brushCache[$hx0]
						if ($monoFont) { $run.FontFamily = $monoFont }
						[void]$para.Inlines.Add($run)
					} else {
						foreach ($tok in $tokens) {
							$k = [string]$tok.K
							if (-not $synColorMap.ContainsKey($k)) { $k = 'plain' }
							$hx = [string]$synColorMap[$k]
							if (-not $brushCache.ContainsKey($hx)) {
								$brushCache[$hx] = $conv.ConvertFromString($hx)
							}
							$run = New-Object System.Windows.Documents.Run ([string]$tok.T)
							$run.Foreground = $brushCache[$hx]
							if ($monoFont) { $run.FontFamily = $monoFont }
							[void]$para.Inlines.Add($run)
						}
					}
					[void]$doc.Blocks.Add($para)
					try {
						$pw = [double]$rtb.ActualWidth
						if ([double]::IsNaN($pw) -or $pw -lt 40) {
							try {
								$par = $rtb.Parent
								while ($null -ne $par -and -not ($par -is [System.Windows.FrameworkElement])) { $par = $par.Parent }
								if ($par -is [System.Windows.FrameworkElement] -and $par.ActualWidth -gt 40) {
									$pw = [double]$par.ActualWidth - 8
								}
							} catch {}
						}
						if ([double]::IsNaN($pw) -or $pw -lt 40) { $pw = 480 }
						$doc.PageWidth = [Math]::Max(80, $pw - 6)
					} catch {}
					$rtb.Document = $doc
				} catch {
					try {
						$doc2 = New-Object System.Windows.Documents.FlowDocument
						$p2 = New-Object System.Windows.Documents.Paragraph
						$r2 = New-Object System.Windows.Documents.Run ($(if ($null -eq $plain) { '' } else { $plain }))
						if ($monoFont) { $r2.FontFamily = $monoFont }
						[void]$p2.Inlines.Add($r2)
						[void]$doc2.Blocks.Add($p2)
						$rtb.Document = $doc2
					} catch {}
				}
			}.GetNewClosure()

			$getCodePlainText = {
				param($box)
				if ($null -eq $box) { return '' }
				try {
					if ($box.Tag -is [hashtable] -and $null -ne $box.Tag['Plain']) {
						return [string]$box.Tag['Plain']
					}
				} catch {}
				try {
					if ($box -is [System.Windows.Controls.TextBox]) { return [string]$box.Text }
				} catch {}
				try {
					$tr = New-Object System.Windows.Documents.TextRange($box.Document.ContentStart, $box.Document.ContentEnd)
					$t = [string]$tr.Text
					return $t.TrimEnd([char]13, [char]10)
				} catch {}
				return ''
			}.GetNewClosure()

			$openHttpLink = {
				param($sender, $e)
				try {
					$u = $null
					try { if ($e -and $e.Uri) { $u = [string]$e.Uri.AbsoluteUri } } catch {}
					if ([string]::IsNullOrWhiteSpace($u)) {
						try { if ($sender -and $sender.NavigateUri) { $u = [string]$sender.NavigateUri.AbsoluteUri } } catch {}
					}
					if ($u -match '^(?i)https?://') {
						$psi = New-Object System.Diagnostics.ProcessStartInfo
						$psi.FileName = $u
						$psi.UseShellExecute = $true
						[void][System.Diagnostics.Process]::Start($psi)
					}
				} catch {}
				try { if ($e) { $e.Handled = $true } } catch {}
			}.GetNewClosure()

			$splitLinkSegments = {
				param([string]$s)
				$out = New-Object System.Collections.ArrayList
				if ([string]::IsNullOrEmpty($s)) { return $out }
				# [label](https://url) first, then bare https:// and www.
				$rx = New-Object System.Text.RegularExpressions.Regex (
					'(?i)\[([^\]]+)\]\(\s*(https?://[^)\s]+)\s*(?:\"[^\"]*\")?\s*\)|(https?://[^\s<>\[\]]+)|(www\.[^\s<>\[\]]+)'
				)
				$pos = 0
				foreach ($m in $rx.Matches($s)) {
					if ($m.Index -gt $pos) {
						[void]$out.Add(@{ Kind = 't'; Text = $s.Substring($pos, $m.Index - $pos) })
					}
					$display = $null
					$url = $null
					$bare = $false
					if ($m.Groups[1].Success -and $m.Groups[2].Success) {
						# Markdown: display label only; full URL on hover
						$display = ([string]$m.Groups[1].Value).Trim()
						$url = ([string]$m.Groups[2].Value).Trim()
					} elseif ($m.Groups[3].Success) {
						$url = [string]$m.Groups[3].Value
						$display = $url
						$bare = $true
					} elseif ($m.Groups[4].Success) {
						$display = [string]$m.Groups[4].Value
						$url = 'https://' + $display
						$bare = $true
					}
					if ($null -ne $url) {
						$trail = ''
						if ($bare) {
							while ($url.Length -gt 0) {
								$ch = $url.Substring($url.Length - 1, 1)
								if ($ch -match '^[.,;:!?)\]]$') {
									$trail = $ch + $trail
									$url = $url.Substring(0, $url.Length - 1)
								} else { break }
							}
							if ($trail.Length -gt 0 -and $display.Length -ge $trail.Length -and $display.EndsWith($trail)) {
								$display = $display.Substring(0, $display.Length - $trail.Length)
							}
						}
						if (($url -match '^(?i)https?://\S+$') -and $display.Length -gt 0) {
							[void]$out.Add(@{ Kind = 'a'; Text = $display; Url = $url })
							if ($trail.Length -gt 0) {
								[void]$out.Add(@{ Kind = 't'; Text = $trail })
							}
						} else {
							[void]$out.Add(@{ Kind = 't'; Text = [string]$m.Value })
						}
					} else {
						[void]$out.Add(@{ Kind = 't'; Text = [string]$m.Value })
					}
					$pos = $m.Index + $m.Length
				}
				if ($pos -lt $s.Length) {
					[void]$out.Add(@{ Kind = 't'; Text = $s.Substring($pos) })
				}
				if ($out.Count -eq 0) {
					[void]$out.Add(@{ Kind = 't'; Text = $s })
				}
				return $out
			}.GetNewClosure()

			$addHyperlink = {
				param($targetPara, $display, $url, $brush, $monoFont)
				if ($null -eq $targetPara -or [string]::IsNullOrEmpty($display)) { return }
				if ($url -notmatch '^(?i)https?://') { return }
				try {
					$uri = New-Object System.Uri ($url)
					$hl = New-Object System.Windows.Documents.Hyperlink
					$hl.NavigateUri = $uri
					$hl.Cursor = [System.Windows.Input.Cursors]::Hand
					try { $hl.ToolTip = [string]$url } catch {}
					$run = New-Object System.Windows.Documents.Run ($display)
					if ($monoFont) { $run.FontFamily = $monoFont }
					$linkHex = '#7AA2F7'
					if (-not $W.BrushCache.ContainsKey($linkHex)) {
						$W.BrushCache[$linkHex] = $conv.ConvertFromString($linkHex)
					}
					$run.Foreground = $W.BrushCache[$linkHex]
					try { $hl.Foreground = $W.BrushCache[$linkHex] } catch {}
					try { $hl.TextDecorations = [System.Windows.TextDecorations]::Underline } catch {}
					$hl.Inlines.Add($run)
					$hl.add_RequestNavigate($openHttpLink)
					$targetPara.Inlines.Add($hl)
				} catch {
					try {
						$run = New-Object System.Windows.Documents.Run ($display)
						$run.Foreground = $brush
						if ($monoFont) { $run.FontFamily = $monoFont }
						$targetPara.Inlines.Add($run)
					} catch {}
				}
			}.GetNewClosure()

			$appendRunsWithLinks = {
				param($para, $chunk, $brush, $monoFont, $emojiFont)
				if ([string]::IsNullOrEmpty($chunk) -or $null -eq $para) { return }
				$segs = @( & $splitLinkSegments $chunk )
				foreach ($seg in $segs) {
					if ($null -eq $seg) { continue }
					if ([string]$seg.Kind -eq 'a') {
						& $addHyperlink $para ([string]$seg.Text) ([string]$seg.Url) $brush $monoFont
					} else {
						$tx = [string]$seg.Text
						if ($tx.Length -gt 0) {
							& $appendRuns $para $tx $brush $monoFont $emojiFont
						}
					}
				}
			}.GetNewClosure()

			$timer = New-Object System.Windows.Threading.DispatcherTimer
			$timer.Interval = [TimeSpan]::FromMilliseconds(16)
			$timer.add_Tick({
				try {
					# Session picker / modal open - freeze host UI work for smooth dialog
					try { if ([bool]$W.ModalUi) { return } } catch {}
					$rtb = $W.Log
					$q = $W.WriteQueue
					if (-not $rtb -or -not $q) { return }
					$doc = $rtb.Document
					if (-not $doc) { return }
					try {
						if ($W -is [hashtable]) {
							if (-not $W.ContainsKey('BrushCache') -or $null -eq $W['BrushCache']) {
								$W['BrushCache'] = @{}
							}
						} elseif ($null -eq $W.BrushCache) {
							$W.BrushCache = @{}
						}
					} catch {
						try { $W['BrushCache'] = @{} } catch {}
					}
					$n = 0
					$item = $null
					while ($n -lt 120 -and $q.TryDequeue([ref]$item)) {
					  try {
						$n++
						if ($null -eq $item) { continue }
						$kind = 'text'
						try { if ($item.Kind) { $kind = [string]$item.Kind } } catch {}

						$newPara = {
							$p = New-Object System.Windows.Documents.Paragraph
							$p.Margin = New-Object System.Windows.Thickness 0
							$p.Padding = New-Object System.Windows.Thickness 0
							$p.LineHeight = 16
							return $p
						}
						$trimTrailingEmptyParas = {
							try {
								while ($doc.Blocks.Count -gt 0) {
									$last = $doc.Blocks.LastBlock
									if (-not ($last -is [System.Windows.Documents.Paragraph])) { break }
									$isEmpty = $false
									try {
										if ($last.Inlines.Count -eq 0) { $isEmpty = $true }
										elseif ($last.Inlines.Count -eq 1) {
											$fi = $last.Inlines.FirstInline
											if ($fi -is [System.Windows.Documents.Run]) {
												if ([string]::IsNullOrWhiteSpace([string]$fi.Text)) { $isEmpty = $true }
											}
										}
									} catch { $isEmpty = $false }
									if (-not $isEmpty) { break }
									[void]$doc.Blocks.Remove($last)
								}
							} catch {}
						}

						$stretchW = 280.0
						try {
							$aw = [double]$rtb.ActualWidth
							if ($aw -gt 48 -and -not [double]::IsNaN($aw)) {
								$padL = 12.0; $padR = 12.0
								try { $padL = [double]$rtb.Padding.Left; $padR = [double]$rtb.Padding.Right } catch {}
								$vBar = 16.0
								try {
									if ($rtb.ComputedVerticalScrollBarVisibility -eq [System.Windows.Visibility]::Visible) {
										$vBar = 16.0
									}
								} catch {}
								$stretchW = [Math]::Max(40.0, $aw - $padL - $padR - $vBar - 2.0)
							}
						} catch {}

						# Chat turn header
						if ($kind -eq 'chat-turn') {
							try {
								& $trimTrailingEmptyParas
								$role = 'agent'
								try { if ($item.Role) { $role = ([string]$item.Role).ToLowerInvariant() } } catch {}
								$nm = ''
								try { $nm = [string]$item.Name } catch {}
								if ([string]::IsNullOrWhiteSpace($nm)) {
									$nm = if ($role -eq 'user') { 'You' } else { 'MiniBot' }
								}
								$bodyTxt = ''
								try { if ($null -ne $item.Body) { $bodyTxt = [string]$item.Body } } catch {}
								$timeTxt = ''
								try { if ($item.Time) { $timeTxt = [string]$item.Time } } catch {}
								$doHl = $false
								try { $doHl = ([int]$item.Highlight -ne 0) } catch { $doHl = ($role -eq 'user') }

								$brushCache = $null
								try { $brushCache = $W['BrushCache'] } catch { try { $brushCache = $W.BrushCache } catch {} }
								if ($null -eq $brushCache) { $brushCache = @{}; try { $W['BrushCache'] = $brushCache } catch {} }
								foreach ($hx in @('#26808080', '#6A6A76', '#A0A0AA', '#B80F0A', '#7DCFFF', '#C8C8D0', '#8A8A96')) {
									if (-not $brushCache.ContainsKey($hx)) {
										$brushCache[$hx] = $conv.ConvertFromString($hx)
									}
								}

								$tsRightInset = 18.0
								$outer = New-Object System.Windows.Controls.Border
								$outer.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
								$outer.SnapsToDevicePixels = $true
								$outer.Width = $stretchW
								$outer.Tag = 'chat-turn'
								if ($doHl) {
									$outer.Background = $brushCache['#26808080']
									$outer.CornerRadius = New-Object System.Windows.CornerRadius(5)
									$outer.Padding = New-Object System.Windows.Thickness(10, 7, $tsRightInset, 8)
									$outer.Margin = New-Object System.Windows.Thickness(0, 8, 0, 6)
								} else {
									$outer.Background = [System.Windows.Media.Brushes]::Transparent
									$outer.Padding = New-Object System.Windows.Thickness(0, 6, $tsRightInset, 2)
									$outer.Margin = New-Object System.Windows.Thickness(0, 10, 0, 2)
								}

								$grid = New-Object System.Windows.Controls.Grid
								$col0 = New-Object System.Windows.Controls.ColumnDefinition
								$col0.Width = New-Object System.Windows.GridLength(1, [System.Windows.GridUnitType]::Star)
								$col1 = New-Object System.Windows.Controls.ColumnDefinition
								$col1.Width = [System.Windows.GridLength]::Auto
								[void]$grid.ColumnDefinitions.Add($col0)
								[void]$grid.ColumnDefinitions.Add($col1)
								$row0 = New-Object System.Windows.Controls.RowDefinition
								$row0.Height = [System.Windows.GridLength]::Auto
								[void]$grid.RowDefinitions.Add($row0)
								if ($doHl -and $bodyTxt.Length -gt 0) {
									$row1 = New-Object System.Windows.Controls.RowDefinition
									$row1.Height = [System.Windows.GridLength]::Auto
									[void]$grid.RowDefinitions.Add($row1)
								}

								$left = New-Object System.Windows.Controls.TextBlock
								$left.FontFamily = $W.MonoFont
								$left.FontSize = 13
								$left.TextWrapping = [System.Windows.TextWrapping]::Wrap
								$left.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								$mkRun = {
									param($t, $br, $bold)
									$r = New-Object System.Windows.Documents.Run ($t)
									$r.Foreground = $br
									if ($bold) { $r.FontWeight = [System.Windows.FontWeights]::Bold }
									return $r
								}
								if ($role -eq 'user') {
									[void]$left.Inlines.Add((& $mkRun '[' $brushCache['#A0A0AA'] $false))
									[void]$left.Inlines.Add((& $mkRun $nm $brushCache['#7DCFFF'] $true))
									[void]$left.Inlines.Add((& $mkRun ']' $brushCache['#A0A0AA'] $false))
								} else {
									[void]$left.Inlines.Add((& $mkRun '[' $brushCache['#A0A0AA'] $false))
									[void]$left.Inlines.Add((& $mkRun $nm $brushCache['#B80F0A'] $true))
									[void]$left.Inlines.Add((& $mkRun '-' $brushCache['#A0A0AA'] $false))
									[void]$left.Inlines.Add((& $mkRun 'Agent' $brushCache['#B80F0A'] $true))
									[void]$left.Inlines.Add((& $mkRun ']' $brushCache['#A0A0AA'] $false))
								}
								[System.Windows.Controls.Grid]::SetRow($left, 0)
								[System.Windows.Controls.Grid]::SetColumn($left, 0)
								[void]$grid.Children.Add($left)

								$right = New-Object System.Windows.Controls.TextBlock
								$right.Text = $timeTxt
								$right.Foreground = $brushCache['#6A6A76']
								$right.FontFamily = $W.MonoFont
								$right.FontSize = 11
								$right.Margin = New-Object System.Windows.Thickness(16, 0, 0, 0)
								$right.Padding = New-Object System.Windows.Thickness(0)
								$right.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								$right.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Right
								$right.TextAlignment = [System.Windows.TextAlignment]::Right
								try { $right.MinWidth = 52 } catch {}
								[System.Windows.Controls.Grid]::SetRow($right, 0)
								[System.Windows.Controls.Grid]::SetColumn($right, 1)
								[void]$grid.Children.Add($right)

								if ($doHl -and $bodyTxt.Length -gt 0) {
									$bodyTb = New-Object System.Windows.Controls.TextBlock
									$bodyTb.Text = $bodyTxt
									$bodyTb.Foreground = $brushCache['#C8C8D0']
									$bodyTb.FontFamily = $W.MonoFont
									$bodyTb.FontSize = 13
									$bodyTb.TextWrapping = [System.Windows.TextWrapping]::Wrap
									$bodyTb.Margin = New-Object System.Windows.Thickness(0, 5, 0, 0)
									[System.Windows.Controls.Grid]::SetRow($bodyTb, 1)
									[System.Windows.Controls.Grid]::SetColumn($bodyTb, 0)
									[System.Windows.Controls.Grid]::SetColumnSpan($bodyTb, 2)
									[void]$grid.Children.Add($bodyTb)
								}

								$outer.Child = $grid
								$buc = New-Object System.Windows.Documents.BlockUIContainer ($outer)
								$buc.Margin = New-Object System.Windows.Thickness 0
								$doc.Blocks.Add($buc)
								try {
									if ($W -is [hashtable]) {
										if (-not $W.ContainsKey('MdStretchElements') -or $null -eq $W['MdStretchElements']) {
											$W['MdStretchElements'] = New-Object System.Collections.ArrayList
										}
										[void]$W['MdStretchElements'].Add($outer)
									} else {
										$sl = $null
										try { $sl = $W.MdStretchElements } catch { $sl = $null }
										if ($null -eq $sl) {
											$sl = New-Object System.Collections.ArrayList
											try { $W | Add-Member -NotePropertyName MdStretchElements -NotePropertyValue $sl -Force } catch {}
										}
										[void]$sl.Add($outer)
									}
								} catch {}
								$doc.Blocks.Add((& $newPara))
								try { $W.LogLineCharRun = 0 } catch {}
							} catch {}
							continue
						}

						if ($kind -eq 'md-code-open') {
							try {
								& $trimTrailingEmptyParas
								$lang = ''
								try { $lang = [string]$item.Text } catch {}
								if ([string]::IsNullOrWhiteSpace($lang)) { $lang = 'code' }

								$brushCache = $null
								try { $brushCache = $W['BrushCache'] } catch { try { $brushCache = $W.BrushCache } catch {} }
								if ($null -eq $brushCache) { $brushCache = @{}; try { $W['BrushCache'] = $brushCache } catch {} }
								foreach ($hx in @('#1A1A1E', '#252530', '#3A3A42', '#7DCFFF', '#8A8A96', '#C8C8D0', '#2A2A30', '#7AA2F7', '#BB9AF7', '#9ECE6A', '#FF9E64', '#E0AF68', '#89DDFF', '#F05C5C', '#6A6A76')) {
									if (-not $brushCache.ContainsKey($hx)) {
										$brushCache[$hx] = $conv.ConvertFromString($hx)
									}
								}

								$outer = New-Object System.Windows.Controls.Border
								$outer.Background = $brushCache['#1A1A1E']
								$outer.BorderBrush = $brushCache['#3A3A42']
								$outer.BorderThickness = New-Object System.Windows.Thickness(1)
								$outer.CornerRadius = New-Object System.Windows.CornerRadius(6)
								$outer.Padding = New-Object System.Windows.Thickness(0)
								$outer.Margin = New-Object System.Windows.Thickness(0, 8, 0, 8)
								$outer.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
								$outer.SnapsToDevicePixels = $true
								$outer.Width = $stretchW

								$root = New-Object System.Windows.Controls.Grid
								$rowHdr = New-Object System.Windows.Controls.RowDefinition
								$rowHdr.Height = [System.Windows.GridLength]::Auto
								$rowBody = New-Object System.Windows.Controls.RowDefinition
								$rowBody.Height = [System.Windows.GridLength]::Auto
								[void]$root.RowDefinitions.Add($rowHdr)
								[void]$root.RowDefinitions.Add($rowBody)

								$hdr = New-Object System.Windows.Controls.Border
								$hdr.Background = $brushCache['#252530']
								$hdr.Padding = New-Object System.Windows.Thickness(10, 5, 8, 5)
								$hdr.CornerRadius = New-Object System.Windows.CornerRadius(6, 6, 0, 0)
								$hdrGrid = New-Object System.Windows.Controls.Grid
								$hc0 = New-Object System.Windows.Controls.ColumnDefinition
								$hc0.Width = New-Object System.Windows.GridLength(1, [System.Windows.GridUnitType]::Star)
								$hc1 = New-Object System.Windows.Controls.ColumnDefinition
								$hc1.Width = [System.Windows.GridLength]::Auto
								[void]$hdrGrid.ColumnDefinitions.Add($hc0)
								[void]$hdrGrid.ColumnDefinitions.Add($hc1)

								$langTb = New-Object System.Windows.Controls.TextBlock
								$langTb.Text = $lang
								$langTb.Foreground = $brushCache['#8A8A96']
								$langTb.FontFamily = $W.MonoFont
								$langTb.FontSize = 11
								$langTb.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								[System.Windows.Controls.Grid]::SetColumn($langTb, 0)
								[void]$hdrGrid.Children.Add($langTb)

								$codeBox = New-Object System.Windows.Controls.RichTextBox
								$codeBox.IsReadOnly = $true
								try { $codeBox.IsReadOnlyCaretVisible = $true } catch {}
								try { $codeBox.IsUndoEnabled = $false } catch {}
								$codeBox.BorderThickness = New-Object System.Windows.Thickness(0)
								$codeBox.Background = [System.Windows.Media.Brushes]::Transparent
								$codeBox.Foreground = $brushCache['#C8C8D0']
								try { $codeBox.CaretBrush = $brushCache['#C8C8D0'] } catch {}
								$codeBox.FontFamily = $W.MonoFont
								$codeBox.FontSize = 12.5
								$codeBox.Padding = New-Object System.Windows.Thickness(10, 8, 10, 10)
								$codeBox.MinHeight = 28
								$codeBox.HorizontalScrollBarVisibility = [System.Windows.Controls.ScrollBarVisibility]::Disabled
								$codeBox.VerticalScrollBarVisibility = [System.Windows.Controls.ScrollBarVisibility]::Disabled
								try {
									$codeBox.Document.PagePadding = New-Object System.Windows.Thickness(0)
									$codeBox.Document.PageWidth = [Math]::Max(80, $stretchW - 8)
								} catch {}
								$codeMeta = @{
									Kind     = 'md-code'
									Lang     = $lang
									Plain    = ''
									Rtb      = $codeBox
									LiveHl   = $true
								}
								$codeBox.Tag = $codeMeta
								$outer.Tag = $codeMeta

								$copyBtn = New-Object System.Windows.Controls.Button
								$copyBtn.Content = 'Copy'
								$copyBtn.Cursor = [System.Windows.Input.Cursors]::Hand
								$copyBtn.Padding = New-Object System.Windows.Thickness(10, 2, 10, 2)
								$copyBtn.Margin = New-Object System.Windows.Thickness(8, 0, 0, 0)
								$copyBtn.FontSize = 11
								$copyBtn.FontFamily = $W.MonoFont
								$copyBtn.Foreground = $brushCache['#C8C8D0']
								$copyBtn.Background = $brushCache['#2A2A30']
								$copyBtn.BorderBrush = $brushCache['#3A3A42']
								$copyBtn.BorderThickness = New-Object System.Windows.Thickness(1)
								$copyBtn.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								$copyBtn.Tag = @{
									Box        = $codeBox
									CopiedOnce = $false
									ResetTimer = $null
								}
								$copyBtn.Add_Click({
									param($sender, $e)
									try {
										$st = $null
										try { $st = $sender.Tag } catch {}
										$tb = $null
										if ($st -is [hashtable]) {
											try { $tb = $st['Box'] } catch {}
										} else {
											$tb = $st
										}
										$txt = ''
										if ($null -ne $tb) {
											try {
												if ($tb.Tag -is [hashtable] -and $null -ne $tb.Tag['Plain']) {
													$txt = [string]$tb.Tag['Plain']
												} else {
													$tr = New-Object System.Windows.Documents.TextRange($tb.Document.ContentStart, $tb.Document.ContentEnd)
													$txt = ([string]$tr.Text).TrimEnd([char]13, [char]10)
												}
											} catch {
												try { $txt = [string]$tb.Text } catch { $txt = '' }
											}
										}
										if ($null -eq $txt) { $txt = '' }
										[System.Windows.Clipboard]::SetText($txt)
										$sender.Content = 'Copied'
										if ($st -is [hashtable]) {
											$st['CopiedOnce'] = $true
											try {
												if ($null -ne $st['ResetTimer']) {
													$st['ResetTimer'].Stop()
													$st['ResetTimer'] = $null
												}
											} catch {}
											$timer = New-Object System.Windows.Threading.DispatcherTimer
											$timer.Interval = [TimeSpan]::FromSeconds(3)
											$timer.Tag = $sender
											$timer.Add_Tick({
												param($tSender, $te)
												try {
													$tSender.Stop()
													$btn = $null
													try { $btn = $tSender.Tag } catch {}
													if ($null -eq $btn) { return }
													$bst = $null
													try { $bst = $btn.Tag } catch {}
													$chk = [string][char]0x2713  # ✓
													if ($bst -is [hashtable] -and [bool]$bst['CopiedOnce']) {
														$btn.Content = ('{0} Copy' -f $chk)
													} else {
														$btn.Content = 'Copy'
													}
													if ($bst -is [hashtable]) { $bst['ResetTimer'] = $null }
												} catch {}
											})
											$st['ResetTimer'] = $timer
											$timer.Start()
										}
									} catch {
										try { $sender.Content = 'Failed' } catch {}
									}
								})
								[System.Windows.Controls.Grid]::SetColumn($copyBtn, 1)
								[void]$hdrGrid.Children.Add($copyBtn)
								$hdr.Child = $hdrGrid
								[System.Windows.Controls.Grid]::SetRow($hdr, 0)
								[void]$root.Children.Add($hdr)

								[System.Windows.Controls.Grid]::SetRow($codeBox, 1)
								[void]$root.Children.Add($codeBox)
								$outer.Child = $root

								$buc = New-Object System.Windows.Documents.BlockUIContainer ($outer)
								$buc.Margin = New-Object System.Windows.Thickness 0
								$doc.Blocks.Add($buc)

								try {
									if ($W -is [hashtable]) {
										$W['ActiveCodeBox'] = $codeBox
										$W['ActiveCodeBorder'] = $outer
										if (-not $W.ContainsKey('MdStretchElements') -or $null -eq $W['MdStretchElements']) {
											$W['MdStretchElements'] = New-Object System.Collections.ArrayList
										}
										[void]$W['MdStretchElements'].Add($outer)
									} else {
										try { $W.ActiveCodeBox = $codeBox } catch {}
										try { $W.ActiveCodeBorder = $outer } catch {}
										$sl = $null
										try { $sl = $W.MdStretchElements } catch { $sl = $null }
										if ($null -eq $sl) {
											$sl = New-Object System.Collections.ArrayList
											try { $W | Add-Member -NotePropertyName MdStretchElements -NotePropertyValue $sl -Force } catch {}
										}
										[void]$sl.Add($outer)
									}
								} catch {}
								try { $W.LogLineCharRun = 0 } catch {}
							} catch {}
							continue
						}

						if ($kind -eq 'md-code-append') {
							try {
								$piece = ''
								try { $piece = [string]$item.Text } catch {}
								if ($piece.Length -gt 0) {
									$box = $null
									try {
										if ($W -is [hashtable]) { $box = $W['ActiveCodeBox'] }
										else { $box = $W.ActiveCodeBox }
									} catch {}
									if ($null -ne $box) {
										$meta = $null
										try { $meta = $box.Tag } catch {}
										if ($meta -is [hashtable]) {
											$meta['Plain'] = [string]$meta['Plain'] + $piece
											$plainNow = [string]$meta['Plain']
											if ($plainNow.Length -le 24000) {
												$bc = $null
												try { $bc = $W['BrushCache'] } catch { try { $bc = $W.BrushCache } catch {} }
												if ($null -eq $bc) { $bc = @{}; try { $W['BrushCache'] = $bc } catch {} }
												& $paintCodeHighlight $box $plainNow ([string]$meta['Lang']) $conv $bc $W.MonoFont
											} else {
												try { $box.AppendText($piece) } catch {}
												$meta['LiveHl'] = $false
											}
										} else {
											try { $box.AppendText($piece) } catch {}
										}
										try { $box.ScrollToEnd() } catch {}
									} else {
										if ($doc.Blocks.Count -eq 0) { $doc.Blocks.Add((& $newPara)) }
										$para = $doc.Blocks | Select-Object -Last 1
										if (-not ($para -is [System.Windows.Documents.Paragraph])) {
											$para = & $newPara
											$doc.Blocks.Add($para)
										}
										$hex = '#7DCFFF'
										if (-not $W.BrushCache.ContainsKey($hex)) {
											$W.BrushCache[$hex] = $conv.ConvertFromString($hex)
										}
										& $appendRuns $para $piece $W.BrushCache[$hex] $W.MonoFont $W.EmojiFont
									}
								}
							} catch {}
							continue
						}

						if ($kind -eq 'md-code-close') {
							try {
								$box = $null
								try {
									if ($W -is [hashtable]) { $box = $W['ActiveCodeBox'] }
									else { $box = $W.ActiveCodeBox }
								} catch {}
								if ($null -ne $box) {
									$meta = $null
									try { $meta = $box.Tag } catch {}
									if ($meta -is [hashtable]) {
										$bc = $null
										try { $bc = $W['BrushCache'] } catch { try { $bc = $W.BrushCache } catch {} }
										if ($null -eq $bc) { $bc = @{}; try { $W['BrushCache'] = $bc } catch {} }
										$plainClose = [string]$meta['Plain']
										if ($plainClose.EndsWith("`r`n")) {
											$plainClose = $plainClose.Substring(0, $plainClose.Length - 2)
										} elseif ($plainClose.EndsWith("`n")) {
											$plainClose = $plainClose.Substring(0, $plainClose.Length - 1)
										}
										$meta['Plain'] = $plainClose
										& $paintCodeHighlight $box $plainClose ([string]$meta['Lang']) $conv $bc $W.MonoFont
									}
								}
								if ($W -is [hashtable]) {
									$W['ActiveCodeBox'] = $null
									$W['ActiveCodeBorder'] = $null
								} else {
									try { $W.ActiveCodeBox = $null } catch {}
									try { $W.ActiveCodeBorder = $null } catch {}
								}
								try { $W.LogLineCharRun = 0 } catch {}
							} catch {}
							continue
						}

						# Inline image / video / audio (markdown ![alt](path) — spaces in path AND label ok)
						if ($kind -eq 'md-media') {
							try {
								& $trimTrailingEmptyParas
								$mediaUri = ''
								$mediaKind = 'image'
								$mediaAlt = ''
								$mediaDisp = ''
								try { $mediaUri = [string]$item.MediaUri } catch {}
								try { $mediaKind = ([string]$item.MediaKind).ToLowerInvariant() } catch {}
								try { $mediaAlt = [string]$item.MediaAlt } catch {}
								try { $mediaDisp = [string]$item.Text } catch {}
								if ([string]::IsNullOrWhiteSpace($mediaUri)) { continue }
								if ($mediaKind -notin @('video', 'audio', 'image')) { $mediaKind = 'image' }
								# STA-local helpers (main-runspace functions are not visible here)
								$normMediaPath = {
									param([string]$Raw)
									$p = [string]$Raw
									if ([string]::IsNullOrWhiteSpace($p)) { return '' }
									$p = $p.Trim().Trim('"').Trim("'")
									if ($p -match '^(.*?)\s+"[^"]*"\s*$') { $p = [string]$Matches[1].Trim() }
									if ($p.Length -ge 2 -and $p[0] -eq [char]'<' -and $p[$p.Length - 1] -eq [char]'>') {
										$p = $p.Substring(1, $p.Length - 2).Trim()
									}
									if ($p -match '^(?i)file://') {
										try { $p = ([Uri]$p).LocalPath } catch {}
										try { $p = [Uri]::UnescapeDataString($p) } catch {}
									}
									$p = $p -replace '/', '\'
									if ($p -match '(?i)(?:^[A-Za-z]:\\)?Windows\\System32\\(Users\\.+)$') { $p = 'C:\' + $Matches[1] }
									elseif ($p -match '(?i)\\Windows\\System32\\(Users\\.+)$') { $p = 'C:\' + $Matches[1] }
									if ($p -match '^(?i)Users\\') { $p = 'C:\' + $p }
									return $p
								}.GetNewClosure()
								# Preserve multi-word titles: ![My Song Title](...) / filenames with spaces
								$fmtMediaLabel = {
									param([string]$Alt, [string]$PathOrDisplay, [string]$Fallback, [int]$MaxLen)
									$name = ''
									if (-not [string]::IsNullOrWhiteSpace($Alt)) {
										$name = [string]$Alt
										try { $name = [regex]::Replace($name, '\\([\\\[\]\(\)!])', '$1') } catch {}
									} elseif (-not [string]::IsNullOrWhiteSpace($PathOrDisplay)) {
										$p = & $normMediaPath $PathOrDisplay
										try {
											if ($p -match '^(?i)https?://') {
												$leaf = [System.IO.Path]::GetFileName(([Uri]$p).AbsolutePath)
												try { $leaf = [Uri]::UnescapeDataString($leaf) } catch {}
												$name = [System.IO.Path]::GetFileNameWithoutExtension($leaf)
												if ([string]::IsNullOrWhiteSpace($name)) { $name = $leaf }
											} else {
												$name = [System.IO.Path]::GetFileNameWithoutExtension($p)
												if ([string]::IsNullOrWhiteSpace($name)) { $name = [System.IO.Path]::GetFileName($p) }
											}
										} catch { $name = [string]$PathOrDisplay }
									}
									$name = [regex]::Replace([string]$name, '[\r\n\t]+', ' ')
									$name = [regex]::Replace($name, ' {2,}', ' ').Trim()
									if ([string]::IsNullOrWhiteSpace($name)) {
										if ([string]::IsNullOrWhiteSpace($Fallback)) { return '' }
										return [string]$Fallback
									}
									if ($MaxLen -gt 0 -and $name.Length -gt $MaxLen) {
										$name = $name.Substring(0, [Math]::Max(1, $MaxLen - 3)).TrimEnd() + '...'
									}
									return $name
								}.GetNewClosure()
								# Normalize display path (spaces / file:// / System32 glue) for all kinds
								try {
									if (-not [string]::IsNullOrWhiteSpace($mediaDisp)) {
										$mediaDisp = & $normMediaPath $mediaDisp
									}
								} catch {}
								# Keep spaces in labels coming from markdown ![label with spaces](...)
								try {
									if (-not [string]::IsNullOrWhiteSpace($mediaAlt)) {
										$mediaAlt = [regex]::Replace([string]$mediaAlt, '[\r\n\t]+', ' ')
										$mediaAlt = [regex]::Replace($mediaAlt, ' {2,}', ' ').Trim()
									}
								} catch {}

								$brushCache = $null
								try { $brushCache = $W['BrushCache'] } catch { try { $brushCache = $W.BrushCache } catch {} }
								if ($null -eq $brushCache) { $brushCache = @{}; try { $W['BrushCache'] = $brushCache } catch {} }
								foreach ($hx in @('#1A1A1E', '#252530', '#3A3A42', '#8A8A96', '#C8C8D0', '#2A2A30', '#7DCFFF', '#6A6A76', '#F05C5C')) {
									if (-not $brushCache.ContainsKey($hx)) {
										try { $brushCache[$hx] = $conv.ConvertFromString($hx) } catch {}
									}
								}

								$outer = New-Object System.Windows.Controls.Border
								$outer.Background = $brushCache['#1A1A1E']
								$outer.BorderBrush = $brushCache['#3A3A42']
								$outer.BorderThickness = New-Object System.Windows.Thickness(1)
								$outer.CornerRadius = New-Object System.Windows.CornerRadius(6)
								$outer.Margin = New-Object System.Windows.Thickness(0, 8, 0, 8)
								$outer.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
								$outer.SnapsToDevicePixels = $true
								$outer.Width = $stretchW
								$outer.MaxWidth = $stretchW

								$root = New-Object System.Windows.Controls.Grid
								$rowHdr = New-Object System.Windows.Controls.RowDefinition
								$rowHdr.Height = [System.Windows.GridLength]::Auto
								$rowBody = New-Object System.Windows.Controls.RowDefinition
								$rowBody.Height = [System.Windows.GridLength]::Auto
								[void]$root.RowDefinitions.Add($rowHdr)
								[void]$root.RowDefinitions.Add($rowBody)

								$hdr = New-Object System.Windows.Controls.Border
								$hdr.Background = $brushCache['#252530']
								$hdr.Padding = New-Object System.Windows.Thickness(10, 5, 10, 5)
								$hdr.CornerRadius = New-Object System.Windows.CornerRadius(6, 6, 0, 0)
								$hdrGrid = New-Object System.Windows.Controls.Grid
								$c0 = New-Object System.Windows.Controls.ColumnDefinition
								$c0.Width = New-Object System.Windows.GridLength(1, [System.Windows.GridUnitType]::Star)
								$c1 = New-Object System.Windows.Controls.ColumnDefinition
								$c1.Width = [System.Windows.GridLength]::Auto
								[void]$hdrGrid.ColumnDefinitions.Add($c0)
								[void]$hdrGrid.ColumnDefinitions.Add($c1)
								# ASCII-safe label build (avoid source-file middot mojibake under PS 5.1)
								# Titles/labels may contain spaces: ![My Song Title](...), ![Lake Day](...)
								$dot = [string][char]0x00B7
								$lab = switch ($mediaKind) { 'video' { 'video' } 'audio' { 'audio' } default { 'image' } }
								$tail = & $fmtMediaLabel $mediaAlt $mediaDisp '' 96
								if (-not [string]::IsNullOrWhiteSpace($tail)) {
									$lab = ('{0} {1} {2}' -f $lab, $dot, $tail)
								}
								$langTb = New-Object System.Windows.Controls.TextBlock
								$langTb.Text = $lab
								$langTb.Foreground = $brushCache['#8A8A96']
								# UI font for labels (mono can mis-render some Unicode paths)
								try {
									$langTb.FontFamily = New-Object System.Windows.Media.FontFamily('Segoe UI, Consolas, Cascadia Mono, Courier New')
								} catch {
									$langTb.FontFamily = $W.MonoFont
								}
								$langTb.FontSize = 11
								$langTb.TextTrimming = [System.Windows.TextTrimming]::CharacterEllipsis
								$langTb.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								[System.Windows.Controls.Grid]::SetColumn($langTb, 0)
								[void]$hdrGrid.Children.Add($langTb)
								$hdr.Child = $hdrGrid
								[System.Windows.Controls.Grid]::SetRow($hdr, 0)
								[void]$root.Children.Add($hdr)

								$body = New-Object System.Windows.Controls.Border
								$body.Background = $brushCache['#121216']
								try {
									if (-not $brushCache.ContainsKey('#121216')) {
										$brushCache['#121216'] = $conv.ConvertFromString('#121216')
									}
									$body.Background = $brushCache['#121216']
								} catch {}
								$body.Padding = New-Object System.Windows.Thickness(8)
								$body.CornerRadius = New-Object System.Windows.CornerRadius(0, 0, 5, 5)

								$maxH = [Math]::Min(420.0, [Math]::Max(120.0, $stretchW * 0.62))
								$mediaHost = New-Object System.Windows.Controls.Grid
								$mediaHost.MaxWidth = [Math]::Max(40.0, $stretchW - 18.0)
								$mediaHost.MaxHeight = $maxH
								$mediaHost.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left

								$uriObj = $null
								try { $uriObj = [Uri]$mediaUri } catch { $uriObj = $null }
								if ($null -eq $uriObj) {
									$errTb = New-Object System.Windows.Controls.TextBlock
									$errTb.Text = 'Invalid media URI'
									$errTb.Foreground = $brushCache['#F05C5C']
									$errTb.FontFamily = $W.MonoFont
									$errTb.FontSize = 12
									$body.Child = $errTb
								} elseif ($mediaKind -eq 'audio') {
									# Minimal inline audio player (PowerPlayer-inspired: progress + volume 0-1 + mute + play/pause icons)
									$filePath = ''
									try {
										if ($null -ne $uriObj -and $uriObj.IsFile) {
											$filePath = [string]$uriObj.LocalPath
											try { $filePath = [Uri]::UnescapeDataString($filePath) } catch {}
										}
									} catch {}
									if ([string]::IsNullOrWhiteSpace($filePath)) { $filePath = [string]$mediaDisp }
									if ([string]::IsNullOrWhiteSpace($filePath)) { $filePath = [string]$mediaUri }
									$filePath = ([string]$filePath).Trim().Trim('"').Trim("'")
									if ($filePath -match '^(?i)file://') {
										try { $filePath = ([Uri]$filePath).LocalPath } catch {}
										try { $filePath = [Uri]::UnescapeDataString($filePath) } catch {}
									}
									$filePath = $filePath -replace '/', '\'
									# Unglue elevated System32 CWD joins (STA-safe; do not rely on Get-MBPathCandidates)
									if ($filePath -match '(?i)(?:^[A-Za-z]:\\)?Windows\\System32\\(Users\\.+)$') {
										$filePath = 'C:\' + $Matches[1]
									} elseif ($filePath -match '(?i)\\Windows\\System32\\(Users\\.+)$') {
										$filePath = 'C:\' + $Matches[1]
									}
									if ($filePath -match '^(?i)Users\\') { $filePath = 'C:\' + $filePath }
									if ($filePath -match '^\\Users\\') { $filePath = 'C:' + $filePath }

									# Multi-word song titles ok: ![My Song Title](C:\...\My Song.mp3)
									$songName = & $fmtMediaLabel $mediaAlt $filePath 'Audio' 96

									# Resolve local path for MediaElement (STA-safe Test-Path only)
									$audioSrc = $filePath
									$audioIsHttp = ($filePath -match '^(?i)https?://')
									if (-not $audioIsHttp) {
										$foundAudio = $null
										try {
											if (Test-Path -LiteralPath $filePath -PathType Leaf) {
												$foundAudio = [System.IO.Path]::GetFullPath($filePath)
											}
										} catch {}
										if (-not $foundAudio) {
											try {
												if ($env:USERPROFILE -and $filePath -notmatch '^[A-Za-z]:' -and $filePath -notmatch '^\\\\') {
													$tryHome = Join-Path $env:USERPROFILE $filePath
													if (Test-Path -LiteralPath $tryHome -PathType Leaf) {
														$foundAudio = [System.IO.Path]::GetFullPath($tryHome)
													}
												}
											} catch {}
										}
										if (-not $foundAudio) {
											try {
												foreach ($c in @(Get-MBPathCandidates -Path $filePath)) {
													if (Test-Path -LiteralPath $c -PathType Leaf) {
														$foundAudio = [System.IO.Path]::GetFullPath($c)
														break
													}
												}
											} catch {}
										}
										if ($foundAudio) { $audioSrc = $foundAudio }
									}

									$panelW = [Math]::Max(300.0, [Math]::Min(520.0, $stretchW - 24.0))

									# NoMouseOver template
									$noMo = $null
									try {
										$own = $null
										try { if ($W -and $W.Window) { $own = $W.Window } } catch {}
										try { if ($null -eq $own -and $W -is [hashtable]) { $own = $W['Window'] } } catch {}
										if ($null -ne $own) { $noMo = $own.TryFindResource('NoMouseOverButtonTemplate') }
									} catch {}
									if ($null -eq $noMo) {
										try {
											$noMoXaml = '<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="Button"><Border Background="{TemplateBinding Background}" BorderBrush="{TemplateBinding BorderBrush}" BorderThickness="{TemplateBinding BorderThickness}" Padding="{TemplateBinding Padding}" CornerRadius="3" SnapsToDevicePixels="True"><ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/></Border></ControlTemplate>'
											$noMo = [System.Windows.Markup.XamlReader]::Parse($noMoXaml)
										} catch {}
									}

									$playerHost = New-Object System.Windows.Controls.Border
									$playerHost.Background = $brushCache['#121216']
									$playerHost.BorderBrush = $brushCache['#3A3A42']
									$playerHost.BorderThickness = New-Object System.Windows.Thickness(1)
									$playerHost.CornerRadius = New-Object System.Windows.CornerRadius(4)
									$playerHost.Padding = New-Object System.Windows.Thickness(12, 10, 12, 10)
									$playerHost.Width = $panelW
									$playerHost.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left

									$sp = New-Object System.Windows.Controls.StackPanel
									$sp.Orientation = [System.Windows.Controls.Orientation]::Vertical

									$titleTb = New-Object System.Windows.Controls.TextBlock
									$titleTb.Text = $songName
									$titleTb.Foreground = $brushCache['#C8C8D0']
									$titleTb.FontSize = 13
									try { $titleTb.FontWeight = [System.Windows.FontWeights]::SemiBold } catch {}
									$titleTb.TextTrimming = [System.Windows.TextTrimming]::CharacterEllipsis
									$titleTb.Margin = New-Object System.Windows.Thickness(0, 0, 0, 4)
									try { $titleTb.FontFamily = New-Object System.Windows.Media.FontFamily('Segoe UI, Consolas, Cascadia Mono, Courier New') } catch {}
									[void]$sp.Children.Add($titleTb)

									$pathTb = New-Object System.Windows.Controls.TextBlock
									$pathTb.Text = $audioSrc
									$pathTb.Foreground = $brushCache['#6A6A76']
									$pathTb.FontSize = 10
									$pathTb.TextTrimming = [System.Windows.TextTrimming]::CharacterEllipsis
									$pathTb.Margin = New-Object System.Windows.Thickness(0, 0, 0, 8)
									$pathTb.FontFamily = $W.MonoFont
									[void]$sp.Children.Add($pathTb)

									# MediaElement (audio-only). Must stay Visible in the tree — Collapsed/0x0
									# often never opens the media clock in WPF FlowDocument hosts.
									$me = New-Object System.Windows.Controls.MediaElement
									$me.LoadedBehavior = [System.Windows.Controls.MediaState]::Manual
									$me.UnloadedBehavior = [System.Windows.Controls.MediaState]::Manual
									$me.Volume = 0.75
									$me.ScrubbingEnabled = $true
									$me.Width = 1
									$me.Height = 1
									$me.Opacity = 0
									$me.IsHitTestVisible = $false
									$me.IsMuted = $false
									$me.Visibility = [System.Windows.Visibility]::Visible
									try {
										if ($audioIsHttp) {
											$me.Source = [Uri]$audioSrc
										} else {
											$me.Source = New-Object System.Uri -ArgumentList ([string]$audioSrc), ([System.UriKind]::Absolute)
										}
									} catch {
										try { $me.Source = [Uri]$audioSrc } catch {}
									}

									# Progress slider (0-100%)
									$posSlider = New-Object System.Windows.Controls.Slider
									$posSlider.Minimum = 0
									$posSlider.Maximum = 100
									$posSlider.Value = 0
									$posSlider.Height = 18
									$posSlider.IsMoveToPointEnabled = $true
									$posSlider.Cursor = [System.Windows.Input.Cursors]::Hand
									$posSlider.Margin = New-Object System.Windows.Thickness(0, 0, 0, 2)
									[void]$sp.Children.Add($posSlider)

									$timeRow = New-Object System.Windows.Controls.Grid
									$tc0 = New-Object System.Windows.Controls.ColumnDefinition
									$tc0.Width = New-Object System.Windows.GridLength(1, [System.Windows.GridUnitType]::Star)
									$tc1 = New-Object System.Windows.Controls.ColumnDefinition
									$tc1.Width = [System.Windows.GridLength]::Auto
									[void]$timeRow.ColumnDefinitions.Add($tc0)
									[void]$timeRow.ColumnDefinitions.Add($tc1)
									$timeLeft = New-Object System.Windows.Controls.TextBlock
									$timeLeft.Text = '0:00'
									$timeLeft.Foreground = $brushCache['#8A8A96']
									$timeLeft.FontSize = 11
									$timeRight = New-Object System.Windows.Controls.TextBlock
									$timeRight.Text = '0:00'
									$timeRight.Foreground = $brushCache['#8A8A96']
									$timeRight.FontSize = 11
									[System.Windows.Controls.Grid]::SetColumn($timeLeft, 0)
									[System.Windows.Controls.Grid]::SetColumn($timeRight, 1)
									[void]$timeRow.Children.Add($timeLeft)
									[void]$timeRow.Children.Add($timeRight)
									$timeRow.Margin = New-Object System.Windows.Thickness(0, 0, 0, 8)
									[void]$sp.Children.Add($timeRow)

									$ctrlRow = New-Object System.Windows.Controls.StackPanel
									$ctrlRow.Orientation = [System.Windows.Controls.Orientation]::Horizontal
									$ctrlRow.VerticalAlignment = [System.Windows.VerticalAlignment]::Center

									# Shared state (PowerPlayer-style mute volume)
									$flags = [System.Collections.Hashtable]::Synchronized(@{
										Playing        = $true
										Failed         = $false
										Player         = $me
										Muted          = $false
										UnMutedVolume  = 0.75
										Scrubbing      = $false
										PosSlider      = $posSlider
										TimeLeft       = $timeLeft
										TimeRight      = $timeRight
										Path           = [string]$audioSrc
										Title          = [string]$songName
										PathTb         = $pathTb
										PlayPath       = $null
										PausePath      = $null
										MutedPath      = $null
										UnMutedPath    = $null
										VolSlider      = $null
										VolPct         = $null
										ProgTimer      = $null
									})
									$me.Tag = $flags

									$fmtTime = {
										param([double]$sec)
										if ($sec -lt 0) { $sec = 0 }
										$ts = [TimeSpan]::FromSeconds([Math]::Floor($sec))
										if ($ts.TotalHours -ge 1) { return ('{0:h\:mm\:ss}' -f $ts) }
										return ('{0:m\:ss}' -f $ts)
									}.GetNewClosure()
									$flags['FmtTime'] = $fmtTime

									# Icon button helper (play/pause/mute use Path content)
									$mkIconBtn = {
										param([double]$Wdt, [double]$Hgt)
										$b = New-Object System.Windows.Controls.Button
										$b.Width = $Wdt
										$b.Height = $Hgt
										$b.Margin = New-Object System.Windows.Thickness(0, 0, 8, 0)
										$b.Padding = New-Object System.Windows.Thickness(4)
										$b.Cursor = [System.Windows.Input.Cursors]::Hand
										$b.Background = New-Object System.Windows.Media.SolidColorBrush ([System.Windows.Media.Color]::FromRgb(0x3A, 0x3A, 0x48))
										$b.BorderBrush = New-Object System.Windows.Media.SolidColorBrush ([System.Windows.Media.Color]::FromRgb(0x4A, 0x8A, 0xB8))
										$b.BorderThickness = New-Object System.Windows.Thickness(1)
										$b.Focusable = $true
										if ($null -ne $noMo) { try { $b.Template = $noMo } catch {} }
										$bgN = $b.Background
										$bgH = New-Object System.Windows.Media.SolidColorBrush ([System.Windows.Media.Color]::FromRgb(0x4A, 0x4A, 0x5A))
										$b.Add_MouseEnter({ param($s,$e) try { $s.Background = $bgH } catch {} }.GetNewClosure())
										$b.Add_MouseLeave({ param($s,$e) try { $s.Background = $bgN } catch {} }.GetNewClosure())
										return $b
									}.GetNewClosure()

									# Play / Pause icons (do NOT name these $playPath — that was the file path var)
									$btnPlay = & $mkIconBtn 34 28
									$iconGrid = New-Object System.Windows.Controls.Grid
									$playIcon = New-Object System.Windows.Shapes.Path
									$playIcon.Data = [System.Windows.Media.Geometry]::Parse('M8,5.14V19.14L19,12.14L8,5.14Z')
									$playIcon.Fill = New-Object System.Windows.Media.SolidColorBrush ([System.Windows.Media.Color]::FromRgb(0xE0, 0xE0, 0xE8))
									$playIcon.Stretch = [System.Windows.Media.Stretch]::Uniform
									$playIcon.Margin = New-Object System.Windows.Thickness(2)
									$playIcon.Visibility = [System.Windows.Visibility]::Collapsed
									$pauseIcon = New-Object System.Windows.Shapes.Path
									$pauseIcon.Data = [System.Windows.Media.Geometry]::Parse('M14,19H18V5H14M6,19H10V5H6V19Z')
									$pauseIcon.Fill = New-Object System.Windows.Media.SolidColorBrush ([System.Windows.Media.Color]::FromRgb(0xE0, 0xE0, 0xE8))
									$pauseIcon.Stretch = [System.Windows.Media.Stretch]::Uniform
									$pauseIcon.Margin = New-Object System.Windows.Thickness(2)
									$pauseIcon.Visibility = [System.Windows.Visibility]::Visible
									[void]$iconGrid.Children.Add($playIcon)
									[void]$iconGrid.Children.Add($pauseIcon)
									$btnPlay.Content = $iconGrid
									$flags['PlayPath'] = $playIcon
									$flags['PausePath'] = $pauseIcon
									$btnPlay.Tag = $flags
									$btnPlay.Add_Click({
										param($s, $e)
										try {
											$f = $s.Tag
											$player = $f['Player']
											if ($null -eq $player) { return }
											if ([bool]$f['Playing']) {
												$player.Pause()
												$f['Playing'] = $false
												try { $f['PlayPath'].Visibility = [System.Windows.Visibility]::Visible } catch {}
												try { $f['PausePath'].Visibility = [System.Windows.Visibility]::Collapsed } catch {}
											} else {
												try {
													if ($null -eq $player.Source -and $f['Path']) {
														$player.Source = New-Object System.Uri -ArgumentList ([string]$f['Path']), ([System.UriKind]::Absolute)
													}
												} catch {}
												$player.Play()
												$f['Playing'] = $true
												try { $f['PlayPath'].Visibility = [System.Windows.Visibility]::Collapsed } catch {}
												try { $f['PausePath'].Visibility = [System.Windows.Visibility]::Visible } catch {}
											}
											if ($e) { $e.Handled = $true }
										} catch {}
									}.GetNewClosure())
									[void]$ctrlRow.Children.Add($btnPlay)

									# Stop
									$btnStop = New-Object System.Windows.Controls.Button
									$btnStop.Content = 'Stop'
									$btnStop.Padding = New-Object System.Windows.Thickness(10, 3, 10, 3)
									$btnStop.Margin = New-Object System.Windows.Thickness(0, 0, 10, 0)
									$btnStop.Cursor = [System.Windows.Input.Cursors]::Hand
									$btnStop.FontSize = 11
									$btnStop.Foreground = $brushCache['#C8C8D0']
									$btnStop.Background = New-Object System.Windows.Media.SolidColorBrush ([System.Windows.Media.Color]::FromRgb(0x3A, 0x3A, 0x48))
									$btnStop.BorderBrush = $brushCache['#3A3A42']
									$btnStop.BorderThickness = New-Object System.Windows.Thickness(1)
									if ($null -ne $noMo) { try { $btnStop.Template = $noMo } catch {} }
									$btnStop.Tag = $flags
									$btnStop.Add_Click({
										param($s, $e)
										try {
											$f = $s.Tag
											$player = $f['Player']
											if ($null -eq $player) { return }
											$player.Stop()
											try { $player.Position = [TimeSpan]::Zero } catch {}
											$f['Playing'] = $false
											try { $f['PlayPath'].Visibility = [System.Windows.Visibility]::Visible } catch {}
											try { $f['PausePath'].Visibility = [System.Windows.Visibility]::Collapsed } catch {}
											try { $f['PosSlider'].Value = 0 } catch {}
											try { $f['TimeLeft'].Text = '0:00' } catch {}
											if ($e) { $e.Handled = $true }
										} catch {}
									}.GetNewClosure())
									[void]$ctrlRow.Children.Add($btnStop)

									# Volume icons (workspace xaml): mute / low / medium / high
									$volIconData = @{
										volMute = 'M3,9H7L12,4V20L7,15H3V9M16.59,12L14,9.41L15.41,8L18,10.59L20.59,8L22,9.41L19.41,12L22,14.59L20.59,16L18,13.41L15.41,16L14,14.59L16.59,12Z'
										volLow  = 'M7,9V15H11L16,20V4L11,9H7Z'
										volMed  = 'M5,9V15H9L14,20V4L9,9M18.5,12C18.5,10.23 17.5,8.71 16,7.97V16C17.5,15.29 18.5,13.76 18.5,12Z'
										volHigh = 'M14,3.23V5.29C16.89,6.15 19,8.83 19,12C19,15.17 16.89,17.84 14,18.7V20.77C18,19.86 21,16.28 21,12C21,7.72 18,4.14 14,3.23M16.5,12C16.5,10.23 15.5,8.71 14,7.97V16C15.5,15.29 16.5,13.76 16.5,12M3,9V15H7L12,20V4L7,9H3Z'
										stop    = 'M18,18H6V6H18V18Z'
										openNew = 'M14,3V5H17.59L7.76,14.83L9.17,16.24L19,6.41V10H21V3M19,19H5V5H12V3H5C3.89,3 3,3.9 3,5V19A2,2 0 0,0 5,21H19A2,2 0 0,0 21,19V12H19V19Z'
									}
									$audioIconFg = New-Object System.Windows.Media.SolidColorBrush ([System.Windows.Media.Color]::FromRgb(0xE0, 0xE0, 0xE8))
									$mkAudioPath = {
										param([string]$Data)
										$pp = New-Object System.Windows.Shapes.Path
										$pp.Width = 14; $pp.Height = 14
										$pp.Stretch = [System.Windows.Media.Stretch]::Uniform
										$pp.Data = [System.Windows.Media.Geometry]::Parse([string]$Data)
										$pp.Fill = $audioIconFg
										$pp.IsHitTestVisible = $false
										return $pp
									}.GetNewClosure()
									$volKeyFromLevel = {
										param([double]$Level, [bool]$Muted = $false)
										if ($Muted -or $Level -le 0.001) { return 'volMute' }
										if ($Level -le 0.33) { return 'volLow' }
										if ($Level -le 0.66) { return 'volMed' }
										return 'volHigh'
									}.GetNewClosure()
									$setAudioVolIcon = {
										param($f, [double]$Level)
										try {
											$btn = $f['MuteBtn']
											if ($null -eq $btn) { return }
											$muted = [bool]$f['Muted'] -or ($Level -le 0.001)
											$k = [string](& $volKeyFromLevel $Level $muted)
											$data = [string]$volIconData[$k]
											if ($data) { $btn.Content = (& $mkAudioPath $data) }
											try {
												$tip = if ($muted) { 'Unmute' } else { 'Mute / volume' }
												if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $btn $tip 220 }
												else { $btn.ToolTip = $tip }
											} catch {}
										} catch {}
									}.GetNewClosure()
									$flags['SetAudioVolIcon'] = $setAudioVolIcon
									$flags['VolIconData'] = $volIconData

									$btnMute = & $mkIconBtn 30 28
									$btnMute.Content = (& $mkAudioPath ([string]$volIconData['volHigh']))
									$btnMute.Tag = $flags
									$flags['MuteBtn'] = $btnMute
									try {
										if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $btnMute 'Mute / unmute' 220 }
										else { $btnMute.ToolTip = 'Mute / unmute' }
									} catch {}
									$btnMute.Add_Click({
										param($s, $e)
										try {
											$f = $s.Tag
											$player = $f['Player']
											if ($null -eq $player) { return }
											$setV = $f['SetAudioVolIcon']
											if (-not [bool]$f['Muted']) {
												$f['UnMutedVolume'] = [double]$player.Volume
												if ([double]$f['UnMutedVolume'] -le 0) { $f['UnMutedVolume'] = 0.5 }
												$player.Volume = 0
												$f['Muted'] = $true
												try { $f['VolSlider'].Value = 0 } catch {}
												try { $f['VolPct'].Text = '0%' } catch {}
												if ($null -ne $setV) { & $setV $f 0.0 }
											} else {
												$v = [double]$f['UnMutedVolume']
												if ($v -le 0) { $v = 0.5 }
												$player.Volume = $v
												$f['Muted'] = $false
												try { $f['VolSlider'].Value = $v } catch {}
												try { $f['VolPct'].Text = ([double]$v).ToString('P0') } catch {}
												if ($null -ne $setV) { & $setV $f $v }
											}
											if ($e) { $e.Handled = $true }
										} catch {}
									}.GetNewClosure())
									[void]$ctrlRow.Children.Add($btnMute)

									# Volume slider 0-1 (PowerPlayer style)
									$volSlider = New-Object System.Windows.Controls.Slider
									$volSlider.Minimum = 0
									$volSlider.Maximum = 1
									$volSlider.SmallChange = 0.01
									$volSlider.LargeChange = 0.1
									$volSlider.Value = 0.75
									$volSlider.Width = 100
									$volSlider.Height = 18
									$volSlider.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
									$volSlider.Margin = New-Object System.Windows.Thickness(0, 0, 6, 0)
									$volSlider.Cursor = [System.Windows.Input.Cursors]::Hand
									$volSlider.IsMoveToPointEnabled = $true
									$volSlider.Tag = $flags
									$flags['VolSlider'] = $volSlider
									$volSlider.Add_ValueChanged({
										param($s, $e)
										try {
											$f = $s.Tag
											$player = $f['Player']
											if ($null -eq $player) { return }
											$v = [double]$s.Value
											$player.Volume = $v
											if ($v -gt 0.001) {
												$f['UnMutedVolume'] = $v
												$f['Muted'] = $false
											} else {
												$f['Muted'] = $true
											}
											try { $f['VolPct'].Text = $v.ToString('P0') } catch {}
											try {
												$setV = $f['SetAudioVolIcon']
												if ($null -ne $setV) { & $setV $f $v }
											} catch {}
										} catch {}
									}.GetNewClosure())
									# PreviewMouseUp also sets UnMutedVolume like PowerPlayer
									$volSlider.Add_PreviewMouseUp({
										param($s, $e)
										try {
											$f = $s.Tag
											$v = [double]$s.Value
											$f['UnMutedVolume'] = $v
											if ($v -gt 0.001) { $f['Muted'] = $false }
										} catch {}
									}.GetNewClosure())
									[void]$ctrlRow.Children.Add($volSlider)
									try { & $setAudioVolIcon $flags 0.75 } catch {}

									$volPct = New-Object System.Windows.Controls.TextBlock
									$volPct.Text = '75%'
									$volPct.Foreground = $brushCache['#8A8A96']
									$volPct.FontSize = 11
									$volPct.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
									$volPct.Width = 36
									$volPct.Margin = New-Object System.Windows.Thickness(0, 0, 10, 0)
									$flags['VolPct'] = $volPct
									[void]$ctrlRow.Children.Add($volPct)

									# Stop icon
									$btnStop.Content = (& $mkAudioPath ([string]$volIconData['stop']))
									try {
										$btnStop.Width = 30; $btnStop.Height = 28
										$btnStop.Padding = New-Object System.Windows.Thickness(4)
										if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $btnStop 'Stop and return to start' 220 }
										else { $btnStop.ToolTip = 'Stop and return to start' }
									} catch {}

									# External / open-in-new icon
									$btnExt = & $mkIconBtn 30 28
									$btnExt.Content = (& $mkAudioPath ([string]$volIconData['openNew']))
									$btnExt.Tag = $flags
									try {
										if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $btnExt 'Open in external player' 220 }
										else { $btnExt.ToolTip = 'Open in external player' }
									} catch {}
									$btnExt.Add_Click({
										param($s, $e)
										try {
											$f = $s.Tag
											$p = [string]$f['Path']
											if ($p -and (Test-Path -LiteralPath $p)) { Start-Process -FilePath $p | Out-Null }
											elseif ($p -match '^(?i)https?://') { Start-Process -FilePath $p | Out-Null }
											if ($e) { $e.Handled = $true }
										} catch {}
									}.GetNewClosure())
									[void]$ctrlRow.Children.Add($btnExt)

									[void]$sp.Children.Add($ctrlRow)
									# Keep MediaElement in tree
									[void]$sp.Children.Add($me)
									$playerHost.Child = $sp

									# Progress timer
									$posSlider.Tag = $flags
									$posSlider.Add_PreviewMouseLeftButtonDown({
										param($s, $e)
										try { $s.Tag['Scrubbing'] = $true } catch {}
									}.GetNewClosure())
									$posSlider.Add_PreviewMouseLeftButtonUp({
										param($s, $e)
										try {
											$f = $s.Tag
											$player = $f['Player']
											if ($null -ne $player -and $player.NaturalDuration.HasTimeSpan) {
												$dur = $player.NaturalDuration.TimeSpan.TotalSeconds
												if ($dur -gt 0) {
													$player.Position = [TimeSpan]::FromSeconds(($s.Value / 100.0) * $dur)
												}
											}
											$f['Scrubbing'] = $false
										} catch {
											try { $s.Tag['Scrubbing'] = $false } catch {}
										}
									}.GetNewClosure())

									$progTimer = New-Object System.Windows.Threading.DispatcherTimer
									$progTimer.Interval = [TimeSpan]::FromMilliseconds(200)
									$progTimer.Tag = $flags
									$progTimer.Add_Tick({
										param($s, $e)
										try {
											$f = $s.Tag
											if ([bool]$f['Scrubbing']) { return }
											$player = $f['Player']
											if ($null -eq $player) { return }
											$fmt = $f['FmtTime']
											if ($player.NaturalDuration.HasTimeSpan) {
												$dur = $player.NaturalDuration.TimeSpan.TotalSeconds
												$pos = $player.Position.TotalSeconds
												if ($dur -gt 0) {
													try { $f['PosSlider'].Value = ($pos / $dur) * 100.0 } catch {}
												}
												try { $f['TimeLeft'].Text = (& $fmt $pos) } catch {}
												try { $f['TimeRight'].Text = (& $fmt $dur) } catch {}
											} else {
												try { $f['TimeLeft'].Text = (& $fmt $player.Position.TotalSeconds) } catch {}
											}
										} catch {}
									}.GetNewClosure())
									$flags['ProgTimer'] = $progTimer
									$progTimer.Start()

									$me.Add_MediaOpened({
										param($s, $e)
										try {
											$s.Play()
											$f = $s.Tag
											if ($f -is [hashtable]) {
												$f['Playing'] = $true
												$f['Failed'] = $false
												try { $f['PlayPath'].Visibility = [System.Windows.Visibility]::Collapsed } catch {}
												try { $f['PausePath'].Visibility = [System.Windows.Visibility]::Visible } catch {}
											}
										} catch {}
									}.GetNewClosure())
									$me.Add_MediaEnded({
										param($s, $e)
										try {
											$s.Stop()
											try { $s.Position = [TimeSpan]::Zero } catch {}
											$f = $s.Tag
											if ($f -is [hashtable]) {
												$f['Playing'] = $false
												try { $f['PlayPath'].Visibility = [System.Windows.Visibility]::Visible } catch {}
												try { $f['PausePath'].Visibility = [System.Windows.Visibility]::Collapsed } catch {}
												try { $f['PosSlider'].Value = 0 } catch {}
											}
										} catch {}
									}.GetNewClosure())
									$me.Add_MediaFailed({
										param($s, $e)
										try {
											$why = ''
											try { if ($e.ErrorException) { $why = [string]$e.ErrorException.Message } } catch {}
											if (-not $why) { $why = 'codec not supported / cannot open' }
											$f = $s.Tag
											if ($f -is [hashtable]) {
												$f['Playing'] = $false
												$f['Failed'] = $true
												try { $f['TimeLeft'].Text = 'failed' } catch {}
												try { $f['TimeRight'].Text = $why } catch {}
												try { $f['PlayPath'].Visibility = [System.Windows.Visibility]::Visible } catch {}
												try { $f['PausePath'].Visibility = [System.Windows.Visibility]::Collapsed } catch {}
												try {
													if ($f['PathTb']) {
														$f['PathTb'].Text = ("(playback failed: {0}) {1}" -f $why, [string]$f['Path'])
														$f['PathTb'].Foreground = New-Object System.Windows.Media.SolidColorBrush ([System.Windows.Media.Color]::FromRgb(240, 92, 92))
													}
												} catch {}
											}
										} catch {}
									}.GetNewClosure())
									# Also kick play once element is in the live tree
									$me.Add_Loaded({
										param($s, $e)
										try {
											$f = $s.Tag
											if ($f -is [hashtable] -and [bool]$f['Failed']) { return }
											$s.Play()
											if ($f -is [hashtable]) { $f['Playing'] = $true }
										} catch {}
									}.GetNewClosure())

									# Stop previous audio on this bag if any
									try {
										$prev = $null
										if ($W -is [hashtable]) { $prev = $W['ActiveAudioFlags'] }
										elseif ($W) { $prev = $W.ActiveAudioFlags }
										if ($prev -is [hashtable] -and $prev['Player'] -and $prev['Player'] -ne $me) {
											try { $prev['Player'].Stop() } catch {}
											try { $prev['Player'].Close() } catch {}
											try { if ($prev['ProgTimer']) { $prev['ProgTimer'].Stop() } } catch {}
										}
										if ($W -is [hashtable]) { $W['ActiveAudioFlags'] = $flags }
										else { try { $W.ActiveAudioFlags = $flags } catch {} }
									} catch {}

									$flags['PathTb'] = $pathTb
									# Show missing-file hint up front (before MediaFailed)
									if (-not $audioIsHttp) {
										try {
											if (-not (Test-Path -LiteralPath $audioSrc -PathType Leaf)) {
												$pathTb.Text = ("(file not found) {0}" -f $audioSrc)
												$pathTb.Foreground = $brushCache['#F05C5C']
												$flags['Failed'] = $true
												$flags['Playing'] = $false
												try { $playIcon.Visibility = [System.Windows.Visibility]::Visible } catch {}
												try { $pauseIcon.Visibility = [System.Windows.Visibility]::Collapsed } catch {}
											}
										} catch {}
									}

									$body.Child = $playerHost
									# Play after attach so the element is parented
									try {
										if (-not [bool]$flags['Failed']) { $me.Play() }
									} catch {}

									$lab = 'audio'
									if (-not [string]::IsNullOrWhiteSpace($songName)) {
										$lab = ('audio - {0}' -f $songName)
									}
									try { $langTb.Text = $lab } catch {}

								} elseif ($mediaKind -eq 'video') {
									# Play / Pop out use $script:MB.Video API (WPF clicks cannot see script functions by name).
									# Paths may contain spaces — always Unescape + LiteralPath-friendly strings.
									$playPath = ''
									try {
										if ($null -ne $uriObj -and $uriObj.IsFile) {
											$playPath = [string]$uriObj.LocalPath
											try { $playPath = [Uri]::UnescapeDataString($playPath) } catch {}
										}
									} catch {}
									if ([string]::IsNullOrWhiteSpace($playPath)) { $playPath = [string]$mediaDisp }
									if ([string]::IsNullOrWhiteSpace($playPath)) { $playPath = [string]$mediaUri }
									try { $playPath = & $normMediaPath $playPath } catch {}
									# Prefer a verified existing path (spaces ok via LiteralPath)
									try {
										if ($playPath -notmatch '^(?i)https?://' -and -not (Test-Path -LiteralPath $playPath -PathType Leaf)) {
											foreach ($c in @(Get-MBPathCandidates -Path $playPath -ErrorAction SilentlyContinue)) {
												if (Test-Path -LiteralPath $c -PathType Leaf) { $playPath = $c; break }
											}
										} elseif ($playPath -notmatch '^(?i)https?://' -and (Test-Path -LiteralPath $playPath -PathType Leaf)) {
											$playPath = [System.IO.Path]::GetFullPath($playPath)
										}
									} catch {}
									# Multi-word video titles ok: ![My Holiday Clip](C:\...\My Clip.mp4)
									$playTitle = & $fmtMediaLabel $mediaAlt $playPath 'Video' 96
									if ([string]::IsNullOrWhiteSpace($playTitle) -and -not [string]::IsNullOrWhiteSpace($mediaDisp)) {
										$playTitle = & $fmtMediaLabel '' $mediaDisp 'Video' 96
									}

									$boxW = [Math]::Max(280.0, [Math]::Min(560.0, $stretchW - 24.0))
									$boxH = [Math]::Round($boxW * 0.56)
									try {
										$rsz = Get-MBVideoFrameSize -Source $playPath
										if ([int]$rsz.Width -gt 0 -and [int]$rsz.Height -gt 0) {
											$ar = [double]$rsz.Width / [double]$rsz.Height
											$boxH = [Math]::Round($boxW / [Math]::Max(0.1, $ar))
											if ($boxH -gt 420) { $boxH = 420.0; $boxW = [Math]::Round($boxH * $ar) }
											if ($boxH -lt 140) { $boxH = 140.0 }
										}
									} catch {}

									# StartFn from $W bag only - do NOT call Register-MBVideoApi here (STA can wipe bag with nulls)
									$startFn = $null
									try {
										if ($W -is [hashtable]) {
											$startFn = $W['VideoStartInline']
											if ($null -eq $startFn -and $W['VideoApi']) { $startFn = $W['VideoApi']['StartInline'] }
										}
									} catch {}
									try { if ($null -eq $startFn -and $W) { $startFn = $W.VideoStartInline } } catch {}
									$vstate = [hashtable]@{
										Path         = [string]$playPath
										Title        = [string]$playTitle
										Playing      = $false
										Started      = $false
										Failed       = $false
										MediaElement = $null
										Popup        = $null
										Mode         = ''
										Host         = $null
										Width        = $boxW
										Height       = $boxH
										StartFn      = $startFn
										WpfBag      = $W
									}

									$card = New-Object System.Windows.Controls.StackPanel
									$card.Orientation = [System.Windows.Controls.Orientation]::Vertical
									$card.Margin = New-Object System.Windows.Thickness(2)

									# Black host only - no "PLAY VIDEO" text. Autoplay injects player+OSD.
									$preview = New-Object System.Windows.Controls.Border
									$preview.Background = [System.Windows.Media.Brushes]::Black
									$preview.BorderBrush = $brushCache['#3A3A42']
									$preview.BorderThickness = New-Object System.Windows.Thickness(1)
									$preview.CornerRadius = New-Object System.Windows.CornerRadius(4)
									$preview.Width = $boxW
									$preview.Height = $boxH
									$preview.MinHeight = $boxH
									$preview.Cursor = [System.Windows.Input.Cursors]::Arrow
									$preview.ClipToBounds = $true
									$preview.Child = $null
									$vstate['Host'] = $preview
									$preview.Tag = $vstate

									$pathTb = New-Object System.Windows.Controls.TextBlock
									$pathTb.Text = $playPath
									$pathTb.Foreground = $brushCache['#8A8A96']
									$pathTb.FontFamily = $W.MonoFont
									$pathTb.FontSize = 10
									$pathTb.TextWrapping = [System.Windows.TextWrapping]::Wrap
									$pathTb.Margin = New-Object System.Windows.Thickness(0, 8, 0, 0)
									$pathTb.MaxWidth = [Math]::Max(280.0, $stretchW - 24.0)

									[void]$card.Children.Add($preview)
									[void]$card.Children.Add($pathTb)
									$body.Child = $card

									# AUTOPLAY: only full StartInline (player + OSD). Never inject a bare MediaElement
									# fallback — that was wiping the OSD controls after a false-negative start.
									$autoOk = $false
									$autoErr = ''
									try {
										if ($playPath -match '(?i)^[A-Za-z]:\\Windows\\System32\\(Users\\.+)$') {
											$playPath = 'C:\' + $Matches[1]
											$vstate['Path'] = $playPath
										}
									} catch {}
									try {
										$fn = $startFn
										if ($null -eq $fn -and $W -is [hashtable]) { $fn = $W['VideoStartInline'] }
										if ($null -eq $fn -and $W -is [hashtable] -and $W['VideoApi']) {
											try { $fn = $W['VideoApi']['StartInline'] } catch {}
										}
										if ($null -ne $fn) {
											try {
												# Named params for Start-MBInlineVideoInHost (HostElement, Path, Width, Height, State)
												$null = & $fn -HostElement $preview -Path ([string]$playPath) -Width ([double]$boxW) -Height ([double]$boxH) -State $vstate
											} catch {
												$autoErr = $_.Exception.Message
											}
										} else {
											$autoErr = 'VideoStartInline missing (restart MiniBot)'
										}
										# Success = full OSD tree (Grid) or Started/MediaElement from StartInline
										if ($vstate['Started'] -or $vstate['MediaElement']) { $autoOk = $true }
										if ($preview.Child -is [System.Windows.Controls.Grid]) {
											$autoOk = $true
											$vstate['Started'] = $true
											$vstate['Failed'] = $false
										}
										if (-not $autoOk) {
											if ($vstate['LastError']) { $autoErr = [string]$vstate['LastError'] }
											elseif (-not $autoErr) { $autoErr = 'StartInline returned false' }
										}
									} catch {
										$autoErr = $_.Exception.Message
									}
									if (-not $autoOk) {
										$vstate['Failed'] = $true
										try {
											$msg = if ($autoErr) { $autoErr } else { 'autoplay failed' }
											$pathTb.Text = ("(autoplay failed: {0}) {1}" -f $msg, $playPath)
											$pathTb.Foreground = $brushCache['#F05C5C']
										} catch {}
									}
									# Click host to retry full StartInline (OSD) if not started
									$preview.Add_MouseLeftButtonUp({
										param($s, $e)
										try {
											$st = $s.Tag
											if (-not ($st -is [hashtable])) { return }
											# Already has full player+OSD
											if ([bool]$st['Started'] -and -not [bool]$st['Failed']) { return }
											if ($s.Child -is [System.Windows.Controls.Grid]) { return }
											$fn2 = $null
											try { $fn2 = $st['StartFn'] } catch {}
											try {
												if ($null -eq $fn2 -and $W -is [hashtable]) { $fn2 = $W['VideoStartInline'] }
											} catch {}
											if ($null -ne $fn2) {
												try {
													$null = & $fn2 -HostElement $st['Host'] -Path ([string]$st['Path']) -Width ([double]$st['Width']) -Height ([double]$st['Height']) -State $st
												} catch {}
												if ($st['Started'] -or $st['MediaElement'] -or ($st['Host'] -and $st['Host'].Child -is [System.Windows.Controls.Grid])) {
													$st['Failed'] = $false
													$st['Started'] = $true
												}
											}
											if ($e) { $e.Handled = $true }
										} catch {}
									}.GetNewClosure())
								} else {
									$img = New-Object System.Windows.Controls.Image
									$img.Stretch = [System.Windows.Media.Stretch]::Uniform
									$img.MaxWidth = [Math]::Max(40.0, $stretchW - 18.0)
									$img.MaxHeight = $maxH
									$img.SnapsToDevicePixels = $true
									try {
										$bmp = New-Object System.Windows.Media.Imaging.BitmapImage
										$bmp.BeginInit()
										$bmp.UriSource = $uriObj
										$bmp.CacheOption = [System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad
										$dw = [int][Math]::Max(80, [Math]::Min(1600, $stretchW * 2))
										try { $bmp.DecodePixelWidth = $dw } catch {}
										$bmp.EndInit()
										if ($bmp.CanFreeze) { $bmp.Freeze() }
										$img.Source = $bmp
									} catch {
										$tb = New-Object System.Windows.Controls.TextBlock
										$tb.Text = "Image failed to load.`n$mediaDisp"
										$tb.Foreground = $brushCache['#F05C5C']
										$tb.FontFamily = $W.MonoFont
										$tb.FontSize = 12
										$tb.TextWrapping = [System.Windows.TextWrapping]::Wrap
										$body.Child = $tb
										$img = $null
									}
									if ($null -ne $img) {
										$img.ToolTip = $mediaDisp
										$body.Child = $img
									}
								}

								[System.Windows.Controls.Grid]::SetRow($body, 1)
								[void]$root.Children.Add($body)
								$outer.Child = $root
								$outer.Tag = @{ Kind = 'md-media'; MediaKind = $mediaKind; Uri = $mediaUri }

								$buc = New-Object System.Windows.Documents.BlockUIContainer ($outer)
								$buc.Margin = New-Object System.Windows.Thickness 0
								$doc.Blocks.Add($buc)
								try {
									$sl = $null
									if ($W -is [hashtable]) {
										if (-not $W.ContainsKey('MdStretchElements') -or $null -eq $W['MdStretchElements']) {
											$W['MdStretchElements'] = New-Object System.Collections.ArrayList
										}
										$sl = $W['MdStretchElements']
									} else {
										try { $sl = $W.MdStretchElements } catch { $sl = $null }
										if ($null -eq $sl) {
											$sl = New-Object System.Collections.ArrayList
											try { $W | Add-Member -NotePropertyName MdStretchElements -NotePropertyValue $sl -Force } catch {}
										}
									}
									if ($null -ne $sl) { [void]$sl.Add($outer) }
								} catch {}
								try { $W.LogLineCharRun = 0 } catch {}
								# trailing empty para so following text continues cleanly
								$doc.Blocks.Add((& $newPara))
							} catch {}
							continue
						}

						if ($kind -eq 'chat-timing') {
							try {
								$tline = ''
								try { $tline = [string]$item.Text } catch {}
								if (-not [string]::IsNullOrWhiteSpace($tline)) {
									& $trimTrailingEmptyParas
									$brushCache = $null
									try { $brushCache = $W['BrushCache'] } catch { try { $brushCache = $W.BrushCache } catch {} }
									if ($null -eq $brushCache) { $brushCache = @{}; try { $W['BrushCache'] = $brushCache } catch {} }
									$hx = '#6A6A76'
									if (-not $brushCache.ContainsKey($hx)) {
										$brushCache[$hx] = $conv.ConvertFromString($hx)
									}
									# Timing stamp spacing (Thought/Worked) - top margin lifts both ~4px
									$doc.Blocks.Add((& $newPara))
									$tb = New-Object System.Windows.Controls.TextBlock
									$tb.Text = $tline
									$tb.Foreground = $brushCache[$hx]
									$tb.FontFamily = $W.MonoFont
									$tb.FontSize = 10
									$tb.FontStyle = [System.Windows.FontStyles]::Italic
									$tb.Margin = New-Object System.Windows.Thickness(5, -14, 0, 10)
									$tb.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
									$tb.TextWrapping = [System.Windows.TextWrapping]::Wrap
									$buc = New-Object System.Windows.Documents.BlockUIContainer ($tb)
									$buc.Margin = New-Object System.Windows.Thickness 0
									$doc.Blocks.Add($buc)
									$doc.Blocks.Add((& $newPara))
									try { $W.LogLineCharRun = 0 } catch {}
								}
							} catch {}
							continue
						}

						if ($kind -eq 'md-list-lead') {
							try {
								& $trimTrailingEmptyParas
								$p = & $newPara
								$p.Margin = New-Object System.Windows.Thickness(0, 8, 0, 0)
								$p.LineHeight = 16
								$doc.Blocks.Add($p)
								try { $W.LogLineCharRun = 0 } catch {}
							} catch {}
							continue
						}

						if ($kind -eq 'md-rule') {
							try {
								& $trimTrailingEmptyParas
								$ruleHex = '#3D4158'
								$brushCache = $null
								try { $brushCache = $W['BrushCache'] } catch { try { $brushCache = $W.BrushCache } catch {} }
								if ($null -eq $brushCache) { $brushCache = @{}; try { $W['BrushCache'] = $brushCache } catch {} }
								if (-not $brushCache.ContainsKey($ruleHex)) {
									$brushCache[$ruleHex] = $conv.ConvertFromString($ruleHex)
								}
								$border = New-Object System.Windows.Controls.Border
								$border.Height = 1
								$border.Background = $brushCache[$ruleHex]
								$border.Margin = New-Object System.Windows.Thickness(0, 10, 0, 10)
								$border.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
								$border.SnapsToDevicePixels = $true
								$border.Width = $stretchW
								$border.Tag = 'md-rule'
								$buc = New-Object System.Windows.Documents.BlockUIContainer ($border)
								$buc.Margin = New-Object System.Windows.Thickness 0
								$doc.Blocks.Add($buc)
								try {
									if ($W -is [hashtable]) {
										if (-not $W.ContainsKey('MdStretchElements') -or $null -eq $W['MdStretchElements']) {
											$W['MdStretchElements'] = New-Object System.Collections.ArrayList
										}
										[void]$W['MdStretchElements'].Add($border)
									} else {
										$sl = $null
										try { $sl = $W.MdStretchElements } catch { $sl = $null }
										if ($null -eq $sl) {
											$sl = New-Object System.Collections.ArrayList
											try { $W | Add-Member -NotePropertyName MdStretchElements -NotePropertyValue $sl -Force } catch {}
										}
										[void]$sl.Add($border)
									}
								} catch {}
								try { $W.LogLineCharRun = 0 } catch {}
							} catch {}
							continue
						}

						if ($kind -eq 'approval-banner' -or $kind -eq 'section-banner') {
							try {
								& $trimTrailingEmptyParas
								$lab = 'section'
								try { if ($item.Text) { $lab = [string]$item.Text } } catch {}
								if ([string]::IsNullOrWhiteSpace($lab)) { $lab = 'section' }
								$cName = 'DarkGray'
								try { if ($item.Color) { $cName = [string]$item.Color } } catch {}
								# Map console color names to theme hex
								$ruleHex = switch -Regex ($cName) {
									'^(?i)red|darkred$' { '#F05C5C' }
									'^(?i)yellow|darkyellow$' { '#E0AF68' }
									'^(?i)green|darkgreen$' { '#9ECE6A' }
									'^(?i)cyan|darkcyan|blue|darkblue$' { '#7DCFFF' }
									'^(?i)magenta|darkmagenta|purple$' { '#BB9AF7' }
									'^(?i)white$' { '#E8E8F0' }
									default { '#BB9AF7' }
								}
								if ($kind -eq 'approval-banner') { $ruleHex = '#F05C5C' }
								$brushCache = $null
								try { $brushCache = $W['BrushCache'] } catch { try { $brushCache = $W.BrushCache } catch {} }
								if ($null -eq $brushCache) { $brushCache = @{}; try { $W['BrushCache'] = $brushCache } catch {} }
								if (-not $brushCache.ContainsKey($ruleHex)) {
									$brushCache[$ruleHex] = $conv.ConvertFromString($ruleHex)
								}
								$grid = New-Object System.Windows.Controls.Grid
								$grid.Margin = New-Object System.Windows.Thickness(0, 8, 0, 6)
								$grid.Width = $stretchW
								$grid.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
								$grid.SnapsToDevicePixels = $true
								$c0 = New-Object System.Windows.Controls.ColumnDefinition
								$c0.Width = New-Object System.Windows.GridLength(1, [System.Windows.GridUnitType]::Star)
								$c1 = New-Object System.Windows.Controls.ColumnDefinition
								$c1.Width = [System.Windows.GridLength]::Auto
								$c2 = New-Object System.Windows.Controls.ColumnDefinition
								$c2.Width = New-Object System.Windows.GridLength(1, [System.Windows.GridUnitType]::Star)
								[void]$grid.ColumnDefinitions.Add($c0)
								[void]$grid.ColumnDefinitions.Add($c1)
								[void]$grid.ColumnDefinitions.Add($c2)
								$lineL = New-Object System.Windows.Controls.Border
								$lineL.Height = 1
								$lineL.Background = $brushCache[$ruleHex]
								$lineL.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								$lineL.Margin = New-Object System.Windows.Thickness(0, 0, 10, 0)
								$lineL.SnapsToDevicePixels = $true
								[System.Windows.Controls.Grid]::SetColumn($lineL, 0)
								[void]$grid.Children.Add($lineL)
								$tb = New-Object System.Windows.Controls.TextBlock
								$tb.Text = $lab
								$tb.Foreground = $brushCache[$ruleHex]
								$tb.FontWeight = [System.Windows.FontWeights]::Bold
								$tb.FontSize = 12
								if ($W.MonoFont) { $tb.FontFamily = $W.MonoFont }
								$tb.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								$tb.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Center
								[System.Windows.Controls.Grid]::SetColumn($tb, 1)
								[void]$grid.Children.Add($tb)
								$lineR = New-Object System.Windows.Controls.Border
								$lineR.Height = 1
								$lineR.Background = $brushCache[$ruleHex]
								$lineR.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								$lineR.Margin = New-Object System.Windows.Thickness(10, 0, 0, 0)
								$lineR.SnapsToDevicePixels = $true
								[System.Windows.Controls.Grid]::SetColumn($lineR, 2)
								[void]$grid.Children.Add($lineR)
								$grid.Tag = $(if ($kind -eq 'approval-banner') { 'approval-banner' } else { 'section-banner' })
								$buc = New-Object System.Windows.Documents.BlockUIContainer ($grid)
								$buc.Margin = New-Object System.Windows.Thickness 0
								$doc.Blocks.Add($buc)
								try {
									if ($W -is [hashtable]) {
										if (-not $W.ContainsKey('MdStretchElements') -or $null -eq $W['MdStretchElements']) {
											$W['MdStretchElements'] = New-Object System.Collections.ArrayList
										}
										[void]$W['MdStretchElements'].Add($grid)
									} else {
										$sl = $null
										try { $sl = $W.MdStretchElements } catch { $sl = $null }
										if ($null -eq $sl) {
											$sl = New-Object System.Collections.ArrayList
											try { $W | Add-Member -NotePropertyName MdStretchElements -NotePropertyValue $sl -Force } catch {}
										}
										[void]$sl.Add($grid)
									}
								} catch {}
								try { $W.LogLineCharRun = 0 } catch {}
							} catch {}
							continue
						}

						if ($kind -eq 'approval-buttons') {
							try {
								& $trimTrailingEmptyParas
								$yesHex = '#9ECE6A'
								$noHex = '#F05C5C'
								$allHex = '#E0AF68'
								$chipBgHex = '#2A2A30'
								$borderHex = '#3A3A42'
								$labelHex = '#C8C8D0'
								foreach ($hx in @($yesHex, $noHex, $allHex, $chipBgHex, $borderHex, $labelHex)) {
									if (-not $W.BrushCache.ContainsKey($hx)) {
										try { $W.BrushCache[$hx] = $conv.ConvertFromString($hx) } catch {}
									}
								}
								$sp = New-Object System.Windows.Controls.StackPanel
								$sp.Orientation = [System.Windows.Controls.Orientation]::Horizontal
								$sp.Margin = New-Object System.Windows.Thickness(8, 13, 8, 0)
								$sp.Tag = 'approval-buttons'
								$lab = New-Object System.Windows.Controls.TextBlock
								$lab.Text = 'Proceed?'
								$lab.Foreground = $W.BrushCache[$labelHex]
								$lab.FontSize = 12
								$lab.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								$lab.Margin = New-Object System.Windows.Thickness(0, 0, 10, 0)
								if ($W.MonoFont) { try { $lab.FontFamily = $W.MonoFont } catch {} }
								[void]$sp.Children.Add($lab)

								$mkBtn = {
									param($caption, $fgHex, $answer)
									$btn = New-Object System.Windows.Controls.Button
									$btn.Content = $caption
									$btn.Foreground = $W.BrushCache[$fgHex]
									$btn.Background = $W.BrushCache[$chipBgHex]
									$btn.BorderBrush = $W.BrushCache[$fgHex]
									$btn.BorderThickness = New-Object System.Windows.Thickness(1)
									$btn.Padding = New-Object System.Windows.Thickness(12, 4, 12, 4)
									$btn.Margin = New-Object System.Windows.Thickness(0, 0, 8, 0)
									$btn.Cursor = [System.Windows.Input.Cursors]::Hand
									$btn.FontSize = 12
									$btn.FontWeight = [System.Windows.FontWeights]::SemiBold
									$btn.MinWidth = 72
									$btn.Tag = $answer
									if ($W.MonoFont) { try { $btn.FontFamily = $W.MonoFont } catch {} }
									try {
										$xamlBtn = @'
<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="Button">
  <Border x:Name="Bd" Background="{TemplateBinding Background}"
          BorderBrush="{TemplateBinding BorderBrush}"
          BorderThickness="{TemplateBinding BorderThickness}"
          CornerRadius="4" SnapsToDevicePixels="True"
          Padding="{TemplateBinding Padding}">
    <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/>
  </Border>
  <ControlTemplate.Triggers>
    <Trigger Property="IsMouseOver" Value="True">
      <Setter TargetName="Bd" Property="Opacity" Value="0.92"/>
    </Trigger>
    <Trigger Property="IsPressed" Value="True">
      <Setter TargetName="Bd" Property="Opacity" Value="0.8"/>
    </Trigger>
    <Trigger Property="IsEnabled" Value="False">
      <Setter TargetName="Bd" Property="Opacity" Value="0.45"/>
    </Trigger>
  </ControlTemplate.Triggers>
</ControlTemplate>
'@
										$tpl = [Windows.Markup.XamlReader]::Parse($xamlBtn)
										if ($null -ne $tpl) { $btn.Template = $tpl }
									} catch {}
									$null = $btn.Add_Click({
										param($sender, $e)
										try {
											$a = ''
											try { $a = [string]$sender.Tag } catch { $a = '' }
											if ([string]::IsNullOrWhiteSpace($a)) { return }
											try {
												foreach ($c in @($sp.Children)) {
													if ($c -is [System.Windows.Controls.Button]) {
														$c.IsEnabled = $false
													}
												}
											} catch {}
											try { $W.ActiveApprovalHost = $null } catch {}
											$W.InputResult = $a
											[void]$W.InputWait.Set()
											try {
												$W.PromptArmed = $false
												if ($W.Prompt) { $W.Prompt.IsReadOnly = $true }
											} catch {}
											try { if ($W.SyncSendBtn) { & $W.SyncSendBtn $false } } catch {}
											try { if ($W.Prompt) { $W.Prompt.Clear() } } catch {}
										} catch {}
									}.GetNewClosure())
									return $btn
								}.GetNewClosure()

								[void]$sp.Children.Add((& $mkBtn 'Yes' $yesHex 'y'))
								[void]$sp.Children.Add((& $mkBtn 'No' $noHex 'n'))
								[void]$sp.Children.Add((& $mkBtn 'Yes to All' $allHex 'a'))

								$hint = New-Object System.Windows.Controls.TextBlock
								$hint.Text = '  or type Y / N / A'
								$hint.Foreground = $W.BrushCache[$labelHex]
								$hint.Opacity = 0.55
								$hint.FontSize = 11
								$hint.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								$hint.Margin = New-Object System.Windows.Thickness(4, 0, 0, 0)
								if ($W.MonoFont) { try { $hint.FontFamily = $W.MonoFont } catch {} }
								[void]$sp.Children.Add($hint)

								$buc = New-Object System.Windows.Documents.BlockUIContainer ($sp)
								$buc.Margin = New-Object System.Windows.Thickness 0
								$doc.Blocks.Add($buc)
								try { $W.ActiveApprovalHost = $sp } catch {}
								try { $W.LogLineCharRun = 0 } catch {}
							} catch {}
							continue
						}

						if ($kind -eq 'syn-inline') {
							try {
								& $trimTrailingEmptyParas
								$plain = ''
								try { if ($null -ne $item.Text) { $plain = [string]$item.Text } } catch {}
								$lang = 'ps'
								try { if ($item.Lang) { $lang = [string]$item.Lang } } catch {}
								$brushCache = $null
								try { $brushCache = $W['BrushCache'] } catch { try { $brushCache = $W.BrushCache } catch {} }
								if ($null -eq $brushCache) { $brushCache = @{}; try { $W['BrushCache'] = $brushCache } catch {} }
								$norm = & $synNormLang $lang
								# One paragraph per line so multi-line commands stay readable
								$lines = @($plain -split "`n", -1)
								if ($lines.Count -eq 0) { $lines = @('') }
								foreach ($ln in $lines) {
									$lineText = [string]$ln
									$para = New-Object System.Windows.Documents.Paragraph
									$para.Margin = New-Object System.Windows.Thickness(0)
									$para.Padding = New-Object System.Windows.Thickness(0)
									try { $para.LineHeight = 18 } catch {}
									$pad = New-Object System.Windows.Documents.Run ('  ')
									if ($W.MonoFont) { $pad.FontFamily = $W.MonoFont }
									[void]$para.Inlines.Add($pad)
									$tokens = & $synTokenize $lineText $norm
									if ($null -eq $tokens -or $tokens.Count -eq 0) {
										$run = New-Object System.Windows.Documents.Run ($lineText)
										$hx0 = '#C8C8D0'
										if (-not $brushCache.ContainsKey($hx0)) { $brushCache[$hx0] = $conv.ConvertFromString($hx0) }
										$run.Foreground = $brushCache[$hx0]
										if ($W.MonoFont) { $run.FontFamily = $W.MonoFont }
										[void]$para.Inlines.Add($run)
									} else {
										foreach ($tok in $tokens) {
											$k = [string]$tok.K
											if (-not $synColorMap.ContainsKey($k)) { $k = 'plain' }
											$hx = [string]$synColorMap[$k]
											if (-not $brushCache.ContainsKey($hx)) {
												$brushCache[$hx] = $conv.ConvertFromString($hx)
											}
											$run = New-Object System.Windows.Documents.Run ([string]$tok.T)
											$run.Foreground = $brushCache[$hx]
											if ($W.MonoFont) { $run.FontFamily = $W.MonoFont }
											[void]$para.Inlines.Add($run)
										}
									}
									$doc.Blocks.Add($para)
								}
								try { $W.LogLineCharRun = 0 } catch {}
							} catch {
								try {
									$fb = New-Object System.Windows.Documents.Paragraph
									$fb.Margin = New-Object System.Windows.Thickness 0
									$fr = New-Object System.Windows.Documents.Run ('  ' + [string]$item.Text)
									if ($W.MonoFont) { $fr.FontFamily = $W.MonoFont }
									[void]$fb.Inlines.Add($fr)
									$doc.Blocks.Add($fb)
								} catch {}
							}
							continue
						}

						if ($kind -eq 'md-table') {
							try {
								$rowsIn = $null
								try { $rowsIn = $item.Rows } catch { $rowsIn = $null }
								$rowList = New-Object System.Collections.ArrayList
								$us = [char]0x1F
								if ($null -ne $rowsIn) {
									foreach ($rr in @($rowsIn)) {
										if ($null -eq $rr) { continue }
										$cellList = New-Object System.Collections.Generic.List[string]
										$isHdr = $false
										try { $isHdr = [bool]$rr.IsHeader } catch { $isHdr = ($rowList.Count -eq 0) }
										$joined = $null
										try { $joined = [string]$rr.CellsJoined } catch { $joined = $null }
										if (-not [string]::IsNullOrEmpty($joined)) {
											foreach ($p in ($joined.Split($us))) {
												$cellList.Add([string]$p)
											}
										} else {
											try {
												$cs = $rr.Cells
												if ($cs -is [System.Array]) {
													for ($ci = 0; $ci -lt $cs.Length; $ci++) {
														$x = $cs.GetValue($ci)
														$cellList.Add($(if ($null -eq $x) { '' } else { [string]$x }))
													}
												} elseif ($cs -is [string]) {
													$cellList.Add([string]$cs)
												}
											} catch {}
										}
										if ($cellList.Count -eq 0) { $cellList.Add('') }
										try {
											$decl = [int]$rr.ColCount
											while ($cellList.Count -lt $decl) { $cellList.Add('') }
										} catch {}
										[void]$rowList.Add([pscustomobject]@{
											Cells    = $cellList
											IsHeader = $isHdr
										})
									}
								}
								if ($rowList.Count -eq 0) { continue }
								$colCount = 1
								foreach ($rr in $rowList) {
									try {
										$cc = [int]$rr.Cells.Count
										if ($cc -gt $colCount) { $colCount = $cc }
									} catch {}
								}
								if ($colCount -lt 1) { $colCount = 1 }

								# --- brushes (hashtable-safe) ---
								$edgeHex = '#3D4158'
								$hdrBg = '#1F1F28'
								$rowBg = '#16161C'
								$rowBgAlt = '#1A1A22'
								$fgHex = '#C0CAF5'
								$hdrFg = '#E8E8F0'
								try {
									if ($null -eq $W['BrushCache']) { $W['BrushCache'] = @{} }
								} catch {
									try { if ($null -eq $W.BrushCache) { $W.BrushCache = @{} } } catch {}
								}
								$bc = $null
								try { $bc = $W['BrushCache'] } catch { try { $bc = $W.BrushCache } catch { $bc = @{} } }
								if ($null -eq $bc) { $bc = @{} }
								foreach ($hx in @($edgeHex, $hdrBg, $rowBg, $rowBgAlt, $fgHex, $hdrFg)) {
									if (-not $bc.ContainsKey($hx)) {
										try { $bc[$hx] = $conv.ConvertFromString($hx) } catch {}
									}
								}

								# Measure: char widths only (no FormattedText)
								$fontSize = 12.5
								$charW = $fontSize * 0.62
								$padX = 16.0
								$borderX = 1.0
								$minCol = 28.0
								$maxCol = [Math]::Max(120.0, $stretchW * 0.55)
								$colMax = New-Object 'System.Double[]' $colCount
								for ($c = 0; $c -lt $colCount; $c++) { $colMax[$c] = 0.0 }
								foreach ($rr in $rowList) {
									$cells = $rr.Cells
									for ($c = 0; $c -lt $colCount; $c++) {
										$t = ''
										try {
											if ($c -lt $cells.Count -and $null -ne $cells[$c]) { $t = [string]$cells[$c] }
										} catch {}
										$mw = [double]$t.Length * $charW
										if ($mw -gt $colMax[$c]) { $colMax[$c] = $mw }
									}
								}
								$colWidths = New-Object 'System.Double[]' $colCount
								$tableW = 0.0
								for ($c = 0; $c -lt $colCount; $c++) {
									$w = $colMax[$c] + $padX + $borderX
									if ($w -lt $minCol) { $w = $minCol }
									if ($w -gt $maxCol) { $w = $maxCol }
									$colWidths[$c] = $w
									$tableW += $w
								}
								if ($tableW -lt 40) { $tableW = 40 }

								& $trimTrailingEmptyParas
								$grid = New-Object System.Windows.Controls.Grid
								$grid.Tag = 'md-table'
								$grid.Width = $tableW
								$grid.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
								$grid.Margin = New-Object System.Windows.Thickness(0, 10, 0, 0)
								for ($c = 0; $c -lt $colCount; $c++) {
									$cd = New-Object System.Windows.Controls.ColumnDefinition
									$cd.Width = New-Object System.Windows.GridLength -ArgumentList @([double]$colWidths[$c], [System.Windows.GridUnitType]::Pixel)
									[void]$grid.ColumnDefinitions.Add($cd)
								}
								$mono = $null
								try { $mono = $W['MonoFont'] } catch { try { $mono = $W.MonoFont } catch { $mono = $null } }

								for ($r = 0; $r -lt $rowList.Count; $r++) {
									$rd = New-Object System.Windows.Controls.RowDefinition
									$rd.Height = [System.Windows.GridLength]::Auto
									[void]$grid.RowDefinitions.Add($rd)
									$rowObj = $rowList[$r]
									if ($null -eq $rowObj) { continue }
									$cells = $rowObj.Cells
									$isHdr = ($r -eq 0)
									try { $isHdr = [bool]$rowObj.IsHeader } catch {}
									$bgHex = if ($isHdr) { $hdrBg } elseif (($r % 2) -eq 0) { $rowBg } else { $rowBgAlt }
									for ($c = 0; $c -lt $colCount; $c++) {
										$cellText = ''
										try {
											if ($null -ne $cells -and $c -lt $cells.Count -and $null -ne $cells[$c]) {
												$cellText = [string]$cells[$c]
											}
										} catch {}
										$cellBorder = New-Object System.Windows.Controls.Border
										try { $cellBorder.BorderBrush = $bc[$edgeHex] } catch {}
										$cellBorder.BorderThickness = New-Object System.Windows.Thickness(1)
										try { $cellBorder.Background = $bc[$bgHex] } catch {}
										$cellBorder.Padding = New-Object System.Windows.Thickness(8, 4, 8, 4)
										$tb = New-Object System.Windows.Controls.TextBlock
										$tb.Text = $cellText
										$est = [double]$cellText.Length * $charW
										if (($est + $padX + $borderX) -gt $maxCol) {
											$tb.TextWrapping = [System.Windows.TextWrapping]::Wrap
										} else {
											$tb.TextWrapping = [System.Windows.TextWrapping]::NoWrap
										}
										try {
											$tb.Foreground = $bc[$(if ($isHdr) { $hdrFg } else { $fgHex })]
										} catch {}
										if ($isHdr) {
											$tb.FontWeight = [System.Windows.FontWeights]::SemiBold
										}
										if ($null -ne $mono) {
											try { $tb.FontFamily = $mono } catch {}
										}
										$tb.FontSize = $fontSize
										$cellBorder.Child = $tb
										[System.Windows.Controls.Grid]::SetRow($cellBorder, [int]$r)
										[System.Windows.Controls.Grid]::SetColumn($cellBorder, [int]$c)
										[void]$grid.Children.Add($cellBorder)
									}
								}
								$buc = New-Object System.Windows.Documents.BlockUIContainer ($grid)
								$buc.Margin = New-Object System.Windows.Thickness 0
								$doc.Blocks.Add($buc)
								try {
									$sp = New-Object System.Windows.Controls.Border
									$sp.Height = 22
									$sp.Width = 1
									$sp.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
									$sp.Background = [System.Windows.Media.Brushes]::Transparent
									$spBuc = New-Object System.Windows.Documents.BlockUIContainer ($sp)
									$spBuc.Margin = New-Object System.Windows.Thickness 0
									$doc.Blocks.Add($spBuc)
								} catch {}
								try {
									$approxChars = [int][Math]::Ceiling($tableW / 7.2)
									$curMax = 0
									try { $curMax = [int]$W['LogMaxLineChars'] } catch {
										try { $curMax = [int]$W.LogMaxLineChars } catch { $curMax = 0 }
									}
									if ($approxChars -gt $curMax) {
										try { $W['LogMaxLineChars'] = $approxChars } catch {
											try { $W.LogMaxLineChars = $approxChars } catch {}
										}
									}
								} catch {}
								try { $W['LogLineCharRun'] = 0 } catch {
									try { $W.LogLineCharRun = 0 } catch {}
								}
							} catch {
							}
							continue
						}

						if ($kind -eq 'dl-progress') {
							try {
								$phase = 'update'
								try { if ($item.Phase) { $phase = [string]$item.Phase } } catch {}
								$label = 'Downloading'
								try { if ($item.Text) { $label = [string]$item.Text } } catch {}
								$pct = -1
								try { if ($null -ne $item.Percent) { $pct = [int]$item.Percent } } catch {}
								$bytes = [int64]0
								$totalB = [int64]0
								try { $bytes = [int64]$item.Bytes } catch {}
								try { $totalB = [int64]$item.TotalBytes } catch {}
								$detail = ''
								try { if ($item.Detail) { $detail = [string]$item.Detail } } catch {}

								$fmtSz = {
									param([int64]$b)
									if ($b -lt 1024) { return ("{0} B" -f $b) }
									if ($b -lt 1048576) { return ("{0:N1} KB" -f ($b / 1024.0)) }
									if ($b -lt 1073741824) { return ("{0:N1} MB" -f ($b / 1048576.0)) }
									return ("{0:N2} GB" -f ($b / 1073741824.0))
								}
								$sizeTxt = if ($totalB -gt 0) {
									"{0} / {1}" -f (& $fmtSz $bytes), (& $fmtSz $totalB)
								} else {
									& $fmtSz $bytes
								}
								$lineTxt = if ($phase -eq 'fail') {
									$d = if ($detail) { " - $detail" } else { '' }
									"  $label  FAIL$d"
								} elseif ($phase -eq 'done') {
									"  $label  OK  $sizeTxt"
								} elseif ($pct -ge 0) {
									"  $label  $pct%  $sizeTxt"
								} else {
									"  $label  $sizeTxt"
								}

								$fgHex = if ($phase -eq 'fail') { '#F05C5C' } elseif ($phase -eq 'done') { '#9ECE6A' } else { '#EEEEEE' }
								$barHex = '#9ECE6A'
								$trackHex = '#333333'
								try {
									if ($null -eq $W['BrushCache']) { $W['BrushCache'] = @{} }
								} catch {
									try { if ($null -eq $W.BrushCache) { $W.BrushCache = @{} } } catch {}
								}
								$bc = $null
								try { $bc = $W['BrushCache'] } catch { try { $bc = $W.BrushCache } catch { $bc = @{} } }
								if ($null -eq $bc) { $bc = @{} }
								foreach ($hx in @($fgHex, $barHex, $trackHex, '#C0CAF5', '#9ECE6A', '#F05C5C', '#EEEEEE')) {
									if (-not $bc.ContainsKey($hx)) {
										try { $bc[$hx] = $conv.ConvertFromString($hx) } catch {}
									}
								}

								$ui = $null
								try { $ui = $W['DlProgressUi'] } catch { try { $ui = $W.DlProgressUi } catch { $ui = $null } }
								if ($phase -eq 'start') {
									try { $W['DlProgressUi'] = $null } catch { try { $W.DlProgressUi = $null } catch {} }
									$ui = $null
								}
								$needNew = ($null -eq $ui) -or ($null -eq $ui.Label) -or ($null -eq $ui.Bar)
								if (-not $needNew) {
									try {
										$stillInDoc = $false
										if ($ui.Container -and $doc.Blocks.Contains($ui.Container)) { $stillInDoc = $true }
										if (-not $stillInDoc) { $needNew = $true }
									} catch { $needNew = $true }
								}

								if ($needNew) {
									$sp = New-Object System.Windows.Controls.StackPanel
									$sp.Orientation = [System.Windows.Controls.Orientation]::Vertical
									$sp.Margin = New-Object System.Windows.Thickness(0, 4, 0, 6)
									$tb = New-Object System.Windows.Controls.TextBlock
									$tb.Text = $lineTxt
									$tb.FontSize = 12.5
									try { if ($W.MonoFont) { $tb.FontFamily = $W.MonoFont } } catch {}
									try { $tb.Foreground = $bc[$fgHex] } catch {}
									$tb.TextWrapping = [System.Windows.TextWrapping]::NoWrap
									$pb = New-Object System.Windows.Controls.ProgressBar
									$pb.Height = 3
									$pb.Minimum = 0
									$pb.Maximum = 100
									$pb.BorderThickness = New-Object System.Windows.Thickness(0)
									$barW = [Math]::Min(280.0, [Math]::Max(120.0, $stretchW - 16.0))
									$pb.Width = $barW
									$pb.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Left
									$pb.Margin = New-Object System.Windows.Thickness(8, 4, 0, 0)
									try { $pb.Foreground = $bc[$barHex] } catch {}
									try { $pb.Background = $bc[$trackHex] } catch {}
									if ($pct -ge 0) {
										$pb.IsIndeterminate = $false
										$pb.Value = [Math]::Max(0, [Math]::Min(100, $pct))
									} else {
										$pb.IsIndeterminate = $true
										$pb.Value = 0
									}
									[void]$sp.Children.Add($tb)
									[void]$sp.Children.Add($pb)
									$buc = New-Object System.Windows.Documents.BlockUIContainer ($sp)
									$buc.Margin = New-Object System.Windows.Thickness 0
									try { $buc.Tag = 'dl-progress' } catch {}
									$doc.Blocks.Add($buc)
									$ui = @{ Container = $buc; Panel = $sp; Label = $tb; Bar = $pb }
									try { $W['DlProgressUi'] = $ui } catch { try { $W.DlProgressUi = $ui } catch {} }
								} else {
									try { $ui.Label.Text = $lineTxt } catch {}
									try { $ui.Label.Foreground = $bc[$fgHex] } catch {}
									if ($pct -ge 0) {
										try {
											$ui.Bar.IsIndeterminate = $false
											$ui.Bar.Value = [Math]::Max(0, [Math]::Min(100, $pct))
										} catch {}
									} elseif ($phase -eq 'update') {
										try { $ui.Bar.IsIndeterminate = $true } catch {}
									}
									if ($phase -eq 'done') {
										try {
											$ui.Bar.IsIndeterminate = $false
											$ui.Bar.Value = 100
										} catch {}
									}
								}
								if ($phase -eq 'done' -or $phase -eq 'fail') {
									try { $W['DlProgressUi'] = $null } catch { try { $W.DlProgressUi = $null } catch {} }
								}
							} catch {}
							continue
						}

						$text = [string]$item.Text
						$cName = [string]$item.Color
						$noNl = [bool]$item.NoNewline
						$isBold = $false; $isItalic = $false; $isStrike = $false; $isCode = $false
						$mdFontSize = 0.0
						$mdHead = 0
						try {
							if ($null -ne $item.MdBold) { $isBold = ([int]$item.MdBold -ne 0) }
							elseif ($null -ne $item.Bold) { $isBold = [bool]$item.Bold }
						} catch {}
						try {
							if ($null -ne $item.MdItalic) { $isItalic = ([int]$item.MdItalic -ne 0) }
							elseif ($null -ne $item.Italic) { $isItalic = [bool]$item.Italic }
						} catch {}
						try {
							if ($null -ne $item.MdStrike) { $isStrike = ([int]$item.MdStrike -ne 0) }
							elseif ($null -ne $item.Strike) { $isStrike = [bool]$item.Strike }
						} catch {}
						try {
							if ($null -ne $item.MdCode) { $isCode = ([int]$item.MdCode -ne 0) }
							elseif ($null -ne $item.Code) { $isCode = [bool]$item.Code }
						} catch {}
						try { if ($null -ne $item.MdFontSize) { $mdFontSize = [double]$item.MdFontSize } } catch {}
						try { if ($null -ne $item.MdHead) { $mdHead = [int]$item.MdHead } } catch {}
						$noLinks = 0
						try { if ($null -ne $item.MdNoLinks) { $noLinks = [int]$item.MdNoLinks } } catch {}
						$hex = $colorMap[$cName]
						if (-not $hex) { $hex = '#A9B1D6' }
						if ($isCode) { $hex = '#7DCFFF' }
						elseif ($mdHead -gt 0) {
							if ($mdHead -eq 1) { $hex = '#7AA2F7' }
							elseif ($mdHead -eq 2) { $hex = '#7DCFFF' }
							else { $hex = '#BB9AF7' }
						}
						elseif ($isBold) { $hex = '#E8E8F0' }
						if (-not $W.BrushCache.ContainsKey($hex)) {
							$W.BrushCache[$hex] = $conv.ConvertFromString($hex)
						}
						if (-not $W.BrushCache.ContainsKey('#1A1A1E')) {
							$W.BrushCache['#1A1A1E'] = $conv.ConvertFromString('#1A1A1E')
						}
						$brush = $W.BrushCache[$hex]
						if ($doc.Blocks.Count -eq 0) {
							$doc.Blocks.Add((& $newPara))
						}
						$para = $doc.Blocks | Select-Object -Last 1
						if (-not ($para -is [System.Windows.Documents.Paragraph])) {
							$para = & $newPara
							$doc.Blocks.Add($para)
						}
						if ($mdHead -gt 0) {
							try {
								if ($mdHead -eq 1) { $para.LineHeight = 22 }
								elseif ($mdHead -eq 2) { $para.LineHeight = 20 }
								else { $para.LineHeight = 18 }
							} catch {}
						}
						$parts = $text -split "(`n)", -1
						for ($i = 0; $i -lt $parts.Count; $i++) {
							$chunk = $parts[$i]
							if ($chunk -eq "`n") {
								try {
									$runLen = [int]$W.LogLineCharRun
									if ($runLen -gt [int]$W.LogMaxLineChars) { $W.LogMaxLineChars = $runLen }
									$W.LogLineCharRun = 0
								} catch {}
								$para = & $newPara
								$doc.Blocks.Add($para)
								continue
							}
							if ($chunk.Length -eq 0) { continue }
							try { $W.LogLineCharRun = [int]$W.LogLineCharRun + $chunk.Length } catch {}
							$needsStyle = $isBold -or $isItalic -or $isStrike -or $isCode -or ($mdFontSize -gt 0) -or ($mdHead -gt 0)
							if (-not $needsStyle) {
								if ($noLinks -ne 0) {
									& $appendRuns $para $chunk $brush $W.MonoFont $W.EmojiFont
								} else {
									& $appendRunsWithLinks $para $chunk $brush $W.MonoFont $W.EmojiFont
								}
								continue
							}
							if ($isCode) {
							} elseif (($noLinks -eq 0) -and ($chunk -match '(?i)https?://|www\.|\[[^\]]+\]\(https?://')) {
								$segs = @( & $splitLinkSegments $chunk )
								foreach ($seg in $segs) {
									if ($null -eq $seg) { continue }
									if ([string]$seg.Kind -eq 'a') {
										& $addHyperlink $para ([string]$seg.Text) ([string]$seg.Url) $brush $W.MonoFont
									} else {
										$sub = [string]$seg.Text
										if ($sub.Length -eq 0) { continue }
										$run = New-Object System.Windows.Documents.Run ($sub)
										$run.Foreground = $brush
										if ($W.MonoFont) { $run.FontFamily = $W.MonoFont }
										if ($isBold -or $mdHead -gt 0) { $run.FontWeight = [System.Windows.FontWeights]::Bold }
										if ($isItalic) { $run.FontStyle = [System.Windows.FontStyles]::Italic }
										if ($isStrike) {
											try { $run.TextDecorations = [System.Windows.TextDecorations]::Strikethrough } catch {}
										}
										if ($mdFontSize -gt 0) { try { $run.FontSize = $mdFontSize } catch {} }
										$para.Inlines.Add($run)
									}
								}
								continue
							}
							if ($needsStyle) {
								if ($mdHead -gt 0 -and $chunk -match '^[\?\uFFFD\uFFFE\uFEFF]+$') {
									continue
								}
								$codeBg = $null
								if ($isCode) {
									try {
										$bc0 = $null
										try { $bc0 = $W['BrushCache'] } catch { $bc0 = $W.BrushCache }
										if ($null -ne $bc0) {
											if (-not $bc0.ContainsKey('#1A1A1E')) {
												$bc0['#1A1A1E'] = $conv.ConvertFromString('#1A1A1E')
											}
											$codeBg = $bc0['#1A1A1E']
										}
									} catch {}
								}
								$headStack = $null
								try {
									$headStack = New-Object System.Windows.Media.FontFamily(
										'Segoe UI Emoji, Segoe UI Symbol, Consolas, Cascadia Mono, Courier New, Segoe UI')
								} catch { $headStack = $W.EmojiFont }
								$applyStyledRun = {
									param($targetPara, $txt, $isEmojiSeg)
									if ([string]::IsNullOrEmpty($txt) -or $null -eq $targetPara) { return }
									if ($txt -match '^[\?\uFFFD]+$') { return }
									$run = New-Object System.Windows.Documents.Run ($txt)
									if ($isEmojiSeg) {
										if ($W.EmojiFont) { $run.FontFamily = $W.EmojiFont }
										elseif ($headStack) { $run.FontFamily = $headStack }
										try { $run.ClearValue([System.Windows.Documents.TextElement]::ForegroundProperty) } catch {
											$run.Foreground = $brush
										}
									} else {
										$run.Foreground = $brush
										# heading font stack includes emoji fallbacks
										if ($mdHead -gt 0 -and $null -ne $headStack) {
											$run.FontFamily = $headStack
										} elseif ($W.MonoFont) {
											$run.FontFamily = $W.MonoFont
										}
									}
									if ($isBold -or $mdHead -gt 0) {
										$run.FontWeight = [System.Windows.FontWeights]::Bold
									}
									if ($isItalic) { $run.FontStyle = [System.Windows.FontStyles]::Italic }
									if ($isStrike) {
										try { $run.TextDecorations = [System.Windows.TextDecorations]::Strikethrough } catch {}
									}
									if ($null -ne $codeBg) {
										try { $run.Background = $codeBg } catch {}
									}
									if ($mdFontSize -gt 0) {
										try { $run.FontSize = $mdFontSize } catch {}
									}
									$targetPara.Inlines.Add($run)
								}
								$sbT = New-Object System.Text.StringBuilder
								$modeSeg = $null  # 'e' emoji, 't' text
								$flushSeg = {
									param($m)
									if ($sbT.Length -eq 0) { return }
									& $applyStyledRun $para $sbT.ToString() ($m -eq 'e')
									[void]$sbT.Clear()
								}
								$si = 0
								$slen = $chunk.Length
								while ($si -lt $slen) {
									$code = [int][char]$chunk[$si]
									$cp = $code
									$take = 1
									if ($code -ge 0xD800 -and $code -le 0xDBFF -and ($si + 1) -lt $slen) {
										$low = [int][char]$chunk[$si + 1]
										if ($low -ge 0xDC00 -and $low -le 0xDFFF) {
											$cp = 0x10000 + (($code - 0xD800) -shl 10) + ($low - 0xDC00)
											$take = 2
										}
									}
									$isEmoji = $false
									# unpaired high surrogate: use emoji font path
									if ($code -ge 0xD800 -and $code -le 0xDBFF -and $take -eq 1) { $isEmoji = $true }
									elseif ($cp -ge 0x1F000 -and $cp -le 0x1FAFF) { $isEmoji = $true }
									elseif ($cp -ge 0x1F1E6 -and $cp -le 0x1F1FF) { $isEmoji = $true }
									elseif ($cp -ge 0x1F300 -and $cp -le 0x1F9FF) { $isEmoji = $true }
									elseif ($cp -ge 0x2190 -and $cp -le 0x21FF) { $isEmoji = $true }
									elseif ($cp -ge 0x2300 -and $cp -le 0x23FF) { $isEmoji = $true }
									elseif ($cp -ge 0x2460 -and $cp -le 0x24FF) { $isEmoji = $true }
									elseif ($cp -ge 0x25A0 -and $cp -le 0x25FF) { $isEmoji = $true }
									elseif ($cp -ge 0x2600 -and $cp -le 0x27BF) { $isEmoji = $true }
									elseif ($cp -ge 0x2B00 -and $cp -le 0x2BFF) { $isEmoji = $true }
									elseif ($cp -ge 0xFE00 -and $cp -le 0xFE0F) { $isEmoji = $true }
									elseif ($cp -eq 0x200D -or $cp -eq 0x20E3 -or $cp -eq 0xFE0F) { $isEmoji = $true }
									elseif ($cp -ge 0xE0020 -and $cp -le 0xE007F) { $isEmoji = $true }
									$want = if ($isEmoji) { 'e' } else { 't' }
									if ($null -eq $modeSeg) { $modeSeg = $want }
									if ($want -ne $modeSeg) {
										& $flushSeg $modeSeg
										$modeSeg = $want
									}
									[void]$sbT.Append($chunk.Substring($si, $take))
									$si += $take
								}
								if ($null -ne $modeSeg) { & $flushSeg $modeSeg }
							} else {
								if ($noLinks -ne 0) {
									& $appendRuns $para $chunk $brush $W.MonoFont $W.EmojiFont
								} else {
									& $appendRunsWithLinks $para $chunk $brush $W.MonoFont $W.EmojiFont
								}
							}
						}
						if (-not $noNl -and $null -ne $text -and -not $text.EndsWith("`n")) {
							try {
								$runLen = [int]$W.LogLineCharRun
								if ($runLen -gt [int]$W.LogMaxLineChars) { $W.LogMaxLineChars = $runLen }
								$W.LogLineCharRun = 0
							} catch {}
							$para = & $newPara
							$doc.Blocks.Add($para)
						} else {
							try {
								$runLen = [int]$W.LogLineCharRun
								if ($runLen -gt [int]$W.LogMaxLineChars) { $W.LogMaxLineChars = $runLen }
							} catch {}
						}
					  } catch {}
					}
					if ($n -gt 0) {
						try { $rtb.ScrollToEnd() } catch {}
						try {
							while ($doc.Blocks.Count -gt 4000 -and $null -ne $doc.Blocks.FirstBlock) {
								$doc.Blocks.Remove($doc.Blocks.FirstBlock)
							}
						} catch {}
						try {
							if ($W.SyncLogPageWidth) { & $W.SyncLogPageWidth $rtb $W }
						} catch {}
						try {
							if ($W.SyncMdStretch) { & $W.SyncMdStretch $rtb $W }
						} catch {}
					}
					# Apply custom titlebar text
					try {
						$pt0 = [string]$W.PendingWindowTitle
						if (-not [string]::IsNullOrWhiteSpace($pt0) -and $W.Window) {
							if ([string]$W.Window.Title -ne $pt0) { $W.Window.Title = $pt0 }
						}
						$bn = [string]$W.PendingTitleBrandName
						if ($W.TitleBrandName -and -not [string]::IsNullOrWhiteSpace($bn)) {
							if ([string]$W.TitleBrandName.Text -ne $bn) {
								$W.TitleBrandName.Text = $bn
								try {
									if ($W.TitleBrandNameShadow) { $W.TitleBrandNameShadow.Text = $bn }
								} catch {}
							}
						}
						$pp = [string]$W.PendingTitlePath
						if ($W.TitlePath -and $null -ne $W.PendingTitlePath) {
							# Skip path update while cwd editor is open
							$cwdOpen = $false
							try { $cwdOpen = [bool]($W.CwdPopup -and $W.CwdPopup.IsOpen) } catch {}
							if (-not $cwdOpen -and [string]$W.TitlePath.Text -ne $pp) {
								$W.TitlePath.Text = $pp
								try { if ($W.TitlePathShadow) { $W.TitlePathShadow.Text = $pp } } catch {}
							}
							# Hide path separator when empty
							try {
								if ($W.TitleDotPath) {
									$W.TitleDotPath.Visibility = $(if ([string]::IsNullOrWhiteSpace($pp)) {
										[System.Windows.Visibility]::Collapsed
									} else {
										[System.Windows.Visibility]::Visible
									})
								}
								if ($W.TitlePathShadow) {
									$W.TitlePathShadow.Visibility = $(if ([string]::IsNullOrWhiteSpace($pp)) {
										[System.Windows.Visibility]::Collapsed
									} else {
										[System.Windows.Visibility]::Visible
									})
								}
							} catch {}
						}
						# Model picker (PoweredBy section)
						try {
							$seq = 0
							try { $seq = [int64]$W.RemoteModelsSeq } catch { $seq = 0 }
							$applied = 0
							try { $applied = [int64]$W.RemoteModelsSeqApplied } catch { $applied = 0 }
							if ($seq -ne 0 -and $seq -ne $applied -and $W.ApplyModelPicker) {
								$models = @()
								try { $models = @($W.RemoteModels) } catch { $models = @() }
								$sel = ''
								try { $sel = [string]$W.ActiveModel } catch { $sel = '' }
								& $W.ApplyModelPicker $models $sel
								$W.RemoteModelsSeqApplied = $seq
							}
						} catch {}
					} catch {}
					$pend = $W.PendingSticky
					if ($pend) {
						$W.PendingSticky = $null
						if ($W.HdrLine1 -and $W.HdrLine1.Visibility -ne [System.Windows.Visibility]::Collapsed) {
							$shadowPlain = $null
							if ($null -ne $pend.BrandName) {
								try {
									$grayHex = '#A0A0AA'   # light gray brackets / dash
									$redHex  = '#B80F0A'   # brand red for name / Agent
									$pathHex = '#C8C8D0'
									foreach ($hx in @($grayHex, $redHex, $pathHex)) {
										if (-not $W.BrushCache.ContainsKey($hx)) {
											$W.BrushCache[$hx] = $conv.ConvertFromString($hx)
										}
									}
									$grayB = $W.BrushCache[$grayHex]
									$redB  = $W.BrushCache[$redHex]
									$pathB = $W.BrushCache[$pathHex]
									$W.HdrLine1.Inlines.Clear()
									$nm = [string]$pend.BrandName
									$rest = if ($null -ne $pend.Line1Rest) { [string]$pend.Line1Rest } else { '' }
									$mk = {
										param($t, $br, $bold)
										$r = New-Object System.Windows.Documents.Run ($t)
										$r.Foreground = $br
										if ($bold) {
											$r.FontWeight = [System.Windows.FontWeights]::Bold
										}
										return $r
									}
									[void]$W.HdrLine1.Inlines.Add((& $mk '[' $grayB $false))
									[void]$W.HdrLine1.Inlines.Add((& $mk $nm $redB $true))
									[void]$W.HdrLine1.Inlines.Add((& $mk '-' $grayB $false))
									[void]$W.HdrLine1.Inlines.Add((& $mk 'Agent' $redB $true))
									[void]$W.HdrLine1.Inlines.Add((& $mk ']' $grayB $false))
									if ($rest.Length -gt 0) {
										[void]$W.HdrLine1.Inlines.Add((& $mk $rest $pathB $false))
									}
									$shadowPlain = ("[{0}-Agent]{1}" -f $nm, $rest)
								} catch {
									if ($null -ne $pend.Line1) {
										$W.HdrLine1.Text = [string]$pend.Line1
										$shadowPlain = [string]$pend.Line1
									}
								}
							} elseif ($null -ne $pend.Line1) {
								$W.HdrLine1.Text = [string]$pend.Line1
								$shadowPlain = [string]$pend.Line1
							} elseif ($null -ne $pend.Left) {
								$W.HdrLine1.Text = [string]$pend.Left
								$shadowPlain = [string]$pend.Left
							}
							if ($null -ne $shadowPlain -and $W.HdrLine1Shadow) {
								try { $W.HdrLine1Shadow.Text = $shadowPlain } catch {}
							}
						}
						# Lower status bar layout
						if ($null -ne $pend.Right -and ($W.LowerRight -or $W.HdrRight)) {
							$lr = if ($W.LowerRight) { $W.LowerRight } else { $W.HdrRight }
							$txt = [string]$pend.Right
							try {
								$grayHex = '#8A8A96'
								# Auto-approve: ON orange, OFF green (existing)
								$aaOnHex = '#FF9E64'
								$aaOffHex = '#9ECE6A'
								# AutoCompact toggle colors
								$acOnHex = '#9ECE6A'
								$acOffHex = '#FF9E64'
								$chipBgHex = '#2A2A30'
								$chipBorderHex = '#3A3A42'
								$activeBgWarm = '#3D2E22'   # warm dim (orange side)
								$activeBgCool = '#2A3328'  # cool dim (green side)
								foreach ($hx in @($grayHex, $aaOnHex, $aaOffHex, $acOnHex, $acOffHex, $chipBgHex, $chipBorderHex, $activeBgWarm, $activeBgCool)) {
									if (-not $W.BrushCache.ContainsKey($hx)) {
										$W.BrushCache[$hx] = $conv.ConvertFromString($hx)
									}
								}
								$autoOn = $false
								try { $autoOn = [bool]$W.AutoApproveOn } catch {
									$autoOn = ($txt -match 'auto-approve:\s*ON')
								}
								$acOn = $true
								try { $acOn = [bool]$W.AutoCompactOn } catch {
									$acOn = ($txt -match 'auto-compact:\s*ON')
								}
								$compactPart = ''
								$toolsPart = ''
								if ($txt -match '(x\d+)') { $compactPart = $Matches[1] }
								elseif ($txt -match '(compact\s+\d+x)') { $compactPart = $Matches[1] }
								if ($txt -match '(tools used\s+\d+)') { $toolsPart = $Matches[1] }
								$sig = ('{0}|ac={1}|aa={2}|{3}' -f $compactPart, $(if ($acOn) { 'ON' } else { 'OFF' }), $(if ($autoOn) { 'ON' } else { 'OFF' }), $toolsPart)
								$isPanel = $false
								try { $isPanel = ($lr -is [System.Windows.Controls.Panel]) } catch { $isPanel = $false }
								if ($isPanel) {
									if ([string]$W.LowerRightSig -eq $sig) {
										# already painted for this state
									} else {
										$W.LowerRightSig = $sig
										try { $lr.Children.Clear() } catch {}
										$mono = $null
										try { $mono = $W.MonoFont } catch {}
										$dot = [string][char]0x00B7
										$addMuted = {
											param([string]$t)
											if ([string]::IsNullOrEmpty($t)) { return }
											$tb = New-Object System.Windows.Controls.TextBlock
											$tb.Text = $t
											$tb.Foreground = $W.BrushCache[$grayHex]
											$tb.FontSize = 12
											$tb.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
											if ($mono) { try { $tb.FontFamily = $mono } catch {} }
											[void]$lr.Children.Add($tb)
										}
										$mkSeg = {
											param([string]$label, [bool]$active, [string]$activeFg, [string]$activeBg)
											$b = New-Object System.Windows.Controls.Border
											$b.CornerRadius = New-Object System.Windows.CornerRadius(3)
											$b.Padding = New-Object System.Windows.Thickness(7, 1, 7, 1)
											$b.Margin = New-Object System.Windows.Thickness(0)
											$b.IsHitTestVisible = $false
											if ($active) {
												$b.Background = $W.BrushCache[$activeBg]
											} else {
												$b.Background = [System.Windows.Media.Brushes]::Transparent
											}
											$t = New-Object System.Windows.Controls.TextBlock
											$t.Text = $label
											$t.FontSize = 11
											$t.FontWeight = [System.Windows.FontWeights]::SemiBold
											$t.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
											$t.IsHitTestVisible = $false
											if ($mono) { try { $t.FontFamily = $mono } catch {} }
											if ($active) {
												$t.Foreground = $W.BrushCache[$activeFg]
											} else {
												$t.Foreground = $W.BrushCache[$grayHex]
												$t.Opacity = 0.55
											}
											$b.Child = $t
											return $b
										}
										$applyToggleLook = {
											param(
												$offSeg, $onSeg, $hitBtn,
												[bool]$isOn,
												[string]$onFg, [string]$offFg,
												[string]$onBg, [string]$offBg,
												[string]$tipOn, [string]$tipOff
											)
											try {
												if ($offSeg) {
													$offSeg.Background = $(if (-not $isOn) { $W.BrushCache[$offBg] } else { [System.Windows.Media.Brushes]::Transparent })
													if ($offSeg.Child) {
														$offSeg.Child.Foreground = $(if (-not $isOn) { $W.BrushCache[$offFg] } else { $W.BrushCache[$grayHex] })
														$offSeg.Child.Opacity = $(if (-not $isOn) { 1.0 } else { 0.55 })
													}
												}
												if ($onSeg) {
													$onSeg.Background = $(if ($isOn) { $W.BrushCache[$onBg] } else { [System.Windows.Media.Brushes]::Transparent })
													if ($onSeg.Child) {
														$onSeg.Child.Foreground = $(if ($isOn) { $W.BrushCache[$onFg] } else { $W.BrushCache[$grayHex] })
														$onSeg.Child.Opacity = $(if ($isOn) { 1.0 } else { 0.55 })
													}
												}
												$tip = if ($isOn) { $tipOn } else { $tipOff }
												if ($hitBtn) {
													try {
														if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $hitBtn $tip 280 }
														else { $hitBtn.ToolTip = $tip }
													} catch {}
												}
											} catch {}
										}.GetNewClosure()
										$mkToggle = {
											param(
												[bool]$isOn,
												[string]$onFg, [string]$offFg,
												[string]$onBg, [string]$offBg,
												[string]$tipOn, [string]$tipOff,
												[scriptblock]$onClick
											)
											$outer = New-Object System.Windows.Controls.Border
											$outer.Background = $W.BrushCache[$chipBgHex]
											$outer.BorderBrush = $W.BrushCache[$chipBorderHex]
											$outer.BorderThickness = New-Object System.Windows.Thickness(1)
											$outer.CornerRadius = New-Object System.Windows.CornerRadius(4)
											$outer.Padding = New-Object System.Windows.Thickness(1)
											$outer.Margin = New-Object System.Windows.Thickness(2, 0, 2, 0)
											$outer.Cursor = [System.Windows.Input.Cursors]::Hand
											$outer.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
											try {
												$tip0 = if ($isOn) { $tipOn } else { $tipOff }
												if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $outer $tip0 280 }
												else { $outer.ToolTip = $tip0 }
											} catch { $outer.ToolTip = $(if ($isOn) { $tipOn } else { $tipOff }) }
											$seg = New-Object System.Windows.Controls.StackPanel
											$seg.Orientation = [System.Windows.Controls.Orientation]::Horizontal
											$offSeg = & $mkSeg 'OFF' (-not $isOn) $offFg $offBg
											$onSeg = & $mkSeg 'ON' $isOn $onFg $onBg
											$seg.IsHitTestVisible = $false
											[void]$seg.Children.Add($offSeg)
											[void]$seg.Children.Add($onSeg)
											$layer = New-Object System.Windows.Controls.Grid
											[void]$layer.Children.Add($seg)
											$hitBtn = New-Object System.Windows.Controls.Button
											$hitBtn.Background = [System.Windows.Media.Brushes]::Transparent
											$hitBtn.BorderThickness = New-Object System.Windows.Thickness(0)
											$hitBtn.Padding = New-Object System.Windows.Thickness(0)
											$hitBtn.Cursor = [System.Windows.Input.Cursors]::Hand
											$hitBtn.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Stretch
											$hitBtn.VerticalAlignment = [System.Windows.VerticalAlignment]::Stretch
											$hitBtn.Focusable = $false
											$hitBtn.IsTabStop = $false
											# NoMouseOver (same idea as Send): no IsMouseOver chrome; hover paints outer via code
											try {
												$hitBtn.Template = [System.Windows.Markup.XamlReader]::Parse(
													'<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="Button"><Border Background="Transparent"/></ControlTemplate>'
												)
											} catch {}
											try {
												$tip1 = if ($isOn) { $tipOn } else { $tipOff }
												if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $hitBtn $tip1 280 }
												else { $hitBtn.ToolTip = $tip1 }
											} catch { $hitBtn.ToolTip = $(if ($isOn) { $tipOn } else { $tipOff }) }
											[void]$layer.Children.Add($hitBtn)
											$outer.Child = $layer
											# Chip hover colors
											$baseChipBg = $W.BrushCache[$chipBgHex]
											$hoverChipBg = $null
											try {
												if (-not $W.BrushCache.ContainsKey('#3A3A42')) {
													$W.BrushCache['#3A3A42'] = $conv.ConvertFromString('#3A3A42')
												}
												$hoverChipBg = $W.BrushCache['#3A3A42']
											} catch { $hoverChipBg = $baseChipBg }
											$hitBtn.add_MouseEnter({
												try { $outer.Background = $hoverChipBg } catch {}
											}.GetNewClosure())
											$hitBtn.add_MouseLeave({
												try { $outer.Background = $baseChipBg } catch {}
											}.GetNewClosure())
											$hitBtn.add_Click($onClick)
											return @{ Outer = $outer; Off = $offSeg; On = $onSeg; Hit = $hitBtn }
										}
										# Compaction count chip
										$compactOrangeHex = '#E0AF68'
										if (-not $W.BrushCache.ContainsKey($compactOrangeHex)) {
											try { $W.BrushCache[$compactOrangeHex] = $conv.ConvertFromString($compactOrangeHex) } catch {}
										}
										if ($compactPart) {
											$cpTb = New-Object System.Windows.Controls.TextBlock
											$cpTb.Text = $compactPart
											$cpTb.Foreground = $W.BrushCache[$compactOrangeHex]
											$cpTb.FontSize = 12
											$cpTb.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
											if ($mono) { try { $cpTb.FontFamily = $mono } catch {} }
											try { $cpTb.FontWeight = [System.Windows.FontWeights]::SemiBold } catch {}
											$W.CompactCountTb = $cpTb
											[void]$lr.Children.Add($cpTb)
											& $addMuted ("  {0}  " -f $dot)
										} else {
											$W.CompactCountTb = $null
										}
										# AutoCompact label and toggle
										$acLabel = New-Object System.Windows.Controls.TextBlock
										$acLabel.Text = 'auto-compact '
										$acLabel.Foreground = $W.BrushCache[$grayHex]
										$acLabel.FontSize = 12
										$acLabel.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
										$acLabel.Cursor = [System.Windows.Input.Cursors]::Hand
										try {
											if ($W.SetThemedToolTip) {
												& $W.SetThemedToolTip $acLabel 'Click for Compact Now - open menu to run compaction immediately' 300
											} else {
												$acLabel.ToolTip = 'Click for Compact Now'
											}
										} catch { $acLabel.ToolTip = 'Click for Compact Now' }
										if ($mono) { try { $acLabel.FontFamily = $mono } catch {} }
										$W.AcLabel = $acLabel
										$W.AcLabelGrayHex = $grayHex
										$W.AcLabelFlashHex = $compactOrangeHex
										# Popup + real Button (NOT MenuItem) so system menu brushes cannot appear.
										# Compact Now button hover
										$acMenuBgHex = '#1E1E24'
										$acMenuFgHex = '#C8C8D0'
										$acMenuBorderHex = '#3A3A42'
										$acHoverBgHex = '#243D2A'
										$acHoverBdHex = '#9ECE6A'
										$acHoverFgHex = '#C3E6A0'
										foreach ($hx in @($acMenuBgHex, $acMenuFgHex, $acMenuBorderHex, $acHoverBgHex, $acHoverBdHex, $acHoverFgHex)) {
											if (-not $W.BrushCache.ContainsKey($hx)) {
												try { $W.BrushCache[$hx] = $conv.ConvertFromString($hx) } catch {}
											}
										}
										$acPopup = New-Object System.Windows.Controls.Primitives.Popup
										# Compact Now popup stays open until dismissed
										$acPopup.StaysOpen = $true
										$acPopup.AllowsTransparency = $true
										$acPopup.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Top
										$acPopup.PlacementTarget = $acLabel
										$acPopup.HorizontalOffset = -2
										$acPopup.VerticalOffset = -9
										$acPopupShell = New-Object System.Windows.Controls.Border
										$acPopupShell.Background = $W.BrushCache[$acMenuBgHex]
										$acPopupShell.BorderBrush = $W.BrushCache[$acMenuBorderHex]
										$acPopupShell.BorderThickness = New-Object System.Windows.Thickness(1)
										$acPopupShell.Padding = New-Object System.Windows.Thickness(2)
										$acPopupShell.CornerRadius = New-Object System.Windows.CornerRadius(0)
										$acPopupShell.SnapsToDevicePixels = $true
										$btnCompact = New-Object System.Windows.Controls.Button
										$btnCompact.Content = 'Compact Now'
										$btnCompact.Cursor = [System.Windows.Input.Cursors]::Hand
										$btnCompact.FontSize = 12
										$btnCompact.Padding = New-Object System.Windows.Thickness(12, 6, 12, 6)
										$btnCompact.BorderThickness = New-Object System.Windows.Thickness(1)
										$btnCompact.Background = $W.BrushCache[$acMenuBgHex]
										$btnCompact.BorderBrush = $W.BrushCache[$acMenuBgHex]
										$btnCompact.Foreground = $W.BrushCache[$acMenuFgHex]
										$btnCompact.Focusable = $false
										try {
											if ($W.SetThemedToolTip) {
												& $W.SetThemedToolTip $btnCompact 'Compact Now - summarize older context to free room for the next replies' 320
											} else {
												$btnCompact.ToolTip = 'Compact Now - free context by summarizing older history'
											}
										} catch {}
										try {
											$btnCompact.Template = [System.Windows.Markup.XamlReader]::Parse(@'
<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="Button">
  <Border Background="{TemplateBinding Background}"
          BorderBrush="{TemplateBinding BorderBrush}"
          BorderThickness="{TemplateBinding BorderThickness}"
          Padding="{TemplateBinding Padding}"
          CornerRadius="4"
          SnapsToDevicePixels="True">
    <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/>
  </Border>
</ControlTemplate>
'@)
										} catch {}
										$btnCompact.add_MouseEnter({
											try {
												$btnCompact.Background = $W.BrushCache['#243D2A']
												$btnCompact.BorderBrush = $W.BrushCache['#9ECE6A']
												$btnCompact.Foreground = $W.BrushCache['#C3E6A0']
											} catch {}
										}.GetNewClosure())
										$btnCompact.add_MouseLeave({
											try {
												$btnCompact.Background = $W.BrushCache['#1E1E24']
												$btnCompact.BorderBrush = $W.BrushCache['#1E1E24']
												$btnCompact.Foreground = $W.BrushCache['#C8C8D0']
											} catch {}
										}.GetNewClosure())
										$btnCompact.add_Click({
											param($s, $e)
											try {
												try { $acPopup.IsOpen = $false } catch {}
												$injected = $false
												try {
													if ([bool]$W.PromptArmed) {
														$W.PendingUiCommand = $null
														$W.InputResult = '/compact'
														[void]$W.InputWait.Set()
														$W.PromptArmed = $false
														$injected = $true
													}
												} catch {}
												if (-not $injected) { $W.PendingUiCommand = '/compact' }
												if ($W.WriteQueue) {
													$W.WriteQueue.Enqueue([pscustomobject]@{
														Kind = 'text'; Text = "`n  Compact Now requested...`n"; Color = 'Cyan'; NoNewline = $false
														Brand = $(try { [string]$W.AgentName } catch { 'MiniBot' })
													})
												}
											} catch {}
										}.GetNewClosure())
										$acPopupShell.Child = $btnCompact
										$acPopup.Child = $acPopupShell
										$W.AcCompactPopup = $acPopup
										# Toggle Compact Now popup
										$acLabel.add_MouseLeftButtonUp({
											param($s, $e)
											try {
												if ($null -ne $e) { $e.Handled = $true }
												$acPopup.PlacementTarget = $acLabel
												$acPopup.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Top
												$acPopup.HorizontalOffset = -2
												$acPopup.VerticalOffset = -9
												$acPopup.IsOpen = -not [bool]$acPopup.IsOpen
											} catch {}
										}.GetNewClosure())
										# Click outside closes popup
										try {
											if ($W.Window -and -not $W.AcPopupOutsideHooked) {
												$W.AcPopupOutsideHooked = $true
												$W.Window.add_PreviewMouseDown({
													param($s, $e)
													try {
														if (-not $W.AcCompactPopup -or -not [bool]$W.AcCompactPopup.IsOpen) { return }
														$src = $null
														try { $src = $e.OriginalSource } catch {}
														# Keep open if click is on label or inside popup
														$keep = $false
														try {
															$vis = $src
															while ($null -ne $vis) {
																if ($vis -eq $W.AcLabel -or $vis -eq $W.AcCompactPopup.Child) { $keep = $true; break }
																try { $vis = [System.Windows.Media.VisualTreeHelper]::GetParent($vis) } catch { break }
															}
														} catch {}
														if (-not $keep) { $W.AcCompactPopup.IsOpen = $false }
													} catch {}
												}.GetNewClosure())
											}
										} catch {}
										[void]$lr.Children.Add($acLabel)
										# Colors for applyToggleLook (stored for click handlers)
										$W.AcOnFg = $acOnHex; $W.AcOffFg = $acOffHex
										$W.AcOnBg = $activeBgCool; $W.AcOffBg = $activeBgWarm
										$W.AcTipOn = 'Auto-compact is ON - click to disable automatic compaction'
										$W.AcTipOff = 'Auto-compact is OFF - click to enable automatic compaction'
										$W.AaOnFg = $aaOnHex; $W.AaOffFg = $aaOffHex
										$W.AaOnBg = $activeBgWarm; $W.AaOffBg = $activeBgCool
										$W.AaTipOn = 'Auto-approve is ON - click to require confirmation again'
										$W.AaTipOff = 'Auto-approve is OFF - click to skip confirmation prompts'
										$acClick = {
											param($s, $e)
											try {
												if ($null -ne $e) { try { $e.Handled = $true } catch {} }
												$now = [Environment]::TickCount
												$last = 0
												try { $last = [int]$W.AutoCompactClickTick } catch { $last = 0 }
												if ($last -ne 0 -and ((($now - $last) -band 0x7fffffff) -lt 280)) { return }
												$W.AutoCompactClickTick = $now
												$cur = $false
												try { $cur = [bool]$W.AutoCompactOn } catch { $cur = $false }
												$nxt = -not $cur
												$W.AutoCompactOn = $nxt
												$W.AutoCompactDirty = $true
												# Immediate UI update
												try {
													& $applyToggleLook $W.AutoCompactOffSeg $W.AutoCompactOnSeg $W.AutoCompactToggleTip `
														$nxt $W.AcOnFg $W.AcOffFg $W.AcOnBg $W.AcOffBg $W.AcTipOn $W.AcTipOff
												} catch {}
												# Keep sig in sync so next paint does not thrash
												try {
													$cp = ''; $tp = ''
													if ($txt -match '(x\d+)') { $cp = $Matches[1] }
													if ($txt -match '(tools used\s+\d+)') { $tp = $Matches[1] }
													$aa = $false; try { $aa = [bool]$W.AutoApproveOn } catch {}
													$W.LowerRightSig = ('{0}|ac={1}|aa={2}|{3}' -f $cp, $(if ($nxt) { 'ON' } else { 'OFF' }), $(if ($aa) { 'ON' } else { 'OFF' }), $tp)
												} catch {}
												try {
													$msg = if ($nxt) { "`n  Auto-compact ON - context will trim automatically.`n" } else { "`n  Auto-compact OFF - context will not auto-trim.`n" }
													$col = if ($nxt) { 'Green' } else { 'DarkYellow' }
													if ($W.WriteQueue) {
														$W.WriteQueue.Enqueue([pscustomobject]@{
															Kind = 'text'; Text = $msg; Color = $col; NoNewline = $false
															Brand = $(try { [string]$W.AgentName } catch { 'MiniBot' })
														})
													}
												} catch {}
											} catch {}
										}.GetNewClosure()
										# ON green / OFF orange
										$acTog = & $mkToggle $acOn $acOnHex $acOffHex $activeBgCool $activeBgWarm `
											$W.AcTipOn $W.AcTipOff $acClick
										$W.AutoCompactOffSeg = $acTog.Off
										$W.AutoCompactOnSeg = $acTog.On
										$W.AutoCompactToggleTip = $acTog.Hit
										[void]$lr.Children.Add($acTog.Outer)
										& $addMuted ("  {0}  " -f $dot)
										# auto-approve
										& $addMuted 'auto-approve '
										$aaClick = {
											param($s, $e)
											try {
												if ($null -ne $e) { try { $e.Handled = $true } catch {} }
												$now = [Environment]::TickCount
												$last = 0
												try { $last = [int]$W.AutoApproveClickTick } catch { $last = 0 }
												if ($last -ne 0 -and ((($now - $last) -band 0x7fffffff) -lt 280)) { return }
												$W.AutoApproveClickTick = $now
												$cur = $false
												try { $cur = [bool]$W.AutoApproveOn } catch { $cur = $false }
												$nxt = -not $cur
												$W.AutoApproveOn = $nxt
												$W.AutoApproveDirty = $true
												try {
													& $applyToggleLook $W.AutoApproveOffSeg $W.AutoApproveOnSeg $W.AutoApproveToggleTip `
														$nxt $W.AaOnFg $W.AaOffFg $W.AaOnBg $W.AaOffBg $W.AaTipOn $W.AaTipOff
												} catch {}
												try {
													$cp = ''; $tp = ''
													if ($txt -match '(x\d+)') { $cp = $Matches[1] }
													if ($txt -match '(tools used\s+\d+)') { $tp = $Matches[1] }
													$ac = $true; try { $ac = [bool]$W.AutoCompactOn } catch {}
													$W.LowerRightSig = ('{0}|ac={1}|aa={2}|{3}' -f $cp, $(if ($ac) { 'ON' } else { 'OFF' }), $(if ($nxt) { 'ON' } else { 'OFF' }), $tp)
												} catch {}
												try {
													$msg = if ($nxt) {
														"`n  Auto-approve ON - modifying actions will not prompt.`n"
													} else {
														"`n  Auto-approve OFF - confirmations restored.`n"
													}
													$col = if ($nxt) { 'DarkYellow' } else { 'Green' }
													if ($W.WriteQueue) {
														$W.WriteQueue.Enqueue([pscustomobject]@{
															Kind = 'text'; Text = $msg; Color = $col; NoNewline = $false
															Brand = $(try { [string]$W.AgentName } catch { 'MiniBot' })
														})
													}
												} catch {}
											} catch {}
										}.GetNewClosure()
										# ON orange / OFF green
										$aaTog = & $mkToggle $autoOn $aaOnHex $aaOffHex $activeBgWarm $activeBgCool `
											$W.AaTipOn $W.AaTipOff $aaClick
										$W.AutoApproveOffSeg = $aaTog.Off
										$W.AutoApproveOnSeg = $aaTog.On
										$W.AutoApproveToggleTip = $aaTog.Hit
										[void]$lr.Children.Add($aaTog.Outer)
										if ($toolsPart) {
											& $addMuted ("  {0}  " -f $dot)
											& $addMuted $toolsPart
										}
									}
								} else {
									try {
										if ($lr -is [System.Windows.Controls.TextBlock]) { $lr.Text = $txt }
									} catch {}
								}
							} catch {
								try {
									if ($lr -is [System.Windows.Controls.TextBlock]) { $lr.Text = $txt }
								} catch {}
							}
						}
						if ($null -ne $pend.Hint -and $W.HintBar) { $W.HintBar.Text = [string]$pend.Hint }
						if ($null -ne $pend.StatusMode) {
							$newMode = [string]$pend.StatusMode
							$oldMode = [string]$W.StatusMode
							$W.StatusMode = $newMode
							$nb = ($newMode -eq 'thinking' -or $newMode -eq 'working' -or $newMode -eq 'compacting')
							$ob = ($oldMode -eq 'thinking' -or $oldMode -eq 'working' -or $oldMode -eq 'compacting')
							if ($nb -and (-not $ob -or $oldMode -ne $newMode)) {
								$W.StatusBusySince = [Environment]::TickCount
							} elseif (-not $nb) {
								$W.StatusBusySince = 0
							}
							if ($oldMode -ne $newMode) {
								try {
									if ($W.SetRobotMood) { & $W.SetRobotMood $newMode $false }
								} catch {}
							}
						}
						if ($null -ne $pend.StatusLabel) { $W.StatusLabel = [string]$pend.StatusLabel }
						if ($null -ne $pend.CtxPct -and $W.CtxBarFill) {
							$pct = [double]$pend.CtxPct
							if ($pct -lt 0) { $pct = 0 }
							if ($pct -gt 1) { $pct = 1 }
							$maxW = 120
							try { if ($W.CtxBarMaxW) { $maxW = [double]$W.CtxBarMaxW } } catch {}
							$W.CtxBarFill.Width = [math]::Max(0, [math]::Round($pct * $maxW))
							if ($pend.CtxColor) {
								try {
									$bh = [string]$pend.CtxColor
									if (-not $W.BrushCache.ContainsKey($bh)) {
										$W.BrushCache[$bh] = $conv.ConvertFromString($bh)
									}
									$W.CtxBarFill.Fill = $W.BrushCache[$bh]
								} catch {}
							}
						}
						if ($null -ne $pend.CtxPctText -and $W.CtxPctText) {
							$W.CtxPctText.Text = [string]$pend.CtxPctText
							if ($pend.CtxColor) {
								try {
									$bh = [string]$pend.CtxColor
									if (-not $W.BrushCache.ContainsKey($bh)) {
										$W.BrushCache[$bh] = $conv.ConvertFromString($bh)
									}
									$W.CtxPctText.Foreground = $W.BrushCache[$bh]
								} catch {}
							}
						}
						if ($null -ne $pend.CtxTokText -and $W.CtxTokText) {
							$W.CtxTokText.Text = [string]$pend.CtxTokText
						}
					}
					# Tool-group chips: grey inactive / lime active; click opens tool list
					try {
						if ($W.ToolGroupsDirty -and $W.HdrToolGroups -and $W.ToolGroupsData) {
							$W.ToolGroupsDirty = $false
							$td = $W.ToolGroupsData
							$panel = $W.HdrToolGroups
							try { $panel.Children.Clear() } catch {}
							$order = @()
							$activeArr = @()
							$toolsMap = @{}
							$fpIn = ''
							try { $order = @($td.order) } catch {}
							try { $activeArr = @($td.active) } catch {}
							try { $toolsMap = $td.tools } catch {}
							try { $fpIn = [string]$td.fp } catch {}
							$installerPkgs = @()
							try { $installerPkgs = @($td.installerPackages) } catch { $installerPkgs = @() }
							$groupTipsMap = @{}
							$toolTipsMap = @{}
							try { $groupTipsMap = $td.groupTips } catch { $groupTipsMap = @{} }
							try { $toolTipsMap = $td.toolTips } catch { $toolTipsMap = @{} }
							if ($null -eq $groupTipsMap) { $groupTipsMap = @{} }
							if ($null -eq $toolTipsMap) { $toolTipsMap = @{} }
							$limeHex = '#9ECE6A'
							$grayHex = '#8A8A96'
							$orangeHex = '#FF9E64'
							$chipBgHex = '#3A3A42'
							$menuBgHex = '#1E1E24'
							$menuFgHex = '#C8C8D0'
							$tipBgHex = '#1A1A1E'
							$tipBdHex = '#3A3A42'
							$sepHex = '#3A3A42'
							foreach ($hx in @($limeHex, $grayHex, $orangeHex, $chipBgHex, $menuBgHex, $menuFgHex, $tipBgHex, $tipBdHex, $sepHex)) {
								if (-not $W.BrushCache.ContainsKey($hx)) {
									try { $W.BrushCache[$hx] = $conv.ConvertFromString($hx) } catch {}
								}
							}
							$limeB = $W.BrushCache[$limeHex]
							$grayB = $W.BrushCache[$grayHex]
							$orangeB = $W.BrushCache[$orangeHex]
							if (-not $orangeB) { $orangeB = $grayB }
							$chipBg = $W.BrushCache[$chipBgHex]
							$menuBg = $W.BrushCache[$menuBgHex]
							$menuFg = $W.BrushCache[$menuFgHex]
							$tipBg = $W.BrushCache[$tipBgHex]
							$tipBd = $W.BrushCache[$tipBdHex]
							$sepB = $W.BrushCache[$sepHex]
							$visionBlockedMap = @{}
							try { $visionBlockedMap = $td.visionBlocked } catch { $visionBlockedMap = @{} }
							if ($null -eq $visionBlockedMap) { $visionBlockedMap = @{} }
							$mono = $null
							try { $mono = $W.MonoFont } catch {}
							$mkThemedTip = {
								param([string]$text)
								if ([string]::IsNullOrWhiteSpace($text)) { return $null }
								try {
									$tip = New-Object System.Windows.Controls.ToolTip
									$tip.Background = $tipBg
									$tip.Foreground = $menuFg
									$tip.BorderBrush = $tipBd
									$tip.BorderThickness = New-Object System.Windows.Thickness(1)
									$tip.Padding = New-Object System.Windows.Thickness(10, 7, 10, 7)
									$tip.HasDropShadow = $true
									try {
										$tip.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Mouse
									} catch {}
									$ttb = New-Object System.Windows.Controls.TextBlock
									$ttb.Text = [string]$text
									$ttb.TextWrapping = [System.Windows.TextWrapping]::Wrap
									$ttb.MaxWidth = 340
									$ttb.Foreground = $menuFg
									$ttb.FontSize = 12
									$ttb.LineHeight = 16
									if ($mono) { try { $ttb.FontFamily = $mono } catch {} }
									$tip.Content = $ttb
									return $tip
								} catch {
									return [string]$text
								}
							}.GetNewClosure()
							foreach ($g in $order) {
								if ([string]::IsNullOrWhiteSpace([string]$g)) { continue }
								$on = $false
								try { $on = ($activeArr -contains [string]$g) } catch { $on = $false }
								$border = New-Object System.Windows.Controls.Border
								$border.Background = $chipBg
								$border.CornerRadius = New-Object System.Windows.CornerRadius(3)
								$border.Padding = New-Object System.Windows.Thickness(5, 1, 5, 1)
								$border.Margin = New-Object System.Windows.Thickness(0, 2, 4, 2)
								$border.Cursor = [System.Windows.Input.Cursors]::Hand
								$border.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								$border.SnapsToDevicePixels = $true
								$tb = New-Object System.Windows.Controls.TextBlock
								$tb.Text = [string]$g
								$tb.FontSize = 11
								$tb.Foreground = $(if ($on) { $limeB } else { $grayB })
								$tb.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
								if ($mono) { try { $tb.FontFamily = $mono } catch {} }
								if ($on) {
									try { $tb.FontWeight = [System.Windows.FontWeights]::SemiBold } catch {}
								}
								try {
									$ds = New-Object System.Windows.Media.Effects.DropShadowEffect
									$ds.Color = [System.Windows.Media.Colors]::Black
									$ds.BlurRadius = 3.2
									$ds.ShadowDepth = 1.15
									$ds.Opacity = 0.9
									$ds.Direction = 315
									$tb.Effect = $ds
								} catch {}
								$border.Child = $tb
								$gTip = ''
								try {
									if ($groupTipsMap -is [hashtable] -and $groupTipsMap.ContainsKey([string]$g)) {
										$gTip = [string]$groupTipsMap[[string]$g]
									} elseif ($groupTipsMap.Contains([string]$g)) {
										$gTip = [string]$groupTipsMap[[string]$g]
									}
								} catch { $gTip = '' }
								if ([string]::IsNullOrWhiteSpace($gTip)) {
									$st = if ($on) { 'Active' } else { 'Inactive' }
									$gTip = ("{0}`nTool group ({1}).`n`nClick to list tools." -f [string]$g, $st)
								} else {
									$st = if ($on) { 'Active' } else { 'Inactive' }
									if ($gTip -notmatch '(?i)active|inactive|enabled') {
										$gTip = ("{0}`n`nStatus: {1}" -f $gTip.TrimEnd(), $st)
									}
								}
								try {
									$tipObj = & $mkThemedTip $gTip
									if ($null -ne $tipObj) { $border.ToolTip = $tipObj }
								} catch {}
								$tools = @()
								try {
									if ($toolsMap -is [hashtable] -and $toolsMap.ContainsKey([string]$g)) {
										$tools = @($toolsMap[[string]$g])
									} elseif ($toolsMap.Contains([string]$g)) {
										$tools = @($toolsMap[[string]$g])
									}
								} catch { $tools = @() }
								$cm = New-Object System.Windows.Controls.ContextMenu
								try {
									$cm.Background = $menuBg
									$cm.Foreground = $menuFg
									$cm.BorderBrush = $chipBg
									$cm.BorderThickness = New-Object System.Windows.Thickness(1)
									$cm.Padding = New-Object System.Windows.Thickness(2)
									if ($null -eq $cm.Resources) {
										$cm.Resources = New-Object System.Windows.ResourceDictionary
									}
									try { $cm.Resources[[System.Windows.SystemColors]::MenuBrushKey] = $menuBg } catch {}
									try { $cm.Resources[[System.Windows.SystemColors]::MenuBarBrushKey] = $menuBg } catch {}
									try { $cm.Resources[[System.Windows.SystemColors]::ControlBrushKey] = $menuBg } catch {}
									try { $cm.Resources[[System.Windows.SystemColors]::MenuTextBrushKey] = $menuFg } catch {}
									try { $cm.Resources[[System.Windows.SystemColors]::HighlightBrushKey] = $chipBg } catch {}
									try { $cm.Resources[[System.Windows.SystemColors]::HighlightTextBrushKey] = $menuFg } catch {}
									try {
										$cmTplXaml = @'
<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="ContextMenu">
  <Border Background="{TemplateBinding Background}"
          BorderBrush="{TemplateBinding BorderBrush}"
          BorderThickness="{TemplateBinding BorderThickness}"
          CornerRadius="4" Padding="{TemplateBinding Padding}"
          SnapsToDevicePixels="True">
    <StackPanel IsItemsHost="True" KeyboardNavigation.DirectionalNavigation="Cycle"/>
  </Border>
</ControlTemplate>
'@
										$cmTpl = [Windows.Markup.XamlReader]::Parse($cmTplXaml)
										if ($null -ne $cmTpl) { $cm.Template = $cmTpl }
									} catch {}
									try {
										$miStyle = New-Object System.Windows.Style ([System.Windows.Controls.MenuItem])
										$miStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::BackgroundProperty, $menuBg)))
										$miStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::BorderThicknessProperty, (New-Object System.Windows.Thickness(0)))))
										$miStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::PaddingProperty, (New-Object System.Windows.Thickness(10, 5, 14, 5)))))
										$miTplXaml = @'
<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="MenuItem">
  <Border x:Name="Bd" Background="{TemplateBinding Background}"
          BorderThickness="0" Padding="{TemplateBinding Padding}" SnapsToDevicePixels="True"
          TextElement.Foreground="{TemplateBinding Foreground}">
    <ContentPresenter ContentSource="Header" RecognizesAccessKey="True"
                      VerticalAlignment="Center" HorizontalAlignment="Left"
                      TextElement.Foreground="{TemplateBinding Foreground}"/>
  </Border>
  <ControlTemplate.Triggers>
    <Trigger Property="IsHighlighted" Value="True">
      <Setter TargetName="Bd" Property="Background" Value="#3A3A42"/>
    </Trigger>
  </ControlTemplate.Triggers>
</ControlTemplate>
'@
										$miTpl = [Windows.Markup.XamlReader]::Parse($miTplXaml)
										if ($null -ne $miTpl) {
											$miStyle.Setters.Add((New-Object System.Windows.Setter([System.Windows.Controls.Control]::TemplateProperty, $miTpl)))
										}
										$cm.Resources[[System.Windows.Controls.MenuItem]] = $miStyle
									} catch {}
								} catch {}
								$itemFg = $(if ($on) { $limeB } else { $grayB })
								$usedSet = @{}
								try {
									foreach ($u in @($td.usedTools)) {
										if ($u) { $usedSet[[string]$u] = $true }
									}
								} catch {}
								$usedLimeHex = '#B8F07A'
								if (-not $W.BrushCache.ContainsKey($usedLimeHex)) {
									try { $W.BrushCache[$usedLimeHex] = $conv.ConvertFromString($usedLimeHex) } catch {}
								}
								$usedLimeB = $W.BrushCache[$usedLimeHex]
								if (-not $usedLimeB) { $usedLimeB = $limeB }
								$addToolItem = {
									param([string]$header, $fgBrush, $bgBrush, [string]$tip = '', [bool]$wasUsed = $false)
									$mi = New-Object System.Windows.Controls.MenuItem
									$mi.IsEnabled = $true
									$mi.IsHitTestVisible = $true
									$mi.Focusable = $false
									try { $mi.StaysOpenOnClick = $true } catch {}
									$useFg = $fgBrush
									if ($wasUsed -and $usedLimeB) { $useFg = $usedLimeB }
									try { $mi.Background = $bgBrush } catch {}
									try { $mi.Foreground = $useFg } catch {}
									$hdrHost = New-Object System.Windows.Controls.Grid
									$hdrTb = New-Object System.Windows.Controls.TextBlock
									$hdrTb.Text = [string]$header
									$hdrTb.Foreground = $useFg
									$hdrTb.FontSize = 12
									$hdrTb.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
									if ($mono) { try { $hdrTb.FontFamily = $mono } catch {} }
									if ($wasUsed) {
										$back = New-Object System.Windows.Controls.TextBlock
										$back.Text = [string]$header
										$back.Foreground = [System.Windows.Media.Brushes]::White
										$back.FontSize = 12
										$back.Opacity = 0.55
										$back.Margin = New-Object System.Windows.Thickness(0)
										$back.IsHitTestVisible = $false
										$back.VerticalAlignment = [System.Windows.VerticalAlignment]::Center
										if ($mono) { try { $back.FontFamily = $mono } catch {} }
										try { $back.FontWeight = [System.Windows.FontWeights]::SemiBold } catch {}
										[void]$hdrHost.Children.Add($back)
										try { $hdrTb.FontWeight = [System.Windows.FontWeights]::SemiBold } catch {}
									}
									[void]$hdrHost.Children.Add($hdrTb)
									try { $mi.SetValue([System.Windows.Documents.TextElement]::ForegroundProperty, $useFg) } catch {}
									if (-not [string]::IsNullOrWhiteSpace($tip)) {
										try {
											$tipObj = & $mkThemedTip $tip
											if ($null -eq $tipObj) { $tipObj = [string]$tip }
											$hdrHost.ToolTip = $tipObj
											$mi.ToolTip = $tipObj
											try {
												[System.Windows.Controls.ToolTipService]::SetInitialShowDelay($hdrHost, 350)
												[System.Windows.Controls.ToolTipService]::SetShowDuration($hdrHost, 25000)
												[System.Windows.Controls.ToolTipService]::SetInitialShowDelay($mi, 350)
												[System.Windows.Controls.ToolTipService]::SetShowDuration($mi, 25000)
											} catch {}
										} catch {
											try { $hdrHost.ToolTip = [string]$tip; $mi.ToolTip = [string]$tip } catch {}
										}
									}
									$mi.Header = $hdrHost
									try {
										$mi.add_PreviewMouseLeftButtonDown({
											param($s, $e)
											try { if ($null -ne $e) { $e.Handled = $true } } catch {}
										})
									} catch {}
									try {
										$mi.add_Click({
											param($s, $e)
											try { if ($null -ne $e) { $e.Handled = $true } } catch {}
										})
									} catch {}
									return $mi
								}.GetNewClosure()
								if ($tools.Count -eq 0) {
									[void]$cm.Items.Add((& $addToolItem '(no tools)' $itemFg $menuBg 'No tools listed for this group.' $false))
								} else {
									foreach ($tn in $tools) {
										$tName = [string]$tn
										$tTip = ''
										try {
											if ($toolTipsMap -is [hashtable] -and $toolTipsMap.ContainsKey($tName)) {
												$tTip = [string]$toolTipsMap[$tName]
											} elseif ($toolTipsMap.Contains($tName)) {
												$tTip = [string]$toolTipsMap[$tName]
											}
										} catch { $tTip = '' }
										if ([string]::IsNullOrWhiteSpace($tTip)) { $tTip = $tName }
										$noVision = $false
										try {
											if ($visionBlockedMap -is [hashtable]) {
												if ($visionBlockedMap.ContainsKey($tName)) { $noVision = $true }
												elseif ($visionBlockedMap.Contains($tName)) { $noVision = $true }
												else {
													foreach ($vk in @($visionBlockedMap.Keys)) {
														if ([string]::Equals([string]$vk, $tName, [StringComparison]::OrdinalIgnoreCase)) {
															$noVision = $true
															break
														}
													}
												}
											}
										} catch { $noVision = $false }
										if ($noVision) {
											if ($tTip -notmatch '(?i)does not support vision|no ''vision'' in Abilities') {
												$tTip = ("{0}`n`nUnavailable: current model does not support vision (no 'vision' in Abilities)." -f $tTip.TrimEnd())
											}
										}
										$wasUsed = $false
										try {
											if ($usedSet.ContainsKey($tName)) { $wasUsed = $true }
											elseif ($usedSet.ContainsKey($tName.ToLowerInvariant())) { $wasUsed = $true }
											else {
												foreach ($uk in @($usedSet.Keys)) {
													if ([string]::Equals([string]$uk, $tName, [StringComparison]::OrdinalIgnoreCase)) {
														$wasUsed = $true
														break
													}
												}
											}
										} catch { $wasUsed = $false }
										if ($wasUsed -and -not $noVision -and $tTip -notmatch '(?i)used this session') {
											$tTip = ("{0}`n`nUsed this session." -f $tTip.TrimEnd())
										}
										$toolFg = $itemFg
										if ($noVision -and $orangeB) { $toolFg = $orangeB }
										# Vision-blocked: orange, never "used" highlight
										[void]$cm.Items.Add((& $addToolItem $tName $toolFg $menuBg $tTip $(if ($noVision) { $false } else { $wasUsed })))
									}
								}
								if ([string]$g -eq 'installers' -and $installerPkgs.Count -gt 0) {
									# Custom dark divider (default Separator is too light on dark theme)
									try {
										$divMi = New-Object System.Windows.Controls.MenuItem
										$divMi.IsEnabled = $true
										$divMi.IsHitTestVisible = $false
										$divMi.Focusable = $false
										$divMi.Background = $menuBg
										$lineBd = New-Object System.Windows.Controls.Border
										$lineBd.Height = 1
										$lineBd.Background = $sepB
										$lineBd.Margin = New-Object System.Windows.Thickness(4, 0, 4, 0)
										$lineBd.HorizontalAlignment = [System.Windows.HorizontalAlignment]::Stretch
										$lineBd.SnapsToDevicePixels = $true
										$divMi.Header = $lineBd
										try {
											$divTplXaml = @'
<ControlTemplate xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" TargetType="MenuItem">
  <Border Background="{TemplateBinding Background}" Padding="6,6,6,6" SnapsToDevicePixels="True">
    <ContentPresenter ContentSource="Header" HorizontalAlignment="Stretch" VerticalAlignment="Center"/>
  </Border>
</ControlTemplate>
'@
											$divTpl = [Windows.Markup.XamlReader]::Parse($divTplXaml)
											if ($null -ne $divTpl) { $divMi.Template = $divTpl }
										} catch {}
										[void]$cm.Items.Add($divMi)
									} catch {}
									foreach ($pkg in $installerPkgs) {
										if ($null -eq $pkg) { continue }
										$pid = ''
										$pnm = ''
										$pnote = ''
										try { $pid = [string]$pkg.id } catch {}
										try { $pnm = [string]$pkg.name } catch {}
										try { $pnote = [string]$pkg.note } catch {}
										if ([string]::IsNullOrWhiteSpace($pnm)) { $pnm = $pid }
										if ([string]::IsNullOrWhiteSpace($pnm)) { continue }
										$pkgTip = ("{0}`nSilent installer package." -f $pnm)
										if (-not [string]::IsNullOrWhiteSpace($pid) -and $pid -ne $pnm) {
											$pkgTip = ("{0}`nId: {1}`nSilent installer package." -f $pnm, $pid)
										}
										if (-not [string]::IsNullOrWhiteSpace($pnote)) {
											$pkgTip = ("{0}`n{1}" -f $pkgTip, $pnote.Trim())
										}
										[void]$cm.Items.Add((& $addToolItem $pnm $itemFg $menuBg $pkgTip))
									}
								}
								try {
									$cm.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Bottom
									$cm.PlacementTarget = $border
									$cm.HorizontalOffset = 0
									$cm.VerticalOffset = 2
								} catch {}
								$border.ContextMenu = $cm
								# Explicit open/closed flag (WPF closes menu before click handlers)
								$chipState = [pscustomobject]@{ Group = [string]$g; Open = $false }
								$border.Tag = $chipState
								$null = $cm.Add_Closed({
									try { $chipState.Open = $false } catch {}
									try {
										# Skip reopen on the same click that dismissed the menu
										$W.ToolMenuToggleSkipChip = $border
										$W.ToolMenuToggleSkipTick = [Environment]::TickCount
									} catch {}
								}.GetNewClosure())
								$null = $border.Add_PreviewMouseLeftButtonDown({
									param($sender, $e)
									try {
										if (-not $sender -or -not $sender.ContextMenu) { return }
										$m = $sender.ContextMenu
										$st = $null
										try { $st = $sender.Tag } catch { $st = $null }

										# Same click that closed the menu: stay closed
										try {
											$skipChip = $null
											$skipTick = 0
											try { $skipChip = $W.ToolMenuToggleSkipChip } catch {}
											try { $skipTick = [int]$W.ToolMenuToggleSkipTick } catch {}
											if ($skipChip -eq $sender -and $skipTick -ne 0) {
												$dt = ([Environment]::TickCount - $skipTick) -band 0x7fffffff
												if ($dt -lt 400) {
													$W.ToolMenuToggleSkipChip = $null
													$W.ToolMenuToggleSkipTick = 0
													if ($st) { $st.Open = $false }
													$m.IsOpen = $false
													$e.Handled = $true
													return
												}
											}
										} catch {}

										# Switch: open <-> closed
										$nowOpen = $false
										try { if ($st -and [bool]$st.Open) { $nowOpen = $true } } catch {}
										try { if ([bool]$m.IsOpen) { $nowOpen = $true } } catch {}

										if ($nowOpen) {
											if ($st) { $st.Open = $false }
											$m.IsOpen = $false
											$e.Handled = $true
											return
										}

										# Close other group menus
										try {
											$parent = $sender.Parent
											if ($parent -and $parent.Children) {
												foreach ($sib in @($parent.Children)) {
													try {
														if ($sib -eq $sender) { continue }
														if ($sib.ContextMenu -and [bool]$sib.ContextMenu.IsOpen) {
															$sib.ContextMenu.IsOpen = $false
														}
														$sst = $sib.Tag
														if ($sst -and ($sst -is [pscustomobject])) {
															try { $sst.Open = $false } catch {}
														}
													} catch {}
												}
											}
										} catch {}

										$m.PlacementTarget = $sender
										$m.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Bottom
										$m.HorizontalOffset = 0
										$m.VerticalOffset = 2
										if ($st) { $st.Open = $true }
										$m.IsOpen = $true
										try {
											$W.ToolMenuToggleSkipChip = $null
											$W.ToolMenuToggleSkipTick = 0
										} catch {}
										$e.Handled = $true
									} catch {}
								}.GetNewClosure())
								[void]$panel.Children.Add($border)
							}
							try {
								$W.ToolGroupsFp = $fpIn
								$W.ToolGroupsBuilt = $true
							} catch {}
						}
					} catch {}
					if ($null -ne $W.PendingPromptEnabled) {
						$en = [bool]$W.PendingPromptEnabled
						$W.PendingPromptEnabled = $null
						$wantFocus = $false
						try {
							$wantFocus = [bool]$W.PendingPromptFocus
							$W.PendingPromptFocus = $false
						} catch { $wantFocus = $false }
						$authUp = $false
						try {
							if ([bool]$W.AuthActive) { $authUp = $true }
							elseif ($W.AuthOverlay -and $W.AuthOverlay.Visibility -eq [System.Windows.Visibility]::Visible) {
								$authUp = $true
							}
							elseif ($W.ConfirmOverlay -and $W.ConfirmOverlay.Visibility -eq [System.Windows.Visibility]::Visible) {
								$authUp = $true
							}
						} catch {}
						if ($authUp) {
							if ($en) {
								$W.PendingPromptEnabled = $true
								if ($wantFocus) { $W.PendingPromptFocus = $true }
							}
							$W.PromptArmed = $false
							if ($W.Prompt) {
								$W.Prompt.IsEnabled = $true
								$W.Prompt.Focusable = $true
								$W.Prompt.IsReadOnly = $true
							}
							try { if ($W.SyncSendBtn) { & $W.SyncSendBtn $false } } catch {}
						} else {
							$W.PromptArmed = $en
							if ($W.Prompt) {
								$W.Prompt.IsEnabled = $true
								$W.Prompt.Focusable = $true
								$W.Prompt.IsReadOnly = -not $en
							}
							try { if ($W.SyncSendBtn) { & $W.SyncSendBtn $en } } catch {}
							if ($en -and $wantFocus -and $W.Prompt) {
								$modal = $false
								try { $modal = [bool]$W.ModalUi } catch { $modal = $false }
								if (-not $modal) {
									try {
										if ($W.Window) { [void]$W.Window.Activate() }
									} catch {}
									try { [void]$W.Prompt.Focus() } catch {}
									try { [void][System.Windows.Input.Keyboard]::Focus($W.Prompt) } catch {}
									try {
										if ($null -ne $W.Prompt.Text) { $W.Prompt.CaretIndex = $W.Prompt.Text.Length }
									} catch {}
								} else {
									try { $W.PendingPromptFocus = $true } catch {}
								}
							}
						}
					}
					# status spinner + elapsed timer
					if ($W.StatusDot) {
						$mode = [string]$W.StatusMode
						if ([string]::IsNullOrWhiteSpace($mode)) { $mode = 'ready' }
						$label = [string]$W.StatusLabel
						if ([string]::IsNullOrWhiteSpace($label)) {
							$label = switch ($mode) {
								'thinking'    { 'thinking...' }
								'working'     { 'working...' }
								'compacting'  { 'auto-compacting...' }
								'error'       { 'error' }
								default       { 'ready' }
							}
						} else {
							if ($mode -eq 'thinking' -and $label -notmatch '\.\.\.$') { $label = 'thinking...' }
							elseif ($mode -eq 'working' -and $label -notmatch '\.\.\.$') { $label = 'working...' }
							elseif ($mode -eq 'compacting' -and $label -notmatch '\.\.\.$') { $label = 'auto-compacting...' }
							elseif ($mode -eq 'error') { $label = 'error' }
						}
						# Sync titlebar robot with status
						try {
							if ($W.SetRobotMood) { & $W.SetRobotMood $mode $false }
						} catch {}
						$busy = ($mode -eq 'thinking' -or $mode -eq 'working' -or $mode -eq 'compacting')
						$now = [Environment]::TickCount
						# Status band layout by mode
						$labelMinW = 0.0
						$timerW = 0.0
						$dotRight = 0.0
						$bandRight = 10.0
						if ($mode -eq 'thinking' -or $mode -eq 'working') {
							$labelMinW = 98.0    # thinking/working label width
							$timerW = 32.0       # "0.0s"..."9999s"
							$dotRight = 0.0      # no gap between label and timer
							$bandRight = 5.0     # +3px after counter before ctx
						} elseif ($mode -eq 'compacting') {
							$labelMinW = 0.0
							$timerW = 32.0
							$dotRight = 0.0
							$bandRight = 5.0     # same +3px after counter
						} else {
							$labelMinW = 0.0
							$timerW = 0.0
							$dotRight = 0.0
							$bandRight = 14.0    # ready: slight offset before ctx
						}
						try {
							if ($W.StatusDot) {
								$W.StatusDot.MinWidth = $labelMinW
								$W.StatusDot.ClearValue([System.Windows.FrameworkElement]::WidthProperty)
								$W.StatusDot.Margin = New-Object System.Windows.Thickness(0, 0, $dotRight, 0)
							}
						} catch {}
						try {
							if ($W.StatusBand) {
								$W.StatusBand.Margin = New-Object System.Windows.Thickness(0, 0, $bandRight, 0)
							}
						} catch {}
						try {
							if ($W.StatusTimer) {
								if ($timerW -gt 0) {
									$W.StatusTimer.Width = $timerW
									$W.StatusTimer.MinWidth = $timerW
									$W.StatusTimer.Margin = New-Object System.Windows.Thickness(0)
									$W.StatusTimer.Visibility = [System.Windows.Visibility]::Visible
								} else {
									$W.StatusTimer.Width = 0
									$W.StatusTimer.MinWidth = 0
									$W.StatusTimer.Text = ''
									$W.StatusTimer.Visibility = [System.Windows.Visibility]::Collapsed
								}
							}
						} catch {}
						if ($busy) {
							$since = 0
							try { $since = [int]$W.StatusBusySince } catch { $since = 0 }
							if ($since -eq 0) {
								$W.StatusBusySince = $now
								$since = $now
							}
							$last = 0
							try { $last = [int]$W.SpinLastTick } catch { $last = 0 }
							if (($now - $last) -ge 80 -or $last -eq 0) {
								$W.SpinLastTick = $now
								$idx = 0
								try { $idx = [int]$W.SpinIdx } catch { $idx = 0 }
								$W.SpinIdx = ($idx + 1) % $brailleFrames.Count
							}
							$fi = 0
							try { $fi = [int]$W.SpinIdx } catch { $fi = 0 }
							if ($fi -lt 0 -or $fi -ge $brailleFrames.Count) { $fi = 0 }
							$spin = [string]$brailleFrames[$fi]
							$W.StatusDot.Text = "$spin $label"
							try {
								$elapsedMs = ($now - $since) -band 0x7fffffff
								if ($elapsedMs -lt 0) { $elapsedMs = 0 }
								$secs = $elapsedMs / 1000.0
								$timerText = ''
								if ($secs -lt 10.0) {
									$timerText = ('{0:0.0}s' -f $secs)
								} else {
									$timerText = (([int][Math]::Floor($secs)).ToString() + 's')
								}
								if ($W.StatusTimer) {
									$W.StatusTimer.Text = $timerText
									$busyHexT = if ($mode -eq 'compacting') { '#E0AF68' } else { '#7DCFFF' }
									$bcT = $null
									try { $bcT = $W['BrushCache'] } catch { try { $bcT = $W.BrushCache } catch {} }
									if ($null -eq $bcT) { $bcT = @{}; try { $W['BrushCache'] = $bcT } catch {} }
									if (-not $bcT.ContainsKey($busyHexT)) {
										$bcT[$busyHexT] = $conv.ConvertFromString($busyHexT)
									}
									$W.StatusTimer.Foreground = $bcT[$busyHexT]
								}
							} catch {}
							try {
								$busyHex = if ($mode -eq 'compacting') { '#E0AF68' } else { '#7DCFFF' }
								$bcSpin = $null
								try { $bcSpin = $W['BrushCache'] } catch { try { $bcSpin = $W.BrushCache } catch {} }
								if ($null -eq $bcSpin) { $bcSpin = @{}; try { $W['BrushCache'] = $bcSpin } catch {} }
								if (-not $bcSpin.ContainsKey($busyHex)) {
									$bcSpin[$busyHex] = $conv.ConvertFromString($busyHex)
								}
								$W.StatusDot.Foreground = $bcSpin[$busyHex]
							} catch {}
							# Flash AutoCompact label while compacting
							try {
								if ($W.AcLabel) {
									$flash = ($mode -eq 'compacting')
									$hx = if ($flash) {
										if ($W.AcLabelFlashHex) { [string]$W.AcLabelFlashHex } else { '#E0AF68' }
									} else {
										if ($W.AcLabelGrayHex) { [string]$W.AcLabelGrayHex } else { '#8A8A96' }
									}
									$bcSpin = $null
									try { $bcSpin = $W['BrushCache'] } catch { try { $bcSpin = $W.BrushCache } catch {} }
									if ($null -eq $bcSpin) { $bcSpin = @{}; try { $W['BrushCache'] = $bcSpin } catch {} }
									if (-not $bcSpin.ContainsKey($hx)) {
										$bcSpin[$hx] = $conv.ConvertFromString($hx)
									}
									$W.AcLabel.Foreground = $bcSpin[$hx]
									if ($flash) {
										try { $W.AcLabel.FontWeight = [System.Windows.FontWeights]::SemiBold } catch {}
									} else {
										try { $W.AcLabel.FontWeight = [System.Windows.FontWeights]::Normal } catch {}
									}
								}
							} catch {}
						} else {
							$W.SpinIdx = 0
							$W.StatusBusySince = 0
							$W.StatusDot.Text = ([string][char]0x00B7) + ' ready'
							if ($W.StatusTimer) {
								$W.StatusTimer.Text = ''
							}
							try {
								$okHex = '#9ECE6A'
								$bcSpin = $null
								try { $bcSpin = $W['BrushCache'] } catch { try { $bcSpin = $W.BrushCache } catch {} }
								if ($null -eq $bcSpin) { $bcSpin = @{}; try { $W['BrushCache'] = $bcSpin } catch {} }
								if (-not $bcSpin.ContainsKey($okHex)) {
									$bcSpin[$okHex] = $conv.ConvertFromString($okHex)
								}
								$W.StatusDot.Foreground = $bcSpin[$okHex]
							} catch {}
							# Restore AutoCompact label color
							try {
								if ($W.AcLabel) {
									$hx = if ($W.AcLabelGrayHex) { [string]$W.AcLabelGrayHex } else { '#8A8A96' }
									$bcSpin = $null
									try { $bcSpin = $W['BrushCache'] } catch { try { $bcSpin = $W.BrushCache } catch {} }
									if ($null -eq $bcSpin) { $bcSpin = @{}; try { $W['BrushCache'] = $bcSpin } catch {} }
									if (-not $bcSpin.ContainsKey($hx)) {
										$bcSpin[$hx] = $conv.ConvertFromString($hx)
									}
									$W.AcLabel.Foreground = $bcSpin[$hx]
									try { $W.AcLabel.FontWeight = [System.Windows.FontWeights]::Normal } catch {}
								}
							} catch {}
						}
					}
				} catch {
					try {
						$msg = [string]$_.Exception.Message
						if ($W -is [hashtable]) {
							$W['LastPaintError'] = $msg
						} else {
							$W.LastPaintError = $msg
						}
					} catch {}
				}
			}.GetNewClosure())
			$timer.Start()
			$W.PumpTimer = $timer

			# Prompt stays focusable; submit gated by PromptArmed
			if ($W.Prompt) {
				$W.Prompt.IsEnabled = $true
				$W.Prompt.IsReadOnly = $true
				$W.Prompt.Focusable = $true
			}

			# Send/Stop button chrome
			# Send/Stop hover colors
			$W.SendBtnHovering = $false
			$setSendBtnIconGrad = {
				param([string[]]$Cols)
				try {
					$stops = @($W.SendBtnGrad0, $W.SendBtnGrad1, $W.SendBtnGrad2)
					for ($i = 0; $i -lt 3; $i++) {
						if (-not $stops[$i]) { continue }
						$hex = [string]$Cols[$i]
						if ([string]::IsNullOrWhiteSpace($hex)) { continue }
						if (-not $hex.StartsWith('#')) { $hex = '#' + $hex }
						try {
							$stops[$i].Color = [System.Windows.Media.ColorConverter]::ConvertFromString($hex)
						} catch {}
					}
				} catch {}
			}.GetNewClosure()
			$W.SetSendBtnIconGrad = $setSendBtnIconGrad
			$applySendBtnLook = {
				param([bool]$forceBase)
				try {
					$btn = $W.SendBtn
					if (-not $btn) { return }
					$bc = New-Object System.Windows.Media.BrushConverter
					$hover = $false
					if (-not $forceBase) {
						try { $hover = [bool]$W.SendBtnHovering } catch { $hover = $false }
					}
					$mode = 'stop'
					try { $mode = [string]$W.SendMode } catch {}
					if ($hover -and $btn.IsEnabled) {
						if ($mode -eq 'send') {
							$btn.Background = $bc.ConvertFromString('#32323A')
							$btn.BorderBrush = $bc.ConvertFromString('#4A4A56')
							$btn.Foreground = $bc.ConvertFromString('#C8C8D0')
							if ($W.SetSendBtnIconGrad) {
								& $W.SetSendBtnIconGrad @('#D0D0D8', '#9A9AA6', '#6A6A76')
							}
						} else {
							$btn.Background = $bc.ConvertFromString('#3A2222')
							$btn.BorderBrush = $bc.ConvertFromString('#6B3838')
							$btn.Foreground = $bc.ConvertFromString('#A85858')
							if ($W.SetSendBtnIconGrad) {
								& $W.SetSendBtnIconGrad @('#B86868', '#8B4040', '#5A2828')
							}
						}
					} else {
						$bg = [string]$W.SendBtnBaseBg
						$bd = [string]$W.SendBtnBaseBorder
						$fg = [string]$W.SendBtnBaseFg
						if ([string]::IsNullOrWhiteSpace($bg)) { $bg = '#2A2A30' }
						if ([string]::IsNullOrWhiteSpace($bd)) { $bd = '#3A3A42' }
						if ([string]::IsNullOrWhiteSpace($fg)) { $fg = '#8A8A96' }
						$btn.Background = $bc.ConvertFromString($bg)
						$btn.BorderBrush = $bc.ConvertFromString($bd)
						$btn.Foreground = $bc.ConvertFromString($fg)
						if ($mode -eq 'send') {
							if ($W.SetSendBtnIconGrad) {
								& $W.SetSendBtnIconGrad @('#C0C0C8', '#8A8A96', '#5A5A66')
							}
						} else {
							if ($W.SetSendBtnIconGrad) {
								& $W.SetSendBtnIconGrad @('#A05050', '#7A3535', '#4A2020')
							}
						}
					}
				} catch {}
			}.GetNewClosure()
			$W.ApplySendBtnLook = $applySendBtnLook
			$syncSendBtn = {
				param([bool]$armed)
				try {
					$btn = $W.SendBtn
					if (-not $btn) { return }
					if ($armed) {
						$W.SendMode = 'send'
						if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $btn 'Send' 140 }
						else { $btn.ToolTip = 'Send' }
						$btn.IsEnabled = $true
						$W.SendBtnBaseBg = '#2A2A30'
						$W.SendBtnBaseFg = '#C8C8D0'
						$W.SendBtnBaseBorder = '#3A3A42'
						try {
							if ($W.SendBtnPath -and $W.SendGeomData) {
								$W.SendBtnPath.Data = [System.Windows.Media.Geometry]::Parse([string]$W.SendGeomData)
							}
						} catch {}
					} else {
						$W.SendMode = 'stop'
						if ($W.SetThemedToolTip) { & $W.SetThemedToolTip $btn 'Stop' 140 }
						else { $btn.ToolTip = 'Stop' }
						$btn.IsEnabled = $true
						$W.SendBtnBaseBg = '#2A1A1A'
						$W.SendBtnBaseFg = '#8B4040'
						$W.SendBtnBaseBorder = '#5A2E2E'
						try {
							if ($W.SendBtnPath -and $W.StopGeomData) {
								$W.SendBtnPath.Data = [System.Windows.Media.Geometry]::Parse([string]$W.StopGeomData)
							}
						} catch {}
					}
					& $applySendBtnLook $false
				} catch {}
			}.GetNewClosure()
			$W.SyncSendBtn = $syncSendBtn
			try { & $syncSendBtn $false } catch {}

			$submitPrompt = {
				try {
					if (-not $W.PromptArmed -or -not $W.Prompt -or $W.Prompt.IsReadOnly) { return $false }
					$text = [string]$W.Prompt.Text
					$W.Prompt.Clear()
					if (-not [string]::IsNullOrWhiteSpace($text)) {
						try {
							[void]$W.History.Add($text)
							while ($W.History.Count -gt 80) { $W.History.RemoveAt(0) }
						} catch {}
					}
					$W.HistIndex = -1
					$W.InputResult = $text
					[void]$W.InputWait.Set()
					try { & $syncSendBtn $false } catch {}
					$W.PromptArmed = $false
					try { $W.Prompt.IsReadOnly = $true } catch {}
					return $true
				} catch { return $false }
			}.GetNewClosure()

			$interruptWork = {
				try {
					$W.InterruptFlag = $true
					if ($W.PromptArmed -and $W.Prompt -and -not $W.Prompt.IsReadOnly) {
						try { $W.Prompt.Clear() } catch {}
					}
				} catch {}
			}.GetNewClosure()

			if ($W.SendBtn) {
				$W.SendBtn.add_MouseEnter({
					try {
						$W.SendBtnHovering = $true
						if ($W.ApplySendBtnLook) { & $W.ApplySendBtnLook $false }
					} catch {}
				}.GetNewClosure())
				$W.SendBtn.add_MouseLeave({
					try {
						$W.SendBtnHovering = $false
						if ($W.ApplySendBtnLook) { & $W.ApplySendBtnLook $true }
					} catch {}
				}.GetNewClosure())
				$W.SendBtn.add_Click({
					param($s, $e)
					try {
						if ([string]$W.SendMode -eq 'stop' -or -not [bool]$W.PromptArmed) {
							& $interruptWork
						} else {
							[void](& $submitPrompt)
						}
					} catch {}
				}.GetNewClosure())
			}

			# UI-thread debug lines (same gate as -DebugLog / debug=1)
			$uiLog = {
				param($step, $detail)
				$on = $false
				try { $on = [bool]$W.DebugLogEnabled } catch { $on = $false }
				if (-not $on) { return }
				try {
					$p = [string]$W.DebugLogPath
					if (-not $p) { $p = Join-Path $env:USERPROFILE 'Desktop\MiniBot-debug.log' }
					$ts = Get-Date -Format 'yyyy-MM-dd HH:mm:ss.fff'
					$tid = [System.Threading.Thread]::CurrentThread.ManagedThreadId
					$line = "[{0}] UI tid={1} | {2}" -f $ts, $tid, $step
					if ($detail) {
						$d2 = ([string]$detail -replace '[\r\n]+', ' ')
						if ($d2.Length -gt 400) { $d2 = $d2.Substring(0, 397) + '...' }
						$line += ' :: ' + $d2
					}
					$line += [Environment]::NewLine
					[System.IO.File]::AppendAllText($p, $line)
				} catch {}
			}.GetNewClosure()

			$W.Prompt.add_PreviewKeyDown({
				param($sender, $e)
				try {
					if ($e.Key -eq 'Return') {
						$e.Handled = $true
						if (-not $W.PromptArmed -or $sender.IsReadOnly) {
							try { & $uiLog 'ENTER_IGNORED' ("armed={0} readOnly={1}" -f $W.PromptArmed, $sender.IsReadOnly) } catch {}
							return
						}
						$mods = [System.Windows.Input.Keyboard]::Modifiers
						$ctrl = ($mods -band [System.Windows.Input.ModifierKeys]::Control) -ne 0
						$shift = ($mods -band [System.Windows.Input.ModifierKeys]::Shift) -ne 0
						if ($ctrl -or $shift) {
							$caret = $sender.CaretIndex
							$sender.Text = $sender.Text.Insert($caret, "`r`n")
							$sender.CaretIndex = $caret + 2
							try { & $uiLog 'ENTER_NEWLINE' '' } catch {}
							return
						}
						try { & $uiLog 'ENTER_PRESSED' ("len={0}" -f ([string]$sender.Text).Length) } catch {}
						[void](& $submitPrompt)
						try { & $uiLog 'ENTER_SIGNALED' 'InputWait.Set() done' } catch {}
						return
					}
					if ($sender.IsReadOnly) {
						if ($e.Key -ne 'Escape') { $e.Handled = $true }
					}
					if ($e.Key -eq 'Up') {
						if (-not $W.PromptArmed -or $sender.IsReadOnly) { return }
						if ($W.History.Count -eq 0) { return }
						$e.Handled = $true
						if ($W.HistIndex -lt 0) { $W.HistIndex = $W.History.Count - 1 }
						elseif ($W.HistIndex -gt 0) { $W.HistIndex-- }
						$sender.Text = [string]$W.History[$W.HistIndex]
						$sender.CaretIndex = $sender.Text.Length
						return
					}
					if ($e.Key -eq 'Down') {
						if (-not $W.PromptArmed -or $sender.IsReadOnly) { return }
						if ($W.HistIndex -lt 0) { return }
						$e.Handled = $true
						if ($W.HistIndex -lt ($W.History.Count - 1)) {
							$W.HistIndex++
							$sender.Text = [string]$W.History[$W.HistIndex]
						} else {
							$W.HistIndex = -1
							$sender.Clear()
						}
						$sender.CaretIndex = $sender.Text.Length
						return
					}
					if ($e.Key -eq 'Escape') {
						$e.Handled = $true
						& $interruptWork
					}
				} catch {
					try { & $uiLog 'ENTER_HANDLER_ERROR' $_.Exception.Message } catch {}
					try {
						[System.Windows.MessageBox]::Show(
							$_.Exception.Message,
							'MiniBot input error',
							[System.Windows.MessageBoxButton]::OK,
							[System.Windows.MessageBoxImage]::Error
						) | Out-Null
					} catch {}
				}
			}.GetNewClosure())

			$window.add_Closing({
				param($s, $ev)
				try { & $uiLog 'WINDOW_CLOSING' ("soft={0}" -f $W.SoftClose) } catch {}
				$W.ExitRequested = $true
				$W.InterruptFlag = $true
				# Hard-exit; release single-instance lock
				$W.CloseKind = 'user_x'
				$W.ForceProcessExit = $true
				$W.SoftClose = $false
				try { [void]$W.InputWait.Set() } catch {}
				try { [void]$W.CredWait.Set() } catch {}
				try { [void]$W.ConfirmWait.Set() } catch {}
				try {
					$W.Dispatcher.BeginInvokeShutdown([System.Windows.Threading.DispatcherPriority]::Normal)
				} catch {}
			}.GetNewClosure())

			$W.Ready = $true
			[void]$W.ReadyWait.Set()
			try { & $uiLog 'WPF_WINDOW_SHOWN' $window.Title } catch {}
			try {
				$window.Topmost = $true
				$W.BootstrapTopmost = $true
			} catch {}
			[void]$window.Show()
			try {
				[void]$window.Activate()
				try { [void]$window.Focus() } catch {}
			} catch {}
			try {
				$safety = New-Object System.Windows.Threading.DispatcherTimer
				$safety.Interval = [TimeSpan]::FromSeconds(6)
				$safety.Tag = $window
				$safety.Add_Tick({
					param($s, $e)
					try { $s.Stop() } catch {}
					try {
						$W.BootstrapTopmost = $false
						$win = $s.Tag
						if ($win) {
							$win.Topmost = $false
							$win.Topmost = $true
							$win.Topmost = $false
						}
					} catch {}
				}.GetNewClosure())
				$safety.Start()
			} catch {}
			[System.Windows.Threading.Dispatcher]::Run()
			try { & $uiLog 'WPF_DISPATCHER_EXIT' '' } catch {}
		} catch {
			$W.Failed = $true
			$W.FailMsg = $_.Exception.Message
			$W.Ready = $false
			try {
				$p = [string]$W.DebugLogPath
				if ($p) {
					[System.IO.File]::AppendAllText($p, ("[{0}] WPF_HOST_FAIL :: {1}`r`n" -f (Get-Date -Format o), $_.Exception.Message))
				}
			} catch {}
			try { [void]$W.ReadyWait.Set() } catch {}
		}
	}).AddArgument($wpf)

	[void]$ps.BeginInvoke()
	[void]$wpf.ReadyWait.WaitOne(15000)

	if ($wpf.Failed -or -not $wpf.Ready) {
		$msg = if ($wpf.FailMsg) { $wpf.FailMsg } else { 'timeout starting WPF host' }
		try { $script:MB.LastWpfFailMsg = [string]$msg } catch {}
		Write-Warning "WPF host failed: $msg"
		try { Write-MBDebugLog -Step 'WPF_HOST_FAIL' -Detail $msg } catch {}
		$script:MB.HostUi = 'wpf'
		# shut down STA host
		try {
			if ($wpf) {
				$wpf.ExitRequested = $true
				$wpf.ForceProcessExit = $true
				try { [void]$wpf.InputWait.Set() } catch {}
				try { [void]$wpf.CredWait.Set() } catch {}
				try { [void]$wpf.ConfirmWait.Set() } catch {}
				try { [void]$wpf.ReadyWait.Set() } catch {}
				try {
					if ($wpf.Dispatcher) {
						$wpf.Dispatcher.BeginInvokeShutdown([System.Windows.Threading.DispatcherPriority]::Normal)
					}
				} catch {}
			}
		} catch {}
		try { $ps.Stop() } catch {}
		try { $ps.Dispose() } catch {}
		try { $rs.Close(); $rs.Dispose() } catch {}
		try { $script:MB.Wpf = $null } catch {}
		return $false
	}

	Hide-MBNativeConsole
	$script:MB.HostUi = 'wpf'
	try { Ensure-MBConNative } catch {}
	try { Invoke-MBWpfBringToFront -StayTopmost } catch {}
	return $true
}

function Stop-MBWpfHost {
	param(
		[switch]$Soft
	)
	Write-MBDebugLog -Step 'WPF_STOP_BEGIN'
	# Ensure sandbox/RunCommand trees die with the host
	try { Stop-MBTrackedChildProcesses } catch {}
	if (-not $script:MB.Wpf) { return }
	try {
		# hard-exit; release single-instance lock
		$script:MB.Wpf.SoftClose = $false
		$script:MB.Wpf.CloseKind = 'user_x'
		$script:MB.Wpf.ForceProcessExit = $true
		$script:MB.Wpf.ExitRequested = $true
		try { $script:MB.Wpf.InterruptFlag = $true } catch {}
		try { [void]$script:MB.Wpf.InputWait.Set() } catch {}
		try { [void]$script:MB.Wpf.CredWait.Set() } catch {}
		try { [void]$script:MB.Wpf.ConfirmWait.Set() } catch {}
		Invoke-MBWpf -Action {
			if ($script:MB.Wpf.Window) { $script:MB.Wpf.Window.Close() }
		}
	} catch {
		Write-MBDebugLog -Step 'WPF_STOP_CLOSE_ERR' -Detail $_.Exception.Message
	}
	try {
		if ($script:MB.Wpf.Ps) { $script:MB.Wpf.Ps.Dispose() }
		if ($script:MB.Wpf.Runspace) { $script:MB.Wpf.Runspace.Close(); $script:MB.Wpf.Runspace.Dispose() }
	} catch {}
	$script:MB.Wpf.Ready = $false
	Write-MBDebugLog -Step 'WPF_STOP_DONE'
}

function Write-Host {
	[CmdletBinding(DefaultParameterSetName = 'object')]
	param(
		[Parameter(Position = 0, ValueFromPipeline = $true)]
		[AllowNull()]
		[object]$Object,
		[switch]$NoNewline,
		[ConsoleColor]$ForegroundColor,
		[ConsoleColor]$BackgroundColor,
		[object]$Separator
	)
	begin { $buf = New-Object System.Collections.ArrayList }
	process {
		try {
			if ($null -ne $Object) { [void]$buf.Add($Object) }
		} catch {}
	}
	end {
		try {
			$text = if ($buf.Count -gt 0) {
				if ($PSBoundParameters.ContainsKey('Separator') -and $null -ne $Separator) {
					($buf | ForEach-Object { "$_" }) -join [string]$Separator
				} else {
					($buf | ForEach-Object { "$_" }) -join ' '
				}
			} else { '' }

			if (Test-MBWpfActive) {
				$c = if ($PSBoundParameters.ContainsKey('ForegroundColor')) { $ForegroundColor } else { [ConsoleColor]::Gray }
				Write-MBWpfRaw -Text $text -Color $c -NoNewline:$NoNewline
				return
			}
			$splat = @{}
			if ($PSBoundParameters.ContainsKey('Object') -or $buf.Count -gt 0) { $splat['Object'] = $text }
			if ($NoNewline) { $splat['NoNewline'] = $true }
			if ($PSBoundParameters.ContainsKey('ForegroundColor')) { $splat['ForegroundColor'] = $ForegroundColor }
			if ($PSBoundParameters.ContainsKey('BackgroundColor')) { $splat['BackgroundColor'] = $BackgroundColor }
			Microsoft.PowerShell.Utility\Write-Host @splat
		} catch {
			try { Microsoft.PowerShell.Utility\Write-Host "[log error] $($_.Exception.Message)" -ForegroundColor Red } catch {}
		}
	}
}

function Start-LocalAgent {
	Write-MBDebugLog -Step 'AGENT_START'
	$resolvedHost = Resolve-MBHostUi
	Write-MBDebugLog -Step 'AGENT_HOST_RESOLVED' -Detail $resolvedHost
	$script:MB.PreferWpfLogin = $true

	Write-MBDebugLog -Step 'AGENT_AUTH_BEGIN'
	$auth = Connect-MBModelEndpoint -TimeoutSeconds 8
	$connTest = $auth.ConnTest
	Write-MBDebugLog -Step 'AGENT_AUTH_DONE' -Detail ("ok={0} exit={1}" -f $auth.Success, $auth.Exit)
	if ($auth.Success) {
		try {
			$null = Refresh-MBRemoteModels -Force
			Write-MBDebugLog -Step 'AGENT_MODELS' -Detail ("count={0} active={1}" -f @($script:MB.RemoteModels).Count, (Get-MBActiveModel))
		} catch {}
	}

	if ($auth.Exit -or -not $auth.Success) {
		$msg = $null
		if ($auth.Message) { $msg = [string]$auth.Message }
		elseif ($connTest -and $connTest.Message) { $msg = [string]$connTest.Message }
		else { $msg = 'Unable to connect.' }

		if ($msg -match '(?i)login UI|requires WPF') {
			try {
				Add-Type -AssemblyName PresentationFramework -ErrorAction SilentlyContinue
				[void][System.Windows.MessageBox]::Show(
					$msg,
					'MiniBot',
					[System.Windows.MessageBoxButton]::OK,
					[System.Windows.MessageBoxImage]::Error
				)
			} catch {}
			Complete-MBSessionExit -Message $msg
			return
		}

		$isCancel = $false
		try {
			if ($auth.SoftExit -or $auth.HardClose) { $isCancel = $true }
			elseif ($msg -match '(?i)cancel') { $isCancel = $true }
		} catch {}
		if ($isCancel) {
			$bye = 'session ended.'
			if ($msg -match '(?i)endpoint setup cancelled|login cancelled') {
				$bye = if ($msg -match '(?i)endpoint') { 'endpoint setup cancelled, session ended.' } else { 'login cancelled, session ended.' }
			}
			Complete-MBSessionExit -Message $bye
			return
		}
		try {
			Write-Host ""
			Write-MBRule -Color DarkRed -Label "connection failed"
			Write-Host "  $msg" -ForegroundColor Yellow
			if ($connTest -and $connTest.StatusCode -and $connTest.StatusCode -notin 401, 403) {
				Write-Host "  Model server unreachable or misconfigured." -ForegroundColor DarkYellow
			}
			Write-Host ""
		} catch {}
		Complete-MBSessionExit -Message 'connection failed, session ended.'
		return
	}

	if (-not (Start-MBWpfHost)) {
		Write-MBDebugLog -Step 'AGENT_WPF_FAILED'
		$detail = ''
		try { $detail = [string]$script:MB.LastWpfFailMsg } catch {}
		if ([string]::IsNullOrWhiteSpace($detail)) {
			try {
				if ($script:MB.Wpf -and $script:MB.Wpf.FailMsg) { $detail = [string]$script:MB.Wpf.FailMsg }
			} catch {}
		}
		if ([string]::IsNullOrWhiteSpace($detail)) { $detail = 'timeout or unknown error starting WPF host' }
		$msg = "MiniBot requires the WPF host and it failed to start.`n`n$detail`n`nCheck MiniBot-debug.log if present."
		try { Write-Warning "WPF host failed: $detail" } catch {}
		try {
			Add-Type -AssemblyName PresentationFramework -ErrorAction SilentlyContinue
			[void][System.Windows.MessageBox]::Show(
				$msg,
				'MiniBot',
				[System.Windows.MessageBoxButton]::OK,
				[System.Windows.MessageBoxImage]::Error
			)
		} catch {}
		Complete-MBSessionExit -Message 'WPF host failed, session ended.'
		return
	}
	Write-MBDebugLog -Step 'AGENT_WPF_READY' -Detail (Get-MBDebugLogPath)
	$script:MB.PreferWpfLogin = $false
	# Push model list into UI bag after host is ready
	try {
		$null = Refresh-MBRemoteModels -Force
		try { Update-MBWpfWindowTitle } catch {}
	} catch {}

	# Hard-exit on post-host failure (STA / instance lock)
	try {
	Initialize-MBToolGroups
	try { Update-MBWpfToolGroupBar -Force } catch {}
	Initialize-MBTokenCounting
	Initialize-MBToolsOverhead
	if ($script:MB.SpeechEnabled) {
		if (Test-MBSpeechUiOk) {
			try { $null = Enable-MBSpeechMode -On $true } catch {}
		} else {
			$script:MB.SpeechEnabled = $false
			Write-MBWarn "Speech disabled: WPF host not active."
		}
	}

	# First banner (default model): no divider above
	$script:MB.BannerShown = $true
	try {
		Show-MBActiveEndpointBanner -AuthType ([string]$connTest.AuthType) -ElapsedMs ([int]$connTest.ElapsedMs) `
			-IncludeNativeHelpers -IncludeTypeHint
	} catch {
		Show-MBBanner
		Write-MBOk ("Connected ({0}, {1} ms)" -f $connTest.AuthType, $connTest.ElapsedMs)
	}

	$script:Messages = @(Sync-MBSystemMessages -Messages @())
	$script:LastUserMessage = $null
	[void](Get-MBContextEstimate -Messages $script:Messages -ForceRefresh)
	try { Refresh-MBWpfStickyFromSession } catch {}
	try {
		Set-MBWpfPromptEnabled -Enabled $true -Focus
		Focus-MBWpfPrompt
	} catch {}
	try { Clear-MBWpfBootstrapTopmost } catch {}
	try {
		Start-Sleep -Milliseconds 30
		Clear-MBWpfBootstrapTopmost
		Focus-MBWpfPrompt
	} catch {}

	Write-MBDebugLog -Step 'AGENT_MAIN_LOOP'
	while ($true) {
		try {
			Write-MBDebugLog -Step 'LOOP_WAIT_INPUT'
			$userInput = Read-MBUserInput
			Write-MBDebugLog -Step 'LOOP_GOT_INPUT' -Detail ("len={0}" -f $(if ($null -eq $userInput) { -1 } else { ([string]$userInput).Length }))
		} catch {
			Write-MBDebugLog -Step 'LOOP_INPUT_ERROR' -Detail $_.Exception.Message
			try {
				Show-MBWpfError -Title 'Input UI error' -Message 'Failed to read the next prompt.' -Exception $_.Exception
			} catch {
				Write-MBErr "Input UI error: $($_.Exception.Message)"
			}
			Write-MBWarn "WPF input error - retrying prompt. (Close window to exit.)"
			$userInput = ""
			Start-Sleep -Milliseconds 200
		}
		if ($null -eq $userInput) { $userInput = "" }
		try {
			$trimmed = $userInput.Trim()
			$lower = $trimmed.ToLower()
		} catch {
			$trimmed = ""
			$lower = ""
		}

		$wpfCloseSentinel = ([string][char]0x1B + 'WPF_CLOSE')
		$wpfClosed = ($userInput -eq $wpfCloseSentinel)
		$exitReq = $false
		try {
			if ((Test-MBWpfActive) -and $null -ne $script:MB.Wpf) {
				$exitReq = [bool]$script:MB.Wpf['ExitRequested']
			}
		} catch { $exitReq = $false }
		# Ignore stale ExitRequested after a real prompt
		if ($wpfClosed -eq $false -and $exitReq -and [string]::IsNullOrWhiteSpace($trimmed)) {
			$wpfClosed = $true
		}

		$typedExit = ($lower -in @('exit', 'quit', '/exit', '/quit'))
		if ($wpfClosed -or $typedExit) {
			Write-MBDebugLog -Step 'LOOP_SESSION_END' -Detail ("wpfClosed={0} exitReq={1} lower={2}" -f $wpfClosed, $exitReq, $lower)
			Complete-MBSessionExit -Message 'session ended.'
			break
		}
		if ([string]::IsNullOrWhiteSpace($trimmed)) {
			try { Refresh-MBWpfStickyFromSession } catch {}
			continue
		}

		if ($trimmed.StartsWith('/') -or $lower -in @('autoapproveenable','autoapprovedisable')) {
			$parts = $trimmed -split '\s+', 2
			$cmd = $parts[0].ToLower()
			$arg = if ($parts.Count -gt 1) { $parts[1] } else { "" }

			switch -Regex ($cmd) {
				'^/help$|^/h$|^/\?$' { Show-MBHelp; continue }
				'^/status$|^/stat$'  { Show-MBStatus; continue }
				'^/context$|^/ctx$' {
					Show-MBContextDetail -Messages $script:Messages
					continue
				}
				'^/model$' {
					Write-MBInfo "Model: $(Get-MBDisplayModel)"
					if (-not [string]::IsNullOrWhiteSpace([string]$ModelAlias) -and [string]$ModelAlias -ne [string]$Model) {
						Write-MBInfo "Model id: $Model"
					}
					Write-MBInfo "Endpoint: $BaseUrl"
					Write-MBInfo ("n_ctx: {0} ({1})" -f $script:MB.ContextWindow, $(try { [string]$script:MB.ContextSource } catch { '?' }))
					Write-MBInfo ("max_out: {0}" -f (Get-MBEffectiveMaxTokens))
					continue
				}
				'^/tools$' {
					Write-Host ""
					if ($arg -match '^(?i)list|groups?$') {
						Write-Host (Get-MBToolGroupsStatus) -ForegroundColor Gray
						Write-Host ""
						continue
					}
					if ($arg) {
						$g = $arg.Trim().ToLowerInvariant()
						if ($g -in @('core','senses','system','network','diag','repair','setup','identity','shares','installers','sandbox','files','packages','registry','clipboard','web','full','all')) {
							$msg = Enable-MBToolGroup -Group $g
							Write-MBOk $msg
						} else {
							Write-MBWarn "Usage: /tools [core|senses|system|network|diag|repair|setup|identity|shares|installers|sandbox|files|packages|registry|clipboard|web|full|list]"
						}
						Write-Host ""
						continue
					}
					Write-Host ("  Profile: {0}  |  Active groups: {1}" -f $script:MB.ToolProfile, ((@($script:MB.ActiveToolGroups) -join ', '))) -ForegroundColor DarkGray
					Write-Host ""
					foreach ($gKey in @($script:MBToolCatalog.Keys)) {
						$meta = if ($script:MBToolGroupMeta -and $script:MBToolGroupMeta.Contains($gKey)) { $script:MBToolGroupMeta[$gKey] } else { $null }
						$isOn = @($script:MB.ActiveToolGroups) -contains $gKey
						$flag = if ($isOn) { 'ON ' } else { 'off' }
						$flagColor = if ($isOn) { 'Green' } else { 'DarkGray' }
						$label = if ($meta) { $meta.Label } else { $gKey }
						Write-Host "  [" -NoNewline -ForegroundColor DarkGray
						Write-Host $flag -NoNewline -ForegroundColor $flagColor
						Write-Host "] " -NoNewline -ForegroundColor DarkGray
						Write-Host $gKey -NoNewline -ForegroundColor Cyan
						Write-Host (" - {0}" -f $label) -ForegroundColor White
						if ($meta -and $meta.Description) {
							Write-Host ("       {0}" -f $meta.Description) -ForegroundColor DarkGray
						}
						foreach ($tn in @($script:MBToolCatalog[$gKey])) {
							if (Test-MBToolNameActive -Name $tn) {
								Write-Host ("       - {0}" -f $tn) -ForegroundColor Cyan
							} else {
								Write-Host ("       - {0}" -f $tn) -ForegroundColor DarkGray
							}
						}
					}
					Write-Host ""
					Write-Host "  /tools <group> enable  |  /tools full  |  /tools core  |  /tools list" -ForegroundColor DarkGray
					Write-Host ""
					continue
				}
				'^/sandbox$|^/sb$' {
					$sa = if ($arg) { $arg.Trim().ToLowerInvariant() } else { '' }
					if ($sa -match '^(clear|reset|wipe)\s+(all|global|machine|\*)$' -or $sa -match '^(clearall|clear-all|wipeall|purge)$') {
						Write-MBOk (Clear-MBSandboxAll)
					} elseif ($sa -match '^(clear|reset|wipe)$') {
						Write-MBOk (Clear-MBSandboxRoot)
					} else {
						Write-Host (Get-MBSandboxInfo) -ForegroundColor Gray
					}
					Write-Host ""
					continue
				}
				'^/speech$|^/voice$|^/tts$|^/ptt$' {
					if (-not (Test-MBSpeechUiOk)) {
						Write-MBWarn "Speech requires the WPF host."
						continue
					}
					$sa = if ($arg) { $arg.Trim() } else { '' }
					$saLow = $sa.ToLowerInvariant()
					if ($saLow -match '^(on|1|true|enable|start)$') {
						Write-MBOk (Enable-MBSpeechMode -On $true)
					} elseif ($saLow -match '^(off|0|false|disable|stop)$') {
						Write-MBOk (Enable-MBSpeechMode -On $false)
					} elseif ($saLow -match '^(auto|autoreply)$') {
						$script:MB.SpeechAutoReply = -not [bool]$script:MB.SpeechAutoReply
						Write-MBOk ("Speech auto-reply TTS: {0}" -f $(if ($script:MB.SpeechAutoReply) { 'ON' } else { 'off' }))
					} elseif ($saLow -match '^(autoon|auto-on)$') {
						$script:MB.SpeechAutoReply = $true
						Write-MBOk "Speech auto-reply TTS: ON"
					} elseif ($saLow -match '^(autooff|auto-off)$') {
						$script:MB.SpeechAutoReply = $false
						Write-MBOk "Speech auto-reply TTS: off"
					} elseif ($saLow -match '^(test|say)(\s|$)') {
						$say = 'MiniBot speech is working.'
						if ($sa -match '(?i)^(test|say)\s+(.+)$') { $say = $Matches[2] }
						Write-Host (Invoke-MBSpeak -Text $say -Async $false) -ForegroundColor Gray
					} elseif ($saLow -match '^(listen|mic)$') {
						$res = Invoke-MBSpeechListen -UpdatePrompt {
							param([string]$msg)
							if ($msg) {
								Write-Host ("  {0}" -f $msg) -ForegroundColor Magenta
							}
						}
						if ($res.ok) {
							Write-MBOk ("Heard: {0}" -f $res.text)
						} else {
							Write-MBWarn ("Listen failed: {0}" -f $(if ($res.error) { $res.error } else { 'no speech' }))
						}
					} else {
						$st = if ($script:MB.SpeechEnabled) { 'ON' } else { 'off' }
						$auto = if ($script:MB.SpeechAutoReply) { 'ON' } else { 'off' }
						$ready = if ($script:MB.SpeechReady) { 'ready' } else { 'not init' }
						Write-Host ""
						Write-Host ("  Speech mode : {0}  ({1})" -f $st, $ready) -ForegroundColor $(if ($script:MB.SpeechEnabled) { 'Green' } else { 'DarkGray' })
						Write-Host ("  Auto-reply  : {0}  (TTS final model answers)" -f $auto) -ForegroundColor Gray
						Write-Host "  Record      : hold Right-Ctrl to talk, release to stop (PTT)" -ForegroundColor Gray
						Write-Host "  Typing      : works anytime Right-Ctrl is not held (Left-Ctrl+Enter still multi-line)" -ForegroundColor DarkGray
						Write-Host "  Status shows on the input line (● REC ...). Esc cancels mid-PTT." -ForegroundColor Gray
						Write-Host "  Model tool  : SpeakText (group senses; enabled with /speech on)" -ForegroundColor Gray
						if ($script:MB.SpeechInitError) {
							Write-Host ("  Last error  : {0}" -f $script:MB.SpeechInitError) -ForegroundColor DarkYellow
						}
						if ($script:MB.SpeechLastHeard) {
							Write-Host ("  Last heard  : {0}" -f $script:MB.SpeechLastHeard) -ForegroundColor DarkGray
						}
						Write-Host ""
						Write-Host "  /speech on|off | auto | test | listen | say <text>" -ForegroundColor DarkGray
						Write-Host "  Launch: -SpeechEnabled:`$true  or  `$env:speech=1" -ForegroundColor DarkGray
						Write-Host ""
					}
					continue
				}
				'^/wd$' {
					Write-MBInfo $script:MB.WorkingDir
					continue
				}
				'^/cd$' {
					if (-not $arg) { Write-MBWarn "Usage: /cd <path>"; continue }
					$r = Invoke-SetWorkingDirectory -path $arg
					$script:Messages = @(Sync-MBSystemMessages -Messages $script:Messages)
					Write-MBInfo $r
					continue
				}
				'^/note$' {
					if (-not $arg) { Write-MBWarn "Usage: /note <text to remember>"; continue }
					if (Add-MBStickyNote -Text $arg -Kind note) {
						$script:Messages = @(Sync-MBSystemMessages -Messages $script:Messages)
						Write-MBOk "Pinned note."
					} else {
						Write-MBInfo "Note unchanged (empty or duplicate)."
					}
					continue
				}
				'^/find$|^/finding$|^/findings$' {
					if (-not $arg) { Write-MBWarn "Usage: /find <finding to pin>"; continue }
					if (Add-MBStickyNote -Text $arg -Kind finding) {
						$script:Messages = @(Sync-MBSystemMessages -Messages $script:Messages)
						Write-MBOk "Pinned finding."
					} else {
						Write-MBInfo "Finding unchanged (empty or duplicate)."
					}
					continue
				}
				'^/forget$' {
					Clear-MBSticky
					$script:Messages = @(Sync-MBSystemMessages -Messages $script:Messages)
					Write-MBOk "Sticky notes, findings, and digest cleared."
					continue
				}
				'^/clear$|^/reset$' {
					$script:Messages = @(Sync-MBSystemMessages -Messages @())
					$script:MB.StickyExtra = ''
					Write-MBOk "Conversation cleared (sticky notes kept - /forget to wipe those)."
					try { Refresh-MBWpfStickyFromSession } catch {}
					continue
				}
				'^/compact$' {
					$before = Get-MBContextEstimate -Messages $script:Messages
					$script:Messages = @(Manage-MBContext -Messages $script:Messages -ForceCompact)
					$script:Messages = @(Ensure-MBPromptBudget -Messages $script:Messages -TargetPct 0.65 -Verbose)
					$after = Get-MBContextEstimate -Messages $script:Messages
					Write-MBOk ("Compacted: {0:P0} -> {1:P0}  (~{2:N0} -> ~{3:N0} tok)  msgs {4}" -f `
						$before.Pct, $after.Pct, $before.PromptTokens, $after.PromptTokens, $script:Messages.Count)
					try { Refresh-MBWpfStickyFromSession } catch {}
					continue
				}
				'^/autocompact$' {
					if ($arg -match '^(off|0|false|disable)') {
						$script:MB.AutoCompact = $false
						Write-MBOk "AutoCompact OFF"
					} elseif ($arg -match '^(on|1|true|enable)') {
						$script:MB.AutoCompact = $true
						Write-MBOk "AutoCompact ON"
					} else {
						$script:MB.AutoCompact = -not $script:MB.AutoCompact
						Write-MBOk ("AutoCompact {0}" -f $(if ($script:MB.AutoCompact) { 'ON' } else { 'OFF' }))
					}
					try {
						if ($script:MB.Wpf) { $script:MB.Wpf.AutoCompactOn = [bool]$script:MB.AutoCompact }
						Refresh-MBWpfStickyFromSession
					} catch {}
					continue
				}
				'^/auto$|^/autoapproveenable$|^/autoapprovedisable$|^autoapproveenable$|^autoapprovedisable$' {
					if ($cmd -match 'disable' -or $arg -match '^(off|0|false|disable)') {
						$script:MB.AutoApprove = $false
						Write-MBOk "auto-approve OFF"
					} elseif ($cmd -match 'enable' -or $arg -match '^(on|1|true|enable)') {
						$script:MB.AutoApprove = $true
						Write-MBWarn "auto-approve ON - modifying actions will not prompt."
					} else {
						$script:MB.AutoApprove = -not $script:MB.AutoApprove
						if ($script:MB.AutoApprove) {
							Write-MBWarn "auto-approve ON"
						} else {
							Write-MBOk "auto-approve OFF"
						}
					}
					try {
						if ($script:MB.Wpf) {
							$script:MB.Wpf.AutoApproveOn = [bool]$script:MB.AutoApprove
							$script:MB.Wpf.AutoApproveDirty = $false
							$script:MB.Wpf.LowerRightSig = ''
						}
						Update-MBWpfLiveChrome -Force
					} catch {}
					$script:Messages = @(Sync-MBSystemMessages -Messages $script:Messages)
					try { Refresh-MBWpfStickyFromSession } catch {}
					continue
				}
				'^/save$' {
					try {
						$spath = [string]$arg
						if ([string]::IsNullOrWhiteSpace($spath)) {
							$def = ("MiniBot-session-{0:yyyyMMdd-HHmmss}.json" -f (Get-Date))
							$spath = Show-MBSessionFilePicker -Mode Save -FileName $def
							if ([string]::IsNullOrWhiteSpace($spath)) {
								Write-MBInfo "Save cancelled."
								continue
							}
						} else {
							$spath = $spath.Trim().Trim('"').Trim("'")
						}
						$p = Save-MBSession -Messages $script:Messages -Path $spath
						$fmt = Get-MBSessionFormat -Path $p
						Write-MBOk ("Saved ({0}): {1}" -f $fmt, $p)
					} catch { Write-MBErr $_.Exception.Message }
					continue
				}
				'^/load$' {
					try {
						$append = $false
						$lpath = [string]$arg
						if (-not [string]::IsNullOrWhiteSpace($lpath)) {
							$lpath = $lpath.Trim()
							if ($lpath -match '^(?i)append\s*$') {
								$append = $true
								$lpath = ''
							} elseif ($lpath -match '^(?i)append\s+(.+)$') {
								$append = $true
								$lpath = $Matches[1].Trim().Trim('"').Trim("'")
							} else {
								$lpath = $lpath.Trim('"').Trim("'")
							}
						}
						if ([string]::IsNullOrWhiteSpace($lpath)) {
							$title = if ($append) { ('{0} Load session (append markdown)' -f (Get-MBAgentDisplayTitle)) } else { '' }
							$lpath = Show-MBSessionFilePicker -Mode Open -Title $title
							if ([string]::IsNullOrWhiteSpace($lpath)) {
								Write-MBInfo "Load cancelled."
								continue
							}
						}
						$r = Load-MBSession -Path $lpath -Append:$append
						$fmt = [string]$r.Format
						Write-MBOk ("Loaded ({0}): {1}  |  messages: {2}" -f $fmt, $r.Path, $r.Count)
						if ($r.Cwd) { Write-Host ("  cwd: {0}" -f $r.Cwd) -ForegroundColor DarkGray }
						if ($r.Tools -and @($r.Tools).Count -gt 0) {
							Write-Host ("  tools: {0}" -f ((@($r.Tools) -join ', '))) -ForegroundColor DarkGray
						}
						if ($r.PSObject.Properties['Model'] -and $r.Model) {
							Write-Host ("  file model: {0}" -f $r.Model) -ForegroundColor DarkGray
						}
						# Model call to refill context; instruction is private (not painted as user bubble).
						# If the model replies anyway, show it normally.
						$userInput = 'Context Fully Reloaded.. Wait for the next message from the user before responding.'
						$trimmed = $userInput
						$script:MB.LoadResumeTurn = $true
					} catch {
						Write-MBErr $_.Exception.Message
						continue
					}
				}
				'^/retry$' {
					if (-not $script:LastUserMessage) {
						Write-MBWarn "No previous user message to retry."
						continue
					}
					$userInput = $script:LastUserMessage
					$trimmed = $userInput
				}
				default {
					if ($cmd.StartsWith('/')) {
						Write-MBWarn "Unknown command: $cmd  (try /help)"
						continue
					}
				}
			}
			if ($cmd -eq '/retry' -or [bool]$script:MB.LoadResumeTurn) {
			} elseif ($trimmed.StartsWith('/') -or $lower -in @('autoapproveenable','autoapprovedisable')) {
				continue
			}
		}

		try {
		$isLoadResume = $false
		try { $isLoadResume = [bool]$script:MB.LoadResumeTurn } catch { $isLoadResume = $false }
		if ($isLoadResume) { $script:MB.LoadResumeTurn = $false }
		Write-MBDebugLog -Step 'TURN_BEGIN' -Detail ("preview={0} loadResume={1}" -f $trimmed, $isLoadResume)
		# Keep /retry on the real last user line from the loaded session
		if (-not $isLoadResume) {
			$script:LastUserMessage = $userInput
		}
		$script:MB.UserTurns++
		try {
			Write-MBDebugLog -Step 'TURN_ADD_USER_MSG'
			$script:Messages += @{ role = 'user'; content = (Sanitize-MBText -Text ([string]$userInput)) }
		} catch {
			Write-MBDebugLog -Step 'TURN_ADD_USER_MSG_ERR' -Detail $_.Exception.Message
			Show-MBWpfError -Title 'Message error' -Message 'Could not add your message to history.' -Exception $_.Exception
			continue
		}

		try { Reset-MBToolLoopGuard } catch {}
		Write-MBDebugLog -Step 'TURN_CONTEXT_MANAGE'
		try {
			$script:Messages = @(Manage-MBContext -Messages $script:Messages)
		} catch {
			Write-MBWarn "Context manage failed: $($_.Exception.Message)"
			try { $script:Messages = @(Optimize-MBHistory -Messages $script:Messages) } catch {}
		}
		try { Update-MBWpfLiveChrome -Force } catch {}
		Write-MBDebugLog -Step 'TURN_CONTEXT_OK' -Detail ("msgs={0}" -f @($script:Messages).Count)

		# Paint user turn and working state
		try {
			Write-MBDebugLog -Step 'TURN_PAINT_USER'
			Write-Host ""
			if ($isLoadResume) {
				Write-MBInfo "Refilling model context..."
			} else {
				Write-MBUserMessage -Text $userInput
			}
			Show-MBWorkingHint
			Write-MBDebugLog -Step 'TURN_PAINT_USER_OK'
		} catch {
			Write-MBDebugLog -Step 'TURN_PAINT_USER_ERR' -Detail $_.Exception.Message
			if (-not $isLoadResume) {
				try { Write-MBUserMessage -Text $userInput } catch {}
			}
			try { Hide-MBPromptForWork } catch {}
		}

		Reset-MBInterrupt
		$turn = 0
		try {
			while ($turn -lt $MaxTurns) {
				$turn++
				$script:MB.AgentTurns++
				Write-MBDebugLog -Step 'TURN_MODEL_ITER' -Detail ("turn={0}" -f $turn)

				# Sync sticky state and budget before model call
				try {
					$script:Messages = @(Manage-MBContext -Messages $script:Messages)
				} catch {
					$script:Messages = @(Sync-MBSystemMessages -Messages $script:Messages)
				}

				$response = $null
				try {
					Write-MBDebugLog -Step 'TURN_CALL_STREAM'
					$response = Invoke-ModelStreaming -Messages $script:Messages
					Write-MBDebugLog -Step 'TURN_CALL_STREAM_DONE' -Detail ("null={0}" -f ($null -eq $response))
				} catch {
					Write-MBDebugLog -Step 'TURN_CALL_STREAM_THROW' -Detail $_.Exception.Message
					Write-MBErr "Model call threw: $($_.Exception.Message)"
					break
				}

				if ($script:MB.Interrupt -or ($response -and $response.interrupted)) {
					Reset-MBInterrupt
					Write-Host "  [turn aborted - stream cancelled]" -ForegroundColor Red
					break
				}
				if (-not $response) {
					Write-MBWarn "No model response after retries - returning to prompt."
					Write-Host "  Use /retry when the server is healthy again (500/502 are often transient)." -ForegroundColor DarkGray
					break
				}

				$assistantMessage = $null
				try {
					if ($response.choices -and @($response.choices).Count -gt 0) {
						$assistantMessage = $response.choices[0].message
					}
				} catch {
					Write-MBErr "Bad response shape: $($_.Exception.Message)"
					break
				}
				if (-not $assistantMessage) {
					Write-MBWarn "Empty assistant message - returning to prompt."
					break
				}

				$script:Messages += $assistantMessage
				try { Update-MBWpfLiveChrome } catch {}

				$tcList = @()
				try {
					$rawTc = Get-MBProp $assistantMessage 'tool_calls'
					if ($rawTc) { $tcList = @($rawTc) }
				} catch { $tcList = @() }

				if ($tcList.Count -eq 0) {
					$finalText = Get-MBProp $assistantMessage 'content'
					if ([string]::IsNullOrWhiteSpace([string]$finalText)) {
						if ($isLoadResume) {
							Write-MBInfo "Context refilled - waiting for your next message."
							break
						}
						Write-MBWarn "Model returned no text and no tools (context may be too noisy). Try GetBSODInfo or a narrower question."
						break
					}

					$fr = ''
					try { $fr = [string](Get-MBProp $response 'finish_reason') } catch { $fr = '' }
					$ct = 0
					try { $ct = [int](Get-MBProp $response 'completion_tokens') } catch {
						$ct = [int]$script:MB.LastServerCompletionTokens
					}
					$needCont = $false
					try { if ($response.truncated) { $needCont = $true } } catch {}
					$haveUsageCont = $false
					try {
						if ($fr -match '^(?i)length|max_tokens|limit$') { $haveUsageCont = $true }
						elseif ($ct -gt 0 -and $response.truncated) { $haveUsageCont = $true }
					} catch {}
					if (-not $needCont) {
						$needCont = Test-MBReplyIncomplete -Text ([string]$finalText) -FinishReason $fr -HasToolCalls $false -CompletionTokens $ct -HaveUsage $haveUsageCont
					}
					$maxCont = [math]::Max(0, [int]$MaxReplyContinues)
					$cont = 0
					while ($cont -lt $maxCont) {
						if (-not $needCont) {
							$needCont = Test-MBReplyIncomplete -Text ([string]$finalText) -FinishReason $fr -HasToolCalls $false -CompletionTokens $ct -HaveUsage $haveUsageCont
						}
						if (-not $needCont) { break }
						$needCont = $false
						$cont++
						Write-MBReplyStatus -Title 'continuing truncated reply' -Meta @(
							('{0}/{1}' -f $cont, $maxCont)
							('max_tokens {0}' -f $(try { [int]$script:MB.LastRequestMaxTokens } catch { [int](Get-MBEffectiveMaxTokens) }))
						) -Muted -DebugOnly
						$script:Messages += @{
							role    = 'user'
							content = (Sanitize-MBText -Text (Get-MBContinuePrompt))
						}
						try {
							$script:Messages = @(Manage-MBContext -Messages $script:Messages)
						} catch {
							$script:Messages = @(Sync-MBSystemMessages -Messages $script:Messages)
						}

						$contResponse = $null
						try {
							$contResponse = Invoke-ModelStreaming -Messages $script:Messages
						} catch {
							Write-MBWarn "Continue call failed: $($_.Exception.Message)"
							break
						}
						if ($script:MB.Interrupt -or ($contResponse -and $contResponse.interrupted)) {
							Reset-MBInterrupt
							Write-MBReplyStatus -Title 'continue aborted' -Error
							break
						}
						if (-not $contResponse) {
							Write-MBWarn "Continue returned no response."
							break
						}

						$contMsg = $null
						try {
							if ($contResponse.choices -and @($contResponse.choices).Count -gt 0) {
								$contMsg = $contResponse.choices[0].message
							}
						} catch {}
						if (-not $contMsg) {
							Write-MBWarn "Continue returned empty message."
							break
						}

						$script:Messages += $contMsg
						$contTools = @()
						try {
							$rawCt = Get-MBProp $contMsg 'tool_calls'
							if ($rawCt) { $contTools = @($rawCt) }
						} catch { $contTools = @() }

						if ($contTools.Count -gt 0) {
							$assistantMessage = $contMsg
							$tcList = $contTools
							break
						}

						$finalText = Get-MBProp $contMsg 'content'
						try { $fr = [string](Get-MBProp $contResponse 'finish_reason') } catch { $fr = '' }
						try { $ct = [int](Get-MBProp $contResponse 'completion_tokens') } catch {
							$ct = [int]$script:MB.LastServerCompletionTokens
						}
						try {
							if ($contResponse.truncated) { $needCont = $true; $haveUsageCont = $true }
						} catch {}
						if ($fr -match '^(?i)length|max_tokens|limit|max_completion_tokens$') {
							$needCont = $true
							$haveUsageCont = $true
						}
						$response = $contResponse
					}

					if ($tcList.Count -eq 0) {
						if ($cont -gt 0 -and (Test-MBReplyIncomplete -Text ([string]$finalText) -FinishReason $fr -HasToolCalls $false -CompletionTokens $ct -HaveUsage $haveUsageCont)) {
							Write-MBReplyStatus -Title 'still incomplete' -Meta @(
								('after {0} continue(s)' -f $cont)
							) -Hint 'say continue, or launch with -MaxTokens / -MaxReplyContinues higher' -DebugOnly -Muted
						}
						if ($script:MB.SpeechEnabled -and $script:MB.SpeechAutoReply -and -not [string]::IsNullOrWhiteSpace([string]$finalText)) {
							try {
								$null = Invoke-MBSpeak -Text ([string]$finalText) -Async $true
							} catch {}
						}
						break
					}
				}

				foreach ($tc in $tcList) {
					if ((Test-MBInterrupt)) { break }

					$fn = $null
					$argString = $null
					try {
						$fn = (Get-MBProp (Get-MBProp $tc 'function') 'name')
						$argString = (Get-MBProp (Get-MBProp $tc 'function') 'arguments')
					} catch {}
					if (-not $fn) { $fn = 'unknown' }

					$argsObj = Convert-MBToolArguments -ArgString $argString
					$parseFailed = $false
					if ($argsObj -and (Get-MBProp $argsObj '_parse_error')) {
						$parseFailed = $true
						Write-Host "  ~ JSON parse issue for $fn - args salvage failed" -ForegroundColor DarkYellow
					}
					if (-not $argsObj) { $argsObj = [pscustomobject]@{} }

					Write-Host "  -> " -NoNewline -ForegroundColor DarkGreen
					$fnLabel = Get-MBToolConsoleLabel -Name $fn -ArgsObj $argsObj
					Write-Host $fnLabel -NoNewline -ForegroundColor Green
					$hint = ""
					if ($fn -eq 'EnableToolGroup') {
						$eg = ''; $egs = $null
						if (Test-MBHasProp $argsObj 'group') { $eg = [string](Get-MBProp $argsObj 'group') }
						if (Test-MBHasProp $argsObj 'groups') { $egs = (Get-MBProp $argsObj 'groups') }
						$etoks = @(Get-MBEnableToolGroupTokens -Group $eg -groups $egs)
						if ($etoks.Count -gt 0) { $hint = "  $($etoks -join ', ')" }
					}
					elseif ($fn -eq 'ScanNetwork') {
						$hint = '  (usually ~30s)'
					}
					elseif ($fn -eq 'ProbeShares') {
						$hint = '  (port filter + map guess)'
					}
					elseif (Test-MBHasProp $argsObj 'path') { $hint = "  $(Get-MBProp $argsObj 'path')" }
					elseif (Test-MBHasProp $argsObj 'name') { $hint = "  $(Get-MBProp $argsObj 'name')" }
					elseif (Test-MBHasProp $argsObj 'piece') { $hint = "  piece=$(Get-MBProp $argsObj 'piece')" }
					elseif (Test-MBHasProp $argsObj 'command') {
						$c = [string](Get-MBProp $argsObj 'command')
						if ($c.Length -gt 70) { $c = $c.Substring(0, 67) + "..." }
						$hint = "  $c"
					}
					elseif (Test-MBHasProp $argsObj 'code') {
						$c = [string](Get-MBProp $argsObj 'code')
						if ($c.Length -gt 50) { $c = $c.Substring(0, 47) + "..." }
						$hint = "  code=$c"
					}
					elseif (Test-MBHasProp $argsObj 'url') { $hint = "  $(Get-MBProp $argsObj 'url')" }
					elseif (Test-MBHasProp $argsObj 'github_url') { $hint = "  $(Get-MBProp $argsObj 'github_url')" }
					Write-Host $hint -ForegroundColor DarkGray

					$toolResult = ""
					try {
						if ($parseFailed -and $fn -match '^(?i)SandBox') {
							$prev = [string](Get-MBProp $argsObj '_raw_preview')
							$toolResult = @"
ERROR: Could not parse tool arguments JSON for $fn.
The model must pass a single JSON object. For code, escape newlines as \n inside the JSON string (or keep code short).
Preview: $prev
Hint: Prefer SandBoxWrite name+code first, then SandBox piece=name with assert like `$Result.Value -eq 4 after printing JSON.
"@
						} else {
							$toolResult = Invoke-MBTool -Name $fn -ArgsObj $argsObj
						}
					} catch {
						$toolResult = "ERROR: tool $fn threw: $($_.Exception.Message)"
						Write-MBErr $toolResult
					}
					if ($null -eq $toolResult) { $toolResult = "" }
					$tr = [string]$toolResult
					if ($tr.TrimStart().StartsWith('{') -or $tr.TrimStart().StartsWith('[')) {
						try {
							$toolResult = [regex]::Replace($tr, '[\x00-\x08\x0B\x0C\x0E-\x1F]', ' ')
						} catch { $toolResult = $tr }
					} else {
						$toolResult = Sanitize-MBText -Text $tr
					}

					Write-Host "    ($($script:MB.LastToolMs) ms, $($toolResult.Length) chars)" -ForegroundColor DarkGray
					try {
						$toolSec = [double]([math]::Max(0, [int]$script:MB.LastToolMs) / 1000.0)
						Write-MBWorkedStamp -Seconds $toolSec
					} catch {}

					$tcId = Get-MBProp $tc 'id'
					if (-not $tcId) { $tcId = "call_$([guid]::NewGuid().ToString('N').Substring(0,8))" }

					$script:Messages += @{
						role         = 'tool'
						tool_call_id = [string]$tcId
						content      = [string]$toolResult
					}
					try { Update-MBWpfLiveChrome } catch {}
				}

				if ($script:MB.Interrupt) {
					Reset-MBInterrupt
					Write-Host "  [tool loop aborted]" -ForegroundColor Yellow
					break
				}

				try {
					$script:Messages = @(Manage-MBContext -Messages $script:Messages)
				} catch {
					Write-MBWarn "History optimize failed: $($_.Exception.Message)"
					try { $script:Messages = @(Optimize-MBHistory -Messages $script:Messages) } catch {}
				}
				try { Update-MBWpfLiveChrome -Force } catch {}

				Write-Host "  ... feeding tool results back to model ..." -ForegroundColor DarkGray
			}
		} catch {
			$errMsg = $_.Exception.Message
			Write-MBDebugLog -Step 'AGENT_LOOP_CATCH' -Detail $errMsg
			$pos = ''
			try {
				if ($_.InvocationInfo -and $_.InvocationInfo.PositionMessage) {
					$pos = [string]$_.InvocationInfo.PositionMessage
				}
			} catch {}
			try {
				Show-MBWpfError -Title 'Agent loop error' -Message ($errMsg + $(if ($pos) { "`n$pos" } else { '' })) -Exception $_.Exception
			} catch {
				Write-MBErr "Agent loop error: $errMsg"
				if ($pos) { Write-Host $pos -ForegroundColor DarkGray }
			}
		}

		if ($turn -ge $MaxTurns) {
			Write-MBWarn "Hit max tool-loop turns ($MaxTurns). Summarizing context for next message."
		}

		try {
			$script:Messages = @(Sync-MBSystemMessages -Messages $script:Messages)
		} catch {}

		try { Clear-MBWorkingState } catch {}
		Write-MBDebugLog -Step 'TURN_END'
		} catch {
			# Per-turn catch; session stays open
			Write-MBDebugLog -Step 'TURN_CATCH' -Detail $_.Exception.Message
			try {
				Show-MBWpfError -Title 'Turn error' -Message 'Something failed while handling your message. You can try again.' -Exception $_.Exception
			} catch {
				Write-MBErr "Turn error: $($_.Exception.Message)"
			}
			try { Clear-MBWorkingState } catch {}
		}
	}
	Write-MBDebugLog -Step 'AGENT_LOOP_EXIT'
	} catch {
		Write-MBDebugLog -Step 'AGENT_SESSION_CATCH' -Detail $_.Exception.Message
		try {
			Show-MBWpfError -Title 'Session error' -Message 'A fatal error occurred in the agent session.' -Exception $_.Exception
		} catch {
			try {
				Add-Type -AssemblyName PresentationFramework -ErrorAction SilentlyContinue
				[void][System.Windows.MessageBox]::Show(
					$_.Exception.Message,
					'MiniBot session error',
					[System.Windows.MessageBoxButton]::OK,
					[System.Windows.MessageBoxImage]::Error
				)
			} catch {}
		}
		$script:MB.SessionEnding = $true
	} finally {
		Write-MBDebugLog -Step 'AGENT_FINALLY' -Detail ("SessionEnding={0}" -f $script:MB.SessionEnding)
		try { Dispose-MBSharedHttpClient } catch {}
		try { Complete-MBSessionExit } catch {
			try { Stop-MBWpfHost } catch {}
			try {
				if ($script:SingleInstanceEvent) {
					$script:SingleInstanceEvent.Close()
					$script:SingleInstanceEvent.Dispose()
					$script:SingleInstanceEvent = $null
				}
			} catch {}
			try { [Environment]::Exit(0) } catch { Exit 0 }
		}
	}
}

try {
	Write-MBDebugLog -Step 'ENTRY_BEGIN'
	Start-LocalAgent
	Write-MBDebugLog -Step 'ENTRY_AGENT_RETURNED'
} catch {
	Write-MBDebugLog -Step 'ENTRY_CATCH' -Detail $_.Exception.Message
	try {
		Show-MBWpfError -Title 'MiniBot failed to start' -Message $_.Exception.Message -Exception $_.Exception
	} catch {
		try {
			Add-Type -AssemblyName PresentationFramework -ErrorAction SilentlyContinue
			[void][System.Windows.MessageBox]::Show(
				$_.Exception.Message,
				'MiniBot failed to start',
				[System.Windows.MessageBoxButton]::OK,
				[System.Windows.MessageBoxImage]::Error
			)
		} catch {
			try { Microsoft.PowerShell.Utility\Write-Host "MiniBot failed: $($_.Exception.Message)" -ForegroundColor Red } catch {}
		}
	}
} finally {
	Write-MBDebugLog -Step 'ENTRY_FINALLY' -Detail ("SessionEnding={0}" -f $script:MB.SessionEnding)
	try { Dispose-MBSharedHttpClient } catch {}
	try { $null = Invoke-MBTempCleanup -All } catch {}
	# tear down host and single-instance lock
	try { Complete-MBSessionExit } catch {
		try { $null = Invoke-MBTempCleanup -All } catch {}
		try { Stop-MBWpfHost } catch {}
		try {
			if ($script:SingleInstanceEvent) {
				$script:SingleInstanceEvent.Close()
				$script:SingleInstanceEvent.Dispose()
				$script:SingleInstanceEvent = $null
			}
		} catch {}
		try { [Environment]::Exit(0) } catch { Exit 0 }
	}
}
